export enum Category {
  MEAT = 'Carne',
  SIDE = 'Acompanhamento',
  SALAD = 'Salada',
  DESSERT = 'Sobremesa',
  DRINK = 'Bebida'
}

export interface Dish {
  id: string;
  name: string;
  category: Category;
  description?: string;
}

export interface MenuConfig {
  counts: Record<Category, number>;
  theme: string;
}

export interface GeneratedMenu {
  selections: Record<Category, Dish[]>;
  chefNote: string;
}

import { Category, Dish } from './types';

