export const ICONS = {
  MEAT: '🥩',
  SIDE: '🍚',
  SALAD: '🥗',
  DESSERT: '🍰',
  DRINK: '🍷',
  CHEF: '👨‍🍳'
};

import { GoogleGenAI, Type } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig
): Promise<GeneratedMenu> {
  const prompt = `
    Como um Chef de Cozinha renomado, crie um cardápio equilibrado e sofisticado baseado nas seguintes restrições:
    - Tema/Vibe desejada: "${config.theme}"
    - Quantidade de itens por categoria:
      ${Object.entries(config.counts)
        .map(([cat, count]) => `- ${cat}: ${count}`)
        .join('\n')}

    Use APENAS os itens da lista abaixo para compor o cardápio:
    ${JSON.stringify(dishPool)}

    Se não houver itens suficientes em uma categoria na lista, você pode sugerir pratos novos que combinem perfeitamente com o tema, mas priorize os existentes.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          selections: {
            type: Type.OBJECT,
            properties: {
              [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DRINK]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
            }
          },
          chefNote: { type: Type.STRING, description: "Uma nota curta explicando a harmonia do cardápio." }
        },
        required: ["selections", "chefNote"]
      }
    }
  });

  return JSON.parse(response.text) as GeneratedMenu;
}

import React, { useState, useCallback } from 'react';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 6,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Casual e Refrescante'
  });

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      const wb = XLSX.read(bstr, { type: 'binary' });
      const wsname = wb.SheetNames[0];
      const ws = wb.Sheets[wsname];
      const data = XLSX.utils.sheet_to_json(ws) as any[];

      const parsedDishes: Dish[] = data.map((item, idx) => ({
        id: `upload-${idx}`,
        name: item.Nome || item.name || item.Prato || 'Sem nome',
        category: (item.Categoria || item.category || item.Tipo) as Category || Category.MEAT,
        description: item.Descricao || item.description || ''
      }));

      if (parsedDishes.length > 0) {
        setDishPool(parsedDishes);
        alert(`${parsedDishes.length} itens carregados com sucesso!`);
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
    } catch (error) {
      console.error(error);
      alert('Ocorreu um erro ao gerar o cardápio. Tente novamente.');
    } finally {
      setIsGenerating(false);
    }
  };

  const updateCount = (cat: Category, delta: number) => {
    setConfig(prev => ({
      ...prev,
      counts: {
        ...prev.counts,
        [cat]: Math.max(0, prev.counts[cat] + delta)
      }
    }));
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="bg-white border-b border-stone-200 py-12 px-6 mb-8 shadow-sm">
        <div className="max-w-4xl mx-auto text-center">
          <h1 className="serif text-5xl md:text-6xl text-orange-900 mb-4">ChefAI</h1>
          <p className="text-stone-500 text-lg">Curadoria inteligente para o seu próximo evento ou refeição.</p>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 grid grid-cols-1 md:grid-cols-12 gap-8">

        {/* Sidebar Controls */}
        <div className="md:col-span-5 space-y-8">
          <section className="bg-white p-6 rounded-2xl shadow-sm border border-stone-100">
            <h2 className="font-bold text-xl mb-4 flex items-center gap-2">
              <span>⚙️</span> Configurações
            </h2>

            <div className="space-y-4">
              {Object.entries(config.counts).map(([cat, count]) => (
                <div key={cat} className="flex items-center justify-between p-3 bg-stone-50 rounded-xl">
                  <span className="flex items-center gap-2">
                    <span className="text-xl">{(ICONS as any)[cat]}</span>
                    <span className="font-medium text-stone-700">{cat}s</span>
                  </span>
                  <div className="flex items-center gap-3">
                    <button 
                      onClick={() => updateCount(cat as Category, -1)}
                      className="w-8 h-8 rounded-full bg-white border border-stone-200 hover:bg-stone-100 transition flex items-center justify-center"
                    >
                      -
                    </button>
                    <span className="w-6 text-center font-bold">{count}</span>
                    <button 
                      onClick={() => updateCount(cat as Category, 1)}
                      className="w-8 h-8 rounded-full bg-white border border-stone-200 hover:bg-stone-100 transition flex items-center justify-center"
                    >
                      +
                    </button>
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-6">
              <label className="block text-sm font-medium text-stone-500 mb-1">Tema / Estilo</label>
              <input 
                type="text" 
                value={config.theme}
                onChange={(e) => setConfig({...config, theme: e.target.value})}
                placeholder="Ex: Jantar Italiano, Saudável, Churrasco..."
                className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-orange-500 focus:outline-none"
              />
            </div>
          </section>

          <section className="bg-white p-6 rounded-2xl shadow-sm border border-stone-100">
            <h2 className="font-bold text-xl mb-4 flex items-center gap-2">
              <span>📊</span> Dados Customizados
            </h2>
            <p className="text-sm text-stone-500 mb-4">Carregue sua própria lista de opções via Excel (.xlsx) ou CSV.</p>
            <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-stone-300 border-dashed rounded-xl cursor-pointer bg-stone-50 hover:bg-stone-100 transition">
              <div className="flex flex-col items-center justify-center pt-5 pb-6">
                <span className="text-2xl mb-2">📁</span>
                <p className="text-xs text-stone-500">Clique para selecionar arquivo</p>
              </div>
              <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
            </label>
            <div className="mt-4 flex items-center justify-between text-sm">
              <span className="text-stone-400">Total no banco:</span>
              <span className="font-bold text-orange-700">{dishPool.length} itens</span>
            </div>
          </section>
        </div>

        {/* Main Display Area */}
        <div className="md:col-span-7 space-y-6">
          <button 
            onClick={handleGenerate}
            disabled={isGenerating}
            className={`w-full py-4 px-6 rounded-2xl font-bold text-lg shadow-lg transition-all transform hover:scale-[1.02] flex items-center justify-center gap-3 ${
              isGenerating ? 'bg-stone-400 cursor-not-allowed' : 'bg-orange-600 hover:bg-orange-700 text-white'
            }`}
          >
            {isGenerating ? (
              <>
                <div className="animate-spin h-5 w-5 border-2 border-white border-t-transparent rounded-full" />
                Criando Cardápio Perfeito...
              </>
            ) : (
              <>
                <span>✨</span> Gerar Cardápio com IA
              </>
            )}
          </button>

          {!generatedMenu && !isGenerating && (
            <div className="bg-stone-100 border-2 border-dashed border-stone-200 rounded-3xl h-96 flex flex-col items-center justify-center p-8 text-center">
              <span className="text-6xl mb-4 opacity-30">🍽️</span>
              <p className="text-stone-400 font-medium">Seu cardápio aparecerá aqui após o processamento da IA.</p>
            </div>
          )}

          {generatedMenu && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
              <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-stone-100">
                <div className="bg-orange-50 p-8 border-b border-orange-100">
                  <div className="flex items-center gap-2 text-orange-600 font-bold uppercase tracking-wider text-sm mb-2">
                    <span className="text-xl">⭐</span> Sugestão do Chef
                  </div>
                  <h3 className="serif text-3xl text-stone-900">{config.theme}</h3>
                </div>

                <div className="p-8 space-y-10">
                  {Object.entries(generatedMenu.selections).map(([cat, items]) => {
                    const typedItems = items as any[];
                    if (typedItems.length === 0) return null;

                    return (
                      <div key={cat} className="space-y-4">
                        <h4 className="flex items-center gap-2 font-bold text-stone-400 uppercase tracking-widest text-xs">
                          <span className="text-lg">{(ICONS as any)[cat]}</span>
                          {cat}s
                        </h4>
                        <div className="grid gap-4">
                          {typedItems.map((item, idx) => (
                            <div key={idx} className="group flex justify-between items-start border-l-2 border-transparent hover:border-orange-200 pl-4 transition-all">
                              <div>
                                <h5 className="font-semibold text-lg text-stone-800">{item.name}</h5>
                                {item.description && (
                                  <p className="text-stone-500 text-sm">{item.description}</p>
                                )}
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}

                  <div className="pt-8 mt-8 border-t border-stone-100 italic text-stone-600 bg-stone-50 p-6 rounded-2xl relative">
                    <span className="absolute -top-4 left-6 text-4xl opacity-20">"</span>
                    <p className="relative z-10 leading-relaxed">
                      {generatedMenu.chefNote}
                    </p>
                    <div className="mt-4 flex items-center gap-2 not-italic font-bold text-stone-800">
                      <span>{ICONS.CHEF}</span> Chef Virtual AI
                    </div>
                  </div>
                </div>

                <div className="p-4 bg-stone-900 flex justify-center gap-4">
                   <button 
                    onClick={() => window.print()} 
                    className="text-white hover:text-orange-400 text-sm flex items-center gap-2 py-2 px-4 rounded-lg transition"
                   >
                     <span>🖨️</span> Imprimir Cardápio
                   </button>
                   <button 
                    onClick={() => {
                      const text = `Meu Cardápio: ${config.theme}\n\n` + 
                        Object.entries(generatedMenu.selections)
                          .map(([cat, items]) => `${cat}s:\n` + (items as any[]).map(i => `- ${i.name}`).join('\n'))
                          .join('\n\n');
                      navigator.clipboard.writeText(text);
                      alert('Copiado para a área de transferência!');
                    }}
                    className="text-white hover:text-orange-400 text-sm flex items-center gap-2 py-2 px-4 rounded-lg transition"
                   >
                     <span>📋</span> Copiar Texto
                   </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer / Info */}
      <footer className="mt-20 text-center text-stone-400 text-sm py-8">
        <p>© 2024 ChefAI - Inteligência Gastronômica</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [showInventory, setShowInventory] = useState(false);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 6,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Experiência Mediterrânea'
  });

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const parsedDishes: Dish[] = data.map((item, idx) => ({
          id: `custom-${Date.now()}-${idx}`,
          name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
          category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
          description: item.Descricao || item.description || item.Ingredientes || ''
        }));

        setDishPool(prev => [...prev, ...parsedDishes]);
        alert(`${parsedDishes.length} novos pratos adicionados ao seu acervo!`);
      } catch (err) {
        alert('Erro ao processar arquivo. Verifique se as colunas estão corretas (Nome, Categoria).');
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
    } catch (error) {
      console.error(error);
      alert('A IA está ocupada na cozinha. Tente novamente em instantes.');
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    setDishPool(prev => prev.filter(d => d.id !== id));
  };

  const clearPool = () => {
    if(confirm('Deseja limpar todos os pratos?')) setDishPool([]);
