            <h2 className="serif text-3xl mb-6 text-[#1a3a3a]">Compor Menu</h2>

            <div className="space-y-5">
              {Object.entries(config.counts).map(([cat, count]) => (
                <div key={cat} className="flex items-center justify-between group">
                  <div className="flex flex-col">
                    <span className="text-xs uppercase tracking-widest text-stone-400 font-bold mb-1">{cat}s</span>
                    <span className="text-lg font-semibold flex items-center gap-2">
                      <span className="opacity-70">{(ICONS as any)[cat]}</span>
                      {cat}
                    </span>
                  </div>
                  <div className="flex items-center gap-4 bg-stone-50 p-1 rounded-full border border-stone-100">
                    <button 
                      onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))}
