        </div>

        {/* Exibição do Cardápio / Inventário */}
        <div className="lg:col-span-8">
          {showInventory ? (
            <div className="bg-white rounded-3xl p-8 border border-stone-200 shadow-sm animate-in fade-in slide-in-from-right-4 duration-300">
              <div className="flex justify-between items-center mb-8">
                <h2 className="serif text-4xl">Acervo de Pratos</h2>
                <button onClick={clearPool} className="text-red-500 text-xs font-bold uppercase tracking-widest hover:underline">Limpar Tudo</button>
