                  <button 
                    onClick={saveAsImage}
                    className="flex items-center gap-3 px-8 py-4 bg-white border-2 border-[#d4af37]/30 rounded-full hover:border-[#d4af37] transition font-bold text-xs uppercase tracking-widest shadow-lg text-[#1a3a3a]"
                  >
