                  <button 
                    onClick={() => window.print()}
                    className="flex items-center gap-3 px-8 py-4 bg-white border-2 border-stone-100 rounded-full hover:border-stone-400 transition font-bold text-xs uppercase tracking-widest shadow-lg text-stone-600"
