            </div>
          )}
        </div>
      </main>

      {/* Background Decor */}
      <div className="fixed inset-0 -z-10 pointer-events-none flex items-center justify-center overflow-hidden opacity-[0.03]">
        <span className="serif text-[50vw] text-stone-900 select-none">CHEF</span>
      </div>
    </div>
  );
};

export default App;

export enum Category {
  MEAT = 'Carne',
  SIDE = 'Acompanhamento',
  SALAD = 'Salada',
  DESSERT = 'Sobremesa',
  DRINK = 'Bebida'
}

export interface Dish {
  id: string;
  name: string;
  category: Category;
  description?: string;
}

export interface MenuConfig {
  counts: Record<Category, number>;
  theme: string;
  baseOption: string;
}

export interface GeneratedMenu {
  selections: Record<Category, Dish[]>;
  chefNote: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig
): Promise<GeneratedMenu> {
  const prompt = `
    Como um Chef Executivo de um restaurante 3 estrelas Michelin, sua tarefa é organizar um cardápio impecável.

    CONDIÇÕES DO EVENTO:
    - Tema: "${config.theme}"
    - Base Gastronômica/Estilo: "${config.baseOption}"
    - Estrutura solicitada:
      ${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${count} Opções de ${cat}`)
        .join('\n')}

    ACERVO DE INGREDIENTES/PRATOS DISPONÍVEIS:
    ${JSON.stringify(dishPool.map(d => ({ name: d.name, cat: d.category, desc: d.description })))}

    REGRAS DE OURO:
    1. PRIORIDADE TOTAL: Use os itens do acervo fornecido que se encaixem na "Base Gastronômica" (${config.baseOption}).
    2. HARMONIA: Se o acervo for insuficiente ou se os itens não combinarem com a base e o tema, você pode "elevar" os pratos do acervo com descrições gourmet ou sugerir novos pratos (apenas se necessário para manter o nível de qualidade e fidelidade ao estilo).
    3. EQUILÍBRIO: Garanta que as carnes não se repitam em textura e as saladas ofereçam frescor e contraste.
    4. DESCRIÇÃO: Escreva descrições apetitosas para cada prato (ex: "Lentamente defumado em lenha de macieira" em vez de apenas "Carne assada").
    5. NOTA DO CHEF: Escreva uma justificativa elegante para a escolha desta composição baseada no estilo "${config.baseOption}".

    Responda em JSON seguindo o schema fornecido.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          selections: {
            type: Type.OBJECT,
            properties: {
              [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DRINK]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
            }
          },
          chefNote: { type: Type.STRING, description: "Justificativa gastronômica do menu." }
        },
        required: ["selections", "chefNote"]
      }
    }
  });

  const parsed = JSON.parse(response.text);

  // Assegurar que categorias vazias não quebrem o mapeamento se a IA omitir chaves
  const finalSelections: any = {};
  Object.values(Category).forEach(cat => {
    finalSelections[cat] = parsed.selections[cat] || [];
  });

  return { ...parsed, selections: finalSelections };
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [showInventory, setShowInventory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [newlyAddedIds, setNewlyAddedIds] = useState<Set<string>>(new Set());
  const menuRef = useRef<HTMLDivElement>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 6,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Almoço Executivo',
    baseOption: 'Cozinha Contemporânea'
  });

  // Auto-hide toast
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Clear highlights after a delay
  useEffect(() => {
    if (newlyAddedIds.size > 0) {
      const timer = setTimeout(() => setNewlyAddedIds(new Set()), 3000);
      return () => clearTimeout(timer);
    }
  }, [newlyAddedIds]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const ids: string[] = [];
        const parsedDishes: Dish[] = data.map((item, idx) => {
          const id = `custom-${Date.now()}-${idx}`;
          ids.push(id);
          return {
            id,
            name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
            category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
            description: item.Descricao || item.description || item.Ingredientes || ''
          };
        });

        setDishPool(prev => [...prev, ...parsedDishes]);
        setNewlyAddedIds(new Set(ids));
        setToast({ message: `${parsedDishes.length} pratos adicionados com sucesso ao acervo!`, type: 'success' });
        if (!showInventory) setShowInventory(true);
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo. Verifique se as colunas estão corretas.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; // Reset input
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
    } catch (error) {
      console.error(error);
      setToast({ message: 'A IA está ocupada na cozinha. Tente novamente em instantes.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    setDishPool(prev => prev.filter(d => d.id !== id));
  };

  const clearPool = () => {
    if(confirm('Deseja limpar todos os pratos do acervo?')) {
        setDishPool([]);
        setToast({ message: 'Acervo limpo com sucesso.', type: 'success' });
    }
  };

  const saveAsImage = async () => {
    if (!menuRef.current) return;

    try {
      const dataUrl = await toPng(menuRef.current, {
        quality: 1,
        pixelRatio: 2,
        backgroundColor: '#ffffff',
      });
      const link = document.createElement('a');
      link.download = `ChefAI-Menu-${config.theme.replace(/\s+/g, '-')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Falha ao salvar imagem', err);
      setToast({ message: 'Não foi possível gerar a imagem. Tente imprimir como PDF.', type: 'error' });
    }
  };

  return (
    <div className="min-h-screen selection:bg-orange-100 pb-20 relative">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#1a3a3a]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✨' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
            <button onClick={() => setToast(null)} className="ml-2 opacity-50 hover:opacity-100 transition">✕</button>
          </div>
        </div>
      )}

      {/* Navbar Minimalista */}
      <nav className="no-print sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-stone-200 px-6 py-4">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-2xl">👨‍🍳</span>
            <span className="serif text-2xl font-bold tracking-tight text-[#1a3a3a]">ChefAI</span>
          </div>
          <button 
            onClick={() => setShowInventory(!showInventory)}
            className={`text-sm font-semibold flex items-center gap-2 px-4 py-2 rounded-full border transition ${
              showInventory 
                ? 'bg-stone-900 text-white border-stone-900 shadow-inner' 
                : 'bg-white text-stone-600 border-stone-200 hover:text-stone-900 hover:border-stone-400'
            }`}
          >
            {showInventory ? 'Fechar Acervo' : 'Gerenciar Acervo'} ({dishPool.length})
          </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 pt-12 grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Painel de Controle */}
        <div className="lg:col-span-4 space-y-8 no-print">
          <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-200">
            <h2 className="serif text-3xl mb-6 text-[#1a3a3a]">Compor Menu</h2>

            <div className="space-y-6">
              {/* Opção Base Field */}
              <div className="p-4 bg-[#fcfaf7] rounded-2xl border border-[#d4af37]/20">
                <label className="block text-[10px] uppercase tracking-[0.2em] text-[#b8860b] font-bold mb-2">Opção Base do Cardápio</label>
                <select 
                  value={config.baseOption}
                  onChange={(e) => setConfig({...config, baseOption: e.target.value})}
                  className="w-full bg-transparent border-none focus:ring-0 serif text-xl text-[#1a3a3a] cursor-pointer"
                >
                  <option value="Cozinha Contemporânea">Cozinha Contemporânea</option>
                  <option value="Tradicional Brasileira">Tradicional Brasileira</option>
                  <option value="Clássica Francesa">Clássica Francesa</option>
                  <option value="Mediterrânea">Mediterrânea</option>
                  <option value="Fusion Oriental">Fusion Oriental</option>
                  <option value="Churrasco Gourmet">Churrasco Gourmet</option>
                  <option value="Vegano & Orgânico">Vegano & Orgânico</option>
                  <option value="Slow Food">Slow Food</option>
                </select>
              </div>

              {/* Category Counts */}
              <div className="space-y-5 py-2">
                {Object.entries(config.counts).map(([cat, count]) => (
                  <div key={cat} className="flex items-center justify-between group">
                    <div className="flex flex-col">
                      <span className="text-xs uppercase tracking-widest text-stone-400 font-bold mb-1">{cat}s</span>
                      <span className="text-lg font-semibold flex items-center gap-2">
                        <span className="opacity-70">{(ICONS as any)[cat]}</span>
                        {cat}
                      </span>
                    </div>
                    <div className="flex items-center gap-4 bg-stone-50 p-1 rounded-full border border-stone-100">
                      <button 
                        onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))}
                        className="w-10 h-10 rounded-full flex items-center justify-center hover:bg-white transition shadow-sm font-bold disabled:opacity-30"
                        disabled={count === 0}
                      >
                        −
                      </button>
