                  <div className="absolute top-0 right-0 w-12 h-12 border-t-4 border-r-4 border-[#d4af37] pointer-events-none"></div>
                  <div className="absolute bottom-0 left-0 w-12 h-12 border-b-4 border-l-4 border-[#d4af37] pointer-events-none"></div>
