export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [showInventory, setShowInventory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [newlyAddedIds, setNewlyAddedIds] = useState<Set<string>>(new Set());
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Almoço de Domingo',
    baseOption: 'Cozinha Brasileira'
  });

  // Auto-hide toast
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Clear highlights after a delay
  useEffect(() => {
    if (newlyAddedIds.size > 0) {
      const timer = setTimeout(() => setNewlyAddedIds(new Set()), 3000);
      return () => clearTimeout(timer);
    }
  }, [newlyAddedIds]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const ids: string[] = [];
        const parsedDishes: Dish[] = data.map((item, idx) => {
          const id = `custom-${Date.now()}-${idx}`;
          ids.push(id);
          return {
            id,
            name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
            category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
            description: item.Descricao || item.description || item.Ingredientes || ''
          };
        });

        setDishPool(prev => [...prev, ...parsedDishes]);
        setNewlyAddedIds(new Set(ids));
        setToast({ message: `${parsedDishes.length} pratos adicionados com sucesso ao acervo!`, type: 'success' });
        if (!showInventory) setShowInventory(true);
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo. Verifique se as colunas estão corretas.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; // Reset input
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio. Adicione pratos ou restaure os padrões.', type: 'error' });
      setShowInventory(true);
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
    } catch (error) {
      console.error(error);
      setToast({ message: 'A IA está ocupada na cozinha. Tente novamente em instantes.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    if (window.confirm('Tem certeza que deseja remover este prato?')) {
      setDishPool(prev => prev.filter(d => d.id !== id));
      if (editingDish?.id === id) setEditingDish(null);
      setNewlyAddedIds(prev => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
      setToast({ message: 'Prato removido com sucesso.', type: 'success' });
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => prev.map(d => d.id === editingDish.id ? editingDish : d));
    setEditingDish(null);
    setToast({ message: 'Prato atualizado com sucesso.', type: 'success' });
  };

  const clearPool = () => {
    if(window.confirm('ATENÇÃO: Deseja apagar TODOS os pratos do acervo? Esta ação não pode ser desfeita.')) {
        setDishPool([]);
        setNewlyAddedIds(new Set());
        setEditingDish(null);
        setToast({ message: 'Acervo completamente limpo.', type: 'success' });
    }
  };

  const restoreDefaults = () => {
    if(window.confirm('Deseja restaurar o acervo para os pratos padrão do sistema?')) {
        setDishPool(DEFAULT_DISHES);
        setNewlyAddedIds(new Set());
        setToast({ message: 'Acervo restaurado com sucesso.', type: 'success' });
    }
  };

  const saveAsImage = async () => {
    if (!menuRef.current) return;

    try {
      const dataUrl = await toPng(menuRef.current, {
        quality: 1,
        pixelRatio: 2,
        backgroundColor: '#ffffff',
      });
      const link = document.createElement('a');
      link.download = `ChefAI-Menu-${config.theme.replace(/\s+/g, '-')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Falha ao salvar imagem', err);
      setToast({ message: 'Não foi possível gerar a imagem. Tente imprimir como PDF.', type: 'error' });
    }
  };

  return (
    <div className="min-h-screen selection:bg-orange-100 pb-20 relative">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#1a3a3a]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✨' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
            <button onClick={() => setToast(null)} className="ml-2 opacity-50 hover:opacity-100 transition">✕</button>
          </div>
        </div>
      )}

      {/* Modal de Edição */}
      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-[#1a3a3a]/40 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 border border-stone-200 animate-in zoom-in duration-300">
            <h3 className="serif text-3xl text-[#1a3a3a] mb-6 border-b border-stone-100 pb-4">Editar Prato</h3>
            <form onSubmit={handleUpdateDish} className="space-y-5">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome do Prato</label>
                <input 
                  type="text" 
                  required
                  value={editingDish.name}
                  onChange={e => setEditingDish({...editingDish, name: e.target.value})}
                  className="w-full px-5 py-4 rounded-2xl border border-stone-200 focus:border-[#d4af37] focus:ring-0 transition serif text-xl"
                />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select 
                  value={editingDish.category}
                  onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})}
                  className="w-full px-5 py-4 rounded-2xl border border-stone-200 focus:border-[#d4af37] focus:ring-0 transition font-medium"
                >
                  {Object.values(Category).map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Descrição (Opcional)</label>
                <textarea 
                  value={editingDish.description || ''}
                  onChange={e => setEditingDish({...editingDish, description: e.target.value})}
                  rows={3}
                  className="w-full px-5 py-4 rounded-2xl border border-stone-200 focus:border-[#d4af37] focus:ring-0 transition text-sm text-stone-600 italic"
                  placeholder="Ex: Lentamente defumado com especiarias..."
                />
              </div>
              <div className="flex gap-4 pt-4">
                <button 
                  type="button"
                  onClick={() => setEditingDish(null)}
                  className="flex-1 py-4 px-6 rounded-2xl font-bold text-stone-400 hover:bg-stone-50 transition border border-stone-100"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-4 px-6 rounded-2xl font-bold text-white bg-[#d4af37] hover:bg-[#b8860b] shadow-xl transition-all active:scale-95"
                >
                  Salvar Alterações
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navbar Minimalista */}
      <nav className="no-print sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-stone-200 px-6 py-4">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-2xl">👨‍🍳</span>
            <span className="serif text-2xl font-bold tracking-tight text-[#1a3a3a]">ChefAI</span>
          </div>
          <button 
            onClick={() => setShowInventory(!showInventory)}
            className={`text-sm font-semibold flex items-center gap-2 px-4 py-2 rounded-full border transition ${
              showInventory 
                ? 'bg-stone-900 text-white border-stone-900 shadow-inner' 
                : 'bg-white text-stone-600 border-stone-200 hover:text-stone-900 hover:border-stone-400'
            }`}
          >
            {showInventory ? 'Fechar Acervo' : 'Gerenciar Acervo'} ({dishPool.length})
          </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 pt-12 grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Painel de Controle */}
        <div className="lg:col-span-4 space-y-8 no-print">
          <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-200">
            <h2 className="serif text-3xl mb-6 text-[#1a3a3a]">Compor Menu</h2>

            <div className="space-y-6">
              <div className="space-y-5">
                {Object.entries(config.counts).map(([cat, count]) => (
                  <div key={cat} className="flex items-center justify-between group">
                    <div className="flex flex-col">
                      <span className="text-xs uppercase tracking-widest text-stone-400 font-bold mb-1">{cat}s</span>
                      <span className="text-lg font-semibold flex items-center gap-2">
                        <span className="opacity-70">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</span>
                        {cat}
                      </span>
                    </div>
                    <div className="flex items-center gap-4 bg-stone-50 p-1 rounded-full border border-stone-100">
                      <button 
                        onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))}
                        className="w-10 h-10 rounded-full flex items-center justify-center hover:bg-white transition shadow-sm font-bold disabled:opacity-30"
                        disabled={count === 0}
                      >
                        −
                      </button>
                      <span className="w-4 text-center text-lg font-bold">{count}</span>
                      <button 
                        onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat as Category] + 1}}))}
                        className="w-10 h-10 rounded-full flex items-center justify-center hover:bg-white transition shadow-sm font-bold"
                      >
                        +
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-stone-100">
                <label className="block text-xs uppercase tracking-widest text-stone-400 font-bold mb-3">Ocasião ou Estilo</label>
                <input 
                  type="text" 
                  value={config.theme}
                  onChange={(e) => setConfig({...config, theme: e.target.value})}
                  placeholder="Ex: Almoço de Domingo, Churrasco..."
                  className="w-full px-5 py-4 rounded-2xl border border-stone-200 focus:border-[#d4af37] focus:ring-0 transition serif text-xl italic"
                />
              </div>
            </div>

            <button 
              onClick={handleGenerate}
              disabled={isGenerating}
              className={`w-full mt-10 py-5 px-6 rounded-2xl font-bold text-lg shadow-2xl transition-all transform active:scale-95 flex items-center justify-center gap-3 ${
                isGenerating ? 'bg-stone-300' : 'bg-[#1a3a3a] text-stone-50 hover:bg-[#2a4a4a]'
              }`}
            >
              {isGenerating ? (
                 <span className="flex items-center gap-2">
                   <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                   Harmonizando Sabores...
                 </span>
              ) : 'Gerar Menu Gourmet'}
            </button>
          </section>

          {/* Seção de Upload */}
          <section className="bg-[#1a3a3a] p-8 rounded-3xl text-stone-50 overflow-hidden relative shadow-xl">
            <div className="relative z-10">
              <h3 className="serif text-2xl mb-2">Importar Acervo</h3>
              <p className="text-stone-300 text-sm mb-6 leading-relaxed">Personalize o motor da IA com seus próprios ingredientes via Excel.</p>

              <label className="block w-full cursor-pointer group">
                <div className="border-2 border-stone-500/50 border-dashed rounded-2xl py-8 flex flex-col items-center justify-center group-hover:border-stone-300 transition bg-white/5 hover:bg-white/10">
                  <span className="text-3xl mb-2 group-hover:scale-110 transition-transform">📂</span>
                  <span className="text-xs uppercase font-bold tracking-widest text-stone-400">Selecionar XLSX</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
              </label>
            </div>
            <div className="absolute top-0 right-0 w-32 h-32 bg-stone-50/5 rounded-full -mr-16 -mt-16 blur-3xl"></div>
          </section>
        </div>

        {/* Exibição do Cardápio / Inventário */}
        <div className="lg:col-span-8">
          {showInventory ? (
            <div className="bg-white rounded-3xl p-8 border border-stone-200 shadow-sm animate-in fade-in slide-in-from-right-4 duration-300 h-full flex flex-col">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8 border-b border-stone-100 pb-6">
                <div>
                  <h2 className="serif text-4xl text-[#1a3a3a]">Seu Acervo Gastronômico</h2>
                  <p className="text-stone-400 text-sm mt-1">Gerencie os pratos que a IA usará para compor seus menus.</p>
                </div>
                <div className="flex gap-2">
                   <button 
                    onClick={restoreDefaults} 
                    className="px-4 py-2 bg-stone-50 text-stone-500 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-stone-200 hover:text-stone-800 transition border border-stone-200"
                  >
                    Restaurar Padrões
                  </button>
                  <button 
                    onClick={clearPool} 
                    className="px-4 py-2 bg-red-50 text-red-500 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-red-500 hover:text-white transition border border-red-100"
                  >
                    Limpar Tudo
                  </button>
                </div>
              </div>

              {/* Filtros e Busca */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400">🔍</span>
                  <input 
                    type="text" 
                    placeholder="Buscar por nome ou descrição..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 bg-stone-50 border border-stone-200 rounded-xl focus:ring-1 focus:ring-[#d4af37] focus:border-[#d4af37] transition text-sm"
                  />
                </div>
                <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0 scrollbar-thin">
                  <button 
                    onClick={() => setFilterCategory('Todos')}
                    className={`px-4 py-2 rounded-xl text-xs font-bold transition whitespace-nowrap border ${
                      filterCategory === 'Todos' 
                        ? 'bg-[#1a3a3a] text-white border-[#1a3a3a]' 
                        : 'bg-white text-stone-500 border-stone-200 hover:border-stone-400'
                    }`}
                  >
                    Todos
                  </button>
                  {Object.values(Category).map(cat => (
                    <button 
                      key={cat}
                      onClick={() => setFilterCategory(cat)}
                      className={`px-4 py-2 rounded-xl text-xs font-bold transition whitespace-nowrap border ${
                        filterCategory === cat 
                          ? 'bg-[#d4af37] text-white border-[#d4af37]' 
                          : 'bg-white text-stone-500 border-stone-200 hover:border-stone-400'
                      }`}
                    >
                      {(ICONS as any)[Object.keys(Category).find(key => (Category as any)[key] === cat) || 'BASE']} {cat}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[60vh] overflow-y-auto pr-4 scrollbar-thin">
                {filteredDishes.length === 0 ? (
                  <div className="col-span-full text-center py-20 bg-stone-50 rounded-2xl border-2 border-dashed border-stone-200 flex flex-col items-center justify-center">
                    <span className="text-4xl mb-4 block">{dishPool.length === 0 ? '🍽️' : '🔎'}</span>
                    <p className="text-stone-400 font-medium mb-4">
                      {dishPool.length === 0 ? 'Seu acervo está vazio.' : 'Nenhum prato encontrado com os filtros atuais.'}
                    </p>
                    {dishPool.length === 0 ? (
                      <button 
                        onClick={restoreDefaults}
                        className="px-8 py-3 bg-[#d4af37] text-white rounded-full font-bold text-xs uppercase tracking-widest shadow-lg hover:bg-[#b8860b] transition active:scale-95"
                      >
                        Restaurar Pratos Padrão
                      </button>
                    ) : (
                       <button 
                        onClick={() => { setSearchTerm(''); setFilterCategory('Todos'); }}
                        className="text-[#d4af37] text-xs font-bold underline uppercase tracking-widest"
                      >
                        Limpar Filtros
                      </button>
                    )}
                  </div>
                ) : (
                  filteredDishes.map(dish => (
                    <div 
                      key={dish.id} 
                      className={`p-4 rounded-xl border flex justify-between items-center group transition shadow-sm hover:shadow-md animate-in fade-in duration-300 ${
                        newlyAddedIds.has(dish.id) 
                          ? 'bg-[#1a3a3a]/5 border-[#1a3a3a] ring-1 ring-[#1a3a3a]/20 scale-[1.02]' 
                          : 'bg-white border-stone-100 hover:border-[#d4af37]/50'
                      }`}
                    >
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded tracking-wider border ${
                             newlyAddedIds.has(dish.id) ? 'bg-[#1a3a3a] text-white border-[#1a3a3a]' : 'text-[#b8860b] bg-amber-50 border-amber-100'
                          }`}>
                            {(ICONS as any)[Object.keys(Category).find(key => (Category as any)[key] === dish.category) || 'BASE']} {dish.category}
                          </span>
                        </div>
                        <div className="font-bold text-stone-800 group-hover:text-[#1a3a3a] transition-colors">{dish.name}</div>
                        {dish.description && <div className="text-[10px] text-stone-400 italic line-clamp-1 mt-0.5">{dish.description}</div>}
                      </div>
                      <div className="flex items-center gap-1 ml-4 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => setEditingDish(dish)}
                          className="p-2.5 text-stone-300 hover:text-[#d4af37] transition hover:bg-amber-50 rounded-full"
                          title="Editar prato"
                        >
                          <svg className="w-4.5 h-4.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                        </button>
                        <button 
                          onClick={() => removeItem(dish.id)}
                          className="p-2.5 text-stone-300 hover:text-red-500 transition hover:bg-red-50 rounded-full"
                          title="Remover prato"
                        >
                          <svg className="w-4.5 h-4.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        </button>
                      </div>
                    </div>
                  ))
                )}
              </div>

              <div className="mt-6 pt-4 border-t border-stone-100 flex justify-between items-center text-stone-400 text-xs font-medium">
                <span>Exibindo {filteredDishes.length} de {dishPool.length} pratos</span>
                <span>ChefAI v2.0</span>
              </div>
            </div>
          ) : (
            <div className="relative">
              {!generatedMenu && !isGenerating && (
                <div className="h-[600px] flex flex-col items-center justify-center text-center opacity-30 px-10">
                  <div className="text-8xl mb-6">🕯️</div>
                  <h3 className="serif text-3xl mb-4 italic">Aguardando seu comando</h3>
                  <p className="max-w-md">Configure os parâmetros e deixe que nossa IA chef crie uma experiência gastronômica memorável.</p>
                </div>
              )}

              {isGenerating && (
                <div className="h-[600px] flex flex-col items-center justify-center">
                  <div className="w-16 h-16 border-4 border-[#d4af37] border-t-transparent rounded-full animate-spin mb-6"></div>
                  <p className="serif text-2xl italic animate-pulse">Consultando acervo e harmonizando ingredientes...</p>
                </div>
              )}

              {generatedMenu && !isGenerating && (
                <div 
                  ref={menuRef}
                  className="menu-card bg-white rounded-none border-[12px] border-stone-100 shadow-2xl p-8 md:p-16 relative overflow-hidden animate-in fade-in zoom-in duration-500 max-w-3xl mx-auto"
                >

                  {/* Luxury Borders */}
                  <div className="absolute inset-2 border-[1px] border-[#d4af37] pointer-events-none opacity-40"></div>
                  <div className="absolute inset-4 border-[2px] border-[#d4af37] pointer-events-none opacity-20"></div>

                  {/* Decorative Corners (Golden accents) */}
                  <div className="absolute top-0 left-0 w-12 h-12 border-t-4 border-l-4 border-[#d4af37] pointer-events-none"></div>
                  <div className="absolute top-0 right-0 w-12 h-12 border-t-4 border-r-4 border-[#d4af37] pointer-events-none"></div>
                  <div className="absolute bottom-0 left-0 w-12 h-12 border-b-4 border-l-4 border-[#d4af37] pointer-events-none"></div>
                  <div className="absolute bottom-0 right-0 w-12 h-12 border-b-4 border-r-4 border-[#d4af37] pointer-events-none"></div>

                  <div className="relative z-10 text-center space-y-10">
                    <header className="space-y-4">
                      <div className="text-[#d4af37] text-4xl mb-2 drop-shadow-sm italic serif">Est. 2024</div>
                      <h1 className="serif text-6xl md:text-8xl text-[#1a3a3a] leading-tight tracking-tight">{config.theme}</h1>
                      <div className="flex items-center justify-center gap-4">
                         <div className="h-[1px] w-20 bg-stone-200"></div>
                         <div className="gold-gradient w-4 h-4 rotate-45 border border-[#b8860b]"></div>
                         <div className="h-[1px] w-20 bg-stone-200"></div>
                      </div>
                      <p className="text-[10px] uppercase tracking-[0.5em] font-bold text-stone-400 mt-4">Fine Dining Experience</p>
                    </header>

                    <div className="grid gap-14 max-w-xl mx-auto">
                      {Object.entries(generatedMenu.selections).map(([cat, items]) => {
                        const typedItems = items as any[];
                        if (typedItems.length === 0) return null;

                        return (
                          <div key={cat} className="space-y-6">
                            <h3 className="serif text-3xl text-[#b8860b] italic flex items-center justify-center gap-6">
                              <span className="flex-1 h-[1px] bg-stone-100"></span>
                              {cat}s
                              <span className="flex-1 h-[1px] bg-stone-100"></span>
                            </h3>
                            <div className="space-y-8">
                              {typedItems.map((item, idx) => (
                                <div key={idx} className="space-y-2 group">
                                  <h4 className="serif text-3xl md:text-4xl text-[#1a3a3a] uppercase tracking-wider group-hover:text-[#d4af37] transition-colors">{item.name}</h4>
                                  {item.description && (
                                    <p className="text-[11px] md:text-xs uppercase tracking-[0.15em] text-stone-500 max-w-xs mx-auto leading-loose italic font-medium">{item.description}</p>
                                  )}
                                </div>
                              ))}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <footer className="pt-16 border-t border-stone-100 space-y-8">
                      <div className="max-w-lg mx-auto italic text-stone-600 leading-relaxed serif text-2xl px-6">
                        "{generatedMenu.chefNote}"
                      </div>
                      <div className="serif text-3xl text-[#d4af37] tracking-[0.2em] uppercase">Bon Appétit</div>
                    </footer>
                  </div>
                </div>
              )}

              {generatedMenu && (
                <div className="no-print mt-12 flex flex-wrap justify-center gap-4">
                  <button 
                    onClick={saveAsImage}
                    className="flex items-center gap-3 px-8 py-4 bg-white border-2 border-[#d4af37]/30 rounded-full hover:border-[#d4af37] transition font-bold text-xs uppercase tracking-widest shadow-lg text-[#1a3a3a]"
                  >
                    <span className="text-lg">💾</span> Salvar Imagem (PNG)
                  </button>
                  <button 
                    onClick={() => window.print()}
                    className="flex items-center gap-3 px-8 py-4 bg-white border-2 border-stone-100 rounded-full hover:border-stone-400 transition font-bold text-xs uppercase tracking-widest shadow-lg text-stone-600"
                  >
                    <span className="text-lg">🖨️</span> PDF / Imprimir
                  </button>
                  <button 
                    onClick={() => {
                      setGeneratedMenu(null);
                    }}
                    className="flex items-center gap-3 px-8 py-4 bg-[#1a3a3a] text-white rounded-full hover:bg-black transition font-bold text-xs uppercase tracking-widest shadow-lg"
                  >
                    <span className="text-lg">🔄</span> Criar Outro
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      </main>

      {/* Background Decor */}
      <div className="fixed inset-0 -z-10 pointer-events-none flex items-center justify-center overflow-hidden opacity-[0.03]">
        <span className="serif text-[50vw] text-stone-900 select-none">CHEF</span>
      </div>
    </div>
  );
};

export default App;

export enum Category {
  BASE = 'Base',
  MEAT = 'Carne',
  SIDE = 'Acompanhamento',
  SALAD = 'Salada',
  DESSERT = 'Sobremesa',
  DRINK = 'Bebida'
}

export interface Dish {
  id: string;
  name: string;
  category: Category;
  description?: string;
}

export interface MenuConfig {
  counts: Record<Category, number>;
  theme: string;
  baseOption: string;
  chefChoice: boolean;
}

export interface GeneratedMenu {
  selections: Record<Category, Dish[]>;
  chefNote: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig
): Promise<GeneratedMenu> {
  const structureRequested = config.chefChoice 
    ? "LIBERDADE TOTAL: Ignore contagens específicas. Crie um menu completo, equilibrado e surpreendente com base no tema. Você decide quantos pratos de cada categoria incluir para a melhor experiência gastronômica."
    : `Estrutura solicitada:\n${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${count} Opções de ${cat}`)
        .join('\n')}`;

  const prompt = `
    Como um Chef Executivo de um restaurante 3 estrelas Michelin, sua tarefa é organizar um cardápio impecável.

    CONDIÇÕES DO EVENTO:
    - Tema: "${config.theme}"
    - ${structureRequested}

    ACERVO DE INGREDIENTES/PRATOS DISPONÍVEIS:
    ${JSON.stringify(dishPool.map(d => ({ name: d.name, cat: d.category, desc: d.description })))}

    REGRAS DE OURO:
    1. PRIORIDADE: Use os itens do acervo fornecido como base.
    2. HARMONIA: Combine os sabores de acordo com o tema "${config.theme}". No modo LIBERDADE TOTAL, foque em uma jornada sensorial coesa.
    3. ELEVAÇÃO: Se o acervo for simples, eleve-o com descrições gourmet ("Arroz agulhinha com leve toque de manteiga de garrafa").
    4. DESCRIÇÃO: Escreva descrições apetitosas para cada prato.
    5. NOTA DO CHEF: Escreva uma justificativa elegante para a escolha desta composição, mencionando por que escolheu esta estrutura específica (especialmente se estiver no modo LIBERDADE TOTAL).

    Responda em JSON seguindo o schema fornecido.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          selections: {
            type: Type.OBJECT,
            properties: {
              [Category.BASE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DRINK]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
            }
          },
          chefNote: { type: Type.STRING, description: "Justificativa gastronômica do menu." }
        },
        required: ["selections", "chefNote"]
      }
    }
  });

  const parsed = JSON.parse(response.text);

  const finalSelections: any = {};
  Object.values(Category).forEach(cat => {
    finalSelections[cat] = parsed.selections[cat] || [];
  });

  return { ...parsed, selections: finalSelections };
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [showInventory, setShowInventory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [newlyAddedIds, setNewlyAddedIds] = useState<Set<string>>(new Set());
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Almoço de Domingo',
    baseOption: 'Cozinha Brasileira',
    chefChoice: false
  });

  // Auto-hide toast
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Clear highlights after a delay
  useEffect(() => {
    if (newlyAddedIds.size > 0) {
      const timer = setTimeout(() => setNewlyAddedIds(new Set()), 3000);
      return () => clearTimeout(timer);
    }
  }, [newlyAddedIds]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const ids: string[] = [];
        const parsedDishes: Dish[] = data.map((item, idx) => {
          const id = `custom-${Date.now()}-${idx}`;
          ids.push(id);
          return {
            id,
            name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
            category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
            description: item.Descricao || item.description || item.Ingredientes || ''
          };
        });

        setDishPool(prev => [...prev, ...parsedDishes]);
        setNewlyAddedIds(new Set(ids));
        setToast({ message: `${parsedDishes.length} pratos adicionados com sucesso ao acervo!`, type: 'success' });
        if (!showInventory) setShowInventory(true);
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo. Verifique se as colunas estão corretas.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; // Reset input
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio. Adicione pratos ou restaure os padrões.', type: 'error' });
      setShowInventory(true);
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
    } catch (error) {
      console.error(error);
      setToast({ message: 'A IA está ocupada na cozinha. Tente novamente em instantes.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    if (window.confirm('Tem certeza que deseja remover este prato?')) {
      setDishPool(prev => prev.filter(d => d.id !== id));
      if (editingDish?.id === id) setEditingDish(null);
      setNewlyAddedIds(prev => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
      setToast({ message: 'Prato removido com sucesso.', type: 'success' });
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => prev.map(d => d.id === editingDish.id ? editingDish : d));
    setEditingDish(null);
    setToast({ message: 'Prato atualizado com sucesso.', type: 'success' });
  };

  const clearPool = () => {
    if(window.confirm('ATENÇÃO: Deseja apagar TODOS os pratos do acervo? Esta ação não pode ser desfeita.')) {
        setDishPool([]);
        setNewlyAddedIds(new Set());
        setEditingDish(null);
        setToast({ message: 'Acervo completamente limpo.', type: 'success' });
    }
  };

  const restoreDefaults = () => {
    if(window.confirm('Deseja restaurar o acervo para os pratos padrão do sistema?')) {
        setDishPool(DEFAULT_DISHES);
        setNewlyAddedIds(new Set());
        setToast({ message: 'Acervo restaurado com sucesso.', type: 'success' });
    }
  };

  const saveAsImage = async () => {
    if (!menuRef.current) return;

    try {
      const dataUrl = await toPng(menuRef.current, {
        quality: 1,
        pixelRatio: 2,
        backgroundColor: '#ffffff',
      });
      const link = document.createElement('a');
      link.download = `ChefAI-Menu-${config.theme.replace(/\s+/g, '-')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Falha ao salvar imagem', err);
      setToast({ message: 'Não foi possível gerar a imagem. Tente imprimir como PDF.', type: 'error' });
    }
  };

  return (
    <div className="min-h-screen selection:bg-orange-100 pb-20 relative text-[#1a3a3a]">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#1a3a3a]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✨' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
            <button onClick={() => setToast(null)} className="ml-2 opacity-50 hover:opacity-100 transition">✕</button>
          </div>
        </div>
      )}

      {/* Modal de Edição */}
      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-[#1a3a3a]/40 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 border border-stone-200 animate-in zoom-in duration-300">
            <h3 className="serif text-3xl text-[#1a3a3a] mb-6 border-b border-stone-100 pb-4">Editar Prato</h3>
            <form onSubmit={handleUpdateDish} className="space-y-5">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome do Prato</label>
                <input 
                  type="text" 
                  required
                  value={editingDish.name}
                  onChange={e => setEditingDish({...editingDish, name: e.target.value})}
                  className="w-full px-5 py-4 rounded-2xl border border-stone-200 focus:border-[#d4af37] focus:ring-0 transition serif text-xl"
                />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select 
                  value={editingDish.category}
                  onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})}
                  className="w-full px-5 py-4 rounded-2xl border border-stone-200 focus:border-[#d4af37] focus:ring-0 transition font-medium"
                >
                  {Object.values(Category).map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Descrição (Opcional)</label>
                <textarea 
                  value={editingDish.description || ''}
                  onChange={e => setEditingDish({...editingDish, description: e.target.value})}
                  rows={3}
                  className="w-full px-5 py-4 rounded-2xl border border-stone-200 focus:border-[#d4af37] focus:ring-0 transition text-sm text-stone-600 italic"
                  placeholder="Ex: Lentamente defumado com especiarias..."
                />
              </div>
              <div className="flex gap-4 pt-4">
                <button 
                  type="button"
                  onClick={() => setEditingDish(null)}
                  className="flex-1 py-4 px-6 rounded-2xl font-bold text-stone-400 hover:bg-stone-50 transition border border-stone-100"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-4 px-6 rounded-2xl font-bold text-white bg-[#d4af37] hover:bg-[#b8860b] shadow-xl transition-all active:scale-95"
                >
                  Salvar Alterações
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navbar Minimalista */}
      <nav className="no-print sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-stone-200 px-6 py-4">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-2xl">👨‍🍳</span>
            <span className="serif text-2xl font-bold tracking-tight text-[#1a3a3a]">ChefAI</span>
          </div>
          <button 
            onClick={() => setShowInventory(!showInventory)}
            className={`text-sm font-semibold flex items-center gap-2 px-4 py-2 rounded-full border transition ${
              showInventory 
                ? 'bg-stone-900 text-white border-stone-900 shadow-inner' 
                : 'bg-white text-stone-600 border-stone-200 hover:text-[#1a3a3a] hover:border-stone-400'
            }`}
          >
            {showInventory ? 'Fechar Acervo' : 'Gerenciar Acervo'} ({dishPool.length})
          </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 pt-12 grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Painel de Controle */}
        <div className="lg:col-span-4 space-y-8 no-print">
          <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-200">
            <h2 className="serif text-3xl mb-6 text-[#1a3a3a]">Compor Menu</h2>

            <div className="space-y-6">

              {/* Opção A Gosto do Chef */}
              <div className={`p-5 rounded-2xl border-2 transition-all duration-300 flex items-center justify-between cursor-pointer ${
                config.chefChoice 
                  ? 'bg-amber-50 border-[#d4af37] shadow-lg shadow-amber-100' 
                  : 'bg-stone-50 border-stone-100 hover:border-stone-200'
              }`}
              onClick={() => setConfig({...config, chefChoice: !config.chefChoice})}
              >
                <div className="flex items-center gap-4">
                  <span className={`text-2xl transition-transform duration-500 ${config.chefChoice ? 'scale-125 rotate-12' : 'scale-100'}`}>✨</span>
                  <div>
                    <h4 className={`font-bold text-sm ${config.chefChoice ? 'text-[#b8860b]' : 'text-stone-600'}`}>A Gosto do Chef</h4>
                    <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-0.5">IA define as quantidades</p>
                  </div>
                </div>
                <div className={`w-12 h-6 rounded-full relative transition-colors duration-300 ${config.chefChoice ? 'bg-[#d4af37]' : 'bg-stone-200'}`}>
                  <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all duration-300 ${config.chefChoice ? 'left-7' : 'left-1'}`}></div>
                </div>
              </div>

              <div className={`space-y-5 transition-all duration-500 ${config.chefChoice ? 'opacity-30 grayscale pointer-events-none blur-[1px]' : 'opacity-100 grayscale-0'}`}>
                {Object.entries(config.counts).map(([cat, count]) => (
                  <div key={cat} className="flex items-center justify-between group">
                    <div className="flex flex-col">
                      <span className="text-xs uppercase tracking-widest text-stone-400 font-bold mb-1">{cat}s</span>
                      <span className="text-lg font-semibold flex items-center gap-2">
                        <span className="opacity-70">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</span>
                        {cat}
                      </span>
                    </div>
                    <div className="flex items-center gap-4 bg-stone-50 p-1 rounded-full border border-stone-100">
                      <button 
                        onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))}
                        className="w-10 h-10 rounded-full flex items-center justify-center hover:bg-white transition shadow-sm font-bold disabled:opacity-30"
                        disabled={count === 0}
                      >
                        −
                      </button>
                      <span className="w-4 text-center text-lg font-bold">{count}</span>
                      <button 
                        onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat as Category] + 1}}))}
                        className="w-10 h-10 rounded-full flex items-center justify-center hover:bg-white transition shadow-sm font-bold"
                      >
                        +
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-stone-100">
                <label className="block text-xs uppercase tracking-widest text-stone-400 font-bold mb-3">Ocasião ou Estilo</label>
                <input 
                  type="text" 
                  value={config.theme}
                  onChange={(e) => setConfig({...config, theme: e.target.value})}
                  placeholder="Ex: Almoço de Domingo, Churrasco..."
                  className="w-full px-5 py-4 rounded-2xl border border-stone-200 focus:border-[#d4af37] focus:ring-0 transition serif text-xl italic"
                />
              </div>
            </div>

            <button 
              onClick={handleGenerate}
              disabled={isGenerating}
              className={`w-full mt-10 py-5 px-6 rounded-2xl font-bold text-lg shadow-2xl transition-all transform active:scale-95 flex items-center justify-center gap-3 ${
                isGenerating ? 'bg-stone-300' : 'bg-[#1a3a3a] text-stone-50 hover:bg-[#2a4a4a]'
              }`}
            >
              {isGenerating ? (
                 <span className="flex items-center gap-2">
                   <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                   Harmonizando Sabores...
                 </span>
              ) : (config.chefChoice ? 'Solicitar Menu do Chef' : 'Gerar Menu Gourmet')}
            </button>
          </section>

          {/* Seção de Upload */}
          <section className="bg-[#1a3a3a] p-8 rounded-3xl text-stone-50 overflow-hidden relative shadow-xl">
            <div className="relative z-10">
              <h3 className="serif text-2xl mb-2">Importar Acervo</h3>
              <p className="text-stone-300 text-sm mb-6 leading-relaxed">Personalize o motor da IA com seus próprios ingredientes via Excel.</p>

              <label className="block w-full cursor-pointer group">
                <div className="border-2 border-stone-500/50 border-dashed rounded-2xl py-8 flex flex-col items-center justify-center group-hover:border-stone-300 transition bg-white/5 hover:bg-white/10">
                  <span className="text-3xl mb-2 group-hover:scale-110 transition-transform">📂</span>
                  <span className="text-xs uppercase font-bold tracking-widest text-stone-400">Selecionar XLSX</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
              </label>
            </div>
            <div className="absolute top-0 right-0 w-32 h-32 bg-stone-50/5 rounded-full -mr-16 -mt-16 blur-3xl"></div>
          </section>
        </div>

        {/* Exibição do Cardápio / Inventário */}
        <div className="lg:col-span-8">
          {showInventory ? (
            <div className="bg-white rounded-3xl p-8 border border-stone-200 shadow-sm animate-in fade-in slide-in-from-right-4 duration-300 h-full flex flex-col">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8 border-b border-stone-100 pb-6">
                <div>
                  <h2 className="serif text-4xl text-[#1a3a3a]">Seu Acervo Gastronômico</h2>
                  <p className="text-stone-400 text-sm mt-1">Gerencie os pratos que a IA usará para compor seus menus.</p>
                </div>
                <div className="flex gap-2">
                   <button 
                    onClick={restoreDefaults} 
                    className="px-4 py-2 bg-stone-50 text-stone-500 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-stone-200 hover:text-stone-800 transition border border-stone-200"
                  >
                    Restaurar Padrões
                  </button>
                  <button 
                    onClick={clearPool} 
                    className="px-4 py-2 bg-red-50 text-red-500 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-red-500 hover:text-white transition border border-red-100"
                  >
                    Limpar Tudo
                  </button>
                </div>
              </div>

              {/* Filtros e Busca */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400">🔍</span>
                  <input 
                    type="text" 
                    placeholder="Buscar por nome ou descrição..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 bg-stone-50 border border-stone-200 rounded-xl focus:ring-1 focus:ring-[#d4af37] focus:border-[#d4af37] transition text-sm"
                  />
                </div>
                <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0 scrollbar-thin">
                  <button 
                    onClick={() => setFilterCategory('Todos')}
                    className={`px-4 py-2 rounded-xl text-xs font-bold transition whitespace-nowrap border ${
                      filterCategory === 'Todos' 
                        ? 'bg-[#1a3a3a] text-white border-[#1a3a3a]' 
                        : 'bg-white text-stone-500 border-stone-200 hover:border-stone-400'
                    }`}
                  >
                    Todos
                  </button>
                  {Object.values(Category).map(cat => (
                    <button 
                      key={cat}
                      onClick={() => setFilterCategory(cat)}
                      className={`px-4 py-2 rounded-xl text-xs font-bold transition whitespace-nowrap border ${
                        filterCategory === cat 
                          ? 'bg-[#d4af37] text-white border-[#d4af37]' 
                          : 'bg-white text-stone-500 border-stone-200 hover:border-stone-400'
                      }`}
                    >
                      {(ICONS as any)[Object.keys(Category).find(key => (Category as any)[key] === cat) || 'BASE']} {cat}
                    </button>
                  ))}
                </div>
              </div>

