import { GoogleGenAI, Type } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig
): Promise<GeneratedMenu> {
  const structureRequested = config.chefChoice 
    ? "SUGESTÃO LIVRE DO DIA: Ignore contagens específicas. Crie um cardápio completo, equilibrado e atrativo para o dia a dia de um restaurante popular ou marmitaria. Escolha a melhor combinação de pratos para garantir variedade e satisfação dos clientes."
    : `Estrutura solicitada para o cardápio:\n${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${count} Opções de ${cat}`)
        .join('\n')}`;

  const prompt = `
    Como um especialista em gestão de cardápios para RESTAURANTES SELF-SERVICE e MARMITARIAS brasileiras, sua tarefa é organizar as opções do dia.

    FOCO: Comida caseira de qualidade, nutritiva, com bom custo-benefício e sabor familiar.

    CONDIÇÕES DO DIA:
    - Ocasião/Tema: "${config.theme}"
    - ${structureRequested}

    ACERVO DE PRATOS DISPONÍVEIS NO RESTAURANTE:
    ${JSON.stringify(dishPool.map(d => ({ name: d.name, cat: d.category, desc: d.description })))}

    REGRAS DE OURO:
    1. REALISMO: Use exclusivamente os itens do acervo fornecido.
    2. HARMONIA CASEIRA: Combine os sabores de forma clássica (ex: se tem feijoada, sugira couve e laranja). Evite termos "gourmet" excessivos; prefira termos apetitosos e diretos como "bem temperado", "suculento" ou "fresquinho".
    3. EQUILÍBRIO: Garanta que o cardápio seja variado para atender diferentes gostos (opção leve, opção mais substanciosa).
    4. DESCRIÇÃO: Escreva descrições que deem fome, focando no preparo caseiro.
    5. NOTA DO ESTABELECIMENTO: Escreva um breve parágrafo justificando a escolha do cardápio do dia, focando no frescor e na combinação dos pratos.

    Responda em JSON seguindo o schema fornecido.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          selections: {
            type: Type.OBJECT,
            properties: {
              [Category.BASE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DRINK]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
            }
          },
          chefNote: { type: Type.STRING, description: "Justificativa do cardápio do dia." }
        },
        required: ["selections", "chefNote"]
      }
    }
  });

  const parsed = JSON.parse(response.text);

  const finalSelections: any = {};
  Object.values(Category).forEach(cat => {
    finalSelections[cat] = parsed.selections[cat] || [];
  });

  return { ...parsed, selections: finalSelections };
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [showInventory, setShowInventory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [newlyAddedIds, setNewlyAddedIds] = useState<Set<string>>(new Set());
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  // Auto-hide toast
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Clear highlights after a delay
  useEffect(() => {
    if (newlyAddedIds.size > 0) {
      const timer = setTimeout(() => setNewlyAddedIds(new Set()), 3000);
      return () => clearTimeout(timer);
    }
  }, [newlyAddedIds]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const ids: string[] = [];
        const parsedDishes: Dish[] = data.map((item, idx) => {
          const id = `custom-${Date.now()}-${idx}`;
          ids.push(id);
          return {
            id,
            name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
            category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
            description: item.Descricao || item.description || item.Ingredientes || ''
          };
        });

        setDishPool(prev => [...prev, ...parsedDishes]);
        setNewlyAddedIds(new Set(ids));
        setToast({ message: `${parsedDishes.length} itens adicionados ao acervo com sucesso!`, type: 'success' });
        if (!showInventory) setShowInventory(true);
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo. Verifique se as colunas estão corretas.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; // Reset input
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio. Adicione pratos ou restaure os padrões.', type: 'error' });
      setShowInventory(true);
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
    } catch (error) {
      console.error(error);
      setToast({ message: 'A IA está organizando a cozinha. Tente novamente em instantes.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    if (window.confirm('Deseja remover este prato do acervo?')) {
      setDishPool(prev => prev.filter(d => d.id !== id));
      if (editingDish?.id === id) setEditingDish(null);
      setToast({ message: 'Prato removido.', type: 'success' });
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => prev.map(d => d.id === editingDish.id ? editingDish : d));
    setEditingDish(null);
    setToast({ message: 'Prato atualizado.', type: 'success' });
  };

  const clearPool = () => {
    if(window.confirm('Atenção: Deseja apagar todos os pratos?')) {
        setDishPool([]);
        setToast({ message: 'Acervo limpo.', type: 'success' });
    }
  };

  const restoreDefaults = () => {
    if(window.confirm('Restaurar opções padrão de restaurante brasileiro?')) {
        setDishPool(DEFAULT_DISHES);
        setToast({ message: 'Acervo restaurado.', type: 'success' });
    }
  };

  const saveAsImage = async () => {
    if (!menuRef.current) return;
    try {
      const dataUrl = await toPng(menuRef.current, { quality: 1, pixelRatio: 2, backgroundColor: '#ffffff' });
      const link = document.createElement('a');
      link.download = `Cardapio-${config.theme.replace(/\s+/g, '-')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      setToast({ message: 'Erro ao gerar imagem.', type: 'error' });
    }
  };

  return (
    <div className="min-h-screen selection:bg-orange-100 pb-20 relative text-[#333]">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {/* Modal de Edição */}
      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/50 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 animate-in zoom-in duration-300">
            <h3 className="serif text-3xl text-[#e67e22] mb-6 border-b border-stone-100 pb-4">Editar Opção</h3>
            <form onSubmit={handleUpdateDish} className="space-y-5">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome do Prato</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 focus:border-[#e67e22] outline-none transition text-lg" />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full px-5 py-3 rounded-xl border border-stone-200 focus:border-[#e67e22] outline-none transition font-medium">
                  {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Descrição / Detalhes</label>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} rows={3} className="w-full px-5 py-3 rounded-xl border border-stone-200 focus:border-[#e67e22] outline-none transition text-sm text-stone-600" placeholder="Ex: Carne moída temperada com ervas finas..." />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setEditingDish(null)} className="flex-1 py-3 rounded-xl font-bold text-stone-400 hover:bg-stone-50 border border-stone-100 transition">Cancelar</button>
                <button type="submit" className="flex-1 py-3 rounded-xl font-bold text-white bg-[#e67e22] hover:bg-[#d35400] shadow-lg transition">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navbar */}
      <nav className="no-print sticky top-0 z-50 bg-white/90 backdrop-blur-md border-b border-stone-200 px-6 py-4">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-2xl">🍲</span>
            <span className="serif text-2xl font-bold tracking-tight text-[#e67e22]">ChefAI <span className="text-stone-400 font-light text-base">Restaurantes</span></span>
          </div>
          <button 
            onClick={() => setShowInventory(!showInventory)}
            className={`text-sm font-semibold flex items-center gap-2 px-5 py-2 rounded-full border transition ${
              showInventory ? 'bg-stone-900 text-white border-stone-900 shadow-inner' : 'bg-white text-stone-600 border-stone-200 hover:text-[#e67e22] hover:border-[#e67e22]'
            }`}
          >
            {showInventory ? 'Fechar Acervo' : 'Meus Itens'} ({dishPool.length})
          </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 pt-12 grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Painel Lateral */}
        <div className="lg:col-span-4 space-y-8 no-print">
          <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
            <h2 className="serif text-3xl mb-6 text-stone-800">Cardápio do Dia</h2>

            <div className="space-y-6">

              <div className={`p-5 rounded-2xl border-2 transition-all duration-300 flex items-center justify-between cursor-pointer ${
                config.chefChoice ? 'bg-orange-50 border-[#e67e22] shadow-lg' : 'bg-stone-50 border-stone-100 hover:border-stone-200'
              }`} onClick={() => setConfig({...config, chefChoice: !config.chefChoice})}>
                <div className="flex items-center gap-4">
                  <span className="text-2xl">💡</span>
                  <div>
                    <h4 className={`font-bold text-sm ${config.chefChoice ? 'text-[#e67e22]' : 'text-stone-600'}`}>Sugestão da Casa</h4>
                    <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-0.5">IA organiza as quantidades</p>
                  </div>
                </div>
                <div className={`w-12 h-6 rounded-full relative transition-colors ${config.chefChoice ? 'bg-[#e67e22]' : 'bg-stone-200'}`}>
                  <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${config.chefChoice ? 'left-7' : 'left-1'}`}></div>
                </div>
              </div>

              <div className={`space-y-5 transition-all duration-300 ${config.chefChoice ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                {Object.entries(config.counts).map(([cat, count]) => (
                  <div key={cat} className="flex items-center justify-between">
                    <div className="flex flex-col">
                      <span className="text-xs uppercase tracking-widest text-stone-400 font-bold mb-1">{cat}s</span>
                      <span className="text-lg font-semibold flex items-center gap-2">
                        <span className="opacity-70">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</span>
                        {cat}
                      </span>
                    </div>
                    <div className="flex items-center gap-4 bg-stone-50 p-1 rounded-full border border-stone-100">
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))} className="w-8 h-8 rounded-full flex items-center justify-center hover:bg-white transition shadow-sm font-bold disabled:opacity-30" disabled={count === 0}>−</button>
                      <span className="w-4 text-center font-bold">{count}</span>
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat as Category] + 1}}))} className="w-8 h-8 rounded-full flex items-center justify-center hover:bg-white transition shadow-sm font-bold">+</button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-stone-100">
                <label className="block text-xs uppercase tracking-widest text-stone-400 font-bold mb-3">Nome da Refeição / Dia</label>
                <input type="text" value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value})} placeholder="Ex: Almoço de Terça-feira" className="w-full px-5 py-3 rounded-xl border border-stone-200 focus:border-[#e67e22] outline-none transition serif text-xl" />
              </div>
            </div>

            <button onClick={handleGenerate} disabled={isGenerating} className={`w-full mt-10 py-4 px-6 rounded-2xl font-bold text-lg shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 ${
                isGenerating ? 'bg-stone-300' : 'bg-[#e67e22] text-white hover:bg-[#d35400]'
              }`}>
              {isGenerating ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : (config.chefChoice ? 'Gerar Sugestão da Casa' : 'Organizar Cardápio')}
            </button>
          </section>

          <section className="bg-stone-900 p-8 rounded-3xl text-white shadow-xl">
              <h3 className="serif text-2xl mb-2">Importar Excel</h3>
              <p className="text-stone-400 text-sm mb-6">Suba sua lista de pratos da semana rapidamente.</p>
              <label className="block w-full cursor-pointer group">
                <div className="border-2 border-stone-700 border-dashed rounded-2xl py-8 flex flex-col items-center justify-center hover:border-orange-500 transition bg-white/5">
                  <span className="text-3xl mb-2">📂</span>
                  <span className="text-[10px] uppercase font-bold tracking-widest text-stone-500">Selecionar arquivo</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
              </label>
          </section>
        </div>

        {/* Área Principal */}
        <div className="lg:col-span-8">
          {showInventory ? (
            <div className="bg-white rounded-3xl p-8 border border-stone-200 shadow-sm animate-in fade-in duration-300">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
                <div>
                  <h2 className="serif text-4xl text-stone-800">Acervo de Pratos</h2>
                  <p className="text-stone-400 text-sm">Estes são os pratos que o sistema usará para criar os cardápios.</p>
                </div>
                <div className="flex gap-2">
                  <button onClick={restoreDefaults} className="px-4 py-2 bg-stone-50 text-stone-500 rounded-lg text-[10px] font-bold uppercase tracking-widest hover:bg-stone-100 transition border border-stone-200">Restaurar Padrão</button>
                  <button onClick={clearPool} className="px-4 py-2 bg-red-50 text-red-400 rounded-lg text-[10px] font-bold uppercase tracking-widest hover:bg-red-400 hover:text-white transition border border-red-100">Esvaziar</button>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                <input type="text" placeholder="Buscar prato..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full px-4 py-2 bg-stone-50 border border-stone-200 rounded-lg outline-none focus:border-[#e67e22] text-sm" />
                <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-thin">
                  {['Todos', ...Object.values(Category)].map(cat => (
                    <button key={cat} onClick={() => setFilterCategory(cat as any)} className={`px-3 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wider transition whitespace-nowrap border ${filterCategory === cat ? 'bg-[#e67e22] text-white border-[#e67e22]' : 'bg-white text-stone-400 border-stone-200'}`}>
                      {cat}
                    </button>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-[500px] overflow-y-auto pr-2 scrollbar-thin">
                {filteredDishes.map(dish => (
                  <div key={dish.id} className="p-4 rounded-xl border border-stone-100 bg-stone-50/50 flex justify-between items-center group hover:border-[#e67e22]/30 transition">
                    <div>
                      <span className="text-[9px] uppercase font-bold text-orange-500 mb-1 block">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === dish.category) || 'BASE']} {dish.category}</span>
                      <div className="font-bold text-stone-800">{dish.name}</div>
                    </div>
                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => setEditingDish(dish)} className="p-2 text-stone-400 hover:text-blue-500">✎</button>
                      <button onClick={() => removeItem(dish.id)} className="p-2 text-stone-400 hover:text-red-500">✕</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <div className="relative">
              {generatedMenu && !isGenerating ? (
                <div ref={menuRef} className="menu-card bg-white rounded-none shadow-2xl p-8 md:p-16 border-[16px] border-[#e67e22]/5 max-w-2xl mx-auto animate-in fade-in zoom-in duration-500">
                  <header className="text-center mb-12 border-b-2 border-stone-100 pb-8">
                    <div className="text-orange-500 text-3xl mb-2">🍽️</div>
                    <h1 className="serif text-5xl text-stone-900 mb-2 uppercase tracking-tight">{config.theme}</h1>
                    <div className="flex items-center justify-center gap-2">
                       <span className="h-[1px] w-8 bg-stone-300"></span>
                       <span className="text-[10px] uppercase font-bold tracking-[0.3em] text-stone-400">Qualidade & Sabor Caseiro</span>
                       <span className="h-[1px] w-8 bg-stone-300"></span>
                    </div>
                  </header>

                  <div className="space-y-10">
                    {Object.entries(generatedMenu.selections).map(([cat, items]) => {
                      const typedItems = items as any[];
                      if (typedItems.length === 0) return null;
                      return (
                        <div key={cat} className="space-y-4">
                          <h3 className="serif text-2xl text-stone-800 border-l-4 border-[#e67e22] pl-4 uppercase tracking-widest">{cat}s</h3>
                          <div className="grid gap-6 pl-5">
                            {typedItems.map((item, idx) => (
                              <div key={idx} className="group">
                                <h4 className="text-xl font-bold text-stone-900 mb-1 group-hover:text-[#e67e22] transition-colors">{item.name}</h4>
                                {item.description && <p className="text-sm text-stone-500 leading-relaxed italic">{item.description}</p>}
                              </div>
                            ))}
                          </div>
                        </div>
                      );
                    })}
                  </div>

                  <footer className="mt-16 pt-10 border-t border-stone-100 text-center">
                    <p className="serif text-2xl italic text-stone-600 mb-6 px-4">"{generatedMenu.chefNote}"</p>
                    <div className="text-orange-500 serif text-3xl font-bold italic tracking-wide">Bom Apetite!</div>
                  </footer>
                </div>
              ) : (
                <div className="h-[600px] flex flex-col items-center justify-center text-center opacity-20 italic">
                  {isGenerating ? (
                    <div className="animate-pulse">
                      <div className="w-16 h-16 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
                      <p className="text-2xl">Organizando as opções do dia...</p>
                    </div>
                  ) : (
                    <>
                      <div className="text-9xl mb-6">🥘</div>
                      <p className="text-2xl">Pronto para criar o cardápio perfeito para seu restaurante.</p>
                    </>
                  )}
                </div>
              )}

              {generatedMenu && !isGenerating && (
                <div className="no-print mt-12 flex justify-center gap-4">
                  <button onClick={saveAsImage} className="px-8 py-3 bg-[#e67e22] text-white rounded-full font-bold text-xs uppercase tracking-widest shadow-lg hover:bg-[#d35400] transition">Baixar Imagem</button>
                  <button onClick={() => window.print()} className="px-8 py-3 bg-white text-stone-600 border border-stone-200 rounded-full font-bold text-xs uppercase tracking-widest shadow-lg hover:bg-stone-50 transition">Imprimir PDF</button>
                  <button onClick={() => setGeneratedMenu(null)} className="px-8 py-3 bg-stone-900 text-white rounded-full font-bold text-xs uppercase tracking-widest shadow-lg transition">Novo Cardápio</button>
                </div>
              )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [showInventory, setShowInventory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [newlyAddedIds, setNewlyAddedIds] = useState<Set<string>>(new Set());
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  useEffect(() => {
    if (newlyAddedIds.size > 0) {
      const timer = setTimeout(() => setNewlyAddedIds(new Set()), 3000);
      return () => clearTimeout(timer);
    }
  }, [newlyAddedIds]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const ids: string[] = [];
        const parsedDishes: Dish[] = data.map((item, idx) => {
          const id = `custom-${Date.now()}-${idx}`;
          ids.push(id);
          return {
            id,
            name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
            category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
            description: item.Descricao || item.description || item.Ingredientes || ''
          };
        });

        setDishPool(prev => [...prev, ...parsedDishes]);
        setNewlyAddedIds(new Set(ids));
        setToast({ message: `${parsedDishes.length} itens adicionados com sucesso!`, type: 'success' });
        if (!showInventory) setShowInventory(true);
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio.', type: 'error' });
      setShowInventory(true);
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    if (window.confirm('Deseja remover este prato?')) {
      setDishPool(prev => prev.filter(d => d.id !== id));
      setToast({ message: 'Removido.', type: 'success' });
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => prev.map(d => d.id === editingDish.id ? editingDish : d));
    setEditingDish(null);
    setToast({ message: 'Atualizado.', type: 'success' });
  };

  const restoreDefaults = () => {
    if(window.confirm('Restaurar opções padrão?')) {
        setDishPool(DEFAULT_DISHES);
        setToast({ message: 'Restaurado.', type: 'success' });
    }
  };

  const saveAsImage = async () => {
    if (!menuRef.current) return;
    try {
      const dataUrl = await toPng(menuRef.current, { 
        quality: 1, 
        pixelRatio: 3, 
        backgroundColor: '#ffffff',
        style: {
          transform: 'scale(1)',
          transformOrigin: 'top left'
        }
      });
      const link = document.createElement('a');
      link.download = `Cardapio-${config.theme.replace(/\s+/g, '-')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      setToast({ message: 'Erro ao gerar imagem.', type: 'error' });
    }
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] selection:bg-orange-100 pb-20 relative text-[#333]">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {/* Modal de Edição */}
      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/50 backdrop-blur-sm">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8">
            <h3 className="serif text-3xl text-[#e67e22] mb-6 border-b pb-4">Editar Opção</h3>
            <form onSubmit={handleUpdateDish} className="space-y-5">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none text-lg" />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none">
                  {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setEditingDish(null)} className="flex-1 py-3 font-bold text-stone-400">Cancelar</button>
                <button type="submit" className="flex-1 py-3 font-bold text-white bg-[#e67e22] rounded-xl">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navbar */}
      <nav className="no-print sticky top-0 z-50 bg-white/90 backdrop-blur-md border-b border-stone-200 px-6 py-4">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-2xl">🍲</span>
            <span className="serif text-2xl font-bold text-[#e67e22]">ChefAI <span className="text-stone-400 font-light text-base">Restaurantes</span></span>
          </div>
          <button 
            onClick={() => setShowInventory(!showInventory)}
            className="text-sm font-semibold flex items-center gap-2 px-5 py-2 rounded-full border border-stone-200 hover:border-[#e67e22] transition"
          >
            {showInventory ? 'Fechar' : 'Meus Itens'} ({dishPool.length})
          </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 pt-12 grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Painel Lateral */}
        <div className="lg:col-span-4 space-y-8 no-print">
          <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
            <h2 className="serif text-3xl mb-6 text-stone-800">Cardápio do Dia</h2>

            <div className="space-y-6">
              <div className={`p-5 rounded-2xl border-2 cursor-pointer ${config.chefChoice ? 'bg-orange-50 border-[#e67e22]' : 'bg-stone-50 border-stone-100'}`} onClick={() => setConfig({...config, chefChoice: !config.chefChoice})}>
                <div className="flex items-center gap-4">
                  <span className="text-2xl">💡</span>
                  <div>
                    <h4 className="font-bold text-sm">Sugestão da Casa</h4>
                    <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-0.5">IA define quantidades</p>
                  </div>
                </div>
              </div>

              <div className={`space-y-5 transition-all duration-300 ${config.chefChoice ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                {Object.entries(config.counts).map(([cat, count]) => (
                  <div key={cat} className="flex items-center justify-between">
                    <span className="font-semibold text-stone-600">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']} {cat}</span>
                    <div className="flex items-center gap-3 bg-stone-100 p-1 rounded-full">
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold">-</button>
                      <span className="w-4 text-center font-bold">{count}</span>
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat as Category] + 1}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold">+</button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-stone-100">
                <label className="block text-xs uppercase text-stone-400 font-bold mb-2">Nome do Dia/Refeição</label>
                <input type="text" value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none" />
              </div>
            </div>

            <button onClick={handleGenerate} disabled={isGenerating} className="w-full mt-10 py-4 bg-[#e67e22] text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-3">
              {isGenerating ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Criar Cardápio Profissional'}
            </button>
          </section>

          <section className="bg-stone-900 p-8 rounded-3xl text-white shadow-xl">
              <h3 className="serif text-2xl mb-2">Importar Lista</h3>
              <p className="text-stone-400 text-sm mb-6">Suba seus pratos via Excel.</p>
              <label className="block w-full cursor-pointer">
                <div className="border-2 border-stone-700 border-dashed rounded-2xl py-8 flex flex-col items-center bg-white/5">
                  <span className="text-3xl mb-2">📂</span>
                  <span className="text-[10px] uppercase font-bold tracking-widest text-stone-500">Selecionar arquivo</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
              </label>
          </section>
        </div>

        {/* Área de Visualização do Cardápio */}
        <div className="lg:col-span-8">
          {showInventory ? (
            <div className="bg-white rounded-3xl p-8 border border-stone-200 shadow-sm min-h-[600px]">
              <div className="flex justify-between items-center mb-8">
                <h2 className="serif text-4xl text-stone-800">Acervo</h2>
                <button onClick={restoreDefaults} className="text-[#e67e22] font-bold text-xs uppercase">Restaurar Padrão</button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-[500px] overflow-y-auto pr-2 scrollbar-thin">
                {dishPool.map(dish => (
                  <div key={dish.id} className="p-4 rounded-xl border border-stone-100 bg-stone-50/50 flex justify-between items-center group">
                    <div>
                      <span className="text-[9px] uppercase font-bold text-orange-500">{dish.category}</span>
