                      {/* Decorative Corners */}
                      <div className="absolute top-0 left-0 w-8 h-8 border-t-2 border-l-2 border-[#e67e22]/40"></div>
                      <div className="absolute top-0 right-0 w-8 h-8 border-t-2 border-r-2 border-[#e67e22]/40"></div>
                      <div className="absolute bottom-0 left-0 w-8 h-8 border-b-2 border-l-2 border-[#e67e22]/40"></div>
                      <div className="absolute bottom-0 right-0 w-8 h-8 border-b-2 border-r-2 border-[#e67e22]/40"></div>

                      <header className="text-center mb-10">
                        <div className="flex items-center justify-center gap-3 mb-2">
                           <div className="h-[1px] w-12 bg-[#e67e22]/30"></div>
                           <span className="text-[#e67e22] text-2xl font-bold">🍲</span>
                           <div className="h-[1px] w-12 bg-[#e67e22]/30"></div>
