                        <h1 className="serif text-5xl text-stone-900 uppercase tracking-tighter leading-none mb-3">{config.theme}</h1>
                        <div className="text-[11px] uppercase tracking-[0.4em] font-bold text-stone-400">Sabores do Dia • Comida com Afeto</div>
                      </header>

                      <div className="flex-1 space-y-10">
                        {Object.entries(generatedMenu.selections).map(([cat, items]) => {
                          const typedItems = items as any[];
                          if (typedItems.length === 0) return null;
                          return (
                            <div key={cat} className="space-y-4">
                              <div className="flex items-center gap-4">
                                <h3 className="serif text-2xl text-stone-800 uppercase tracking-widest whitespace-nowrap">{cat}s</h3>
                                <div className="h-[1px] w-full bg-stone-100"></div>
                              </div>
                              <div className="grid gap-5">
                                {typedItems.map((item, idx) => (
                                  <div key={idx} className="group">
                                    <div className="flex justify-between items-baseline mb-1">
                                      <h4 className="text-lg font-bold text-stone-900 leading-tight uppercase group-hover:text-[#e67e22] transition-colors">{item.name}</h4>
                                      <div className="h-[1px] flex-1 border-b border-dotted border-stone-200 mx-2 mb-1 opacity-50"></div>
                                      <span className="text-[10px] text-stone-300 font-bold">ITEM {idx + 1}</span>
                                    </div>
                                    {item.description && (
                                      <p className="text-[13px] text-stone-500 leading-relaxed italic font-medium pr-4">{item.description}</p>
                                    )}
                                  </div>
                                ))}
                              </div>
                            </div>
                          );
                        })}
                      </div>

                      <footer className="mt-14 pt-10 border-t-2 border-stone-50 relative">
                        {/* Seal */}
                        <div className="absolute top-[-25px] right-0 bg-[#e67e22] text-white w-14 h-14 rounded-full flex items-center justify-center text-[8px] font-bold uppercase text-center leading-tight rotate-12 shadow-md">
                          Qualidade<br/>Garantida
                        </div>

                        <div className="bg-stone-50/80 p-6 rounded-2xl border border-stone-100">
                          <p className="serif text-xl italic text-stone-600 leading-relaxed text-center">
                            "{generatedMenu.chefNote}"
                          </p>
                        </div>
                        <div className="text-center mt-8 text-stone-300 text-[10px] uppercase font-bold tracking-[0.2em]">
                          ChefAI • Cardápio Gerado por Inteligência Artificial
                        </div>
                      </footer>
                    </div>
                  </div>

                  {/* Ações pós-geração */}
                  <div className="no-print mt-10 flex flex-wrap justify-center gap-4">
                    <button onClick={saveAsImage} className="px-10 py-4 bg-[#e67e22] text-white rounded-full font-bold text-sm uppercase tracking-widest shadow-2xl hover:bg-[#d35400] transition active:scale-95 flex items-center gap-3">
                      <span>💾</span> Baixar Cardápio (HD)
                    </button>
                    <button onClick={() => window.print()} className="px-10 py-4 bg-white text-stone-600 border border-stone-200 rounded-full font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-stone-50 transition active:scale-95 flex items-center gap-3">
                      <span>🖨️</span> Imprimir / PDF
                    </button>
                    <button onClick={() => setGeneratedMenu(null)} className="px-10 py-4 bg-stone-900 text-white rounded-full font-bold text-sm uppercase tracking-widest shadow-xl transition active:scale-95">
                      🔄 Novo Ajuste
                    </button>
