              ) : (
                <div className="h-[700px] flex flex-col items-center justify-center text-center px-10 border-4 border-dashed border-stone-100 rounded-[40px] bg-white/50">
                  {isGenerating ? (
                    <div className="space-y-6">
                      <div className="relative">
                        <div className="w-24 h-24 border-8 border-orange-500/10 border-t-orange-500 rounded-full animate-spin mx-auto"></div>
                        <div className="absolute inset-0 flex items-center justify-center text-3xl">👨‍🍳</div>
                      </div>
                      <p className="serif text-3xl text-stone-700 italic animate-pulse">Equilibrando sabores e preparando seu menu...</p>
                      <p className="text-stone-400 text-sm">Nossa IA está analisando seu acervo para as melhores combinações.</p>
                    </div>
                  ) : (
                    <>
                      <div className="text-[120px] mb-8 grayscale opacity-20">🍱</div>
                      <h3 className="serif text-4xl text-stone-800 mb-4">Crie o seu Cardápio de Sucesso</h3>
                      <p className="text-stone-500 max-w-md text-lg leading-relaxed">
                        Configure as quantidades ao lado ou deixe por nossa conta. Geramos uma imagem profissional pronta para enviar no WhatsApp ou imprimir.
                      </p>
                    </>
                  )}
