              )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [showInventory, setShowInventory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [newlyAddedIds, setNewlyAddedIds] = useState<Set<string>>(new Set());
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  useEffect(() => {
    if (newlyAddedIds.size > 0) {
      const timer = setTimeout(() => setNewlyAddedIds(new Set()), 3000);
      return () => clearTimeout(timer);
    }
  }, [newlyAddedIds]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const ids: string[] = [];
        const parsedDishes: Dish[] = data.map((item, idx) => {
          const id = `custom-${Date.now()}-${idx}`;
          ids.push(id);
          return {
            id,
            name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
            category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
            description: item.Descricao || item.description || item.Ingredientes || ''
          };
        });

        setDishPool(prev => [...prev, ...parsedDishes]);
        setNewlyAddedIds(new Set(ids));
        setToast({ message: `${parsedDishes.length} itens adicionados com sucesso!`, type: 'success' });
        if (!showInventory) setShowInventory(true);
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio.', type: 'error' });
      setShowInventory(true);
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    if (window.confirm('Deseja remover este prato?')) {
      setDishPool(prev => prev.filter(d => d.id !== id));
      setToast({ message: 'Removido.', type: 'success' });
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => prev.map(d => d.id === editingDish.id ? editingDish : d));
    setEditingDish(null);
    setToast({ message: 'Atualizado.', type: 'success' });
  };

  const restoreDefaults = () => {
    if(window.confirm('Restaurar opções padrão?')) {
        setDishPool(DEFAULT_DISHES);
        setToast({ message: 'Restaurado.', type: 'success' });
    }
  };

  const saveAsImage = async () => {
    if (!menuRef.current) return;
    try {
      const dataUrl = await toPng(menuRef.current, { 
        quality: 1, 
        pixelRatio: 3, 
        backgroundColor: '#ffffff',
        style: {
          transform: 'scale(1)',
          transformOrigin: 'top left'
        }
      });
      const link = document.createElement('a');
      link.download = `Cardapio-${config.theme.replace(/\s+/g, '-')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      setToast({ message: 'Erro ao gerar imagem.', type: 'error' });
    }
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] selection:bg-orange-100 pb-20 relative text-[#333]">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {/* Modal de Edição */}
      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/50 backdrop-blur-sm">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8">
            <h3 className="serif text-3xl text-[#e67e22] mb-6 border-b pb-4">Editar Opção</h3>
            <form onSubmit={handleUpdateDish} className="space-y-5">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none text-lg" />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none">
                  {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setEditingDish(null)} className="flex-1 py-3 font-bold text-stone-400">Cancelar</button>
                <button type="submit" className="flex-1 py-3 font-bold text-white bg-[#e67e22] rounded-xl">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navbar */}
      <nav className="no-print sticky top-0 z-50 bg-white/90 backdrop-blur-md border-b border-stone-200 px-6 py-4">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-2xl">🍲</span>
            <span className="serif text-2xl font-bold text-[#e67e22]">ChefAI <span className="text-stone-400 font-light text-base">Restaurantes</span></span>
          </div>
          <button 
            onClick={() => setShowInventory(!showInventory)}
            className="text-sm font-semibold flex items-center gap-2 px-5 py-2 rounded-full border border-stone-200 hover:border-[#e67e22] transition"
          >
            {showInventory ? 'Fechar' : 'Meus Itens'} ({dishPool.length})
          </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 pt-12 grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Painel Lateral */}
        <div className="lg:col-span-4 space-y-8 no-print">
          <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
            <h2 className="serif text-3xl mb-6 text-stone-800">Cardápio do Dia</h2>

            <div className="space-y-6">
              <div className={`p-5 rounded-2xl border-2 cursor-pointer transition-all ${config.chefChoice ? 'bg-orange-50 border-[#e67e22]' : 'bg-stone-50 border-stone-100'}`} onClick={() => setConfig({...config, chefChoice: !config.chefChoice})}>
                <div className="flex items-center gap-4">
                  <span className="text-2xl">💡</span>
                  <div>
                    <h4 className="font-bold text-sm">Sugestão da Casa</h4>
                    <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-0.5">IA define quantidades</p>
                  </div>
                </div>
              </div>

              <div className={`space-y-5 transition-all duration-300 ${config.chefChoice ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                {Object.entries(config.counts).map(([cat, count]) => (
                  <div key={cat} className="flex items-center justify-between">
                    <span className="font-semibold text-stone-600">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']} {cat}</span>
                    <div className="flex items-center gap-3 bg-stone-100 p-1 rounded-full">
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold">-</button>
                      <span className="w-4 text-center font-bold">{count}</span>
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat as Category] + 1}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold">+</button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-stone-100">
                <label className="block text-xs uppercase text-stone-400 font-bold mb-2">Nome do Dia/Refeição</label>
                <input type="text" value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] transition-colors" />
              </div>
            </div>

            <button onClick={handleGenerate} disabled={isGenerating} className="w-full mt-10 py-4 bg-[#e67e22] text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-3 hover:bg-[#d35400] transition-colors active:scale-95">
              {isGenerating ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Criar Cardápio'}
            </button>
          </section>

          <section className="bg-stone-900 p-8 rounded-3xl text-white shadow-xl">
              <h3 className="serif text-2xl mb-2">Importar Lista</h3>
              <p className="text-stone-400 text-sm mb-6">Suba seus pratos via Excel.</p>
              <label className="block w-full cursor-pointer">
                <div className="border-2 border-stone-700 border-dashed rounded-2xl py-8 flex flex-col items-center bg-white/5 hover:border-[#e67e22] transition-colors group">
                  <span className="text-3xl mb-2 group-hover:scale-110 transition-transform">📂</span>
                  <span className="text-[10px] uppercase font-bold tracking-widest text-stone-500">Selecionar arquivo</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
              </label>
          </section>
        </div>

        {/* Área de Visualização do Cardápio */}
        <div className="lg:col-span-8">
          {showInventory ? (
            <div className="bg-white rounded-3xl p-8 border border-stone-200 shadow-sm min-h-[600px] animate-in fade-in duration-300">
              <div className="flex justify-between items-center mb-8">
                <h2 className="serif text-4xl text-stone-800">Seu Acervo</h2>
                <button onClick={restoreDefaults} className="text-[#e67e22] font-bold text-xs uppercase hover:underline">Restaurar Padrão</button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-[500px] overflow-y-auto pr-2 scrollbar-thin">
                {dishPool.map(dish => (
                  <div key={dish.id} className="p-4 rounded-xl border border-stone-100 bg-stone-50/50 flex justify-between items-center group hover:border-orange-200 transition-colors">
                    <div>
                      <span className="text-[9px] uppercase font-bold text-orange-500">{dish.category}</span>
                      <div className="font-bold text-stone-800">{dish.name}</div>
                    </div>
                    <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition">
                      <button onClick={() => setEditingDish(dish)} className="p-2 text-stone-400 hover:text-blue-500">✎</button>
                      <button onClick={() => removeItem(dish.id)} className="p-2 text-stone-400 hover:text-red-500">✕</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <div className="relative">
              {generatedMenu && !isGenerating ? (
                <div className="flex flex-col items-center animate-in fade-in zoom-in duration-500">
                  {/* CARDÁPIO FORMATADO PARA IMAGEM */}
                  <div 
                    ref={menuRef} 
                    className="w-full max-w-[600px] bg-white shadow-[0_40px_80px_-20px_rgba(0,0,0,0.2)] border-[1px] border-stone-100 relative overflow-hidden"
                    style={{ minHeight: '840px' }}
                  >
                    {/* Decorative Background Pattern */}
                    <div className="absolute inset-0 opacity-[0.02] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#000 0.5px, transparent 0.5px)', backgroundSize: '20px 20px' }}></div>
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#e67e22]/50 to-transparent"></div>

                    {/* Content Container */}
                    <div className="relative z-10 p-10 md:p-14 flex flex-col h-full border-[1px] border-stone-100 m-6">

                      {/* Subtlest Header Box with Gradient */}
                      <header className="text-center mb-12 p-8 rounded-3xl bg-gradient-to-b from-orange-50/50 to-transparent relative overflow-hidden">
                        <div className="absolute -top-10 -right-10 w-32 h-32 bg-orange-100/30 rounded-full blur-3xl"></div>
                        <div className="absolute -bottom-10 -left-10 w-32 h-32 bg-orange-100/30 rounded-full blur-3xl"></div>

                        <div className="inline-block px-4 py-1 mb-4 rounded-full bg-[#e67e22] text-white text-[9px] font-bold uppercase tracking-[0.3em]">
                          Restaurante & Marmitaria
                        </div>

                        <h1 className="serif text-5xl md:text-6xl text-stone-900 uppercase tracking-tighter leading-none mb-4 font-bold">
                          {config.theme}
                        </h1>

                        <div className="flex items-center justify-center gap-4">
                          <div className="h-[1px] flex-1 bg-stone-200"></div>
                          <span className="text-stone-400 text-xs italic serif">Sabor que acolhe</span>
                          <div className="h-[1px] flex-1 bg-stone-200"></div>
                        </div>
                      </header>

                      {/* Menu Items List */}
                      <div className="flex-1 space-y-12">
                        {Object.entries(generatedMenu.selections).map(([cat, items]) => {
                          const typedItems = items as any[];
                          if (typedItems.length === 0) return null;
                          return (
                            <div key={cat} className="space-y-6">
                              <div className="flex items-center gap-4">
                                <h3 className="text-[11px] font-bold text-[#e67e22] uppercase tracking-[0.4em] whitespace-nowrap bg-white px-2 relative z-10">{cat}s</h3>
                                <div className="h-[1px] w-full bg-stone-100 absolute left-0"></div>
                              </div>
                              <div className="grid gap-6">
                                {typedItems.map((item, idx) => (
                                  <div key={idx} className="flex flex-col">
                                    <div className="flex justify-between items-baseline mb-2">
                                      <h4 className="text-xl font-bold text-stone-800 leading-tight">
                                        {item.name}
                                      </h4>
                                    </div>
                                    {item.description && (
                                      <p className="text-[14px] text-stone-500 leading-relaxed font-normal opacity-90 max-w-[90%]">
                                        {item.description}
                                      </p>
                                    )}
                                  </div>
                                ))}
                              </div>
                            </div>
                          );
                        })}
                      </div>

                      {/* Refined Footer */}
                      <footer className="mt-16 pt-10 border-t border-stone-100 relative">
                        {/* Modern Quality Seal */}
                        <div className="absolute -top-10 right-4 w-20 h-20 rounded-full bg-white shadow-xl border border-orange-50 flex items-center justify-center p-2 rotate-6">
                           <div className="w-full h-full rounded-full border border-dashed border-orange-200 flex flex-col items-center justify-center text-center">
                              <span className="text-[7px] font-bold uppercase text-orange-400 mb-0.5">Ingredientes</span>
                              <span className="text-[10px] font-bold text-orange-600 leading-none">FRESCOS</span>
                           </div>
                        </div>

                        <div className="px-6 py-8 rounded-3xl bg-stone-50/50 border border-stone-100 relative">
                          <span className="absolute top-2 left-4 text-4xl text-orange-200 font-serif opacity-50">“</span>
                          <p className="serif text-2xl italic text-stone-600 leading-tight text-center relative z-10">
                            {generatedMenu.chefNote}
                          </p>
                          <span className="absolute bottom-[-10px] right-4 text-4xl text-orange-200 font-serif opacity-50">”</span>
                        </div>

                        <div className="flex flex-col items-center mt-10 space-y-2">
                           <div className="text-stone-900 serif text-3xl font-bold italic">Bom Apetite!</div>
                           <div className="text-stone-300 text-[9px] uppercase font-bold tracking-[0.3em]">ChefAI Digital</div>
                        </div>
                      </footer>
                    </div>
                  </div>

                  {/* Actions Bar */}
                  <div className="no-print mt-12 flex flex-wrap justify-center gap-4">
                    <button onClick={saveAsImage} className="px-10 py-4 bg-[#e67e22] text-white rounded-full font-bold text-sm uppercase tracking-widest shadow-2xl hover:bg-[#d35400] transition-all active:scale-95 flex items-center gap-3">
                      <span>💾</span> Baixar Cardápio (HD)
                    </button>
                    <button onClick={() => window.print()} className="px-10 py-4 bg-white text-stone-600 border border-stone-200 rounded-full font-bold text-sm uppercase tracking-widest shadow-lg hover:bg-stone-50 transition active:scale-95 flex items-center gap-3">
                      <span>🖨️</span> Imprimir / PDF
                    </button>
                    <button onClick={() => setGeneratedMenu(null)} className="px-10 py-4 bg-stone-900 text-white rounded-full font-bold text-sm uppercase tracking-widest shadow-xl transition hover:bg-black active:scale-95">
                      🔄 Novo Ajuste
                    </button>
                  </div>
                </div>
              ) : (
                <div className="h-[700px] flex flex-col items-center justify-center text-center px-10 border-4 border-dashed border-stone-100 rounded-[60px] bg-white/50 backdrop-blur-sm">
                  {isGenerating ? (
                    <div className="space-y-8">
                      <div className="relative">
                        <div className="w-28 h-28 border-[6px] border-orange-500/10 border-t-orange-500 rounded-full animate-spin mx-auto"></div>
                        <div className="absolute inset-0 flex items-center justify-center text-4xl">🥘</div>
                      </div>
                      <div className="space-y-2">
                        <p className="serif text-3xl text-stone-700 italic font-medium">Preparando seu cardápio...</p>
                        <p className="text-stone-400 text-sm max-w-[300px] mx-auto">Selecionando as melhores combinações e organizando o layout para você.</p>
                      </div>
                    </div>
                  ) : (
                    <>
                      <div className="w-32 h-32 bg-orange-50 rounded-full flex items-center justify-center mb-10 shadow-inner">
                        <span className="text-6xl">🍛</span>
                      </div>
                      <h3 className="serif text-4xl text-stone-800 mb-4 font-bold">Menu Profissional em Segundos</h3>
                      <p className="text-stone-500 max-w-sm text-lg leading-relaxed">
                        Defina suas opções diárias e gere uma imagem elegante para compartilhar com seus clientes no WhatsApp ou imprimir.
                      </p>
                    </>
                  )}
                </div>
              )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [showInventory, setShowInventory] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [newlyAddedIds, setNewlyAddedIds] = useState<Set<string>>(new Set());
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  useEffect(() => {
    if (newlyAddedIds.size > 0) {
      const timer = setTimeout(() => setNewlyAddedIds(new Set()), 3000);
      return () => clearTimeout(timer);
    }
  }, [newlyAddedIds]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const ids: string[] = [];
        const parsedDishes: Dish[] = data.map((item, idx) => {
          const id = `custom-${Date.now()}-${idx}`;
          ids.push(id);
          return {
            id,
            name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
            category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
            description: item.Descricao || item.description || item.Ingredientes || ''
          };
        });

        setDishPool(prev => [...prev, ...parsedDishes]);
        setNewlyAddedIds(new Set(ids));
        setToast({ message: `${parsedDishes.length} itens adicionados com sucesso!`, type: 'success' });
        if (!showInventory) setShowInventory(true);
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio.', type: 'error' });
      setShowInventory(true);
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    if (window.confirm('Deseja remover este prato?')) {
      setDishPool(prev => prev.filter(d => d.id !== id));
      setToast({ message: 'Removido.', type: 'success' });
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => prev.map(d => d.id === editingDish.id ? editingDish : d));
    setEditingDish(null);
    setToast({ message: 'Atualizado com sucesso.', type: 'success' });
  };

  const restoreDefaults = () => {
    if(window.confirm('Restaurar opções padrão?')) {
        setDishPool(DEFAULT_DISHES);
        setToast({ message: 'Restaurado.', type: 'success' });
    }
  };

  const copyMenuToClipboard = () => {
    if (!generatedMenu) return;
    let text = `*${config.theme.toUpperCase()}*\n\n`;
    Object.entries(generatedMenu.selections).forEach(([cat, items]) => {
      const typedItems = items as any[];
      if (typedItems.length > 0) {
        text += `*${cat}s:*\n`;
        typedItems.forEach(item => {
          text += `• ${item.name}${item.description ? ` (${item.description})` : ''}\n`;
        });
        text += `\n`;
      }
    });
    text += `_"${generatedMenu.chefNote}"_\n\nBom Apetite!`;
    navigator.clipboard.writeText(text);
    setToast({ message: 'Texto copiado para o WhatsApp!', type: 'success' });
  };

  const saveAsImage = async () => {
    if (!menuRef.current) return;
    try {
      const dataUrl = await toPng(menuRef.current, { 
        quality: 1, 
        pixelRatio: 3, 
        backgroundColor: '#ffffff'
      });
      const link = document.createElement('a');
      link.download = `Cardapio-${config.theme.replace(/\s+/g, '-')}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      setToast({ message: 'Erro ao gerar imagem.', type: 'error' });
    }
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] selection:bg-orange-100 pb-20 relative text-[#333]">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {/* Modal de Edição */}
      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 transform animate-in zoom-in-95 duration-200">
            <h3 className="serif text-3xl text-[#e67e22] mb-6 border-b pb-4 font-bold">Editar Opção</h3>
            <form onSubmit={handleUpdateDish} className="space-y-5">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome do Prato</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none text-lg focus:border-[#e67e22] transition-colors" />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] transition-colors">
                  {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Descrição / Detalhes</label>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] transition-colors min-h-[100px]" placeholder="Ex: Carne moída temperada com ervas..." />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setEditingDish(null)} className="flex-1 py-3 font-bold text-stone-400 hover:bg-stone-50 rounded-xl transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-3 font-bold text-white bg-[#e67e22] rounded-xl shadow-lg hover:bg-[#d35400] transition-colors">Salvar Alterações</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navbar */}
      <nav className="no-print sticky top-0 z-50 bg-white/90 backdrop-blur-md border-b border-stone-200 px-6 py-4">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-2xl">🍲</span>
            <span className="serif text-2xl font-bold text-[#e67e22]">ChefAI <span className="text-stone-400 font-light text-base hidden sm:inline">Restaurantes</span></span>
          </div>
          <button 
            onClick={() => setShowInventory(!showInventory)}
            className={`text-sm font-semibold flex items-center gap-2 px-5 py-2 rounded-full border transition-all ${
              showInventory ? 'bg-stone-900 text-white border-stone-900' : 'bg-white text-stone-600 border-stone-200 hover:border-[#e67e22] hover:text-[#e67e22]'
            }`}
          >
            {showInventory ? 'Voltar ao Menu' : 'Gerenciar Acervo'} ({dishPool.length})
          </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 pt-12 grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Painel Lateral de Configuração */}
        <div className="lg:col-span-4 space-y-8 no-print">
          <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
            <h2 className="serif text-3xl mb-6 text-stone-800">Cardápio do Dia</h2>

            <div className="space-y-6">
              <div 
                className={`p-5 rounded-2xl border-2 cursor-pointer transition-all ${config.chefChoice ? 'bg-orange-50 border-[#e67e22]' : 'bg-stone-50 border-stone-100 hover:border-stone-200'}`} 
                onClick={() => setConfig({...config, chefChoice: !config.chefChoice})}
              >
                <div className="flex items-center gap-4">
                  <div className={`w-12 h-12 rounded-full flex items-center justify-center text-2xl transition-all ${config.chefChoice ? 'bg-[#e67e22] text-white shadow-lg rotate-12' : 'bg-white text-stone-400'}`}>
                    ✨
                  </div>
                  <div>
                    <h4 className="font-bold text-sm">Sugestão da Casa</h4>
                    <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-0.5">IA define quantidades</p>
                  </div>
                </div>
              </div>

              <div className={`space-y-5 transition-all duration-300 ${config.chefChoice ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                {Object.entries(config.counts).map(([cat, count]) => (
                  <div key={cat} className="flex items-center justify-between group">
                    <span className="font-semibold text-stone-600 flex items-center gap-2">
                      <span className="opacity-70">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</span>
                      {cat}
                    </span>
                    <div className="flex items-center gap-3 bg-stone-100 p-1 rounded-full group-hover:bg-stone-200 transition-colors">
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold flex items-center justify-center hover:text-[#e67e22] transition-colors">-</button>
                      <span className="w-4 text-center font-bold text-sm">{count}</span>
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat as Category] + 1}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold flex items-center justify-center hover:text-[#e67e22] transition-colors">+</button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-stone-100">
                <label className="block text-xs uppercase text-stone-400 font-bold mb-2">Título do Cardápio</label>
                <input type="text" value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] transition-colors" placeholder="Ex: Almoço de Terça" />
              </div>
            </div>

            <button onClick={handleGenerate} disabled={isGenerating} className="w-full mt-10 py-4 bg-[#e67e22] text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-3 hover:bg-[#d35400] transition-all active:scale-95 disabled:bg-stone-300">
              {isGenerating ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Gerar Cardápio Profissional'}
            </button>
          </section>

          <section className="bg-stone-900 p-8 rounded-3xl text-white shadow-xl">
              <h3 className="serif text-2xl mb-2">Importar Acervo</h3>
              <p className="text-stone-400 text-sm mb-6 leading-relaxed">Suba seus pratos favoritos via planilha Excel.</p>
              <label className="block w-full cursor-pointer">
                <div className="border-2 border-stone-700 border-dashed rounded-2xl py-8 flex flex-col items-center bg-white/5 hover:border-[#e67e22] transition-colors group">
                  <span className="text-3xl mb-2 group-hover:scale-110 transition-transform">📂</span>
                  <span className="text-[10px] uppercase font-bold tracking-widest text-stone-500">Selecionar arquivo</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
              </label>
          </section>
        </div>

        {/* Área Principal de Exibição */}
        <div className="lg:col-span-8">
          {showInventory ? (
            <div className="bg-white rounded-3xl p-8 border border-stone-200 shadow-sm min-h-[600px] animate-in fade-in duration-300">
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8">
                <div>
                  <h2 className="serif text-4xl text-stone-800">Meus Pratos</h2>
                  <p className="text-stone-400 text-sm">Gerencie o que a IA pode usar nos cardápios.</p>
                </div>
                <button onClick={restoreDefaults} className="text-[#e67e22] font-bold text-xs uppercase hover:underline">Restaurar Padrão</button>
              </div>

              <div className="mb-6">
                <input 
                  type="text" 
                  placeholder="Pesquisar no acervo..." 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)} 
                  className="w-full px-5 py-3 bg-stone-50 border border-stone-200 rounded-xl focus:border-[#e67e22] outline-none transition-colors"
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-[500px] overflow-y-auto pr-2 scrollbar-thin">
                {filteredDishes.length > 0 ? filteredDishes.map(dish => (
                  <div key={dish.id} className="p-4 rounded-xl border border-stone-100 bg-stone-50/50 flex justify-between items-center group hover:border-[#e67e22]/30 transition-colors">
                    <div className="flex-1 overflow-hidden">
                      <span className="text-[9px] uppercase font-bold text-orange-500 block">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === dish.category) || 'BASE']} {dish.category}</span>
                      <div className="font-bold text-stone-800 truncate">{dish.name}</div>
                      {dish.description && <div className="text-[10px] text-stone-400 truncate italic">{dish.description}</div>}
                    </div>
                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => setEditingDish(dish)} className="p-2 text-stone-400 hover:text-blue-500" title="Editar">✎</button>
                      <button onClick={() => removeItem(dish.id)} className="p-2 text-stone-400 hover:text-red-500" title="Remover">✕</button>
                    </div>
                  </div>
                )) : (
                  <div className="col-span-2 py-10 text-center text-stone-400 italic">Nenhum item encontrado.</div>
                )}
              </div>
            </div>
          ) : (
            <div className="relative">
              {generatedMenu && !isGenerating ? (
                <div className="flex flex-col items-center animate-in fade-in zoom-in duration-500">
                  <div 
                    ref={menuRef} 
                    className="w-full max-w-[600px] bg-white shadow-[0_40px_80px_-20px_rgba(0,0,0,0.2)] border-[1px] border-stone-100 relative overflow-hidden"
                    style={{ minHeight: '840px' }}
                  >
                    <div className="absolute inset-0 opacity-[0.02] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#000 0.5px, transparent 0.5px)', backgroundSize: '20px 20px' }}></div>
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#e67e22]/50 to-transparent"></div>

                    <div className="relative z-10 p-10 md:p-14 flex flex-col h-full border-[1px] border-stone-100 m-6">
                      <header className="text-center mb-12 p-8 rounded-3xl bg-gradient-to-b from-orange-50/50 to-transparent relative overflow-hidden">
                        <div className="absolute -top-10 -right-10 w-32 h-32 bg-orange-100/30 rounded-full blur-3xl"></div>
                        <div className="absolute -bottom-10 -left-10 w-32 h-32 bg-orange-100/30 rounded-full blur-3xl"></div>

                        <div className="inline-block px-4 py-1 mb-4 rounded-full bg-[#e67e22] text-white text-[9px] font-bold uppercase tracking-[0.3em] shadow-sm">
                          Restaurante & Marmitaria
                        </div>

                        <h1 className="serif text-5xl md:text-6xl text-stone-900 uppercase tracking-tighter leading-none mb-4 font-bold">
                          {config.theme}
                        </h1>

                        <div className="flex items-center justify-center gap-4">
                          <div className="h-[1px] flex-1 bg-stone-200"></div>
                          <span className="text-stone-400 text-xs italic serif">Sabor que acolhe</span>
                          <div className="h-[1px] flex-1 bg-stone-200"></div>
                        </div>
                      </header>

                      <div className="flex-1 space-y-12">
                        {Object.entries(generatedMenu.selections).map(([cat, items]) => {
                          const typedItems = items as any[];
                          if (typedItems.length === 0) return null;
                          return (
                            <div key={cat} className="space-y-6">
                              <div className="flex items-center gap-4">
                                <h3 className="text-[11px] font-bold text-[#e67e22] uppercase tracking-[0.4em] whitespace-nowrap bg-white px-2 relative z-10">{cat}s</h3>
                                <div className="h-[1px] w-full bg-stone-100 absolute left-0"></div>
                              </div>
                              <div className="grid gap-6">
                                {typedItems.map((item, idx) => (
