                      <span className="text-[9px] uppercase font-bold text-orange-500 block">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === dish.category) || 'BASE']} {dish.category}</span>
                      <div className="font-bold text-stone-800 truncate">{dish.name}</div>
                      {dish.description && <div className="text-[10px] text-stone-400 truncate italic">{dish.description}</div>}
                    </div>
                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => setEditingDish(dish)} className="p-2 text-stone-400 hover:text-blue-500" title="Editar">✎</button>
                      <button onClick={() => removeItem(dish.id)} className="p-2 text-stone-400 hover:text-red-500" title="Remover">✕</button>
                    </div>
                  </div>
                )) : (
                  <div className="col-span-2 py-10 text-center text-stone-400 italic">Nenhum item encontrado no filtro.</div>
                )}
              </div>
            </div>
          ) : (
            <div className="relative">
              {generatedMenu && !isGenerating ? (
                <div className="flex flex-col items-center animate-in fade-in zoom-in duration-500">

                  {/* CONTAINER DO CARDÁPIO (CAPTURA) */}
                  <div 
                    ref={menuRef} 
                    className={`bg-white shadow-2xl relative overflow-hidden transition-all duration-500 ${
                      exportFormat === 'story' 
                        ? 'w-[450px] aspect-[9/16]' 
                        : 'w-full max-w-[600px] min-h-[840px] border border-stone-100'
                    }`}
                  >
                    {/* Background decorativo */}
                    <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#000 0.5px, transparent 0.5px)', backgroundSize: '20px 20px' }}></div>

                    {/* Estilo Story vs Standard */}
                    {exportFormat === 'story' ? (
                      <div className="absolute inset-0 bg-gradient-to-b from-orange-50/20 via-white to-orange-50/20 pointer-events-none"></div>
                    ) : (
                      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#e67e22]/50 to-transparent"></div>
                    )}

                    {/* Conteúdo Real */}
                    <div className={`relative z-10 flex flex-col h-full ${exportFormat === 'story' ? 'p-12' : 'p-14 m-6 border-[1px] border-stone-100'}`}>

                      <header className={`text-center relative overflow-hidden ${exportFormat === 'story' ? 'mb-16 mt-8' : 'mb-12 p-8 rounded-3xl bg-gradient-to-b from-orange-50/50 to-transparent'}`}>
                        {exportFormat !== 'story' && (
                          <>
                            <div className="absolute -top-10 -right-10 w-32 h-32 bg-orange-100/30 rounded-full blur-3xl"></div>
                            <div className="absolute -bottom-10 -left-10 w-32 h-32 bg-orange-100/30 rounded-full blur-3xl"></div>
                          </>
                        )}

                        <div className="inline-block px-4 py-1 mb-4 rounded-full bg-[#e67e22] text-white text-[9px] font-bold uppercase tracking-[0.3em] shadow-sm">
                          Restaurante & Marmitaria
                        </div>

                        <h1 className={`${exportFormat === 'story' ? 'text-6xl' : 'text-5xl md:text-6xl'} serif text-stone-900 uppercase tracking-tighter leading-none mb-4 font-bold`}>
                          {config.theme}
                        </h1>

                        <div className="flex items-center justify-center gap-4">
                          <div className="h-[1px] flex-1 bg-stone-200"></div>
                          <span className="text-stone-400 text-xs italic serif">Sabor que acolhe</span>
                          <div className="h-[1px] flex-1 bg-stone-200"></div>
                        </div>
                      </header>

                      <div className={`flex-1 ${exportFormat === 'story' ? 'space-y-16' : 'space-y-12'}`}>
                        {Object.entries(generatedMenu.selections).map(([cat, items]) => {
                          const typedItems = items as any[];
                          if (typedItems.length === 0) return null;
                          return (
                            <div key={cat} className="space-y-6">
                              <div className="flex items-center gap-4">
                                <h3 className="text-[11px] font-bold text-[#e67e22] uppercase tracking-[0.4em] whitespace-nowrap bg-white px-2 relative z-10">{cat}s</h3>
                                <div className="h-[1px] w-full bg-stone-100 absolute left-0"></div>
                              </div>
                              <div className={`grid ${exportFormat === 'story' ? 'gap-8' : 'gap-6'}`}>
                                {typedItems.map((item, idx) => (
                                  <div key={idx} className="flex flex-col">
                                    <h4 className={`${exportFormat === 'story' ? 'text-2xl' : 'text-xl'} font-bold text-stone-800 leading-tight`}>
                                      {item.name}
                                    </h4>
                                    {item.description && (
                                      <p className={`${exportFormat === 'story' ? 'text-lg' : 'text-[14px]'} text-stone-500 leading-relaxed font-normal opacity-90 max-w-[95%]`}>
                                        {item.description}
                                      </p>
                                    )}
                                  </div>
                                ))}
                              </div>
                            </div>
                          );
                        })}
                      </div>

                      <footer className={`${exportFormat === 'story' ? 'mt-20 pb-12' : 'mt-16 pt-10 border-t border-stone-100'} relative`}>
                        <div className="absolute -top-10 right-4 w-20 h-20 rounded-full bg-white shadow-xl border border-orange-50 flex items-center justify-center p-2 rotate-6">
                           <div className="w-full h-full rounded-full border border-dashed border-orange-200 flex flex-col items-center justify-center text-center">
                              <span className="text-[7px] font-bold uppercase text-orange-400 mb-0.5">Qualidade</span>
                              <span className="text-[10px] font-bold text-orange-600 leading-none">FRESCO</span>
                           </div>
                        </div>

                        <div className={`px-6 py-8 rounded-3xl bg-stone-50/50 border border-stone-100 relative ${exportFormat === 'story' ? 'mb-10' : ''}`}>
                          <span className="absolute top-2 left-4 text-4xl text-orange-200 font-serif opacity-50">“</span>
                          <p className={`serif italic text-stone-600 leading-tight text-center relative z-10 px-4 ${exportFormat === 'story' ? 'text-3xl' : 'text-2xl'}`}>
                            {generatedMenu.chefNote}
                          </p>
                        </div>

                        <div className="flex flex-col items-center mt-10 space-y-2">
                           <div className={`text-stone-900 serif font-bold italic ${exportFormat === 'story' ? 'text-4xl' : 'text-3xl'}`}>Bom Apetite!</div>
                           <div className="text-stone-300 text-[9px] uppercase font-bold tracking-[0.3em]">ChefAI Digital</div>
                        </div>
                      </footer>
                    </div>
                  </div>

                  {/* Botões de Ação */}
                  <div className="no-print mt-12 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 w-full">
                    <button 
                      onClick={() => saveAsImage('standard')} 
                      className="px-6 py-4 bg-white text-stone-700 border border-stone-200 rounded-2xl font-bold text-sm uppercase tracking-widest shadow-md hover:bg-stone-50 transition-all flex items-center justify-center gap-2"
                    >
                      <span>📸</span> Baixar Post (Square)
                    </button>
                    <button 
                      onClick={() => saveAsImage('story')} 
                      className="px-6 py-4 bg-[#e67e22] text-white rounded-2xl font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-[#d35400] transition-all flex items-center justify-center gap-2"
                    >
                      <span>📱</span> Baixar Story (9:16)
                    </button>
                    <button 
                      onClick={copyMenuToClipboard} 
                      className="px-6 py-4 bg-white text-stone-700 border border-stone-200 rounded-2xl font-bold text-sm uppercase tracking-widest shadow-md hover:bg-stone-50 transition-all flex items-center justify-center gap-2"
                    >
                      <span>📋</span> Copiar Texto WhatsApp
                    </button>
                    <button 
                      onClick={() => setGeneratedMenu(null)} 
                      className="px-6 py-4 bg-stone-900 text-white rounded-2xl font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-black transition-all"
                    >
                      🔄 Refazer Cardápio
                    </button>
                  </div>
                </div>
              ) : (
                <div className="h-[700px] flex flex-col items-center justify-center text-center px-10 border-4 border-dashed border-stone-100 rounded-[60px] bg-white/50 backdrop-blur-sm">
                  {isGenerating ? (
                    <div className="space-y-8">
                      <div className="relative">
                        <div className="w-28 h-28 border-[6px] border-orange-500/10 border-t-orange-500 rounded-full animate-spin mx-auto"></div>
                        <div className="absolute inset-0 flex items-center justify-center text-4xl">🥘</div>
                      </div>
                      <div className="space-y-2">
                        <p className="serif text-3xl text-stone-700 italic font-medium">Equilibrando os pratos...</p>
                        <p className="text-stone-400 text-sm max-w-[300px] mx-auto">A IA está escolhendo as melhores combinações do seu acervo.</p>
                      </div>
                    </div>
                  ) : (
                    <>
                      <div className="w-32 h-32 bg-orange-50 rounded-full flex items-center justify-center mb-10 shadow-inner">
                        <span className="text-6xl">🍛</span>
                      </div>
                      <h3 className="serif text-4xl text-stone-800 mb-4 font-bold">Crie Cardápios Profissionais</h3>
                      <p className="text-stone-500 max-w-sm text-lg leading-relaxed">
                        Defina suas opções e gere imagens incríveis para o Instagram e WhatsApp em segundos.
                      </p>
                    </>
                  )}
                </div>
              )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const parsedDishes: Dish[] = data.map((item, idx) => ({
          id: `custom-${Date.now()}-${idx}`,
          name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
          category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
          description: item.Descricao || item.description || item.Ingredientes || ''
        }));

        setDishPool(prev => [...prev, ...parsedDishes]);
        setToast({ message: `${parsedDishes.length} itens adicionados!`, type: 'success' });
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio.', type: 'error' });
      setActiveTab('inventory');
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
      setExportFormat('standard');
      setActiveTab('result');
      setToast({ message: 'Cardápio gerado com sucesso!', type: 'success' });
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    if (window.confirm('Deseja remover este prato?')) {
      setDishPool(prev => prev.filter(d => d.id !== id));
      setToast({ message: 'Item removido.', type: 'success' });
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => prev.map(d => d.id === editingDish.id ? editingDish : d));
    setEditingDish(null);
    setToast({ message: 'Prato atualizado!', type: 'success' });
  };

  const restoreDefaults = () => {
    if(window.confirm('Restaurar opções padrão?')) {
        setDishPool(DEFAULT_DISHES);
        setToast({ message: 'Restaurado com sucesso!', type: 'success' });
    }
  };

  const copyMenuToClipboard = () => {
    if (!generatedMenu) return;
    let text = `*${config.theme.toUpperCase()}*\n\n`;
    Object.entries(generatedMenu.selections).forEach(([cat, items]) => {
      const typedItems = items as any[];
      if (typedItems.length > 0) {
        text += `*${cat}s:*\n`;
        typedItems.forEach(item => {
          text += `• ${item.name}${item.description ? ` (${item.description})` : ''}\n`;
        });
        text += `\n`;
      }
    });
    text += `_"${generatedMenu.chefNote}"_\n\nBom Apetite!`;
    navigator.clipboard.writeText(text);
    setToast({ message: 'Texto copiado para o WhatsApp!', type: 'success' });
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);

    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { 
          quality: 1, 
          pixelRatio: 3, 
          backgroundColor: '#ffffff'
        });
        const link = document.createElement('a');
        link.download = `Cardapio-${format === 'story' ? 'Story' : 'Post'}-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
        setToast({ message: `Download concluído!`, type: 'success' });
      } catch (err) {
        setToast({ message: 'Erro ao gerar imagem.', type: 'error' });
      }
    }, 150);
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] selection:bg-orange-100 pb-20 relative text-[#333]">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {/* Modal de Edição */}
      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 transform animate-in zoom-in-95 duration-200">
            <h3 className="serif text-3xl text-[#e67e22] mb-6 border-b pb-4 font-bold">Editar Item</h3>
            <form onSubmit={handleUpdateDish} className="space-y-5">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome do Prato</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none text-lg focus:border-[#e67e22] transition-colors" />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] transition-colors">
                  {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Descrição / Ingredientes</label>
                <textarea 
                  value={editingDish.description || ''} 
                  onChange={e => setEditingDish({...editingDish, description: e.target.value})} 
                  className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] transition-colors min-h-[100px]" 
                  placeholder="Ex: Arroz soltinho com alho e cebola..."
                />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setEditingDish(null)} className="flex-1 py-3 font-bold text-stone-400 hover:bg-stone-50 rounded-xl transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-3 font-bold text-white bg-[#e67e22] rounded-xl shadow-lg hover:bg-[#d35400] transition-colors">Salvar Alterações</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navbar Superior */}
      <nav className="no-print sticky top-0 z-50 bg-white border-b border-stone-200 px-6 py-5 shadow-sm">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-3xl">🍲</span>
            <div>
              <h1 className="serif text-2xl font-bold text-[#e67e22] leading-none">ChefAI</h1>
              <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-1">Sua Marmitaria Digital</p>
            </div>
          </div>

          <div className="flex bg-stone-100 p-1 rounded-xl">
            <button 
              onClick={() => setActiveTab('compose')}
              className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'compose' ? 'bg-white text-[#e67e22] shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
            >
              Criação
            </button>
            <button 
              onClick={() => setActiveTab('inventory')}
              className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'inventory' ? 'bg-white text-[#e67e22] shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
            >
              Acervo
            </button>
            <button 
              onClick={() => setActiveTab('result')}
              disabled={!generatedMenu}
              className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'result' ? 'bg-white text-[#e67e22] shadow-sm' : !generatedMenu ? 'opacity-30 cursor-not-allowed text-stone-400' : 'text-stone-500 hover:text-stone-700'}`}
            >
              Resultado {generatedMenu && <span className="ml-1 inline-block w-1.5 h-1.5 bg-orange-500 rounded-full"></span>}
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 mt-12">

        {/* CONTEÚDO DA ABA: CRIAÇÃO */}
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 animate-in fade-in duration-500">
            <div className="lg:col-span-4 space-y-6">
               <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
                  <h2 className="serif text-3xl mb-6 text-stone-800">Defina o Menu</h2>
                  <div className="space-y-6">
                    <div 
                      className={`p-5 rounded-2xl border-2 cursor-pointer transition-all ${config.chefChoice ? 'bg-orange-50 border-[#e67e22]' : 'bg-stone-50 border-stone-100 hover:border-stone-200'}`} 
                      onClick={() => setConfig({...config, chefChoice: !config.chefChoice})}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-full flex items-center justify-center text-2xl transition-all ${config.chefChoice ? 'bg-[#e67e22] text-white shadow-lg rotate-12' : 'bg-white text-stone-400'}`}>
                          ✨
                        </div>
                        <div>
                          <h4 className="font-bold text-sm">Sugestão Livre</h4>
                          <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-0.5">IA escolhe tudo</p>
                        </div>
                      </div>
                    </div>

                    <div className={`space-y-4 transition-all duration-300 ${config.chefChoice ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                      {Object.entries(config.counts).map(([cat, count]) => (
                        <div key={cat} className="flex items-center justify-between group">
                          <span className="font-semibold text-stone-600 text-sm flex items-center gap-2">
                            <span className="opacity-70">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</span>
                            {cat}s
                          </span>
                          <div className="flex items-center gap-3 bg-stone-100 p-1 rounded-full group-hover:bg-stone-200 transition-colors">
                            <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold flex items-center justify-center hover:text-[#e67e22] transition-colors">-</button>
                            <span className="w-4 text-center font-bold text-xs">{count}</span>
                            <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat as Category] + 1}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold flex items-center justify-center hover:text-[#e67e22] transition-colors">+</button>
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="pt-4 border-t border-stone-100">
                      <label className="block text-[10px] uppercase text-stone-400 font-bold mb-2 tracking-widest">Nome do Cardápio</label>
                      <input type="text" value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] transition-colors" placeholder="Ex: Marmita de Terça" />
                    </div>
                  </div>
                  <button onClick={handleGenerate} disabled={isGenerating} className="w-full mt-10 py-4 bg-[#e67e22] text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-3 hover:bg-[#d35400] transition-all active:scale-95 disabled:bg-stone-300">
                    {isGenerating ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Gerar com Inteligência'}
                  </button>
               </section>
            </div>

            <div className="lg:col-span-8">
              <div className="h-full flex flex-col items-center justify-center text-center p-12 border-4 border-dashed border-stone-100 rounded-[60px] bg-white/50">
                <div className="w-24 h-24 bg-orange-50 rounded-full flex items-center justify-center mb-8 shadow-inner">
                  <span className="text-5xl">🖋️</span>
                </div>
                <h3 className="serif text-4xl text-stone-800 mb-4 font-bold">Pronto para começar?</h3>
                <p className="text-stone-500 max-w-sm text-lg leading-relaxed">
                  Ajuste as quantidades desejadas ao lado e clique em gerar. O ChefAI criará uma combinação equilibrada e deliciosa.
                </p>
                <div className="mt-8 flex gap-4 text-[10px] font-bold uppercase tracking-widest text-stone-400">
                  <div className="flex items-center gap-1">✅ 100% Personalizado</div>
                  <div className="flex items-center gap-1">✅ Formato WhatsApp</div>
                  <div className="flex items-center gap-1">✅ Pronto p/ Impressão</div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* CONTEÚDO DA ABA: ACERVO */}
        {activeTab === 'inventory' && (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-5 duration-500">
            <div className="bg-white rounded-[40px] p-10 shadow-sm border border-stone-100">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 mb-12">
                <div>
                  <h2 className="serif text-5xl text-stone-800 font-bold">Gerenciar Acervo</h2>
                  <p className="text-stone-400 mt-2 text-lg">Personalize os itens que sua IA pode utilizar.</p>
                </div>
                <div className="flex gap-4">
                  <button onClick={restoreDefaults} className="px-6 py-3 rounded-xl border border-stone-200 text-stone-500 font-bold text-xs uppercase hover:bg-stone-50 transition">Restaurar Padrão</button>
                  <label className="cursor-pointer px-6 py-3 rounded-xl bg-stone-900 text-white font-bold text-xs uppercase hover:bg-black transition flex items-center gap-2">
                    <span>📂 Importar Planilha</span>
                    <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
                  </label>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
                <div className="lg:col-span-1 space-y-6">
                  <div>
                    <label className="block text-[10px] font-bold uppercase text-stone-400 mb-3 tracking-widest">Pesquisar</label>
                    <input 
                      type="text" 
                      placeholder="Ex: Picanha, Arroz..." 
                      value={searchTerm} 
                      onChange={(e) => setSearchTerm(e.target.value)} 
                      className="w-full px-5 py-3 bg-stone-50 border border-stone-200 rounded-xl focus:border-[#e67e22] outline-none transition-colors"
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold uppercase text-stone-400 mb-3 tracking-widest">Categoria</label>
                    <div className="space-y-2">
                      {['Todos', ...Object.values(Category)].map(cat => (
                        <button 
                          key={cat} 
                          onClick={() => setFilterCategory(cat as any)}
                          className={`w-full text-left px-4 py-2 rounded-lg text-sm font-medium transition-colors ${filterCategory === cat ? 'bg-orange-50 text-[#e67e22]' : 'hover:bg-stone-50 text-stone-500'}`}
                        >
                          {cat}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>

                <div className="lg:col-span-3 grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[600px] overflow-y-auto pr-4 scrollbar-thin">
                  {filteredDishes.length > 0 ? filteredDishes.map(dish => (
                    <div key={dish.id} className="p-5 rounded-2xl border border-stone-100 bg-stone-50/30 flex justify-between items-center group hover:border-[#e67e22]/40 transition-all hover:shadow-md">
                      <div className="flex-1 overflow-hidden">
                        <span className="text-[9px] uppercase font-bold text-[#e67e22] bg-orange-50 px-2 py-0.5 rounded-full mb-2 inline-block">
                          {(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === dish.category) || 'BASE']} {dish.category}
                        </span>
                        <div className="font-bold text-stone-800 text-lg truncate">{dish.name}</div>
                        {dish.description && <div className="text-xs text-stone-400 mt-1 truncate italic">{dish.description}</div>}
                      </div>
                      <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingDish(dish)} className="p-2 bg-white rounded-lg shadow-sm text-stone-400 hover:text-blue-500 transition" title="Editar">✎</button>
                        <button onClick={() => removeItem(dish.id)} className="p-2 bg-white rounded-lg shadow-sm text-stone-400 hover:text-red-500 transition" title="Remover">✕</button>
                      </div>
                    </div>
                  )) : (
                    <div className="col-span-2 py-20 text-center text-stone-400 italic">Nenhum prato encontrado com esses filtros.</div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* CONTEÚDO DA ABA: RESULTADO */}
        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in fade-in zoom-in-95 duration-700">
            <div className="mb-8 flex gap-4 no-print">
               <div className="flex bg-stone-100 p-1 rounded-full">
                  <button 
                    onClick={() => setExportFormat('standard')}
                    className={`px-6 py-2 rounded-full text-xs font-bold uppercase transition-all ${exportFormat === 'standard' ? 'bg-white text-stone-900 shadow-md' : 'text-stone-500'}`}
                  >
                    Post / A4
                  </button>
                  <button 
                    onClick={() => setExportFormat('story')}
                    className={`px-6 py-2 rounded-full text-xs font-bold uppercase transition-all ${exportFormat === 'story' ? 'bg-white text-stone-900 shadow-md' : 'text-stone-500'}`}
                  >
                    Stories (9:16)
                  </button>
               </div>
            </div>

            <div 
              ref={menuRef} 
              className={`bg-white shadow-[0_50px_100px_-20px_rgba(0,0,0,0.15)] relative overflow-hidden transition-all duration-500 ${
                exportFormat === 'story' 
                  ? 'w-[450px] aspect-[9/16]' 
                  : 'w-full max-w-[620px] min-h-[860px] border border-stone-100'
              }`}
            >
              <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#000 0.5px, transparent 0.5px)', backgroundSize: '24px 24px' }}></div>

              {exportFormat === 'story' ? (
                <div className="absolute inset-0 bg-gradient-to-b from-orange-50/20 via-white to-orange-50/20 pointer-events-none"></div>
              ) : (
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#e67e22] to-transparent"></div>
              )}

              <div className={`relative z-10 flex flex-col h-full ${exportFormat === 'story' ? 'p-12' : 'p-16 m-6 border border-stone-100'}`}>

                <header className={`text-center relative ${exportFormat === 'story' ? 'mb-16 mt-10' : 'mb-12'}`}>
                  <div className="inline-block px-5 py-1.5 mb-5 rounded-full bg-[#e67e22] text-white text-[10px] font-bold uppercase tracking-[0.3em] shadow-lg">
                    Culinária Artesanal
                  </div>

                  <h1 className={`${exportFormat === 'story' ? 'text-7xl' : 'text-6xl'} serif text-stone-900 uppercase tracking-tighter leading-none mb-6 font-bold`}>
                    {config.theme}
                  </h1>

                  <div className="flex items-center justify-center gap-4">
                    <div className="h-[1px] flex-1 bg-stone-200"></div>
                    <span className="text-stone-400 text-xs italic serif">O melhor sabor da região</span>
                    <div className="h-[1px] flex-1 bg-stone-200"></div>
                  </div>
                </header>

                <div className={`flex-1 ${exportFormat === 'story' ? 'space-y-16' : 'space-y-12'}`}>
                  {Object.entries(generatedMenu.selections).map(([cat, items]) => {
                    const typedItems = items as any[];
                    if (typedItems.length === 0) return null;
                    return (
                      <div key={cat} className="space-y-6">
                        <div className="flex items-center gap-4">
                          <h3 className="text-[12px] font-bold text-[#e67e22] uppercase tracking-[0.4em] whitespace-nowrap bg-white px-3 relative z-10">{cat}s</h3>
                          <div className="h-[1px] w-full bg-stone-100 absolute left-0"></div>
                        </div>
                        <div className={`grid ${exportFormat === 'story' ? 'gap-10' : 'gap-7'}`}>
                          {typedItems.map((item, idx) => (
                            <div key={idx} className="flex flex-col">
                              <h4 className={`${exportFormat === 'story' ? 'text-3xl' : 'text-2xl'} font-bold text-stone-800 leading-tight flex items-baseline gap-2`}>
                                {item.name}
                              </h4>
                              {item.description && (
                                <p className={`${exportFormat === 'story' ? 'text-xl' : 'text-[15px]'} text-stone-500 mt-1 leading-relaxed font-normal opacity-90 max-w-[95%]`}>
                                  {item.description}
                                </p>
                              )}
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                <footer className={`${exportFormat === 'story' ? 'mt-24 pb-16' : 'mt-20 pt-12 border-t border-stone-100'} relative`}>
                  <div className="absolute -top-12 right-6 w-24 h-24 rounded-full bg-white shadow-2xl border border-orange-50 flex items-center justify-center p-3 rotate-12">
                     <div className="w-full h-full rounded-full border border-dashed border-orange-200 flex flex-col items-center justify-center text-center">
                        <span className="text-[8px] font-bold uppercase text-orange-400 mb-0.5 tracking-tighter">Preparado</span>
                        <span className="text-[12px] font-bold text-orange-600 leading-none">NA HORA</span>
                     </div>
                  </div>

                  <div className={`px-8 py-10 rounded-[30px] bg-stone-50/50 border border-stone-100 relative ${exportFormat === 'story' ? 'mb-12' : ''}`}>
                    <span className="absolute top-2 left-4 text-5xl text-orange-200 font-serif opacity-40">“</span>
                    <p className={`serif italic text-stone-600 leading-snug text-center relative z-10 px-6 ${exportFormat === 'story' ? 'text-4xl' : 'text-3xl'}`}>
                      {generatedMenu.chefNote}
                    </p>
                  </div>

                  <div className="flex flex-col items-center mt-12 space-y-3">
                     <div className={`text-stone-900 serif font-bold italic ${exportFormat === 'story' ? 'text-5xl' : 'text-4xl'}`}>Bom Apetite!</div>
                     <div className="text-stone-300 text-[10px] uppercase font-bold tracking-[0.4em]">ChefAI • Digital Menu</div>
                  </div>
                </footer>
              </div>
            </div>

            <div className="no-print mt-16 flex flex-wrap justify-center gap-6 w-full max-w-4xl">
              <button 
                onClick={() => saveAsImage(exportFormat)} 
                className="flex-1 min-w-[200px] px-8 py-5 bg-[#e67e22] text-white rounded-2xl font-bold text-sm uppercase tracking-widest shadow-2xl hover:bg-[#d35400] transition-all active:scale-95 flex items-center justify-center gap-3"
              >
                <span>📥</span> Baixar Imagem (HD)
              </button>
              <button 
                onClick={copyMenuToClipboard} 
                className="flex-1 min-w-[200px] px-8 py-5 bg-white text-stone-700 border border-stone-200 rounded-2xl font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-stone-50 transition-all flex items-center justify-center gap-3"
              >
                <span>📋</span> Texto p/ WhatsApp
              </button>
              <button 
                onClick={() => setActiveTab('compose')} 
                className="flex-1 min-w-[200px] px-8 py-5 bg-stone-900 text-white rounded-2xl font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-black transition-all flex items-center justify-center gap-3"
              >
                <span>⚙️</span> Alterar Configuração
              </button>
            </div>
          </div>
        )}

        {/* MENSAGEM DE ERRO/PLACEHOLDER SE NÃO HOUVER RESULTADO E TENTAR ACESSAR ABA */}
        {activeTab === 'result' && !generatedMenu && (
          <div className="h-[500px] flex flex-col items-center justify-center text-center text-stone-400 italic">
             <span className="text-6xl mb-6">🥘</span>
             <p className="text-xl serif">Nenhum cardápio foi gerado ainda.</p>
             <button onClick={() => setActiveTab('compose')} className="mt-4 text-[#e67e22] font-bold underline">Clique aqui para começar</button>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const parsedDishes: Dish[] = data.map((item, idx) => ({
          id: `custom-${Date.now()}-${idx}`,
          name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
          category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
          description: item.Descricao || item.description || item.Ingredientes || ''
        }));

        setDishPool(prev => [...prev, ...parsedDishes]);
        setToast({ message: `${parsedDishes.length} itens adicionados!`, type: 'success' });
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio.', type: 'error' });
      setActiveTab('inventory');
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
      setExportFormat('standard');
      setActiveTab('result');
      setToast({ message: 'Cardápio gerado com sucesso!', type: 'success' });
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    if (window.confirm('Deseja remover este prato?')) {
      setDishPool(prev => prev.filter(d => d.id !== id));
      setToast({ message: 'Item removido.', type: 'success' });
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => prev.map(d => d.id === editingDish.id ? editingDish : d));
    setEditingDish(null);
    setToast({ message: 'Prato atualizado!', type: 'success' });
  };

  const restoreDefaults = () => {
    if(window.confirm('Restaurar opções padrão?')) {
        setDishPool(DEFAULT_DISHES);
        setToast({ message: 'Restaurado com sucesso!', type: 'success' });
    }
  };

  const copyMenuToClipboard = () => {
    if (!generatedMenu) return;
    let text = `*${config.theme.toUpperCase()}*\n\n`;
    Object.entries(generatedMenu.selections).forEach(([cat, items]) => {
      const typedItems = items as any[];
      if (typedItems.length > 0) {
        text += `*${cat}s:*\n`;
        typedItems.forEach(item => {
          text += `• ${item.name}${item.description ? ` (${item.description})` : ''}\n`;
        });
        text += `\n`;
      }
    });
    text += `_"${generatedMenu.chefNote}"_\n\nBom Apetite!`;
    navigator.clipboard.writeText(text);
    setToast({ message: 'Texto copiado para o WhatsApp!', type: 'success' });
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);

    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { 
          quality: 1, 
          pixelRatio: 3, 
          backgroundColor: '#ffffff'
        });
        const link = document.createElement('a');
        link.download = `Cardapio-${format === 'story' ? 'Story' : 'Post'}-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
        setToast({ message: `Download concluído!`, type: 'success' });
      } catch (err) {
        setToast({ message: 'Erro ao gerar imagem.', type: 'error' });
      }
    }, 150);
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] selection:bg-orange-100 pb-20 relative text-[#333]">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {/* Modal de Edição */}
      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 transform animate-in zoom-in-95 duration-200">
            <h3 className="serif text-3xl text-[#e67e22] mb-6 border-b pb-4 font-bold">Editar Item</h3>
            <form onSubmit={handleUpdateDish} className="space-y-5">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome do Prato</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none text-lg focus:border-[#e67e22] transition-colors" />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] transition-colors">
                  {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Descrição / Ingredientes</label>
                <textarea 
                  value={editingDish.description || ''} 
                  onChange={e => setEditingDish({...editingDish, description: e.target.value})} 
                  className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] transition-colors min-h-[100px]" 
                  placeholder="Ex: Arroz soltinho com alho e cebola..."
                />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setEditingDish(null)} className="flex-1 py-3 font-bold text-stone-400 hover:bg-stone-50 rounded-xl transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-3 font-bold text-white bg-[#e67e22] rounded-xl shadow-lg hover:bg-[#d35400] transition-colors">Salvar Alterações</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navbar Superior */}
      <nav className="no-print sticky top-0 z-50 bg-white border-b border-stone-200 px-6 py-5 shadow-sm">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-3xl">🍲</span>
            <div>
              <h1 className="serif text-2xl font-bold text-[#e67e22] leading-none">ChefAI</h1>
              <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-1">Sua Marmitaria Digital</p>
            </div>
          </div>

          <div className="flex bg-stone-100 p-1 rounded-xl">
            <button 
              onClick={() => setActiveTab('compose')}
              className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'compose' ? 'bg-white text-[#e67e22] shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
            >
              Criação
            </button>
            <button 
              onClick={() => setActiveTab('inventory')}
              className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'inventory' ? 'bg-white text-[#e67e22] shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
            >
              Acervo
            </button>
            <button 
              onClick={() => setActiveTab('result')}
              disabled={!generatedMenu}
              className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'result' ? 'bg-white text-[#e67e22] shadow-sm' : !generatedMenu ? 'opacity-30 cursor-not-allowed text-stone-400' : 'text-stone-500 hover:text-stone-700'}`}
