import { GoogleGenAI, Type } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig
): Promise<GeneratedMenu> {
  // Analisar a disponibilidade real do acervo para informar a IA
  const availability = Object.values(Category).reduce((acc, cat) => {
    acc[cat] = dishPool.filter(d => d.category === cat).length;
    return acc;
  }, {} as Record<string, number>);

  const structureRequested = config.chefChoice 
    ? "SUGESTÃO LIVRE E CRIATIVA: Ignore contagens fixas. Crie um cardápio completo, equilibrado e SURPREENDENTE. Varie as proteínas e acompanhamentos para não repetir o que foi sugerido anteriormente."
    : `QUANTIDADES OBRIGATÓRIAS:\n${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${count} Opções de ${cat} (Disponível no acervo: ${availability[cat]})`)
        .join('\n')}`;

  const prompt = `
    Você é um Chef Executivo de uma rede de marmitarias premium. Sua missão é montar o cardápio de hoje: "${config.theme}".

    DIRETRIZES DE SELEÇÃO:
    1. VARIABILIDADE MÁXIMA: Escolha combinações que fujam do óbvio. Se houver muitos itens no acervo, priorize aqueles que trazem cor e contraste ao prato. 
    2. CUMPRIMENTO DE METAS: Se o usuário pediu 4, 5 ou mais opções de uma categoria, você DEVE selecionar exatamente essa quantidade, desde que existam itens suficientes no acervo.
    3. ESCASSEZ DE ITENS: Caso o usuário solicite MAIS itens de uma categoria do que o acervo possui, retorne TODOS os itens disponíveis dessa categoria específica. Nunca invente nomes de pratos fora do acervo.
    4. DESCRIÇÕES APETITOSAS: Crie descrições curtas que destaquem o frescor e o tempero (ex: "ao murro", "selado na manteiga", "fresquinho da horta").

    ACERVO REAL (USE APENAS ESTES):
    ${JSON.stringify(dishPool.map(d => ({ name: d.name, cat: d.category, desc: d.description })))}

    ${structureRequested}

    NOTA DO CHEF: Justifique a harmonia nutricional e de sabor do conjunto escolhido em até 2 linhas.

    IMPORTANTE: Garanta que o JSON retornado contenha as listas completas conforme as quantidades solicitadas.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      temperature: 0.9, // Aumentado para garantir maior variabilidade entre gerações
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          selections: {
            type: Type.OBJECT,
            properties: {
              [Category.BASE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DRINK]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
            }
          },
          chefNote: { type: Type.STRING }
        },
        required: ["selections", "chefNote"]
      }
    }
  });

  try {
    const text = response.text;
    const parsed = JSON.parse(text);

    const finalSelections: any = {};
    Object.values(Category).forEach(cat => {
      finalSelections[cat] = parsed.selections[cat] || [];
    });

    return { ...parsed, selections: finalSelections };
  } catch (e) {
    console.error("Erro ao processar resposta da IA:", e);
    throw new Error("Falha na geração do cardápio estruturado.");
  }
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS } from './constants';
import { generateMenuWithAI } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
      [Category.DRINK]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const parsedDishes: Dish[] = data.map((item, idx) => ({
          id: `custom-${Date.now()}-${idx}`,
          name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
          category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
          description: item.Descricao || item.description || item.Ingredientes || ''
        }));

        setDishPool(prev => [...prev, ...parsedDishes]);
        setToast({ message: `${parsedDishes.length} itens adicionados!`, type: 'success' });
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

