export enum Category {
  BASE = 'Base',
  MEAT = 'Carne',
  PASTA = 'Massa',
  SIDE = 'Acompanhamento',
  SALAD = 'Salada',
  DESSERT = 'Sobremesa'
}

export interface VisualTheme {
  primaryColor: string;
  secondaryColor: string;
  backgroundColor: string;
  backgroundGradient: string;
  textColor: string;
  accentColor: string;
}

export interface Dish {
  id: string;
  name: string;
  category: Category;
  description?: string;
}

export interface MenuConfig {
  counts: Record<Category, number>;
  theme: string;
  baseOption: string;
  chefChoice: boolean;
  logo?: string; // Base64
}

export interface GeneratedMenu {
  selections: Record<Category, Dish[]>;
  chefNote: string;
  visualTheme?: VisualTheme;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

async function analyzeLogoTheme(logoBase64: string): Promise<VisualTheme> {
  const imagePart = {
    inlineData: {
      mimeType: "image/png",
      data: logoBase64.split(',')[1] || logoBase64,
    },
  };

  const prompt = `
    Analise esta logomarca de restaurante e extraia uma paleta de cores sofisticada para um cardápio digital.
    Retorne um JSON com:
    1. primaryColor: A cor principal da logo (Hex).
    2. secondaryColor: Uma cor secundária que harmonize (Hex).
    3. backgroundColor: Uma cor de fundo muito clara ou escura baseada na logo (Hex).
    4. backgroundGradient: Um CSS linear-gradient sutil e elegante que use as cores da logo.
    5. textColor: Uma cor de texto com alto contraste (Hex).
    6. accentColor: Uma cor de destaque vibrante da logo (Hex).
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [imagePart, { text: prompt }] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          primaryColor: { type: Type.STRING },
          secondaryColor: { type: Type.STRING },
          backgroundColor: { type: Type.STRING },
          backgroundGradient: { type: Type.STRING },
          textColor: { type: Type.STRING },
          accentColor: { type: Type.STRING },
        },
        required: ["primaryColor", "secondaryColor", "backgroundColor", "backgroundGradient", "textColor", "accentColor"]
      }
    }
  });

  return JSON.parse(response.text);
}

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig
): Promise<GeneratedMenu> {
  const availability = Object.values(Category).reduce((acc, cat) => {
    acc[cat] = dishPool.filter(d => d.category === cat).length;
    return acc;
  }, {} as Record<string, number>);

  let visualTheme: VisualTheme | undefined;
  if (config.logo) {
    try {
      visualTheme = await analyzeLogoTheme(config.logo);
    } catch (e) {
      console.error("Erro ao analisar logo:", e);
    }
  }

  const structureRequested = config.chefChoice 
    ? "SUGESTÃO LIVRE E CRIATIVA: Ignore contagens fixas. Crie um cardápio completo e equilibrado."
    : `QUANTIDADES OBRIGATÓRIAS:\n${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${count} Opções de ${cat}`)
        .join('\n')}`;

  const prompt = `
    Você é um Chef Executivo. Monte o cardápio: "${config.theme}".
    Use apenas estes itens: ${JSON.stringify(dishPool.map(d => ({ name: d.name, cat: d.category, desc: d.description })))}
    ${structureRequested}
    NOTA DO CHEF: 2 linhas de justificativa gourmet.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      temperature: 0.9,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          selections: {
            type: Type.OBJECT,
            properties: {
              [Category.BASE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.PASTA]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
            }
          },
          chefNote: { type: Type.STRING }
        },
        required: ["selections", "chefNote"]
      }
    }
  });

  const parsed = JSON.parse(response.text);
  return { ...parsed, visualTheme };
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.PASTA]: 1,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
      setToast({ message: "Logo carregada! A IA personalizará o estilo.", type: "success" });
    };
    reader.readAsDataURL(file);
  };

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description && dish.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const parsedDishes: Dish[] = data.map((item, idx) => ({
          id: `custom-${Date.now()}-${idx}`,
          name: item.Nome || item.name || item.Prato || 'Item Sem Nome',
          category: (item.Categoria || item.category || item.Tipo || Category.MEAT) as Category,
          description: item.Descricao || item.description || item.Ingredientes || ''
        }));

        setDishPool(prev => [...prev, ...parsedDishes]);
        setToast({ message: `${parsedDishes.length} itens adicionados!`, type: 'success' });
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = ''; 
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio.', type: 'error' });
      setActiveTab('inventory');
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
      setExportFormat('standard');
      setActiveTab('result');
      setToast({ message: 'Cardápio gourmet gerado!', type: 'success' });
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio. Tente novamente.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
    if (window.confirm('Deseja remover este prato?')) {
      setDishPool(prev => prev.filter(d => d.id !== id));
      setToast({ message: 'Item removido.', type: 'success' });
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => prev.map(d => d.id === editingDish.id ? editingDish : d));
    setEditingDish(null);
    setToast({ message: 'Prato atualizado!', type: 'success' });
  };

  const restoreDefaults = () => {
    if(window.confirm('Restaurar opções padrão?')) {
        setDishPool(DEFAULT_DISHES);
        setToast({ message: 'Restaurado com sucesso!', type: 'success' });
    }
  };

  const copyMenuToClipboard = () => {
    if (!generatedMenu) return;
    let text = `*${config.theme.toUpperCase()}*\n\n`;

    CATEGORY_ORDER.forEach(cat => {
      const items = generatedMenu.selections[cat];
      if (items && items.length > 0) {
        text += `*${cat}s:*\n`;
        items.forEach(item => {
          text += `• ${item.name}${item.description ? ` (${item.description})` : ''}\n`;
        });
        text += `\n`;
      }
    });

    text += `_"${generatedMenu.chefNote}"_\n\nBom Apetite!`;
    navigator.clipboard.writeText(text);
    setToast({ message: 'Texto copiado para o WhatsApp!', type: 'success' });
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);

    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { 
          quality: 1, 
          pixelRatio: 3, 
          backgroundColor: generatedMenu?.visualTheme?.backgroundColor || '#ffffff'
        });
        const link = document.createElement('a');
        link.download = `Cardapio-${format === 'story' ? 'Story' : 'Post'}-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
        setToast({ message: `Download concluído!`, type: 'success' });
      } catch (err) {
        setToast({ message: 'Erro ao gerar imagem.', type: 'error' });
      }
    }, 150);
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] selection:bg-orange-100 pb-20 relative text-[#333]">

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${
            toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'
          }`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {/* Modal de Edição */}
      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 transform animate-in zoom-in-95 duration-200">
            <h3 className="serif text-3xl text-[#e67e22] mb-6 border-b pb-4 font-bold">Editar Item</h3>
            <form onSubmit={handleUpdateDish} className="space-y-5">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome do Prato</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none text-lg focus:border-[#e67e22] transition-colors" />
              </div>
