      setGeneratedMenu(result);
      setExportFormat('standard');
      setActiveTab('result');
      setToast({ message: 'Cardápio gourmet gerado!', type: 'success' });
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio. Tente novamente.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const removeItem = (id: string) => {
