    e.preventDefault();
    if (!editingDish) return;

    setDishPool(prev => {
        const exists = prev.find(d => d.id === editingDish.id);
        if (exists) {
            return prev.map(d => d.id === editingDish.id ? editingDish : d);
        } else {
            return [...prev, editingDish];
        }
    });

    setEditingDish(null);
    setToast({ message: 'Prato salvo com sucesso!', type: 'success' });
  };

