                            <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: (p.counts[cat as Category] || 0) + 1}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold flex items-center justify-center">+</button>
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="pt-4 border-t border-stone-100">
                      <label className="block text-[10px] uppercase text-stone-400 font-bold mb-2 tracking-widest">Tema do Cardápio</label>
                      <input type="text" value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22]" placeholder="Ex: Menu de Verão" />
                    </div>
                  </div>
                  <button onClick={handleGenerate} disabled={isGenerating} className="w-full mt-10 py-4 bg-[#e67e22] text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-3 hover:bg-[#d35400] transition-all disabled:bg-stone-300">
                    {isGenerating ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Criar Cardápio Profissional'}
                  </button>
               </section>
            </div>

            <div className="lg:col-span-8 flex flex-col items-center justify-center text-center p-12 border-4 border-dashed border-stone-100 rounded-[60px] bg-white/50 min-h-[500px]">
              <div className="w-24 h-24 bg-orange-50 rounded-full flex items-center justify-center mb-8 shadow-inner animate-pulse">
                <span className="text-5xl">🎨</span>
              </div>
              <h3 className="serif text-4xl text-stone-800 mb-4 font-bold">Design Automático</h3>
              <p className="text-stone-500 max-w-sm text-lg leading-relaxed">
                Ao subir sua logomarca, nossa IA cria um plano de fundo exclusivo com as cores e o estilo da sua marca.
              </p>
              <div className="mt-12 grid grid-cols-2 gap-4">
                {['mesh', 'dots', 'grid', 'stripes'].map(p => (
                  <div key={p} className="px-4 py-2 bg-white rounded-xl border border-stone-100 text-[10px] uppercase font-bold text-stone-400 tracking-widest shadow-sm">Estilo {p}</div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="animate-in fade-in slide-in-from-bottom-5 duration-500">
            <div className="bg-white rounded-[40px] p-10 shadow-sm border border-stone-100">
              <div className="flex flex-col md:flex-row justify-between items-center gap-6 mb-12">
                <h2 className="serif text-5xl text-stone-800 font-bold">Meu Acervo</h2>
                <div className="flex gap-4">
                  <button onClick={() => setEditingDish({ id: `manual-${Date.now()}`, name: '', category: Category.MEAT, description: '' })} className="px-6 py-3 rounded-xl bg-[#e67e22] text-white font-bold text-xs uppercase shadow-lg shadow-orange-100 hover:scale-105 transition-transform">+ Novo Prato</button>
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredDishes.map((dish, i) => (
                  <div key={dish.id} className="p-6 rounded-[28px] border border-stone-100 hover:border-orange-200 transition-all hover:shadow-xl hover:-translate-y-1 group animate-in fade-in zoom-in-95" style={{ animationDelay: `${i * 30}ms` }}>
                    <div className="flex justify-between items-start mb-4">
                      <span className="text-[10px] uppercase font-bold text-orange-500 bg-orange-50 px-3 py-1 rounded-full">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === dish.category) || 'BASE']} {dish.category}</span>
                      <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                        <button onClick={() => setEditingDish(dish)} className="text-blue-500 hover:scale-110">✎</button>
                        <button onClick={() => setDishPool(p => p.filter(d => d.id !== dish.id))} className="text-red-500 hover:scale-110">✕</button>
                      </div>
                    </div>
                    <h4 className="font-bold text-xl text-stone-800 mb-2">{dish.name}</h4>
                    <p className="text-xs text-stone-400 line-clamp-2 italic">{dish.description || 'Sem descrição cadastrada.'}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in fade-in zoom-in-95 duration-700">
            <div className="mb-12 flex bg-stone-100 p-1.5 rounded-full shadow-inner">
               <button onClick={() => setExportFormat('standard')} className={`px-8 py-3 rounded-full text-xs font-bold uppercase transition-all ${exportFormat === 'standard' ? 'bg-white text-[#e67e22] shadow-md' : 'text-stone-500'}`}>Vertical / A4</button>
               <button onClick={() => setExportFormat('story')} className={`px-8 py-3 rounded-full text-xs font-bold uppercase transition-all ${exportFormat === 'story' ? 'bg-white text-[#e67e22] shadow-md' : 'text-stone-500'}`}>Stories (9:16)</button>
            </div>

            <div ref={menuRef} className={`bg-white shadow-[0_60px_100px_-30px_rgba(0,0,0,0.2)] relative overflow-hidden transition-all duration-500 ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16]' : 'w-full max-w-[620px] min-h-[860px] border border-stone-100'}`} style={{ backgroundColor: generatedMenu.visualTheme?.backgroundColor }}>
              {/* Pattern Dinâmico da IA */}
              {renderBackgroundPattern(generatedMenu.visualTheme)}
              <div className="absolute inset-0 pointer-events-none" style={{ background: generatedMenu.visualTheme?.backgroundGradient, opacity: 0.15 }}></div>

              <div className={`relative z-10 flex flex-col h-full border-[20px] border-transparent ${exportFormat === 'story' ? 'p-10' : 'p-16'}`}>
                <div className="absolute inset-0 border border-white/30 m-2 pointer-events-none" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}></div>

                <header className="text-center mb-16 relative">
                  {logoPreview && <img src={logoPreview} alt="Logo" className="mx-auto h-24 w-24 object-contain mb-10 drop-shadow-lg animate-in fade-in zoom-in-50 duration-1000" />}
                  <div className="inline-block px-6 py-2 mb-6 rounded-full text-white text-[10px] font-bold uppercase tracking-[0.4em] shadow-xl" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor || '#e67e22' }}>Cardápio do Dia</div>
                  <h1 className={`${exportFormat === 'story' ? 'text-7xl' : 'text-6xl'} serif uppercase tracking-tighter leading-none mb-8 font-bold`} style={{ color: generatedMenu.visualTheme?.textColor }}>{config.theme}</h1>
                  <div className="flex items-center justify-center gap-6">
                    <div className="h-[1px] flex-1 opacity-20" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                    <span className="text-stone-400 text-xs italic font-medium uppercase tracking-widest opacity-60">Sabores de Verdade</span>
                    <div className="h-[1px] flex-1 opacity-20" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                  </div>
                </header>

                <div className="flex-1 space-y-16">
                  {CATEGORY_ORDER.map(cat => {
                    const items = generatedMenu.selections[cat];
                    if (!items || items.length === 0) return null;
                    return (
                      <div key={cat} className="space-y-8 animate-in slide-in-from-left-5">
                        <div className="flex items-center gap-4">
                          <h3 className="text-[11px] font-bold uppercase tracking-[0.5em] whitespace-nowrap" style={{ color: generatedMenu.visualTheme?.primaryColor }}>{cat}s</h3>
                          <div className="h-[1px] w-full opacity-10" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                        </div>
                        <div className="grid gap-8">
                          {items.map((item, idx) => (
                            <div key={idx} className="flex flex-col group">
                              <h4 className="text-2xl font-bold leading-tight flex items-baseline gap-3" style={{ color: generatedMenu.visualTheme?.textColor }}>
                                <span className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{ backgroundColor: generatedMenu.visualTheme?.accentColor }}></span>
                                {item.name}
                              </h4>
                              {item.description && <p className="text-base mt-2 leading-relaxed opacity-60 ml-4 border-l-2 pl-4 italic" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '40', color: generatedMenu.visualTheme?.textColor }}>{item.description}</p>}
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                <footer className="mt-20 pt-16 border-t relative" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}>
                  <div className="absolute -top-14 right-4 w-28 h-28 rounded-full bg-white shadow-2xl flex items-center justify-center p-3 rotate-12 scale-110 border" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '10' }}>
                     <div className="w-full h-full rounded-full border border-dashed flex flex-col items-center justify-center text-center p-1" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '40' }}>
                        <span className="text-[9px] font-bold uppercase tracking-tight" style={{ color: generatedMenu.visualTheme?.secondaryColor }}>Culinária</span>
                        <span className="text-[14px] font-black leading-none" style={{ color: generatedMenu.visualTheme?.primaryColor }}>PREMIUM</span>
                     </div>
                  </div>
                  <div className="px-10 py-12 rounded-[40px] border relative overflow-hidden" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor + '05', borderColor: generatedMenu.visualTheme?.primaryColor + '10' }}>
                    <span className="absolute -top-4 -left-2 text-9xl font-serif opacity-10 leading-none" style={{ color: generatedMenu.visualTheme?.primaryColor }}>“</span>
                    <p className="serif italic leading-relaxed text-center relative z-10 px-6" style={{ color: generatedMenu.visualTheme?.textColor, fontSize: exportFormat === 'story' ? '1.75rem' : '1.35rem' }}>{generatedMenu.chefNote}</p>
                  </div>
                  <div className="flex flex-col items-center mt-16 space-y-4">
                     <div className="serif font-bold italic text-5xl tracking-tight" style={{ color: generatedMenu.visualTheme?.textColor }}>Bon Appétit</div>
                     <div className="text-[10px] uppercase font-bold tracking-[0.5em] opacity-40" style={{ color: generatedMenu.visualTheme?.textColor }}>ChefAI • Identidade Inteligente</div>
                  </div>
                </footer>
              </div>
            </div>

            <div className="mt-16 flex flex-wrap justify-center gap-6 w-full max-w-4xl no-print">
              <button onClick={() => saveAsImage(exportFormat)} className="flex-1 min-w-[200px] px-10 py-5 text-white rounded-[20px] font-bold text-sm uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor || '#e67e22' }}>📥 Download HD</button>
              <button onClick={copyMenuToClipboard} className="flex-1 min-w-[200px] px-10 py-5 bg-white text-stone-700 border border-stone-200 rounded-[20px] font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-stone-50 transition-all">📋 Copiar WhatsApp</button>
              <button onClick={() => setActiveTab('compose')} className="flex-1 min-w-[200px] px-10 py-5 bg-stone-900 text-white rounded-[20px] font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-black transition-all">⚙️ Alterar Menu</button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.PASTA]: 1,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  // Fix: Added useMemo to calculate filteredDishes based on searchTerm and filterCategory
  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description || '').toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
      setToast({ message: "Logo identificada! O design será adaptado.", type: "success" });
    };
    reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio.', type: 'error' });
      setActiveTab('inventory');
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
      setExportFormat('standard');
      setActiveTab('result');
      setToast({ message: 'Cardápio e design gerados!', type: 'success' });
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => {
        const exists = prev.find(d => d.id === editingDish.id);
        if (exists) return prev.map(d => d.id === editingDish.id ? editingDish : d);
        return [...prev, editingDish];
    });
    setEditingDish(null);
    setToast({ message: 'Prato salvo!', type: 'success' });
  };

  const copyMenuToClipboard = () => {
    if (!generatedMenu) return;
    let text = `*${config.theme.toUpperCase()}*\n\n`;
    CATEGORY_ORDER.forEach(cat => {
      const items = generatedMenu.selections[cat];
      if (items && items.length > 0) {
        text += `*${cat}s:*\n`;
        items.forEach(item => { text += `• ${item.name}${item.description ? ` (${item.description})` : ''}\n`; });
        text += `\n`;
      }
    });
    text += `_"${generatedMenu.chefNote}"_\n\nBom Apetite!`;
    navigator.clipboard.writeText(text);
    setToast({ message: 'Texto copiado!', type: 'success' });
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);
    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { quality: 1, pixelRatio: 3 });
        const link = document.createElement('a');
        link.download = `Cardapio-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) {
        setToast({ message: 'Erro na imagem.', type: 'error' });
      }
    }, 200);
  };

  const renderBackgroundPattern = (theme?: VisualTheme) => {
    if (!theme) return null;
    const color = theme.primaryColor + '10'; // 10% opacity

    switch (theme.patternType) {
      case 'dots':
        return <div className="absolute inset-0 opacity-40 pointer-events-none" style={{ backgroundImage: `radial-gradient(${color} 2px, transparent 2px)`, backgroundSize: '24px 24px' }} />;
      case 'grid':
        return <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: `linear-gradient(${color} 1px, transparent 1px), linear-gradient(90deg, ${color} 1px, transparent 1px)`, backgroundSize: '40px 40px' }} />;
      case 'stripes':
        return <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: `linear-gradient(45deg, ${color} 25%, transparent 25%, transparent 50%, ${color} 50%, ${color} 75%, transparent 75%, transparent)`, backgroundSize: '60px 60px' }} />;
      case 'mesh':
        return <div className="absolute inset-0 opacity-30 pointer-events-none blur-[100px]" style={{ background: `radial-gradient(circle at 20% 20%, ${theme.primaryColor}33, transparent), radial-gradient(circle at 80% 80%, ${theme.secondaryColor}33, transparent)` }} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] selection:bg-orange-100 pb-20 text-[#333]">
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'}`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-[32px] shadow-2xl w-full max-w-lg p-8 animate-in zoom-in-95 duration-200">
            <h3 className="serif text-3xl text-[#e67e22] font-bold mb-6 border-b pb-4">Detalhes do Prato</h3>
            <form onSubmit={handleUpdateDish} className="space-y-6">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-3 rounded-2xl border border-stone-200 outline-none text-lg focus:border-[#e67e22] transition-all" />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full px-5 py-3 rounded-2xl border border-stone-200 outline-none focus:border-[#e67e22] transition-all">
                  {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Descrição</label>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-stone-200 outline-none focus:border-[#e67e22] min-h-[120px] resize-none" />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setEditingDish(null)} className="flex-1 py-4 font-bold text-stone-400 hover:bg-stone-50 rounded-2xl border border-stone-100 transition-colors">Cancelar</button>
                <button type="submit" className="flex-2 px-8 py-4 font-bold text-white bg-[#e67e22] rounded-2xl shadow-lg hover:bg-[#d35400] transition-all">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <nav className="sticky top-0 z-50 bg-white/90 backdrop-blur-md border-b border-stone-200 px-6 py-5 shadow-sm">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-3xl">🍲</span>
            <div>
              <h1 className="serif text-2xl font-bold text-[#e67e22] leading-none">ChefAI</h1>
              <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-1">Sua Marmitaria Digital</p>
            </div>
          </div>
          <div className="flex bg-stone-100 p-1 rounded-xl">
            {['compose', 'inventory', 'result'].map((tab) => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab as TabType)}
                disabled={tab === 'result' && !generatedMenu}
                className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${activeTab === tab ? 'bg-white text-[#e67e22] shadow-sm' : 'text-stone-500 hover:text-stone-700 disabled:opacity-30'}`}
              >
                {tab === 'compose' ? 'Criação' : tab === 'inventory' ? 'Acervo' : 'Resultado'}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 mt-12">
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 animate-in fade-in duration-500">
            <div className="lg:col-span-4 space-y-6">
               <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
                  <h2 className="serif text-3xl mb-6 text-stone-800">Design & Estrutura</h2>
                  <div className="space-y-6">
                    <div className="p-5 rounded-2xl border-2 border-dashed border-stone-200 bg-stone-50 hover:border-[#e67e22] transition-all relative group overflow-hidden">
                      {logoPreview ? (
                        <div className="flex items-center gap-4 animate-in zoom-in-95">
                          <img src={logoPreview} alt="Logo" className="w-20 h-20 object-contain rounded-lg bg-white p-1 border shadow-sm" />
                          <div className="flex-1">
                            <p className="font-bold text-sm text-stone-700">Logo Carregada</p>
                            <button onClick={() => {setLogoPreview(null); setConfig(p => ({...p, logo: undefined}))}} className="text-[10px] text-red-500 uppercase font-bold mt-1 hover:underline">Remover</button>
                          </div>
                        </div>
                      ) : (
                        <label className="cursor-pointer flex flex-col items-center justify-center py-6">
                          <span className="text-4xl mb-3">🖼️</span>
                          <span className="text-[10px] uppercase font-bold text-stone-400 tracking-widest text-center">Subir Logomarca<br/><span className="text-[#e67e22]">A IA fará o design</span></span>
                          <input type="file" className="hidden" accept="image/*" onChange={handleLogoUpload} />
                        </label>
                      )}
                    </div>

                    <div className={`p-5 rounded-2xl border-2 cursor-pointer transition-all ${config.chefChoice ? 'bg-orange-50 border-[#e67e22]' : 'bg-stone-50 border-stone-100'}`} onClick={() => setConfig({...config, chefChoice: !config.chefChoice})}>
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-full flex items-center justify-center text-2xl ${config.chefChoice ? 'bg-[#e67e22] text-white shadow-lg rotate-12' : 'bg-white text-stone-400'}`}>✨</div>
                        <div>
                          <h4 className="font-bold text-sm">Sugestão Criativa</h4>
                          <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-0.5">A IA decide as quantidades</p>
                        </div>
                      </div>
                    </div>

                    <div className={`space-y-4 transition-all duration-300 ${config.chefChoice ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                      {CATEGORY_ORDER.map(cat => (
                        <div key={cat} className="flex items-center justify-between">
                          <span className="font-semibold text-stone-600 text-sm flex items-center gap-2">
                            <span className="opacity-70">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</span>
                            {cat}s
                          </span>
                          <div className="flex items-center gap-3 bg-stone-100 p-1 rounded-full">
                            <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold flex items-center justify-center">-</button>
                            <span className="w-4 text-center font-bold text-xs">{config.counts[cat] || 0}</span>
                            <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: (p.counts[cat as Category] || 0) + 1}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold flex items-center justify-center">+</button>
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="pt-4 border-t border-stone-100">
                      <label className="block text-[10px] uppercase text-stone-400 font-bold mb-2 tracking-widest">Tema do Cardápio</label>
                      <input type="text" value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22]" placeholder="Ex: Menu de Verão" />
                    </div>
                  </div>
                  <button onClick={handleGenerate} disabled={isGenerating} className="w-full mt-10 py-4 bg-[#e67e22] text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-3 hover:bg-[#d35400] transition-all disabled:bg-stone-300">
                    {isGenerating ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Criar Cardápio Profissional'}
                  </button>
               </section>
            </div>

            <div className="lg:col-span-8 flex flex-col items-center justify-center text-center p-12 border-4 border-dashed border-stone-100 rounded-[60px] bg-white/50 min-h-[500px]">
              <div className="w-24 h-24 bg-orange-50 rounded-full flex items-center justify-center mb-8 shadow-inner animate-pulse">
                <span className="text-5xl">🎨</span>
              </div>
              <h3 className="serif text-4xl text-stone-800 mb-4 font-bold">Design Automático</h3>
              <p className="text-stone-500 max-w-sm text-lg leading-relaxed">
                Ao subir sua logomarca, nossa IA cria um plano de fundo exclusivo com as cores e o estilo da sua marca.
              </p>
              <div className="mt-12 grid grid-cols-2 gap-4">
                {['mesh', 'dots', 'grid', 'stripes'].map(p => (
                  <div key={p} className="px-4 py-2 bg-white rounded-xl border border-stone-100 text-[10px] uppercase font-bold text-stone-400 tracking-widest shadow-sm">Estilo {p}</div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="animate-in fade-in slide-in-from-bottom-5 duration-500">
            <div className="bg-white rounded-[40px] p-10 shadow-sm border border-stone-100">
              <div className="flex flex-col md:flex-row justify-between items-center gap-6 mb-12">
                <h2 className="serif text-5xl text-stone-800 font-bold">Meu Acervo</h2>
                {/* Fix: Added search and filter inputs to the Inventory tab */}
                <div className="flex flex-1 max-w-md gap-4">
                  <input 
                    type="text" 
                    placeholder="Buscar prato..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="flex-1 px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22]"
                  />
                  <select 
                    value={filterCategory}
                    onChange={(e) => setFilterCategory(e.target.value as Category | 'Todos')}
                    className="px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] bg-white"
                  >
                    <option value="Todos">Todas Categorias</option>
                    {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                  </select>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => setEditingDish({ id: `manual-${Date.now()}`, name: '', category: Category.MEAT, description: '' })} className="px-6 py-3 rounded-xl bg-[#e67e22] text-white font-bold text-xs uppercase shadow-lg shadow-orange-100 hover:scale-105 transition-transform">+ Novo Prato</button>
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredDishes.map((dish, i) => (
                  <div key={dish.id} className="p-6 rounded-[28px] border border-stone-100 hover:border-orange-200 transition-all hover:shadow-xl hover:-translate-y-1 group animate-in fade-in zoom-in-95" style={{ animationDelay: `${i * 30}ms` }}>
                    <div className="flex justify-between items-start mb-4">
                      <span className="text-[10px] uppercase font-bold text-orange-500 bg-orange-50 px-3 py-1 rounded-full">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === dish.category) || 'BASE']} {dish.category}</span>
                      <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                        <button onClick={() => setEditingDish(dish)} className="text-blue-500 hover:scale-110">✎</button>
                        <button onClick={() => setDishPool(p => p.filter(d => d.id !== dish.id))} className="text-red-500 hover:scale-110">✕</button>
                      </div>
                    </div>
                    <h4 className="font-bold text-xl text-stone-800 mb-2">{dish.name}</h4>
                    <p className="text-xs text-stone-400 line-clamp-2 italic">{dish.description || 'Sem descrição cadastrada.'}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in fade-in zoom-in-95 duration-700">
            <div className="mb-12 flex bg-stone-100 p-1.5 rounded-full shadow-inner">
               <button onClick={() => setExportFormat('standard')} className={`px-8 py-3 rounded-full text-xs font-bold uppercase transition-all ${exportFormat === 'standard' ? 'bg-white text-[#e67e22] shadow-md' : 'text-stone-500'}`}>Vertical / A4</button>
               <button onClick={() => setExportFormat('story')} className={`px-8 py-3 rounded-full text-xs font-bold uppercase transition-all ${exportFormat === 'story' ? 'bg-white text-[#e67e22] shadow-md' : 'text-stone-500'}`}>Stories (9:16)</button>
            </div>

            <div ref={menuRef} className={`bg-white shadow-[0_60px_100px_-30px_rgba(0,0,0,0.2)] relative overflow-hidden transition-all duration-500 ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16]' : 'w-full max-w-[620px] min-h-[860px] border border-stone-100'}`} style={{ backgroundColor: generatedMenu.visualTheme?.backgroundColor }}>
              {/* Pattern Dinâmico da IA */}
              {renderBackgroundPattern(generatedMenu.visualTheme)}
              <div className="absolute inset-0 pointer-events-none" style={{ background: generatedMenu.visualTheme?.backgroundGradient, opacity: 0.15 }}></div>

              <div className={`relative z-10 flex flex-col h-full border-[20px] border-transparent ${exportFormat === 'story' ? 'p-10' : 'p-16'}`}>
                <div className="absolute inset-0 border border-white/30 m-2 pointer-events-none" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}></div>

                <header className="text-center mb-16 relative">
                  {logoPreview && <img src={logoPreview} alt="Logo" className="mx-auto h-24 w-24 object-contain mb-10 drop-shadow-lg animate-in fade-in zoom-in-50 duration-1000" />}
                  <div className="inline-block px-6 py-2 mb-6 rounded-full text-white text-[10px] font-bold uppercase tracking-[0.4em] shadow-xl" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor || '#e67e22' }}>Cardápio do Dia</div>
                  <h1 className={`${exportFormat === 'story' ? 'text-7xl' : 'text-6xl'} serif uppercase tracking-tighter leading-none mb-8 font-bold`} style={{ color: generatedMenu.visualTheme?.textColor }}>{config.theme}</h1>
                  <div className="flex items-center justify-center gap-6">
                    <div className="h-[1px] flex-1 opacity-20" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                    <span className="text-stone-400 text-xs italic font-medium uppercase tracking-widest opacity-60">Sabores de Verdade</span>
                    <div className="h-[1px] flex-1 opacity-20" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                  </div>
                </header>

                <div className="flex-1 space-y-16">
                  {CATEGORY_ORDER.map(cat => {
                    const items = generatedMenu.selections[cat];
                    if (!items || items.length === 0) return null;
                    return (
                      <div key={cat} className="space-y-8 animate-in slide-in-from-left-5">
                        <div className="flex items-center gap-4">
                          <h3 className="text-[11px] font-bold uppercase tracking-[0.5em] whitespace-nowrap" style={{ color: generatedMenu.visualTheme?.primaryColor }}>{cat}s</h3>
                          <div className="h-[1px] w-full opacity-10" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                        </div>
                        <div className="grid gap-8">
                          {items.map((item, idx) => (
                            <div key={idx} className="flex flex-col group">
                              <h4 className="text-2xl font-bold leading-tight flex items-baseline gap-3" style={{ color: generatedMenu.visualTheme?.textColor }}>
                                <span className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{ backgroundColor: generatedMenu.visualTheme?.accentColor }}></span>
                                {item.name}
                              </h4>
                              {item.description && <p className="text-base mt-2 leading-relaxed opacity-60 ml-4 border-l-2 pl-4 italic" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '40', color: generatedMenu.visualTheme?.textColor }}>{item.description}</p>}
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                <footer className="mt-20 pt-16 border-t relative" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}>
                  <div className="absolute -top-14 right-4 w-28 h-28 rounded-full bg-white shadow-2xl flex items-center justify-center p-3 rotate-12 scale-110 border" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '10' }}>
                     <div className="w-full h-full rounded-full border border-dashed flex flex-col items-center justify-center text-center p-1" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '40' }}>
                        <span className="text-[9px] font-bold uppercase tracking-tight" style={{ color: generatedMenu.visualTheme?.secondaryColor }}>Culinária</span>
                        <span className="text-[14px] font-black leading-none" style={{ color: generatedMenu.visualTheme?.primaryColor }}>PREMIUM</span>
                     </div>
                  </div>
                  <div className="px-10 py-12 rounded-[40px] border relative overflow-hidden" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor + '05', borderColor: generatedMenu.visualTheme?.primaryColor + '10' }}>
                    <span className="absolute -top-4 -left-2 text-9xl font-serif opacity-10 leading-none" style={{ color: generatedMenu.visualTheme?.primaryColor }}>“</span>
                    <p className="serif italic leading-relaxed text-center relative z-10 px-6" style={{ color: generatedMenu.visualTheme?.textColor, fontSize: exportFormat === 'story' ? '1.75rem' : '1.35rem' }}>{generatedMenu.chefNote}</p>
                  </div>
                  <div className="flex flex-col items-center mt-16 space-y-4">
                     <div className="serif font-bold italic text-5xl tracking-tight" style={{ color: generatedMenu.visualTheme?.textColor }}>Bon Appétit</div>
                     <div className="text-[10px] uppercase font-bold tracking-[0.5em] opacity-40" style={{ color: generatedMenu.visualTheme?.textColor }}>ChefAI • Identidade Inteligente</div>
                  </div>
                </footer>
              </div>
            </div>

            <div className="mt-16 flex flex-wrap justify-center gap-6 w-full max-w-4xl no-print">
              <button onClick={() => saveAsImage(exportFormat)} className="flex-1 min-w-[200px] px-10 py-5 text-white rounded-[20px] font-bold text-sm uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor || '#e67e22' }}>📥 Download HD</button>
              <button onClick={copyMenuToClipboard} className="flex-1 min-w-[200px] px-10 py-5 bg-white text-stone-700 border border-stone-200 rounded-[20px] font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-stone-50 transition-all">📋 Copiar WhatsApp</button>
              <button onClick={() => setActiveTab('compose')} className="flex-1 min-w-[200px] px-10 py-5 bg-stone-900 text-white rounded-[20px] font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-black transition-all">⚙️ Alterar Menu</button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.PASTA]: 1,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description || '').toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
      setToast({ message: "Logo identificada! O design será adaptado.", type: "success" });
    };
    reader.readAsDataURL(file);
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio.', type: 'error' });
      setActiveTab('inventory');
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
      setExportFormat('standard');
      setActiveTab('result');
      setToast({ message: 'Cardápio e design gerados!', type: 'success' });
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => {
        const exists = prev.find(d => d.id === editingDish.id);
        if (exists) return prev.map(d => d.id === editingDish.id ? editingDish : d);
        return [...prev, editingDish];
    });
    setEditingDish(null);
    setToast({ message: 'Prato salvo!', type: 'success' });
  };

  const copyMenuToClipboard = () => {
    if (!generatedMenu) return;
    let text = `*${config.theme.toUpperCase()}*\n\n`;
    CATEGORY_ORDER.forEach(cat => {
      const items = generatedMenu.selections[cat];
      if (items && items.length > 0) {
        text += `*${cat}s:*\n`;
        items.forEach(item => { text += `• ${item.name}${item.description ? ` (${item.description})` : ''}\n`; });
        text += `\n`;
      }
    });
    text += `_"${generatedMenu.chefNote}"_\n\nBom Apetite!`;
    navigator.clipboard.writeText(text);
    setToast({ message: 'Texto copiado!', type: 'success' });
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);
    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { quality: 1, pixelRatio: 3 });
        const link = document.createElement('a');
        link.download = `Cardapio-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) {
        setToast({ message: 'Erro na imagem.', type: 'error' });
      }
    }, 200);
  };

  const renderBackgroundPattern = (theme?: VisualTheme) => {
    if (!theme) return null;
    const color = theme.primaryColor + '10';

    switch (theme.patternType) {
      case 'dots':
        return <div className="absolute inset-0 opacity-40 pointer-events-none" style={{ backgroundImage: `radial-gradient(${color} 2px, transparent 2px)`, backgroundSize: '24px 24px' }} />;
      case 'grid':
        return <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: `linear-gradient(${color} 1px, transparent 1px), linear-gradient(90deg, ${color} 1px, transparent 1px)`, backgroundSize: '40px 40px' }} />;
      case 'stripes':
        return <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: `linear-gradient(45deg, ${color} 25%, transparent 25%, transparent 50%, ${color} 50%, ${color} 75%, transparent 75%, transparent)`, backgroundSize: '60px 60px' }} />;
      case 'mesh':
        return <div className="absolute inset-0 opacity-30 pointer-events-none blur-[100px]" style={{ background: `radial-gradient(circle at 20% 20%, ${theme.primaryColor}33, transparent), radial-gradient(circle at 80% 80%, ${theme.secondaryColor}33, transparent)` }} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] selection:bg-orange-100 pb-20 text-[#333]">
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'}`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-[32px] shadow-2xl w-full max-w-lg p-8 animate-in zoom-in-95 duration-200">
            <h3 className="serif text-3xl text-[#e67e22] font-bold mb-6 border-b pb-4">Detalhes do Prato</h3>
            <form onSubmit={handleUpdateDish} className="space-y-6">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-3 rounded-2xl border border-stone-200 outline-none text-lg focus:border-[#e67e22] transition-all" />
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Categoria</label>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full px-5 py-3 rounded-2xl border border-stone-200 outline-none focus:border-[#e67e22] transition-all">
                  {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Descrição</label>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-stone-200 outline-none focus:border-[#e67e22] min-h-[120px] resize-none" />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setEditingDish(null)} className="flex-1 py-4 font-bold text-stone-400 hover:bg-stone-50 rounded-2xl border border-stone-100 transition-colors">Cancelar</button>
                <button type="submit" className="flex-2 px-8 py-4 font-bold text-white bg-[#e67e22] rounded-2xl shadow-lg hover:bg-[#d35400] transition-all">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <nav className="sticky top-0 z-50 bg-white/90 backdrop-blur-md border-b border-stone-200 px-6 py-5 shadow-sm">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-3xl">🍲</span>
            <div>
              <h1 className="serif text-2xl font-bold text-[#e67e22] leading-none">ChefAI</h1>
              <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-1">Sua Marmitaria Digital</p>
            </div>
          </div>
          <div className="flex bg-stone-100 p-1 rounded-xl">
            {['compose', 'inventory', 'result'].map((tab) => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab as TabType)}
                disabled={tab === 'result' && !generatedMenu}
                className={`px-5 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${activeTab === tab ? 'bg-white text-[#e67e22] shadow-sm' : 'text-stone-500 hover:text-stone-700 disabled:opacity-30'}`}
              >
                {tab === 'compose' ? 'Criação' : tab === 'inventory' ? 'Acervo' : 'Resultado'}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 mt-12">
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 animate-in fade-in duration-500">
            <div className="lg:col-span-4 space-y-6">
               <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
                  <h2 className="serif text-3xl mb-6 text-stone-800">Design & Estrutura</h2>
                  <div className="space-y-6">
                    <div className="p-5 rounded-2xl border-2 border-dashed border-stone-200 bg-stone-50 hover:border-[#e67e22] transition-all relative group overflow-hidden">
                      {logoPreview ? (
                        <div className="flex items-center gap-4 animate-in zoom-in-95">
                          <img src={logoPreview} alt="Logo" className="w-20 h-20 object-contain rounded-lg bg-white p-1 border shadow-sm" />
                          <div className="flex-1">
                            <p className="font-bold text-sm text-stone-700">Logo Carregada</p>
                            <button onClick={() => {setLogoPreview(null); setConfig(p => ({...p, logo: undefined}))}} className="text-[10px] text-red-500 uppercase font-bold mt-1 hover:underline">Remover</button>
                          </div>
                        </div>
                      ) : (
                        <label className="cursor-pointer flex flex-col items-center justify-center py-6">
                          <span className="text-4xl mb-3">🖼️</span>
                          <span className="text-[10px] uppercase font-bold text-stone-400 tracking-widest text-center">Subir Logomarca<br/><span className="text-[#e67e22]">A IA fará o design</span></span>
                          <input type="file" className="hidden" accept="image/*" onChange={handleLogoUpload} />
                        </label>
                      )}
                    </div>

                    <div className={`p-5 rounded-2xl border-2 cursor-pointer transition-all ${config.chefChoice ? 'bg-orange-50 border-[#e67e22]' : 'bg-stone-50 border-stone-100'}`} onClick={() => setConfig({...config, chefChoice: !config.chefChoice})}>
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-full flex items-center justify-center text-2xl ${config.chefChoice ? 'bg-[#e67e22] text-white shadow-lg rotate-12' : 'bg-white text-stone-400'}`}>✨</div>
                        <div>
                          <h4 className="font-bold text-sm">Sugestão Criativa</h4>
                          <p className="text-[10px] text-stone-400 uppercase tracking-widest mt-0.5">A IA decide as quantidades</p>
                        </div>
                      </div>
                    </div>

                    <div className={`space-y-4 transition-all duration-300 ${config.chefChoice ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                      {CATEGORY_ORDER.map(cat => (
                        <div key={cat} className="flex items-center justify-between">
                          <span className="font-semibold text-stone-600 text-sm flex items-center gap-2">
                            <span className="opacity-70">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</span>
                            {cat}s
                          </span>
                          <div className="flex items-center gap-3 bg-stone-100 p-1 rounded-full">
                            <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold flex items-center justify-center">-</button>
                            <span className="w-4 text-center font-bold text-xs">{config.counts[cat] || 0}</span>
                            <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: (p.counts[cat as Category] || 0) + 1}}))} className="w-8 h-8 rounded-full bg-white shadow-sm font-bold flex items-center justify-center">+</button>
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="pt-4 border-t border-stone-100">
                      <label className="block text-[10px] uppercase text-stone-400 font-bold mb-2 tracking-widest">Tema do Cardápio</label>
                      <input type="text" value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value})} className="w-full px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22]" placeholder="Ex: Menu de Verão" />
                    </div>
                  </div>
                  <button onClick={handleGenerate} disabled={isGenerating} className="w-full mt-10 py-4 bg-[#e67e22] text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-3 hover:bg-[#d35400] transition-all disabled:bg-stone-300">
                    {isGenerating ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Criar Cardápio Profissional'}
                  </button>
               </section>
            </div>

            <div className="lg:col-span-8 flex flex-col items-center justify-center text-center p-12 border-4 border-dashed border-stone-100 rounded-[60px] bg-white/50 min-h-[500px]">
              <div className="w-24 h-24 bg-orange-50 rounded-full flex items-center justify-center mb-8 shadow-inner animate-pulse">
                <span className="text-5xl">🎨</span>
              </div>
              <h3 className="serif text-4xl text-stone-800 mb-4 font-bold">Design Automático</h3>
              <p className="text-stone-500 max-w-sm text-lg leading-relaxed">
                Ao subir sua logomarca, nossa IA cria um plano de fundo exclusivo com as cores e o estilo da sua marca.
              </p>
              <div className="mt-12 grid grid-cols-2 gap-4">
                {['mesh', 'dots', 'grid', 'stripes'].map(p => (
                  <div key={p} className="px-4 py-2 bg-white rounded-xl border border-stone-100 text-[10px] uppercase font-bold text-stone-400 tracking-widest shadow-sm">Estilo {p}</div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="animate-in fade-in slide-in-from-bottom-5 duration-500">
            <div className="bg-white rounded-[40px] p-10 shadow-sm border border-stone-100">
              <div className="flex flex-col md:flex-row justify-between items-center gap-6 mb-12">
                <h2 className="serif text-5xl text-stone-800 font-bold">Meu Acervo</h2>
                <div className="flex flex-1 max-w-md gap-4">
                  <input 
                    type="text" 
                    placeholder="Buscar prato..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="flex-1 px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22]"
                  />
                  <select 
                    value={filterCategory}
                    onChange={(e) => setFilterCategory(e.target.value as Category | 'Todos')}
                    className="px-5 py-3 rounded-xl border border-stone-200 outline-none focus:border-[#e67e22] bg-white"
                  >
                    <option value="Todos">Todas Categorias</option>
                    {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                  </select>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => setEditingDish({ id: `manual-${Date.now()}`, name: '', category: Category.MEAT, description: '' })} className="px-6 py-3 rounded-xl bg-[#e67e22] text-white font-bold text-xs uppercase shadow-lg shadow-orange-100 hover:scale-105 transition-transform">+ Novo Prato</button>
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredDishes.map((dish, i) => (
                  <div key={dish.id} className="p-6 rounded-[28px] border border-stone-100 hover:border-orange-200 transition-all hover:shadow-xl hover:-translate-y-1 group animate-in fade-in zoom-in-95" style={{ animationDelay: `${i * 30}ms` }}>
                    <div className="flex justify-between items-start mb-4">
                      <span className="text-[10px] uppercase font-bold text-orange-500 bg-orange-50 px-3 py-1 rounded-full">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === dish.category) || 'BASE']} {dish.category}</span>
                      <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                        <button onClick={() => setEditingDish(dish)} className="text-blue-500 hover:scale-110">✎</button>
                        <button onClick={() => setDishPool(p => p.filter(d => d.id !== dish.id))} className="text-red-500 hover:scale-110">✕</button>
                      </div>
                    </div>
                    <h4 className="font-bold text-xl text-stone-800 mb-2">{dish.name}</h4>
                    <p className="text-xs text-stone-400 line-clamp-2 italic">{dish.description || 'Sem descrição cadastrada.'}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in fade-in zoom-in-95 duration-700">
            <div className="mb-12 flex bg-stone-100 p-1.5 rounded-full shadow-inner">
               <button onClick={() => setExportFormat('standard')} className={`px-8 py-3 rounded-full text-xs font-bold uppercase transition-all ${exportFormat === 'standard' ? 'bg-white text-[#e67e22] shadow-md' : 'text-stone-500'}`}>Vertical / A4</button>
               <button onClick={() => setExportFormat('story')} className={`px-8 py-3 rounded-full text-xs font-bold uppercase transition-all ${exportFormat === 'story' ? 'bg-white text-[#e67e22] shadow-md' : 'text-stone-500'}`}>Stories (9:16)</button>
            </div>

            <div ref={menuRef} className={`bg-white shadow-[0_60px_100px_-30px_rgba(0,0,0,0.2)] relative overflow-hidden transition-all duration-500 ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16]' : 'w-full max-w-[620px] min-h-[860px] border border-stone-100'}`} style={{ backgroundColor: generatedMenu.visualTheme?.backgroundColor }}>
              {renderBackgroundPattern(generatedMenu.visualTheme)}
              <div className="absolute inset-0 pointer-events-none" style={{ background: generatedMenu.visualTheme?.backgroundGradient, opacity: 0.15 }}></div>

              <div className={`relative z-10 flex flex-col h-full border-[20px] border-transparent ${exportFormat === 'story' ? 'p-6' : 'p-16'}`}>
                <div className="absolute inset-0 border border-white/30 m-2 pointer-events-none" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}></div>

                <header className={`text-center relative ${exportFormat === 'story' ? 'mb-8' : 'mb-16'}`}>
                  {logoPreview && <img src={logoPreview} alt="Logo" className={`mx-auto object-contain drop-shadow-lg animate-in fade-in zoom-in-50 duration-1000 ${exportFormat === 'story' ? 'h-16 w-16 mb-4' : 'h-24 w-24 mb-10'}`} />}
                  <div className={`inline-block px-4 py-1.5 mb-4 rounded-full text-white text-[9px] font-bold uppercase tracking-[0.4em] shadow-xl`} style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor || '#e67e22' }}>Cardápio do Dia</div>
                  <h1 className={`${exportFormat === 'story' ? 'text-5xl mb-4' : 'text-6xl mb-8'} serif uppercase tracking-tighter leading-none font-bold`} style={{ color: generatedMenu.visualTheme?.textColor }}>{config.theme}</h1>
                  <div className="flex items-center justify-center gap-4">
                    <div className="h-[1px] flex-1 opacity-20" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                    <span className="text-stone-400 text-[10px] italic font-medium uppercase tracking-widest opacity-60">Sabores de Verdade</span>
                    <div className="h-[1px] flex-1 opacity-20" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                  </div>
                </header>

                <div className={`flex-1 ${exportFormat === 'story' ? 'space-y-6' : 'space-y-16'}`}>
                  {CATEGORY_ORDER.map(cat => {
                    const items = generatedMenu.selections[cat];
                    if (!items || items.length === 0) return null;
                    return (
                      <div key={cat} className={`${exportFormat === 'story' ? 'space-y-4' : 'space-y-8'} animate-in slide-in-from-left-5`}>
                        <div className="flex items-center gap-3">
                          <h3 className={`${exportFormat === 'story' ? 'text-[9px]' : 'text-[11px]'} font-bold uppercase tracking-[0.5em] whitespace-nowrap`} style={{ color: generatedMenu.visualTheme?.primaryColor }}>{cat}s</h3>
                          <div className="h-[1px] w-full opacity-10" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                        </div>
                        <div className={`grid ${exportFormat === 'story' ? 'gap-4' : 'gap-8'}`}>
                          {items.map((item, idx) => (
                            <div key={idx} className="flex flex-col group">
                              <h4 className={`${exportFormat === 'story' ? 'text-lg' : 'text-2xl'} font-bold leading-tight flex items-baseline gap-2`} style={{ color: generatedMenu.visualTheme?.textColor }}>
                                <span className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{ backgroundColor: generatedMenu.visualTheme?.accentColor }}></span>
                                {item.name}
                              </h4>
                              {item.description && <p className={`${exportFormat === 'story' ? 'text-xs mt-1' : 'text-base mt-2'} leading-relaxed opacity-60 ml-3.5 border-l pl-3 italic`} style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '40', color: generatedMenu.visualTheme?.textColor }}>{item.description}</p>}
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                <footer className={`${exportFormat === 'story' ? 'mt-8 pt-8' : 'mt-20 pt-16'} border-t relative`} style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}>
                  <div className={`absolute right-2 rounded-full bg-white shadow-2xl flex items-center justify-center p-2 rotate-12 border ${exportFormat === 'story' ? '-top-10 w-20 h-20' : '-top-14 w-28 h-28 scale-110'}`} style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '10' }}>
                     <div className="w-full h-full rounded-full border border-dashed flex flex-col items-center justify-center text-center p-0.5" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '40' }}>
                        <span className="text-[7px] font-bold uppercase tracking-tight" style={{ color: generatedMenu.visualTheme?.secondaryColor }}>Culinária</span>
                        <span className={`${exportFormat === 'story' ? 'text-[11px]' : 'text-[14px]'} font-black leading-none`} style={{ color: generatedMenu.visualTheme?.primaryColor }}>PREMIUM</span>
                     </div>
                  </div>
                  <div className={`${exportFormat === 'story' ? 'px-6 py-6 rounded-[24px]' : 'px-10 py-12 rounded-[40px]'} border relative overflow-hidden`} style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor + '05', borderColor: generatedMenu.visualTheme?.primaryColor + '10' }}>
                    <span className="absolute -top-3 -left-1 text-7xl font-serif opacity-10 leading-none" style={{ color: generatedMenu.visualTheme?.primaryColor }}>“</span>
                    <p className={`serif italic leading-relaxed text-center relative z-10 px-4`} style={{ color: generatedMenu.visualTheme?.textColor, fontSize: exportFormat === 'story' ? '1.1rem' : '1.35rem' }}>{generatedMenu.chefNote}</p>
                  </div>
                  <div className={`${exportFormat === 'story' ? 'mt-8 space-y-2' : 'mt-16 space-y-4'} flex flex-col items-center`}>
                     <div className={`serif font-bold italic tracking-tight ${exportFormat === 'story' ? 'text-3xl' : 'text-5xl'}`} style={{ color: generatedMenu.visualTheme?.textColor }}>Bon Appétit</div>
                     <div className="text-[9px] uppercase font-bold tracking-[0.5em] opacity-40" style={{ color: generatedMenu.visualTheme?.textColor }}>ChefAI • Design Digital</div>
                  </div>
                </footer>
              </div>
            </div>

            <div className="mt-16 flex flex-wrap justify-center gap-6 w-full max-w-4xl no-print">
              <button onClick={() => saveAsImage(exportFormat)} className="flex-1 min-w-[200px] px-10 py-5 text-white rounded-[20px] font-bold text-sm uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor || '#e67e22' }}>📥 Download HD</button>
              <button onClick={copyMenuToClipboard} className="flex-1 min-w-[200px] px-10 py-5 bg-white text-stone-700 border border-stone-200 rounded-[20px] font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-stone-50 transition-all">📋 Copiar WhatsApp</button>
              <button onClick={() => setActiveTab('compose')} className="flex-1 min-w-[200px] px-10 py-5 bg-stone-900 text-white rounded-[20px] font-bold text-sm uppercase tracking-widest shadow-xl hover:bg-black transition-all">⚙️ Alterar Menu</button>
            </div>
          </div>
        )}

        {activeTab === 'result' && !generatedMenu && (
          <div className="h-[500px] flex flex-col items-center justify-center text-center text-stone-400 italic">
             <span className="text-6xl mb-6">🥘</span>
             <p className="text-xl serif">Nenhum cardápio foi gerado ainda.</p>
             <button onClick={() => setActiveTab('compose')} className="mt-4 text-[#e67e22] font-bold underline">Clique aqui para começar</button>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { toPng } from 'html-to-image';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.PASTA]: 1,
      [Category.SIDE]: 2,
      [Category.SALAD]: 4,
      [Category.DESSERT]: 0,
    },
    theme: 'Sugestão de Hoje',
    baseOption: 'Comida Caseira',
    chefChoice: false
  });

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description || '').toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
      setToast({ message: "Logo pronta para análise!", type: "success" });
    };
    reader.readAsDataURL(file);
  };

  const handleRemoveLogo = (e: React.MouseEvent) => {
    e.stopPropagation(); // Evita disparar o seletor de arquivo se clicado dentro do label
    setLogoPreview(null);
    setConfig(prev => ({ ...prev, logo: undefined }));
    setToast({ message: "Identidade visual removida.", type: "error" });
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Seu acervo está vazio.', type: 'error' });
      setActiveTab('inventory');
      return;
    }
    setIsGenerating(true);
    try {
      const result = await generateMenuWithAI(dishPool, config);
      setGeneratedMenu(result);
      setExportFormat('standard');
      setActiveTab('result');
      setToast({ message: 'Cardápio e design gerados!', type: 'success' });
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (error) {
      setToast({ message: 'Erro ao gerar cardápio.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleUpdateDish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDish) return;
    setDishPool(prev => {
        const exists = prev.find(d => d.id === editingDish.id);
        if (exists) return prev.map(d => d.id === editingDish.id ? editingDish : d);
        return [...prev, editingDish];
    });
    setEditingDish(null);
    setToast({ message: 'Prato salvo!', type: 'success' });
  };

  const copyMenuToClipboard = () => {
    if (!generatedMenu) return;
    let text = `*${config.theme.toUpperCase()}*\n\n`;
    CATEGORY_ORDER.forEach(cat => {
      const items = generatedMenu.selections[cat];
      if (items && items.length > 0) {
        text += `*${cat}s:*\n`;
        items.forEach(item => { text += `• ${item.name}${item.description ? ` (${item.description})` : ''}\n`; });
        text += `\n`;
      }
    });
    text += `_"${generatedMenu.chefNote}"_\n\nBom Apetite!`;
    navigator.clipboard.writeText(text);
    setToast({ message: 'Texto copiado!', type: 'success' });
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);
    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { quality: 1, pixelRatio: 3 });
        const link = document.createElement('a');
        link.download = `Cardapio-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) {
        setToast({ message: 'Erro na imagem.', type: 'error' });
      }
    }, 200);
  };

  const renderBackgroundPattern = (theme?: VisualTheme) => {
    if (!theme) return null;
    const color = theme.primaryColor + '10';

    switch (theme.patternType) {
      case 'dots':
        return <div className="absolute inset-0 opacity-40 pointer-events-none" style={{ backgroundImage: `radial-gradient(${color} 2px, transparent 2px)`, backgroundSize: '24px 24px' }} />;
      case 'grid':
        return <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: `linear-gradient(${color} 1px, transparent 1px), linear-gradient(90deg, ${color} 1px, transparent 1px)`, backgroundSize: '40px 40px' }} />;
      case 'stripes':
        return <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: `linear-gradient(45deg, ${color} 25%, transparent 25%, transparent 50%, ${color} 50%, ${color} 75%, transparent 75%, transparent)`, backgroundSize: '60px 60px' }} />;
      case 'mesh':
        return <div className="absolute inset-0 opacity-30 pointer-events-none blur-[100px]" style={{ background: `radial-gradient(circle at 20% 20%, ${theme.primaryColor}33, transparent), radial-gradient(circle at 80% 80%, ${theme.secondaryColor}33, transparent)` }} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] selection:bg-orange-100 pb-20 text-[#333]">
      {toast && (
        <div className="fixed top-24 right-6 z-[100] animate-in slide-in-from-right-10 fade-in duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 backdrop-blur-md ${toast.type === 'success' ? 'bg-[#e67e22]/90 text-white border-white/20' : 'bg-red-500/90 text-white border-white/20'}`}>
            <span className="text-xl">{toast.type === 'success' ? '✅' : '⚠️'}</span>
            <p className="font-semibold text-sm">{toast.message}</p>
          </div>
        </div>
      )}

      {editingDish && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-[32px] shadow-2xl w-full max-w-lg p-8 animate-in zoom-in-95 duration-200">
            <h3 className="serif text-3xl text-[#e67e22] font-bold mb-6 border-b pb-4">Detalhes do Prato</h3>
            <form onSubmit={handleUpdateDish} className="space-y-6">
              <div>
                <label className="block text-[10px] uppercase tracking-widest text-stone-400 font-bold mb-2">Nome</label>
