               <section className="bg-white p-8 rounded-3xl shadow-sm border border-stone-100">
                  <h2 className="serif text-3xl mb-6 text-stone-800">Design & Estrutura</h2>
                  <div className="space-y-6">

                    {/* Upload de Logo com Preview e Remoção */}
                    <div className="relative group">
                      {logoPreview ? (
                        <div className="p-6 rounded-3xl border border-orange-100 bg-orange-50/30 flex flex-col items-center animate-in zoom-in-95 duration-300">
                          <div className="relative">
                            <img src={logoPreview} alt="Sua Logo" className="w-24 h-24 object-contain rounded-2xl bg-white p-2 border border-stone-100 shadow-md mb-4" />
                            <button 
