              <span className="text-4xl animate-bounce">👨‍🍳</span>
            </div>
          </div>
          <div className="text-center space-y-4 px-6 max-w-sm">
            <h3 className="serif text-3xl font-bold text-stone-800 animate-pulse">Cozinhando seu Menu</h3>
            <div className="flex flex-col items-center gap-2">
              <p className="text-[#e67e22] font-bold text-sm uppercase tracking-widest transition-all duration-300">
                {generationStep}
              </p>
              <div className="w-48 h-1.5 bg-stone-100 rounded-full overflow-hidden">
                <div className="h-full bg-[#e67e22] animate-progress-indeterminate"></div>
              </div>
            </div>
            <p className="text-stone-400 text-xs italic">Isso pode levar alguns segundos, a IA está criando algo único para você.</p>
          </div>
        </div>
