            <div ref={menuRef} className={`bg-white shadow-[0_80px_140px_-40px_rgba(0,0,0,0.15)] relative overflow-hidden transition-all duration-700 flex flex-col ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16] h-[800px]' : 'w-full max-w-[700px] min-h-[960px] border border-stone-100'}`} style={{ backgroundColor: generatedMenu.visualTheme?.backgroundColor }}>
              {/* Background Design */}
              <div className="absolute inset-0 pointer-events-none" style={{ background: generatedMenu.visualTheme?.backgroundGradient, opacity: 0.12 }}></div>
              <div className="absolute inset-0 pointer-events-none overflow-hidden opacity-5">
                 {/* Decorative large logo watermark */}
                 {logoPreview && <img src={logoPreview} className="absolute -right-20 -bottom-20 w-[400px] opacity-10 rotate-12 grayscale" />}
