                <div className="absolute inset-4 border border-white/40 pointer-events-none" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '15' }}></div>

                <header className={`text-center relative ${exportFormat === 'story' ? 'mb-4' : 'mb-20'}`}>
                  {logoPreview && (
                    <img 
                      src={logoPreview} 
                      alt="Logo" 
                      className={`mx-auto object-contain drop-shadow-2xl animate-in fade-in zoom-in-50 duration-1000 ${exportFormat === 'story' ? 'h-16 mb-2' : 'h-28 mb-12'}`} 
