                       {config.chefChoice ? '✨ Escolha do Chef Ativa' : '✨ Escolha do Chef'}
                     </button>
                   </div>
                </div>

                <div className={`relative grid grid-cols-1 md:grid-cols-2 gap-8 transition-all duration-700 ${config.chefChoice ? 'opacity-40 grayscale-50 pointer-events-none scale-[0.98]' : 'opacity-100'}`}>
                  {config.chefChoice && (
                    <div className="absolute inset-0 z-10 flex items-center justify-center">
                      <div className="bg-white/80 backdrop-blur-sm px-8 py-4 rounded-3xl border border-stone-100 shadow-xl flex flex-col items-center gap-2 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <span className="text-3xl">👨‍🍳</span>
                        <span className="text-[10px] font-black text-stone-800 uppercase tracking-widest">IA no comando das quantidades</span>
                        <p className="text-[9px] text-stone-400 text-center uppercase tracking-widest">Os controles foram desativados para<br/>dar liberdade criativa ao ChefAI.</p>
                      </div>
                    </div>
                  )}
                  {CATEGORY_ORDER.map(cat => (
                    <div key={cat} className={`group p-6 rounded-3xl border border-stone-100 transition-all ${config.chefChoice ? 'bg-stone-100/50' : 'bg-stone-50/30 hover:bg-white hover:border-orange-200 hover:shadow-xl hover:shadow-orange-500/5'}`}>
                      <div className="flex items-center justify-between mb-4">
                        <div className="flex items-center gap-3">
                           <div className={`w-10 h-10 rounded-xl shadow-sm flex items-center justify-center text-xl transition-all ${config.chefChoice ? 'bg-stone-200 opacity-50' : 'bg-white'}`}>{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</div>
                           <span className={`font-bold transition-all ${config.chefChoice ? 'text-stone-300' : 'text-stone-700'}`}>{cat}s</span>
                        </div>
                        <div className={`flex items-center rounded-2xl p-1 shadow-sm border border-stone-100 transition-all ${config.chefChoice ? 'bg-stone-200/50' : 'bg-white'}`}>
                           <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))} className={`w-8 h-8 rounded-xl font-black transition-all ${config.chefChoice ? 'text-stone-300 cursor-not-allowed' : 'text-stone-400 hover:bg-stone-50'}`}>-</button>
                           <span className={`w-10 text-center font-black text-sm transition-all ${config.chefChoice ? 'text-stone-300' : 'text-stone-800'}`}>{config.counts[cat] || 0}</span>
                           <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: (p.counts[cat as Category] || 0) + 1}}))} className={`w-8 h-8 rounded-xl font-black transition-all ${config.chefChoice ? 'text-stone-300 cursor-not-allowed' : 'text-stone-400 hover:bg-stone-50'}`}>+</button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
             <div className="bg-white rounded-[48px] p-12 border border-stone-200/50 shadow-sm">
                <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-16">
                  <div>
                    <h2 className="serif text-5xl font-bold text-stone-900 leading-tight">Gestão de Acervo</h2>
                    <p className="text-stone-400 text-xs font-bold uppercase tracking-[0.3em] mt-2">Alimente a Inteligência do Chef</p>
                  </div>
                  <div className="flex flex-wrap gap-3 w-full lg:w-auto">
                    <button 
                      onClick={() => setShowImportGuide(true)} 
                      className="px-6 py-4 bg-orange-100 text-orange-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-orange-200 transition-all flex items-center gap-2"
                    >
                      📥 Importar Excel
                    </button>
                    <button 
                      onClick={() => setEditingDish({ id: `manual-${Date.now()}`, name: '', category: Category.MEAT, description: '' })} 
                      className="px-8 py-4 bg-stone-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-black transition-all"
                    >
                      + Novo Prato
                    </button>
                  </div>
                </div>

                {/* Search and Filters */}
                <div className="flex flex-col md:flex-row gap-4 mb-10">
                   <input type="text" placeholder="Pesquisar no acervo..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="flex-1 bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none focus:ring-2 ring-orange-100 transition-all font-semibold" />
                   <select value={filterCategory} onChange={e => setFilterCategory(e.target.value as any)} className="bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-500">
                      <option value="Todos">Todas as Categorias</option>
                      {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                   </select>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {filteredDishes.map((dish) => (
                    <div key={dish.id} className="group relative p-8 rounded-[36px] bg-white border border-stone-100 shadow-[0_4px_20px_rgba(0,0,0,0.02)] hover:shadow-[0_20px_50px_rgba(230,126,34,0.08)] hover:-translate-y-2 transition-all duration-500 overflow-hidden">
                       <span className="inline-block px-3 py-1 bg-stone-50 text-[9px] font-black uppercase tracking-widest text-stone-400 rounded-full border border-stone-100 mb-4">{dish.category}</span>
                       <h4 className="serif text-2xl font-black text-stone-800 mb-2 leading-tight group-hover:text-orange-500 transition-colors">{dish.name}</h4>
                       <p className="text-[11px] text-stone-400 leading-relaxed italic line-clamp-2">{dish.description || 'Nenhuma descrição especial cadastrada.'}</p>
                       <div className="mt-8 pt-6 border-t border-stone-50 flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => setEditingDish(dish)} className="p-3 bg-stone-50 rounded-xl hover:bg-orange-500 hover:text-white transition-all">✎</button>
                          <button onClick={() => setDishPool(p => p.filter(d => d.id !== dish.id))} className="p-3 bg-stone-50 rounded-xl hover:bg-red-500 hover:text-white transition-all">✕</button>
                       </div>
                    </div>
                  ))}
                </div>
             </div>
          </div>
        )}

        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in fade-in zoom-in-95 duration-700">
            <div className="mb-12 flex items-center gap-6 no-print">
               <div className="flex bg-stone-200/50 p-1.5 rounded-[24px] shadow-inner border border-stone-200/30">
                  <button onClick={() => setExportFormat('standard')} className={`px-10 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'standard' ? 'bg-white text-stone-900 shadow-lg' : 'text-stone-500'}`}>Impressão (A4)</button>
                  <button onClick={() => setExportFormat('story')} className={`px-10 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'story' ? 'bg-white text-stone-900 shadow-lg' : 'text-stone-500'}`}>Digital (Story)</button>
               </div>

               <button 
                  onClick={saveCurrentAsDefault}
                  className={`px-8 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border ${defaultLayout?.visualTheme === generatedMenu.visualTheme ? 'bg-stone-900 text-white border-stone-900' : 'bg-white text-stone-600 border-stone-200 hover:bg-stone-50'}`}
                >
                  {defaultLayout?.visualTheme === generatedMenu.visualTheme ? '✓ Layout Padrão Salvo' : '⭐ Salvar como Layout Padrão'}
               </button>
            </div>

            <div 
              ref={menuRef} 
              className={`bg-white shadow-[0_80px_140px_-40px_rgba(0,0,0,0.15)] relative flex flex-col transition-all duration-500 ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16] h-[800px] overflow-hidden' : 'w-full max-w-[700px] min-h-[960px] border border-stone-100'}`} 
              style={{ 
                backgroundColor: generatedMenu.visualTheme?.backgroundColor,
                overflow: 'hidden'
              }}
            >
              <div className="absolute inset-0 pointer-events-none" style={{ background: generatedMenu.visualTheme?.backgroundGradient, opacity: 0.12 }}></div>
              <div className="absolute inset-0 pointer-events-none overflow-hidden opacity-5">
                 {logoPreview && <img src={logoPreview} className="absolute -right-20 -bottom-20 w-[400px] opacity-10 rotate-12 grayscale" />}
              </div>

              <div 
                className={`relative z-10 flex flex-col h-full ${exportFormat === 'story' ? 'p-6' : 'p-20'}`}
                style={{
                  gap: exportFormat === 'story' ? `${Math.max(4, 12 * layoutScale)}px` : '40px'
                }}
              >
                <div className="absolute inset-4 border border-white/40 pointer-events-none" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '15' }}></div>

                <header className={`text-center relative flex flex-col items-center flex-shrink-0 ${exportFormat === 'story' ? 'mb-2' : 'mb-20'}`}>
                  {logoPreview && (
                    <img 
                      src={logoPreview} 
                      alt="Logo" 
                      className={`object-contain drop-shadow-2xl transition-all ${exportFormat === 'story' ? 'mb-2' : 'mb-12'}`} 
                      style={{ 
                        height: exportFormat === 'story' ? `${Math.max(30, 80 * layoutScale)}px` : '110px'
                      }}
                    />
                  )}
                  <div className={`inline-block px-4 py-1 mb-2 rounded-full text-white font-bold uppercase tracking-[0.4em] shadow-lg ${exportFormat === 'story' ? 'text-[6px]' : 'text-[10px]'}`} style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor || '#e67e22', transform: exportFormat === 'story' ? `scale(${layoutScale})` : 'none' }}>
                    Sabor & Arte
                  </div>
                  <h1 
                    className={`serif uppercase tracking-tighter leading-[0.9] font-black text-stone-900 transition-all`} 
                    style={{ 
                      color: generatedMenu.visualTheme?.textColor,
                      fontSize: exportFormat === 'story' ? `${Math.max(20, 48 * layoutScale)}px` : '72px',
                      marginBottom: exportFormat === 'story' ? '4px' : '40px'
                    }}
                  >
                    {config.theme}
                  </h1>
                </header>

                <div className={`flex-1 flex flex-col justify-center transition-all ${exportFormat === 'story' ? 'space-y-2' : 'space-y-16'}`}>
                  {CATEGORY_ORDER.map(cat => {
                    const items = generatedMenu.selections[cat];
                    if (!items || items.length === 0) return null;
                    return (
                      <div key={cat} className={`${exportFormat === 'story' ? 'space-y-1' : 'space-y-10'}`}>
                        <div className="flex items-center gap-2">
                          <h3 className={`${exportFormat === 'story' ? 'text-[7px]' : 'text-[12px]'} font-black uppercase tracking-[0.4em] whitespace-nowrap`} style={{ color: generatedMenu.visualTheme?.primaryColor, transform: exportFormat === 'story' ? `scale(${layoutScale})` : 'none', transformOrigin: 'left' }}>
                            {cat}s
                          </h3>
                          <div className="h-[0.5px] w-full opacity-10" style={{ backgroundColor: generatedMenu.visualTheme?.textColor }}></div>
                        </div>
                        <div className={`grid ${exportFormat === 'story' ? 'gap-1.5' : 'gap-10'}`}>
                          {items.map((item, idx) => (
                            <div key={idx} className="flex flex-col relative group">
                              <h4 
                                className={`font-bold leading-tight flex items-baseline gap-2`} 
                                style={{ 
                                  color: generatedMenu.visualTheme?.textColor,
                                  fontSize: exportFormat === 'story' ? `${Math.max(10, 16 * layoutScale)}px` : '24px'
                                }}
                              >
                                <span className={`${exportFormat === 'story' ? 'w-1 h-1' : 'w-2 h-2'} rounded-full flex-shrink-0`} style={{ backgroundColor: generatedMenu.visualTheme?.accentColor }}></span>
                                {item.name}
                              </h4>
                              {item.description && (
                                <p 
                                  className={`leading-relaxed opacity-60 ml-3 pr-4 border-l-[1px] pl-2 italic font-medium`} 
                                  style={{ 
                                    borderColor: generatedMenu.visualTheme?.primaryColor + '30', 
                                    color: generatedMenu.visualTheme?.textColor,
                                    fontSize: exportFormat === 'story' ? `${Math.max(7, 10 * layoutScale)}px` : '16px',
                                    marginTop: exportFormat === 'story' ? '1px' : '8px'
                                  }}
                                >
                                  {item.description}
                                </p>
                              )}
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                <footer className={`${exportFormat === 'story' ? 'mt-2 pt-3 flex-shrink-0' : 'mt-24 pt-20'} border-t relative`} style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '15' }}>
                  <div className={`${exportFormat === 'story' ? 'px-3 py-3 rounded-[16px]' : 'px-14 py-16 rounded-[48px]'} border relative overflow-hidden transition-all`} style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor + '03', borderColor: generatedMenu.visualTheme?.primaryColor + '10' }}>
                    <span className={`${exportFormat === 'story' ? 'text-3xl -top-2' : 'text-8xl -top-6'} absolute -left-1 font-serif opacity-10 leading-none text-stone-900`}>“</span>
                    <p className={`serif italic leading-relaxed text-center relative z-10 px-2 text-stone-600`} style={{ fontSize: exportFormat === 'story' ? `${Math.max(10, 15 * layoutScale)}px` : '24px' }}>
                      {generatedMenu.chefNote}
                    </p>
                  </div>
                  <div className={`${exportFormat === 'story' ? 'mt-3' : 'mt-20'} flex flex-col items-center`}>
                     <div className={`serif font-black italic tracking-tighter text-stone-800`} style={{ fontSize: exportFormat === 'story' ? `${Math.max(18, 28 * layoutScale)}px` : '60px' }}>Bon Appétit</div>
                     <div className={`${exportFormat === 'story' ? 'text-[5px]' : 'text-[10px]'} font-black uppercase tracking-[0.6em] opacity-30 mt-1 text-stone-900`}>ChefAI Digital Studio</div>
                  </div>
                </footer>
              </div>
            </div>

            <div className="mt-20 flex flex-wrap justify-center gap-4 w-full max-w-5xl no-print">
              <button onClick={() => saveAsImage(exportFormat)} className="flex-1 min-w-[220px] px-10 py-5 bg-stone-900 text-white rounded-[24px] font-black text-[11px] uppercase tracking-widest shadow-2xl hover:bg-black hover:-translate-y-1 transition-all">📥 Salvar em Alta Definição</button>
              <button onClick={() => setActiveTab('compose')} className="flex-1 min-w-[220px] px-10 py-5 bg-white border border-stone-200 text-stone-600 rounded-[24px] font-black text-[11px] uppercase tracking-widest shadow-xl hover:bg-stone-50 transition-all">⚙️ Ajustar Configurações</button>
            </div>
          </div>
        )}
      </main>

      {/* Import Guide Modal with Preview */}
      {showImportGuide && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/40 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-3xl p-10 animate-in zoom-in-95 duration-300 overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="serif text-3xl font-black text-stone-800">
                {pendingDishes ? 'Prévia da Importação' : 'Importar Acervo'}
              </h3>
              <button onClick={() => { setShowImportGuide(false); setPendingDishes(null); }} className="text-stone-400 hover:text-stone-900 text-2xl">✕</button>
            </div>

            <div className="overflow-y-auto pr-2 space-y-8">
              {pendingDishes ? (
                <>
                  <p className="text-stone-500 text-sm leading-relaxed">
                    Encontramos <span className="font-bold text-stone-900">{pendingDishes.length}</span> pratos no seu arquivo. Verifique se os dados estão corretos antes de confirmar.
                  </p>
                  <div className="bg-stone-50 border border-stone-100 rounded-3xl overflow-hidden">
                    <table className="w-full text-left text-[11px] font-medium text-stone-600 border-collapse">
                      <thead className="bg-stone-100/50">
                        <tr className="border-b border-stone-200">
                          <th className="py-3 px-4 uppercase tracking-widest text-[9px] font-black">Nome</th>
                          <th className="py-3 px-4 uppercase tracking-widest text-[9px] font-black">Categoria</th>
                          <th className="py-3 px-4 uppercase tracking-widest text-[9px] font-black">Descrição</th>
                        </tr>
                      </thead>
                      <tbody>
                        {pendingDishes.slice(0, 10).map((dish, idx) => (
                          <tr key={idx} className="border-b border-stone-100/50 last:border-0">
                            <td className="py-3 px-4 text-stone-900 font-bold">{dish.name}</td>
                            <td className="py-3 px-4">{dish.category}</td>
                            <td className="py-3 px-4 italic text-stone-400 max-w-[200px] truncate">{dish.description || '-'}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                    {pendingDishes.length > 10 && (
                      <div className="py-3 px-4 text-center bg-white text-[10px] text-stone-400 uppercase tracking-widest border-t border-stone-100">
                        + {pendingDishes.length - 10} outros pratos...
                      </div>
                    )}
                  </div>

                  <div className="flex gap-4 pt-4">
                    <button 
                      onClick={() => setPendingDishes(null)} 
                      className="flex-1 py-5 font-black text-[10px] text-stone-400 uppercase tracking-widest hover:bg-stone-50 rounded-2xl transition-all"
                    >
                      Escolher Outro Arquivo
                    </button>
                    <button 
                      onClick={confirmImport} 
                      className="flex-1 py-5 bg-stone-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl"
                    >
                      Confirmar {pendingDishes.length} Itens
                    </button>
                  </div>
                </>
              ) : (
                <>
                  <p className="text-stone-500 text-sm leading-relaxed">
                    Para que o ChefAI reconheça seus pratos corretamente, seu arquivo Excel (.xlsx ou .csv) deve seguir o modelo abaixo. A IA usará esses dados para criar combinações inteligentes.
                  </p>

                  <div className="bg-stone-50 border border-stone-100 rounded-3xl p-6">
                    <h4 className="text-[10px] font-black uppercase tracking-widest text-stone-400 mb-4 flex items-center gap-2">
                      <span className="w-2 h-2 bg-orange-500 rounded-full"></span> Modelo de Tabela Esperado
                    </h4>
                    <div className="overflow-x-auto">
                      <table className="w-full text-left text-sm font-medium text-stone-600 border-collapse">
                        <thead>
                          <tr className="border-b border-stone-200">
                            <th className="pb-3 px-2">Nome</th>
                            <th className="pb-3 px-2">Categoria</th>
                            <th className="pb-3 px-2">Descrição</th>
                          </tr>
                        </thead>
                        <tbody className="text-[12px]">
                          <tr className="border-b border-stone-100/50">
                            <td className="py-3 px-2 text-stone-900 font-bold">Picanha Nobre</td>
                            <td className="py-3 px-2">Carne</td>
                            <td className="py-3 px-2 italic text-stone-400 text-[10px]">Grelhada ao sal grosso...</td>
                          </tr>
                          <tr className="border-b border-stone-100/50">
                            <td className="py-3 px-2 text-stone-900 font-bold">Arroz à Grega</td>
                            <td className="py-3 px-2">Base</td>
                            <td className="py-3 px-2 italic text-stone-400 text-[10px]">Com pimentões e passas</td>
                          </tr>
                          <tr>
                            <td className="py-3 px-2 text-stone-900 font-bold">Lasanha Veggie</td>
                            <td className="py-3 px-2">Massa</td>
                            <td className="py-3 px-2 italic text-stone-400 text-[10px]">Massa artesanal integral</td>
                          </tr>
                        </tbody>
                      </table>
                    </div>
                  </div>

                  <div className="p-4 rounded-2xl bg-orange-50 border border-orange-100 text-[11px] text-orange-700 leading-relaxed">
                    <strong>Atenção:</strong> As categorias devem ser escritas exatamente como: 
                    <span className="font-bold"> {Object.values(Category).join(', ')}</span>.
                  </div>

                  <label className="block">
                    <div className="w-full py-8 border-2 border-dashed border-stone-200 rounded-[32px] hover:border-orange-300 hover:bg-orange-50/30 transition-all cursor-pointer flex flex-col items-center justify-center text-center group">
                       <span className="text-4xl mb-4 group-hover:scale-110 transition-transform">📊</span>
                       <span className="font-bold text-stone-800">Selecionar arquivo Excel</span>
                       <span className="text-[10px] text-stone-400 uppercase tracking-widest mt-1">Formatos: .xlsx, .xls, .csv</span>
                    </div>
                    <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleImportExcel} />
                  </label>
                </>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Editor Modal */}
      {editingDish && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/40 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg p-10 animate-in zoom-in-95 duration-300 border border-white">
            <h3 className="serif text-3xl font-black text-stone-800 mb-8 border-b pb-6">Detalhes do Prato</h3>
            <form onSubmit={e => {
              e.preventDefault();
              setDishPool(prev => {
                const exists = prev.find(d => d.id === editingDish.id);
                if (exists) return prev.map(d => d.id === editingDish.id ? editingDish : d);
                return [...prev, editingDish];
              });
              setEditingDish(null);
              setToast({ message: 'Salvo no acervo!', type: 'success' });
            }} className="space-y-8">
              <div>
                <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest block mb-2">Nome Comercial</label>
                <input type="text" required value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-stone-100 bg-stone-50 outline-none focus:border-orange-500 transition-all font-bold text-lg" />
              </div>
              <div>
                <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest block mb-2">Categoria</label>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full px-5 py-4 rounded-2xl border border-stone-100 bg-stone-50 outline-none focus:border-orange-500 transition-all font-bold text-stone-600">
                  {Object.values(Category).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
              <div>
                <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest block mb-2">Descrição Gourmet (Opcional)</label>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-stone-100 bg-stone-50 outline-none focus:border-orange-500 transition-all min-h-[120px] font-medium text-stone-600 text-sm" placeholder="Ex: Grelhado lentamente em lenha de carvalho..." />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setEditingDish(null)} className="flex-1 py-5 font-black text-[10px] text-stone-400 uppercase tracking-widest hover:bg-stone-50 rounded-2xl transition-all">Cancelar</button>
                <button type="submit" className="flex-1 py-5 bg-orange-500 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-orange-100">Confirmar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export enum Category {
  BASE = 'Base',
  MEAT = 'Carne',
  PASTA = 'Massa',
  SIDE = 'Acompanhamento',
  SALAD = 'Salada',
  DESSERT = 'Sobremesa'
}

export interface VisualTheme {
  primaryColor: string;
  secondaryColor: string;
  backgroundColor: string;
  backgroundGradient: string;
  textColor: string;
  accentColor: string;
  patternType: 'dots' | 'grid' | 'mesh' | 'clean' | 'stripes';
}

export interface Dish {
  id: string;
  name: string;
  category: Category;
  description?: string;
}

export interface MealOption {
  id: string;
  title: string;
  price: string;
  description?: string;
}

export interface MenuConfig {
  counts: Record<Category, number>;
  theme: string;
  baseOption: string;
  chefChoice: boolean;
  logo?: string; // Base64
  useDefaultLayout?: boolean;
  mealOptions?: MealOption[];
}

export interface GeneratedMenu {
  selections: Record<Category, Dish[]>;
  chefNote: string;
  visualTheme?: VisualTheme;
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const LOCAL_STORAGE_KEY = 'chefai_default_layout';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(DEFAULT_DISHES);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [defaultLayout, setDefaultLayout] = useState<{ visualTheme: VisualTheme, theme: string } | null>(null);

  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.PASTA]: 0,
      [Category.SIDE]: 2,
      [Category.SALAD]: 2,
      [Category.DESSERT]: 0,
    },
    theme: 'Especial do Dia',
    baseOption: 'Tradicional',
    chefChoice: false,
    useDefaultLayout: false,
    mealOptions: []
  });

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      setDefaultLayout(parsed);
      setConfig(prev => ({ ...prev, useDefaultLayout: true }));
    }
  }, []);

  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return (Object.values(generatedMenu.selections) as Dish[][]).reduce((acc, items) => acc + (items?.length || 0), 0);
  }, [generatedMenu]);

  const layoutScale = useMemo(() => {
    if (totalItemsCount <= 6) return 1.0;
    if (totalItemsCount <= 10) return 0.85;
    if (totalItemsCount <= 14) return 0.75;
    return 0.65;
  }, [totalItemsCount]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description || '').toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
      setToast({ message: "Identidade visual carregada!", type: "success" });
    };
    reader.readAsDataURL(file);
  };

  const handleImportExcel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const importedDishes: Dish[] = data.map((item, index) => ({
          id: `imp-${Date.now()}-${index}`,
          name: item.Nome || item.nome || 'Sem nome',
          category: (Object.values(Category).includes(item.Categoria || item.categoria) 
            ? item.Categoria || item.categoria 
            : Category.MEAT) as Category,
          description: item.Descrição || item.descrição || item.Descricao || ''
        }));

        setPendingDishes(importedDishes);
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo Excel.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = () => {
    if (pendingDishes) {
      setDishPool(prev => [...prev, ...pendingDishes]);
      setToast({ message: `${pendingDishes.length} pratos importados com sucesso!`, type: 'success' });
      setPendingDishes(null);
      setShowImportGuide(false);
    }
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Adicione pratos ao seu acervo antes.', type: 'error' });
      setActiveTab('inventory');
      return;
    }
    setIsGenerating(true);
    setGenerationStep('Iniciando o ChefAI...');
    try {
      const forcedTheme = config.useDefaultLayout && defaultLayout ? defaultLayout.visualTheme : undefined;
      const result = await generateMenuWithAI(dishPool, config, (step) => setGenerationStep(step), forcedTheme);
      setGeneratedMenu(result);
      setExportFormat('standard');
      setActiveTab('result');
      setToast({ message: 'Menu criado com perfeição!', type: 'success' });
    } catch (error) {
      setToast({ message: 'Falha na conexão com o ChefAI.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);
    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { 
          quality: 1, 
          pixelRatio: 3,
          style: {
            transform: 'none',
          }
        });
        const link = document.createElement('a');
        link.download = `Menu-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) {
        setToast({ message: 'Erro ao processar imagem.', type: 'error' });
      }
    }, 300);
  };

  const saveCurrentAsDefault = () => {
    if (generatedMenu && generatedMenu.visualTheme) {
      const data = {
        visualTheme: generatedMenu.visualTheme,
        theme: config.theme
      };
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(data));
      setDefaultLayout(data);
      setToast({ message: 'Layout salvo como padrão!', type: 'success' });
    }
  };

  const addMealOption = () => {
    if ((config.mealOptions?.length || 0) >= 3) {
      setToast({ message: 'Limite de 3 marmitas atingido.', type: 'error' });
      return;
    }
    const newOption: MealOption = {
      id: `meal-${Date.now()}`,
      title: '',
      price: '',
      description: ''
    };
    setConfig(prev => ({ ...prev, mealOptions: [...(prev.mealOptions || []), newOption] }));
  };

  const updateMealOption = (id: string, field: keyof MealOption, value: string) => {
    setConfig(prev => ({
      ...prev,
      mealOptions: prev.mealOptions?.map(opt => opt.id === id ? { ...opt, [field]: value } : opt)
    }));
  };

  const removeMealOption = (id: string) => {
    setConfig(prev => ({
      ...prev,
      mealOptions: prev.mealOptions?.filter(opt => opt.id !== id)
    }));
  };

  return (
    <div className="min-h-screen bg-[#faf9f6] text-[#2d2d2d] antialiased scrollbar-thin">
      {isGenerating && (
        <div className="fixed inset-0 z-[1000] bg-white/60 backdrop-blur-3xl flex flex-col items-center justify-center animate-in fade-in duration-700">
          <div className="relative mb-12">
            <div className="w-32 h-32 border-[1px] border-stone-100 rounded-full animate-ping opacity-20 absolute inset-0"></div>
            <div className="w-32 h-32 border-[2px] border-stone-200 border-t-orange-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-5xl">👨‍🍳</div>
          </div>
          <div className="text-center px-6">
            <h2 className="serif text-3xl font-bold text-stone-800 mb-3 tracking-tight">{generationStep}</h2>
            <div className="flex items-center justify-center gap-1">
               <span className="w-1.5 h-1.5 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
               <span className="w-1.5 h-1.5 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
               <span className="w-1.5 h-1.5 bg-orange-500 rounded-full animate-bounce"></span>
            </div>
          </div>
        </div>
      )}

      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[1100] animate-in slide-in-from-bottom-5">
          <div className={`px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 ${toast.type === 'success' ? 'bg-stone-900 text-white' : 'bg-red-500 text-white'}`}>
            <span className="text-sm font-bold uppercase tracking-widest">{toast.message}</span>
          </div>
        </div>
      )}

      <nav className="fixed top-0 left-0 right-0 h-20 bg-white/70 backdrop-blur-xl border-b border-stone-200/50 z-[100] px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-orange-500 rounded-xl flex items-center justify-center shadow-lg shadow-orange-200">
               <span className="text-white text-xl">🥗</span>
            </div>
            <div>
              <h1 className="serif text-xl font-black text-stone-900 tracking-tight leading-none">CHEF AI</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase tracking-widest">Digital Menu Studio</span>
            </div>
          </div>

          <div className="flex bg-stone-100/80 p-1.5 rounded-2xl border border-stone-200/30">
            {[
              { id: 'compose', label: 'Criação', icon: '✨' },
              { id: 'inventory', label: 'Acervo', icon: '📦' },
              { id: 'result', label: 'Preview', icon: '🖼️', disabled: !generatedMenu }
            ].map((t) => (
              <button 
                key={t.id}
                onClick={() => setActiveTab(t.id as TabType)}
                disabled={t.disabled}
                className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-[0.1em] transition-all flex items-center gap-2 ${activeTab === t.id ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400 hover:text-stone-600 disabled:opacity-30'}`}
              >
                <span>{t.icon}</span> {t.label}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-8 pt-32 pb-20">
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="lg:col-span-4 space-y-8">
              <section className="bg-white rounded-[32px] p-8 border border-stone-200/50 shadow-sm">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="serif text-2xl font-bold text-stone-800">Estação de Marca</h2>
                  {defaultLayout && (
                    <button 
                      onClick={() => setConfig(prev => ({ ...prev, useDefaultLayout: !prev.useDefaultLayout }))}
                      className={`px-3 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest transition-all flex items-center gap-1 ${config.useDefaultLayout ? 'bg-stone-900 text-white' : 'bg-stone-100 text-stone-400'}`}
                    >
                      {config.useDefaultLayout ? '🌟 Layout Padrão: ON' : '🌟 Usar Padrão?'}
                    </button>
                  )}
                </div>

                <div className={`relative group mb-8 transition-all duration-300 ${config.useDefaultLayout ? 'opacity-30 pointer-events-none grayscale' : ''}`}>
                  <label className={`cursor-pointer flex flex-col items-center justify-center py-12 rounded-[24px] border-2 border-dashed transition-all overflow-hidden ${logoPreview ? 'bg-stone-50 border-orange-200' : 'bg-stone-50/50 border-stone-200 hover:border-orange-300'}`}>
                    {logoPreview ? (
                      <div className="relative flex flex-col items-center">
                        <img src={logoPreview} alt="Brand" className="h-20 w-20 object-contain mb-4 bg-white p-2 rounded-xl shadow-sm" />
                        <span className="text-[10px] font-bold text-orange-500 uppercase tracking-widest">Logo Ativa</span>
                        <button onClick={(e) => { e.preventDefault(); setLogoPreview(null); setConfig({...config, logo: undefined})}} className="absolute -top-14 -right-14 w-8 h-8 bg-white border border-stone-100 rounded-full flex items-center justify-center shadow-sm hover:text-red-500">✕</button>
                      </div>
                    ) : (
                      <>
                        <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center shadow-sm mb-4 text-2xl">🖼️</div>
                        <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest text-center px-6 leading-relaxed">
                          Arraste sua Logomarca<br/><span className="text-orange-500">Para Identidade Visual</span>
                        </span>
                      </>
                    )}
                    <input type="file" className="hidden" accept="image/*" onChange={handleLogoUpload} />
                  </label>
                  {config.useDefaultLayout && (
                    <div className="absolute inset-0 flex items-center justify-center">
                       <span className="bg-white/90 px-4 py-2 rounded-xl text-[9px] font-bold text-stone-800 shadow-sm border border-stone-100 uppercase tracking-widest">Ignorado: Usando Layout Padrão</span>
                    </div>
                  )}
                </div>

                <div className="space-y-6">
                  <div>
                    <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest block mb-2 ml-1">Tema do Dia</label>
                    <input type="text" value={config.theme} onChange={e => setConfig({...config, theme: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-xl px-5 py-3 outline-none focus:border-orange-500 transition-all font-semibold text-stone-700" placeholder="Ex: Menu Mediterrâneo" />
                  </div>
                </div>
              </section>

              {/* Seção de Marmitas */}
              <section className="bg-white rounded-[32px] p-8 border border-stone-200/50 shadow-sm">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="serif text-2xl font-bold text-stone-800">Ofertas de Marmitas</h2>
                  <button onClick={addMealOption} disabled={(config.mealOptions?.length || 0) >= 3} className="w-8 h-8 bg-orange-500 text-white rounded-lg flex items-center justify-center shadow-lg disabled:opacity-30 disabled:grayscale transition-all">+</button>
                </div>
                <p className="text-[9px] text-stone-400 uppercase tracking-widest mb-6">Cadastre até 3 opções de marmitas para destaque</p>

                <div className="space-y-4">
                  {config.mealOptions?.map((opt, idx) => (
                    <div key={opt.id} className="p-4 rounded-2xl bg-stone-50 border border-stone-100 relative group animate-in slide-in-from-right-2">
                       <button onClick={() => removeMealOption(opt.id)} className="absolute -top-2 -right-2 w-6 h-6 bg-white border border-stone-100 rounded-full flex items-center justify-center text-[10px] shadow-sm hover:text-red-500 transition-colors">✕</button>
                       <div className="space-y-3">
                         <div className="flex gap-2">
                           <input 
                             type="text" 
                             placeholder="Ex: Marmita G" 
                             value={opt.title} 
                             onChange={e => updateMealOption(opt.id, 'title', e.target.value)}
                             className="flex-1 bg-white border border-stone-200 rounded-lg px-3 py-1.5 text-[11px] font-bold outline-none focus:border-orange-500"
                           />
                           <input 
                             type="text" 
                             placeholder="R$ 25,00" 
                             value={opt.price} 
                             onChange={e => updateMealOption(opt.id, 'price', e.target.value)}
                             className="w-20 bg-white border border-stone-200 rounded-lg px-3 py-1.5 text-[11px] font-bold outline-none focus:border-orange-500"
                           />
                         </div>
                         <textarea 
                           placeholder="Descrição curta..." 
                           value={opt.description} 
                           onChange={e => updateMealOption(opt.id, 'description', e.target.value)}
                           className="w-full bg-white border border-stone-200 rounded-lg px-3 py-1.5 text-[10px] outline-none focus:border-orange-500 h-16 resize-none"
                         />
                       </div>
                    </div>
                  ))}
                  {(!config.mealOptions || config.mealOptions.length === 0) && (
                    <div className="py-8 text-center border-2 border-dashed border-stone-100 rounded-2xl">
                       <span className="text-[9px] font-black text-stone-300 uppercase tracking-widest">Nenhuma marmita cadastrada</span>
                    </div>
                  )}
                </div>
              </section>

              <button 
                onClick={handleGenerate} 
                disabled={isGenerating}
                className={`group relative w-full h-[72px] rounded-[24px] font-black text-xs uppercase tracking-[0.2em] shadow-2xl transition-all duration-500 flex items-center justify-center overflow-hidden
                  ${isGenerating 
                    ? 'bg-stone-900 shadow-stone-200 cursor-wait' 
                    : 'bg-orange-500 text-white shadow-orange-200 hover:bg-orange-600 hover:-translate-y-1 active:scale-95'
                  }`}
              >
                <div className={`absolute inset-0 bg-gradient-to-r from-orange-600 via-orange-400 to-orange-600 bg-[length:200%_100%] transition-opacity duration-700 ${isGenerating ? 'opacity-0' : 'opacity-0 group-hover:opacity-100 animate-[shimmer_2s_infinite_linear]'}`}></div>

                {isGenerating ? (
                  <div className="relative z-10 flex items-center gap-4">
                    <div className="flex items-center gap-1">
                      <div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                      <div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                      <div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></div>
                    </div>
                    <span className="text-white">Preparando Menu...</span>
                  </div>
                ) : (
                  <div className="relative z-10 flex items-center gap-3">
                    <span className="text-xl group-hover:scale-125 transition-transform group-hover:rotate-12">🔥</span>
                    <span>Criar Menu Masterchef</span>
                  </div>
                )}
              </button>
            </div>

            <div className="lg:col-span-8">
              <section className="bg-white rounded-[40px] p-10 border border-stone-200/50 shadow-sm min-h-full transition-colors duration-500">
                <div className="flex items-center justify-between mb-12">
                   <div className="flex items-center gap-4">
                     <div>
                       <div className="flex items-center gap-2">
                         <h2 className="serif text-4xl font-bold text-stone-800">Estrutura</h2>
                         {config.chefChoice && (
                           <div className="bg-stone-100 p-1.5 rounded-full animate-in zoom-in duration-300">
                             <svg xmlns="http://www.w3.org/2000/svg" className="w-5 h-5 text-stone-400" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg>
                           </div>
                         )}
                       </div>
                       <p className="text-stone-400 text-xs uppercase tracking-widest mt-1">Defina as proporções do seu cardápio</p>
                     </div>
                   </div>
                   <div className="flex gap-2">
                     <button onClick={() => setConfig({...config, chefChoice: !config.chefChoice})} className={`px-5 py-2 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${config.chefChoice ? 'bg-orange-500 text-white shadow-lg shadow-orange-100' : 'bg-stone-100 text-stone-400 hover:bg-stone-200'}`}>
                       {config.chefChoice ? '✨ Escolha do Chef Ativa' : '✨ Escolha do Chef'}
                     </button>
                   </div>
                </div>

                <div className={`relative grid grid-cols-1 md:grid-cols-2 gap-8 transition-all duration-700 ${config.chefChoice ? 'opacity-40 grayscale-50 pointer-events-none scale-[0.98]' : 'opacity-100'}`}>
                  {config.chefChoice && (
                    <div className="absolute inset-0 z-10 flex items-center justify-center">
                      <div className="bg-white/80 backdrop-blur-sm px-8 py-4 rounded-3xl border border-stone-100 shadow-xl flex flex-col items-center gap-2 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <span className="text-3xl">👨‍🍳</span>
                        <span className="text-[10px] font-black text-stone-800 uppercase tracking-widest">IA no comando das quantidades</span>
                        <p className="text-[9px] text-stone-400 text-center uppercase tracking-widest">Os controles foram desativados para<br/>dar liberdade criativa ao ChefAI.</p>
                      </div>
                    </div>
                  )}
                  {CATEGORY_ORDER.map(cat => (
                    <div key={cat} className={`group p-6 rounded-3xl border border-stone-100 transition-all ${config.chefChoice ? 'bg-stone-100/50' : 'bg-stone-50/30 hover:bg-white hover:border-orange-200 hover:shadow-xl hover:shadow-orange-500/5'}`}>
                      <div className="flex items-center justify-between mb-4">
                        <div className="flex items-center gap-3">
                           <div className={`w-10 h-10 rounded-xl shadow-sm flex items-center justify-center text-xl transition-all ${config.chefChoice ? 'bg-stone-200 opacity-50' : 'bg-white'}`}>{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</div>
                           <span className={`font-bold transition-all ${config.chefChoice ? 'text-stone-300' : 'text-stone-700'}`}>{cat}s</span>
                        </div>
                        <div className={`flex items-center rounded-2xl p-1 shadow-sm border border-stone-100 transition-all ${config.chefChoice ? 'bg-stone-200/50' : 'bg-white'}`}>
                           <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat as Category] - 1)}}))} className={`w-8 h-8 rounded-xl font-black transition-all ${config.chefChoice ? 'text-stone-300 cursor-not-allowed' : 'text-stone-400 hover:bg-stone-50'}`}>-</button>
                           <span className={`w-10 text-center font-black text-sm transition-all ${config.chefChoice ? 'text-stone-300' : 'text-stone-800'}`}>{config.counts[cat] || 0}</span>
                           <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: (p.counts[cat as Category] || 0) + 1}}))} className={`w-8 h-8 rounded-xl font-black transition-all ${config.chefChoice ? 'text-stone-300 cursor-not-allowed' : 'text-stone-400 hover:bg-stone-50'}`}>+</button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
             <div className="bg-white rounded-[48px] p-12 border border-stone-200/50 shadow-sm">
                <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-16">
                  <div>
                    <h2 className="serif text-5xl font-bold text-stone-900 leading-tight">Gestão de Acervo</h2>
