  const [config, setConfig] = useState<MenuConfig>({
    counts: {
      [Category.BASE]: 2,
      [Category.MEAT]: 2,
      [Category.PASTA]: 0,
      [Category.SIDE]: 2,
      [Category.SALAD]: 2,
