                            <div className={`inline-block px-5 py-1.5 mb-3 rounded-full text-white font-bold uppercase tracking-[0.4em] shadow-lg ${exportFormat === 'story' ? 'text-[8px]' : 'text-[11px]'}`} style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor || '#e67e22', transform: exportFormat === 'story' ? `scale(${layoutScale})` : 'none' }}>
