                                className={`serif uppercase tracking-tighter leading-[0.95] font-black text-stone-900 transition-all`} 
                                style={{ 
                                    color: generatedMenu.visualTheme?.textColor,
                                    fontSize: exportFormat === 'story' ? `${Math.max(28, 52 * layoutScale)}px` : '82px',
                                    marginBottom: exportFormat === 'story' ? '8px' : '48px'
