import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme } from "../types";

async function analyzeLogoTheme(logoBase64: string): Promise<VisualTheme> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: "image/png",
      data: logoBase64.split(',')[1] || logoBase64,
    },
  };

  const prompt = `
    Analise esta logomarca de restaurante e extraia uma paleta de cores sofisticada e um conceito de design para um cardápio digital.
    Retorne um JSON com:
    1. primaryColor: A cor de maior destaque da marca (Hex).
    2. secondaryColor: Uma cor de suporte (Hex).
    3. backgroundColor: Uma cor de fundo (muito clara, creme, ou escura luxuosa) que combine (Hex).
    4. backgroundGradient: Um CSS linear-gradient (ou radial) moderno usando as cores da logo.
    5. textColor: Cor para o texto principal, garantindo legibilidade máxima sobre o backgroundColor (Hex).
    6. accentColor: Uma cor vibrante para selos e detalhes (Hex).
    7. patternType: Escolha o padrão de fundo que melhor combina com o estilo da logo: 'dots', 'grid', 'mesh', 'stripes' ou 'clean'.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [imagePart, { text: prompt }] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          primaryColor: { type: Type.STRING },
          secondaryColor: { type: Type.STRING },
          backgroundColor: { type: Type.STRING },
          backgroundGradient: { type: Type.STRING },
          textColor: { type: Type.STRING },
          accentColor: { type: Type.STRING },
          patternType: { type: Type.STRING, enum: ['dots', 'grid', 'mesh', 'stripes', 'clean'] },
        },
        required: ["primaryColor", "secondaryColor", "backgroundColor", "backgroundGradient", "textColor", "accentColor", "patternType"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
}

export async function generateDishDescription(dishName: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Você é um Chef Executivo de um restaurante com estrela Michelin. 
  Escreva uma descrição extremamente curta, elegante e apetitosa (máximo 8 palavras) para o prato: "${dishName}".
  Foque em texturas, métodos de cocção ou ingredientes nobres. 
  Não use frases prontas como 'delicioso' ou 'o melhor'. Seja cirúrgico.
  Responda APENAS com a descrição, sem aspas.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      temperature: 0.7,
      maxOutputTokens: 50,
    }
  });

  return response.text?.trim() || "";
}

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig,
  onProgress?: (step: string) => void,
  forcedTheme?: VisualTheme
): Promise<GeneratedMenu> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let visualTheme: VisualTheme | undefined = forcedTheme;

  if (!forcedTheme && config.logo) {
    onProgress?.("Sintonizando cores da sua marca...");
    try {
      visualTheme = await analyzeLogoTheme(config.logo);
    } catch (e) {
      console.error("Erro ao analisar logo:", e);
    }
  }

  onProgress?.("Selecionando os melhores ingredientes...");

  const structureRequested = config.chefChoice 
    ? "SUGESTÃO LIVRE E CRIATIVA: Crie um cardápio equilibrado e surpreendente baseado no acervo."
    : `QUANTIDADES OBRIGATÓRIAS POR CATEGORIA:\n${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${cat}: selecionar exatamente ${count} item(ns)`)
        .join('\n')}`;

  const prompt = `
    Você é um Chef Executivo premiado. Seu objetivo é montar o cardápio: "${config.theme}".

    ACERVO DISPONÍVEL (Use APENAS itens desta lista):
    ${JSON.stringify(dishPool.map(d => ({ name: d.name, category: d.category, description: d.description, isDefault: d.isDefault })))}

    REGRAS DE SELEÇÃO:
    1. ${structureRequested}
    2. Selecione apenas itens que existam no ACERVO acima.
    3. IMPORTANTE: Itens marcados com "isDefault: true" são PRATOS PADRÃO. Se uma categoria possuir um prato padrão e você estiver selecionando itens para essa categoria (quantidade > 0), você DEVE incluir esse prato padrão obrigatoriamente como uma das opções.
    4. Mantenha os nomes e descrições originais do acervo.
    5. Crie uma "chefNote" elegante (máximo 12 palavras) resumindo o conceito deste menu.

    ESTRUTURA DE RESPOSTA:
    Retorne um objeto JSON onde 'selections' contém arrays de objetos {name, description} para cada categoria solicitada.
  `;

  onProgress?.("Finalizando a montagem gourmet...");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        temperature: 0.7,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            selections: {
              type: Type.OBJECT,
              properties: {
                [Category.BASE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.PASTA]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              }
            },
            chefNote: { type: Type.STRING }
          },
          required: ["selections", "chefNote"]
        }
      }
    });

    const parsed = JSON.parse(response.text || '{}');

    const finalSelections: any = {};
    Object.values(Category).forEach(cat => {
      finalSelections[cat] = parsed.selections?.[cat] || [];
    });

    return { 
      selections: finalSelections, 
      chefNote: parsed.chefNote || "Bom apetite!", 
      visualTheme 
    };
  } catch (error) {
    console.error("Erro na geração da IA:", error);
    throw error;
  }
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI, generateDishDescription } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const LOCAL_STORAGE_KEY = 'chefai_default_layout';
const STORAGE_INVENTORY_KEY = 'chefai_inventory';
const STORAGE_CONFIG_KEY = 'chefai_session_config';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(() => {
    const saved = localStorage.getItem(STORAGE_INVENTORY_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_DISHES;
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);
  const [isBulkGenerating, setIsBulkGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [defaultLayout, setDefaultLayout] = useState<{ visualTheme: VisualTheme, theme: string } | null>(null);

  // Totais para cálculos de layout dinâmico
  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return (Object.values(generatedMenu.selections) as Dish[][]).reduce((acc, curr) => acc + (curr?.length || 0), 0);
  }, [generatedMenu]);

  const activeCategoriesCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return (Object.values(generatedMenu.selections) as Dish[][]).filter(list => list.length > 0).length;
  }, [generatedMenu]);

  const isMultiColumn = useMemo(() => {
    if (exportFormat === 'story' || !generatedMenu) return false;
    return totalItemsCount > 8 && activeCategoriesCount > 3;
  }, [exportFormat, totalItemsCount, activeCategoriesCount, generatedMenu]);

  const layoutScale = useMemo(() => {
    if (exportFormat === 'story') {
      if (totalItemsCount > 15) return 0.5;
      if (totalItemsCount > 10) return 0.65;
      return 0.85;
    }
    if (totalItemsCount > 12) return 0.9;
    return 1;
  }, [exportFormat, totalItemsCount]);

  const [config, setConfig] = useState<MenuConfig>(() => {
    const saved = localStorage.getItem(STORAGE_CONFIG_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      return {
        ...parsed,
        useDefaultLayout: false
      };
    }
    return {
      counts: {
        [Category.BASE]: 2,
        [Category.MEAT]: 2,
        [Category.PASTA]: 0,
        [Category.SIDE]: 2,
        [Category.SALAD]: 2,
        [Category.DESSERT]: 0,
      },
      theme: 'Especial do Dia',
      baseOption: 'Tradicional',
      chefChoice: false,
      useDefaultLayout: false,
      mealOptions: []
    };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_INVENTORY_KEY, JSON.stringify(dishPool));
  }, [dishPool]);

  useEffect(() => {
    const { logo, useDefaultLayout, ...persistableConfig } = config;
    localStorage.setItem(STORAGE_CONFIG_KEY, JSON.stringify(persistableConfig));
  }, [config]);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      setDefaultLayout(parsed);
      setConfig(prev => ({ ...prev, useDefaultLayout: true }));
    }
    if (config.logo) {
      setLogoPreview(config.logo);
    }
  }, []);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           (dish.description || '').toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    });
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
      setToast({ message: "Identidade visual carregada!", type: "success" });
    };
    reader.readAsDataURL(file);
  };

  const handleImportExcel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws) as any[];

        const importedDishes: Dish[] = data.map((item, index) => ({
          id: `imp-${Date.now()}-${index}`,
          name: item.Nome || item.nome || 'Sem nome',
          category: (Object.values(Category).includes(item.Categoria || item.categoria) 
            ? item.Categoria || item.categoria 
            : Category.MEAT) as Category,
          description: item.Descrição || item.descrição || item.Descricao || ''
        }));

        setPendingDishes(importedDishes);
      } catch (err) {
        setToast({ message: 'Erro ao processar arquivo Excel.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = () => {
    if (pendingDishes) {
      setDishPool(prev => [...prev, ...pendingDishes]);
      setToast({ message: `${pendingDishes.length} pratos importados com sucesso!`, type: 'success' });
      setPendingDishes(null);
      setShowImportGuide(false);
    }
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) {
      setToast({ message: 'Adicione pratos ao seu acervo antes.', type: 'error' });
      setActiveTab('inventory');
      return;
    }
    setIsGenerating(true);
    setGenerationStep('Iniciando o ChefAI...');
    try {
      const forcedTheme = config.useDefaultLayout && defaultLayout ? defaultLayout.visualTheme : undefined;
      const result = await generateMenuWithAI(dishPool, config, (step) => setGenerationStep(step), forcedTheme);
      setGeneratedMenu(result);
      setExportFormat('standard');
      setActiveTab('result');
      setToast({ message: 'Menu criado com perfeição!', type: 'success' });
    } catch (error) {
      console.error(error);
      setToast({ message: 'Falha na conexão com o ChefAI.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);
    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { 
          quality: 1, 
          pixelRatio: 3,
          skipAutoScale: true,
          style: {
            transform: 'none',
            overflow: 'visible'
          }
        });
        const link = document.createElement('a');
        link.download = `Menu-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) {
        setToast({ message: 'Erro ao processar imagem.', type: 'error' });
      }
    }, 500);
  };

  const saveCurrentAsDefault = () => {
    if (generatedMenu && generatedMenu.visualTheme) {
      const data = {
        visualTheme: generatedMenu.visualTheme,
        theme: config.theme
      };
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(data));
      setDefaultLayout(data);
      setToast({ message: 'Layout salvo como padrão!', type: 'success' });
    }
  };

  const handleAutoGenerateDesc = async () => {
    if (!editingDish || !editingDish.name) {
      setToast({ message: 'Insira o nome do prato primeiro.', type: 'error' });
      return;
    }
    setIsGeneratingDesc(true);
    try {
      const description = await generateDishDescription(editingDish.name);
      setEditingDish({ ...editingDish, description });
      setToast({ message: 'Descrição mágica gerada!', type: 'success' });
    } catch (err) {
      setToast({ message: 'Erro ao gerar descrição.', type: 'error' });
    } finally {
      setIsGeneratingDesc(false);
    }
  };

  const handleBulkGenerateDescriptions = async () => {
    const dishesWithoutDesc = dishPool.filter(d => !d.description || d.description.trim() === "");
    const totalToGenerate = dishesWithoutDesc.length;

    if (totalToGenerate === 0) {
      setToast({ message: 'Todos os pratos já possuem descrição.', type: 'success' });
      return;
    }

    if (!window.confirm(`Deseja gerar descrições automáticas para ${totalToGenerate} pratos? Isso pode levar um momento.`)) {
      return;
    }

    setIsBulkGenerating(true);
    let processedCount = 0;

    try {
      const updatedPool = [...dishPool];
      for (let i = 0; i < updatedPool.length; i++) {
        if (!updatedPool[i].description || updatedPool[i].description?.trim() === "") {
          processedCount++;
          setGenerationStep(`Redigindo descrições: ${processedCount} de ${totalToGenerate}`);

          try {
            const desc = await generateDishDescription(updatedPool[i].name);
            updatedPool[i] = { ...updatedPool[i], description: desc };

            // Re-batch state updates to maintain UI responsiveness
            if (processedCount % 5 === 0) {
              setDishPool([...updatedPool]);
            }
          } catch (e) {
            console.error(`Erro ao gerar para ${updatedPool[i].name}`, e);
          }
        }
      }
      setDishPool([...updatedPool]);
      setToast({ message: 'Acervo atualizado com descrições da IA!', type: 'success' });
    } catch (err) {
      setToast({ message: 'Erro durante a geração em massa.', type: 'error' });
    } finally {
      setIsBulkGenerating(false);
    }
  };

  const handleToggleDefault = (dish: Dish) => {
    setDishPool(prev => {
      return prev.map(d => {
        // Se for o mesmo prato, inverte o estado
        if (d.id === dish.id) {
          const newState = !d.isDefault;
          if (newState) {
            setToast({ message: `"${d.name}" definido como padrão da categoria ${d.category}!`, type: 'success' });
          }
          return { ...d, isDefault: newState };
        }
        // Se for outro prato da MESMA categoria, remove o padrão (apenas um por categoria)
        if (d.category === dish.category) {
          return { ...d, isDefault: false };
        }
        return d;
      });
    });
  };

  const addMealOption = () => {
    if ((config.mealOptions?.length || 0) >= 3) {
      setToast({ message: 'Limite de 3 marmitas atingido.', type: 'error' });
      return;
    }
    const newOption: MealOption = {
      id: `meal-${Date.now()}`,
      title: '',
      price: '',
      description: ''
    };
    setConfig(prev => ({ ...prev, mealOptions: [...(prev.mealOptions || []), newOption] }));
  };

  const updateMealOption = (id: string, field: keyof MealOption, value: string) => {
    let formattedValue = value;
    if (field === 'price' && value && !value.startsWith('R$')) {
      formattedValue = 'R$ ' + value;
    }

    setConfig(prev => ({
      ...prev,
      mealOptions: prev.mealOptions?.map(opt => opt.id === id ? { ...opt, [field]: formattedValue } : opt)
    }));
  };

  const removeMealOption = (id: string) => {
    setConfig(prev => ({
      ...prev,
      mealOptions: prev.mealOptions?.filter(opt => opt.id !== id)
    }));
  };

  const clearInventory = () => {
    if (window.confirm('Deseja realmente limpar todo o seu acervo?')) {
      setDishPool([]);
      setToast({ message: 'Acervo limpo com sucesso.', type: 'success' });
    }
  };

  const handleDeleteDish = (id: string, name: string) => {
    setDishPool(p => p.filter(d => d.id !== id));
    setToast({ message: `Prato "${name}" removido com sucesso!`, type: 'success' });
  };

  return (
    <div className="min-h-screen bg-[#faf9f6] text-[#2d2d2d] antialiased scrollbar-thin">
      {(isGenerating || isBulkGenerating) && (
        <div className="fixed inset-0 z-[1000] bg-white/60 backdrop-blur-3xl flex flex-col items-center justify-center animate-in fade-in duration-700">
          <div className="relative mb-12">
            <div className="w-32 h-32 border-[1px] border-stone-100 rounded-full animate-ping opacity-20 absolute inset-0"></div>
            <div className="w-32 h-32 border-[2px] border-stone-200 border-t-orange-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-5xl">👨‍🍳</div>
          </div>
          <div className="text-center px-6">
            <h2 className="serif text-3xl font-bold text-stone-800 mb-3 tracking-tight">{generationStep}</h2>
            <div className="flex items-center justify-center gap-1">
               <span className="w-1.5 h-1.5 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
               <span className="w-1.5 h-1.5 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
               <span className="w-1.5 h-1.5 bg-orange-500 rounded-full animate-bounce"></span>
            </div>
          </div>
        </div>
      )}

      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[1100] animate-in slide-in-from-bottom-5">
          <div className={`px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 ${toast.type === 'success' ? 'bg-stone-900 text-white' : 'bg-red-500 text-white'}`}>
            <span className="text-sm font-bold uppercase tracking-widest">{toast.message}</span>
          </div>
        </div>
      )}

      <nav className="fixed top-0 left-0 right-0 h-20 bg-white/70 backdrop-blur-xl border-b border-stone-200/50 z-[100] px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-orange-500 rounded-xl flex items-center justify-center shadow-lg shadow-orange-200">
               <span className="text-white text-xl">🥗</span>
            </div>
            <div>
              <h1 className="serif text-xl font-black text-stone-900 tracking-tight leading-none">CHEF AI</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase tracking-widest">Digital Menu Studio</span>
            </div>
          </div>

          <div className="flex bg-stone-100/80 p-1.5 rounded-2xl border border-stone-200/30">
            {[
              { id: 'compose', label: 'Criação', icon: '✨' },
              { id: 'inventory', label: 'Acervo', icon: '📦' },
              { id: 'result', label: 'Preview', icon: '🖼️', disabled: !generatedMenu }
            ].map((t) => (
              <button 
                key={t.id}
                onClick={() => setActiveTab(t.id as TabType)}
                disabled={t.disabled}
                className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-[0.1em] transition-all flex items-center gap-2 ${activeTab === t.id ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400 hover:text-stone-600 disabled:opacity-30'}`}
              >
                <span>{t.icon}</span> {t.label}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-8 pt-32 pb-20">
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="lg:col-span-4 space-y-8">
              <section className="bg-white rounded-[32px] p-8 border border-stone-200/50 shadow-sm">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="serif text-2xl font-bold text-stone-800">Estação de Marca</h2>
                  {defaultLayout && (
                    <button 
                      onClick={() => setConfig(prev => ({ ...prev, useDefaultLayout: !prev.useDefaultLayout }))}
                      className={`px-3 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest transition-all flex items-center gap-1 ${config.useDefaultLayout ? 'bg-stone-900 text-white' : 'bg-stone-100 text-stone-400'}`}
                    >
                      {config.useDefaultLayout ? '🌟 Layout Padrão: ON' : '🌟 Usar Padrão?'}
                    </button>
                  )}
                </div>

                <div className={`relative group mb-8 transition-all duration-300 ${config.useDefaultLayout ? 'opacity-30 pointer-events-none grayscale' : ''}`}>
                  <label className={`cursor-pointer flex flex-col items-center justify-center py-12 rounded-[24px] border-2 border-dashed transition-all overflow-hidden ${logoPreview ? 'bg-stone-50 border-orange-200' : 'bg-stone-50/50 border-stone-200 hover:border-orange-300'}`}>
                    {logoPreview ? (
                      <div className="relative flex flex-col items-center">
                        <img src={logoPreview} alt="Brand" className="h-20 w-20 object-contain mb-4 bg-white p-2 rounded-xl shadow-sm" />
                        <span className="text-[10px] font-bold text-orange-500 uppercase tracking-widest">Logo Ativa</span>
                        <button onClick={(e) => { e.preventDefault(); setLogoPreview(null); setConfig({...config, logo: undefined})}} className="absolute -top-14 -right-14 w-8 h-8 bg-white border border-stone-100 rounded-full flex items-center justify-center shadow-sm hover:text-red-500">✕</button>
                      </div>
                    ) : (
                      <>
                        <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center shadow-sm mb-4 text-2xl">🖼️</div>
                        <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest text-center px-6 leading-relaxed">
                          Arraste sua Logomarca<br/><span className="text-orange-500">Para Identidade Visual</span>
                        </span>
                      </>
                    )}
                    <input type="file" className="hidden" accept="image/*" onChange={handleLogoUpload} />
                  </label>
                  {config.useDefaultLayout && (
                    <div className="absolute inset-0 flex items-center justify-center">
                       <span className="bg-white/90 px-4 py-2 rounded-xl text-[9px] font-bold text-stone-800 shadow-sm border border-stone-100 uppercase tracking-widest">Ignorado: Usando Layout Padrão</span>
                    </div>
                  )}
                </div>

                <div className="space-y-6">
                  <div>
                    <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest block mb-2 ml-1">Tema do Dia</label>
                    <input type="text" value={config.theme} onChange={e => setConfig({...config, theme: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-xl px-5 py-3 outline-none focus:border-orange-500 transition-all font-semibold text-stone-700" placeholder="Ex: Menu Mediterrâneo" />
                  </div>
                </div>
              </section>

              <section className="bg-white rounded-[32px] p-8 border border-stone-200/50 shadow-sm">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="serif text-2xl font-bold text-stone-800">Ofertas de Marmitas</h2>
                  <button onClick={addMealOption} disabled={(config.mealOptions?.length || 0) >= 3} className="w-8 h-8 bg-orange-500 text-white rounded-lg flex items-center justify-center shadow-lg disabled:opacity-30 disabled:grayscale transition-all hover:scale-105 active:scale-95 transition-transform">+</button>
                </div>
                <p className="text-[9px] text-stone-400 uppercase tracking-widest mb-6">Cadastre até 3 opções de marmitas para destaque</p>

                <div className="space-y-4">
                  {config.mealOptions?.map((opt, idx) => (
                    <div key={opt.id} className="p-5 rounded-2xl bg-stone-50 border border-stone-100 relative group animate-in slide-in-from-right-2">
                       <button onClick={() => removeMealOption(opt.id)} className="absolute -top-2 -right-2 w-7 h-7 bg-white border border-stone-100 rounded-full flex items-center justify-center text-[10px] shadow-sm hover:text-red-500 hover:border-red-100 transition-colors z-10">✕</button>
                       <div className="space-y-4">
                         <div className="grid grid-cols-12 gap-3">
                           <div className="col-span-7">
                             <label className="text-[8px] font-black text-stone-400 uppercase tracking-widest block mb-1.5 ml-1">Título/Tamanho</label>
                             <input 
                               type="text" 
                               placeholder="Ex: Marmita G" 
                               value={opt.title} 
                               onChange={e => updateMealOption(opt.id, 'title', e.target.value)}
                               className="w-full bg-white border border-stone-200 rounded-xl px-3 py-2 text-[11px] font-bold outline-none focus:border-orange-500 transition-all"
                             />
                           </div>
                           <div className="col-span-5">
                             <label className="text-[8px] font-black text-stone-400 uppercase tracking-widest block mb-1.5 ml-1">Preço Sugerido</label>
                             <div className="relative">
                               <input 
