import { GoogleGenAI, Type } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme } from "../types";

async function analyzeLogoTheme(logoBase64: string): Promise<VisualTheme> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: "image/png",
      data: logoBase64.split(',')[1] || logoBase64,
    },
  };

  const prompt = `
    Analise esta logomarca de restaurante e extraia uma paleta de cores sofisticada e um conceito de design para um cardápio digital.
    Retorne um JSON com:
    1. primaryColor: A cor de maior destaque da marca (Hex).
    2. secondaryColor: Uma cor de suporte (Hex).
    3. backgroundColor: Uma cor de fundo (muito clara, creme, ou escura luxuosa) que combine (Hex).
    4. backgroundGradient: Um CSS linear-gradient moderno usando as cores da logo.
    5. textColor: Cor para o texto principal, garantindo legibilidade máxima sobre o backgroundColor (Hex).
    6. accentColor: Uma cor vibrante para selos e detalhes (Hex).
    7. patternType: Escolha o padrão de fundo: 'dots', 'grid', 'mesh', 'stripes' ou 'clean'.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [imagePart, { text: prompt }] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          primaryColor: { type: Type.STRING },
          secondaryColor: { type: Type.STRING },
          backgroundColor: { type: Type.STRING },
          backgroundGradient: { type: Type.STRING },
          textColor: { type: Type.STRING },
          accentColor: { type: Type.STRING },
          patternType: { type: Type.STRING, enum: ['dots', 'grid', 'mesh', 'stripes', 'clean'] },
        },
        required: ["primaryColor", "secondaryColor", "backgroundColor", "backgroundGradient", "textColor", "accentColor", "patternType"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
}

export async function generateDishDescription(dishName: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Você é um Chef Michelin. Escreva uma descrição curta, elegante e apetitosa (max 8 palavras) para: "${dishName}". Foque em texturas e sabores. Responda APENAS a frase.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: { temperature: 0.7 }
  });

  return response.text?.trim() || "";
}

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig,
  onProgress?: (step: string) => void,
  forcedTheme?: VisualTheme
): Promise<GeneratedMenu> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let visualTheme: VisualTheme | undefined = forcedTheme;

  if (!forcedTheme && config.logo) {
    onProgress?.("Sintonizando identidade visual...");
    try {
      visualTheme = await analyzeLogoTheme(config.logo);
    } catch (e) {
      console.error("Erro ao analisar logo:", e);
    }
  }

  onProgress?.("Selecionando pratos do acervo...");

  const structureRequested = config.chefChoice 
    ? "ESTILO LIVRE: Escolha as melhores combinações do acervo para um menu equilibrado."
    : `METAS POR CATEGORIA:\n${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${cat}: selecionar exatamente ${count} item(ns)`)
        .join('\n')}`;

  const prompt = `
    Aja como um Chef Executivo montando o cardápio: "${config.theme}".

    ACERVO DISPONÍVEL (Use APENAS itens desta lista exata):
    ${JSON.stringify(dishPool.map(d => ({ name: d.name, category: d.category, description: d.description, isDefault: d.isDefault })))}

    REGRAS DE OURO:
    1. SELEÇÃO: ${structureRequested}
    2. PRATOS PADRÃO: Se um item tem "isDefault: true", você DEVE incluí-lo se a categoria dele tiver quantidade > 0. Ele conta como 1 daquela categoria.
    3. FIDELIDADE: Use nomes e descrições ORIGINAIS do acervo.
    4. CHEF NOTE: Crie uma frase de boas-vindas elegante (max 15 palavras).

    Retorne JSON seguindo o schema rigorosamente.
  `;

  onProgress?.("Finalizando design gastronômico...");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        temperature: 0.7,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            selections: {
              type: Type.OBJECT,
              properties: {
                [Category.BASE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.PASTA]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              }
            },
            chefNote: { type: Type.STRING }
          },
          required: ["selections", "chefNote"]
        }
      }
    });

    const parsed = JSON.parse(response.text || '{}');
    const finalSelections: any = {};
    Object.values(Category).forEach(cat => {
      finalSelections[cat] = parsed.selections?.[cat] || [];
    });

    return { selections: finalSelections, chefNote: parsed.chefNote || "Uma experiência gastronômica única preparada para você.", visualTheme };
  } catch (error) {
    console.error("Erro ChefAI:", error);
    throw error;
  }
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI, generateDishDescription } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const LOCAL_STORAGE_KEY = 'chefai_default_layout';
const STORAGE_INVENTORY_KEY = 'chefai_inventory';
const STORAGE_CONFIG_KEY = 'chefai_session_config';

const App: React.FC = () => {
  const [dishPool, setDishPool] = useState<Dish[]>(() => {
    const saved = localStorage.getItem(STORAGE_INVENTORY_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_DISHES;
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);
  const [isBulkGenerating, setIsBulkGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [defaultLayout, setDefaultLayout] = useState<{ visualTheme: VisualTheme, theme: string } | null>(null);

  // Dynamic Layout Calculations
  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return (Object.values(generatedMenu.selections) as any[][]).reduce((acc, curr) => acc + (curr?.length || 0), 0);
  }, [generatedMenu]);

  const activeCategoriesCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return (Object.values(generatedMenu.selections) as any[][]).filter(list => list.length > 0).length;
  }, [generatedMenu]);

  const isMultiColumn = useMemo(() => {
    if (exportFormat === 'story' || !generatedMenu) return false;
    return totalItemsCount > 10;
  }, [exportFormat, totalItemsCount, generatedMenu]);

  const layoutScale = useMemo(() => {
    if (exportFormat === 'story') {
      if (totalItemsCount > 12) return 0.6;
      if (totalItemsCount > 8) return 0.75;
      return 0.9;
    }
    return 1;
  }, [exportFormat, totalItemsCount]);

  const [config, setConfig] = useState<MenuConfig>(() => {
    const saved = localStorage.getItem(STORAGE_CONFIG_KEY);
    if (saved) return { ...JSON.parse(saved), useDefaultLayout: false };
    return {
      counts: { [Category.BASE]: 2, [Category.MEAT]: 2, [Category.PASTA]: 0, [Category.SIDE]: 2, [Category.SALAD]: 2, [Category.DESSERT]: 0 },
      theme: 'Cardápio Especial', baseOption: 'Tradicional', chefChoice: false, useDefaultLayout: false, mealOptions: []
    };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_INVENTORY_KEY, JSON.stringify(dishPool));
  }, [dishPool]);

  useEffect(() => {
    const { logo, useDefaultLayout, ...persistableConfig } = config;
    localStorage.setItem(STORAGE_CONFIG_KEY, JSON.stringify(persistableConfig));
  }, [config]);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      setDefaultLayout(parsed);
      setConfig(prev => ({ ...prev, useDefaultLayout: true }));
    }
  }, []);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    }).sort((a, b) => (a.isDefault === b.isDefault) ? 0 : a.isDefault ? -1 : 1);
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
    };
    reader.readAsDataURL(file);
  };

  const handleImportExcel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const wb = XLSX.read(evt.target?.result, { type: 'binary' });
        const data = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]) as any[];
        setPendingDishes(data.map((item, i) => ({
          id: `imp-${Date.now()}-${i}`,
          name: item.Nome || item.nome || 'S/N',
          category: (Object.values(Category).includes(item.Categoria) ? item.Categoria : Category.MEAT) as Category,
          description: item.Descrição || item.descrição || ''
        })));
      } catch (err) { setToast({ message: 'Erro no Excel', type: 'error' }); }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = () => {
    if (pendingDishes) {
      setDishPool(prev => [...prev, ...pendingDishes]);
      setToast({ message: 'Pratos importados!', type: 'success' });
      setPendingDishes(null);
      setShowImportGuide(false);
    }
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) { setToast({ message: 'Acervo vazio!', type: 'error' }); setActiveTab('inventory'); return; }
    setIsGenerating(true);
    setGenerationStep('ChefAI está pensando...');
    try {
      const forcedTheme = config.useDefaultLayout && defaultLayout ? defaultLayout.visualTheme : undefined;
      const result = await generateMenuWithAI(dishPool, config, (step) => setGenerationStep(step), forcedTheme);
      setGeneratedMenu(result);
      setActiveTab('result');
      setToast({ message: 'Menu finalizado!', type: 'success' });
    } catch (error) { setToast({ message: 'Erro na IA', type: 'error' }); }
    finally { setIsGenerating(false); }
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);
    setToast({ message: 'Processando imagem...', type: 'success' });
    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { quality: 1, pixelRatio: 3 });
        const link = document.createElement('a');
        link.download = `Menu-${Date.now()}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) { setToast({ message: 'Falha na imagem', type: 'error' }); }
    }, 600);
  };

  const handleToggleDefault = (dish: Dish) => {
    setDishPool(prev => prev.map(d => {
      if (d.id === dish.id) return { ...d, isDefault: !d.isDefault };
      if (d.category === dish.category && !d.isDefault === false) return { ...d, isDefault: false };
      return d;
    }));
    if (!dish.isDefault) setToast({ message: `${dish.name} é o novo padrão para ${dish.category}`, type: 'success' });
  };

  const handleBulkGenerateDescriptions = async () => {
    const targets = dishPool.filter(d => !d.description);
    if (targets.length === 0) { setToast({ message: 'Tudo preenchido!', type: 'success' }); return; }
    if (!window.confirm(`Gerar descrições para ${targets.length} pratos?`)) return;
    setIsBulkGenerating(true);
    let count = 0;
    const updated = [...dishPool];
    for (let i = 0; i < updated.length; i++) {
      if (!updated[i].description) {
        count++;
        setGenerationStep(`Chef escrevendo: ${count}/${targets.length}`);
        try {
          updated[i] = { ...updated[i], description: await generateDishDescription(updated[i].name) };
          if (count % 3 === 0) setDishPool([...updated]);
        } catch (e) { console.error(e); }
      }
    }
    setDishPool(updated);
    setIsBulkGenerating(false);
    setToast({ message: 'Descrições atualizadas!', type: 'success' });
  };

  return (
    <div className="min-h-screen bg-[#faf9f6] text-[#2d2d2d] antialiased scrollbar-thin">
      {(isGenerating || isBulkGenerating) && (
        <div className="fixed inset-0 z-[1000] bg-white/80 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-500">
          <div className="relative mb-8">
            <div className="w-24 h-24 border-4 border-stone-100 border-t-orange-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-3xl">👨‍🍳</div>
          </div>
          <h2 className="serif text-2xl font-bold text-stone-800 animate-pulse">{generationStep}</h2>
        </div>
      )}

      {toast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[1100] animate-in slide-in-from-bottom-4">
