                    setEditingDish({...editingDish, description: desc});
                    setIsGeneratingDesc(false);
                  }} className="text-[9px] font-black text-orange-500 uppercase">✨ IA</button>
                </div>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full bg-stone-50 rounded-2xl px-5 py-4 outline-none min-h-[100px] text-sm" />
