              <div className="flex gap-4 pt-4">
                <button onClick={() => setEditingDish(null)} className="flex-1 py-4 font-black uppercase text-[10px] text-stone-400">Cancelar</button>
                <button onClick={() => {
                  setDishPool(p => {
                    const idx = p.findIndex(d => d.id === editingDish.id);
                    if (idx >= 0) {
                      const copy = [...p];
                      copy[idx] = editingDish;
                      return copy;
                    }
                    return [...p, editingDish];
                  });
                  setEditingDish(null);
                  setToast({ message: 'Salvo com sucesso!', type: 'success' });
