};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI, generateDishDescription } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const LOCAL_STORAGE_KEY = 'chefai_default_layout';
const STORAGE_INVENTORY_KEY = 'chefai_inventory';
const STORAGE_CONFIG_KEY = 'chefai_session_config';

const App: React.FC = () => {
  // 1. Inventory State with Persistence
  const [dishPool, setDishPool] = useState<Dish[]>(() => {
    const saved = localStorage.getItem(STORAGE_INVENTORY_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_DISHES;
  });

  // 2. Configuration State with Robust LocalStorage Hydration
  const [config, setConfig] = useState<MenuConfig>(() => {
    const saved = localStorage.getItem(STORAGE_CONFIG_KEY);
    const defaultConfig: MenuConfig = {
      counts: {
        [Category.BASE]: 2,
        [Category.MEAT]: 2,
        [Category.PASTA]: 0,
        [Category.SIDE]: 2,
        [Category.SALAD]: 2,
        [Category.DESSERT]: 0
      },
      theme: 'Cardápio Especial do Dia',
      baseOption: 'Tradicional',
      chefChoice: false,
      useDefaultLayout: false,
      mealOptions: []
    };

    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return {
          ...defaultConfig,
          ...parsed,
          // Garante que counts tenha todas as categorias mesmo se o save for antigo
          counts: { ...defaultConfig.counts, ...parsed.counts },
          useDefaultLayout: false // Sempre inicia desligado para nova sessão
        };
      } catch (e) {
        return defaultConfig;
      }
    }
    return defaultConfig;
  });

  // 3. UI States
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);
  const [isBulkGenerating, setIsBulkGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [defaultLayout, setDefaultLayout] = useState<{ visualTheme: VisualTheme, theme: string } | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Persistence Effects
  useEffect(() => {
    localStorage.setItem(STORAGE_INVENTORY_KEY, JSON.stringify(dishPool));
  }, [dishPool]);

  useEffect(() => {
    const { logo, useDefaultLayout, ...persistableConfig } = config;
    localStorage.setItem(STORAGE_CONFIG_KEY, JSON.stringify(persistableConfig));
  }, [config]);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) setDefaultLayout(JSON.parse(saved));
    if (config.logo) setLogoPreview(config.logo);
  }, []);

  // Dynamic Layout Calculations
  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return (Object.values(generatedMenu.selections) as any[][]).reduce((acc, curr) => acc + (curr?.length || 0), 0);
  }, [generatedMenu]);

  const isMultiColumn = useMemo(() => {
    if (exportFormat === 'story' || !generatedMenu) return false;
    return totalItemsCount > 10;
  }, [exportFormat, totalItemsCount, generatedMenu]);

  const layoutScale = useMemo(() => {
    if (exportFormat === 'story') {
      if (totalItemsCount > 15) return 0.55;
      if (totalItemsCount > 10) return 0.7;
      return 0.85;
    }
    return 1;
  }, [exportFormat, totalItemsCount]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    }).sort((a, b) => (a.isDefault === b.isDefault) ? 0 : a.isDefault ? -1 : 1);
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Handlers
  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
    };
    reader.readAsDataURL(file);
  };

  const handleToggleDefault = (dish: Dish) => {
    setDishPool(prev => prev.map(d => {
      if (d.id === dish.id) return { ...d, isDefault: !d.isDefault };
      if (d.category === dish.category) return { ...d, isDefault: false };
      return d;
    }));
    if (!dish.isDefault) {
      setToast({ message: `${dish.name} agora é o padrão de ${dish.category}`, type: 'success' });
    }
  };

  const updateMealOption = (id: string, field: keyof MealOption, value: string) => {
    let finalValue = value;
    if (field === 'price' && value && !value.startsWith('R$')) {
      finalValue = 'R$ ' + value;
    }
    setConfig(prev => ({
      ...prev,
      mealOptions: prev.mealOptions?.map(o => o.id === id ? { ...o, [field]: finalValue } : o)
    }));
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) { setToast({ message: 'Seu acervo está vazio!', type: 'error' }); setActiveTab('inventory'); return; }
    setIsGenerating(true);
    setGenerationStep('ChefAI está criando sua obra-prima...');
    try {
      const forcedTheme = config.useDefaultLayout && defaultLayout ? defaultLayout.visualTheme : undefined;
      const result = await generateMenuWithAI(dishPool, config, (step) => setGenerationStep(step), forcedTheme);
      setGeneratedMenu(result);
      setActiveTab('result');
      setToast({ message: 'Menu gerado com sucesso!', type: 'success' });
    } catch (error) {
      setToast({ message: 'Erro ao conectar com o ChefAI.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);
    setToast({ message: 'Preparando sua imagem...', type: 'success' });
    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { quality: 1, pixelRatio: 3, skipAutoScale: true });
        const link = document.createElement('a');
        link.download = `ChefAI-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) { setToast({ message: 'Erro ao baixar imagem.', type: 'error' }); }
    }, 600);
  };

  const handleBulkGenerateDescriptions = async () => {
    const targets = dishPool.filter(d => !d.description);
    if (targets.length === 0) { setToast({ message: 'Todos os itens já possuem descrição!', type: 'success' }); return; }
    if (!window.confirm(`Deseja gerar descrições automáticas para ${targets.length} pratos?`)) return;

    setIsBulkGenerating(true);
    const updated = [...dishPool];
    for (let i = 0; i < updated.length; i++) {
      if (!updated[i].description) {
        setGenerationStep(`Redigindo: ${updated[i].name}`);
        try {
          updated[i] = { ...updated[i], description: await generateDishDescription(updated[i].name) };
          // Atualiza o estado parcial para feedback visual
          if (i % 3 === 0) setDishPool([...updated]);
        } catch (e) { console.error(e); }
      }
    }
    setDishPool(updated);
    setIsBulkGenerating(false);
    setToast({ message: 'Acervo atualizado com descrições!', type: 'success' });
  };

  return (
    <div className="min-h-screen bg-[#faf9f6] text-[#2d2d2d] antialiased scrollbar-thin">
      {/* Loading Overlay */}
      {(isGenerating || isBulkGenerating) && (
        <div className="fixed inset-0 z-[1000] bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-500">
          <div className="relative mb-10">
            <div className="w-28 h-28 border-4 border-stone-100 border-t-orange-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-4xl">👨‍🍳</div>
          </div>
          <h2 className="serif text-3xl font-bold text-stone-800 animate-pulse tracking-tight">{generationStep}</h2>
          <p className="text-stone-400 text-[10px] uppercase tracking-[0.3em] mt-4">Aguarde a finalização do Chef</p>
        </div>
      )}

      {/* Toast Notification */}
      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[1100] animate-in slide-in-from-bottom-6">
          <div className={`px-8 py-4 rounded-3xl shadow-2xl font-bold uppercase tracking-widest text-[10px] flex items-center gap-3 ${toast.type === 'success' ? 'bg-stone-900 text-white' : 'bg-red-500 text-white'}`}>
            <span className="text-lg">{toast.type === 'success' ? '✨' : '⚠️'}</span>
            {toast.message}
          </div>
        </div>
      )}

      {/* Navbar */}
      <nav className="fixed top-0 inset-x-0 h-20 bg-white/80 backdrop-blur-lg border-b border-stone-200/50 z-[100] px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center shadow-xl shadow-orange-200 text-white text-2xl">🥗</div>
            <div className="leading-tight">
              <h1 className="serif text-2xl font-black tracking-tighter">CHEF AI</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase tracking-[0.4em]">Menu Designer</span>
            </div>
          </div>
          <div className="flex bg-stone-100 p-1.5 rounded-2xl shadow-inner">
            {[
              { id: 'compose', label: 'Criação', icon: '✨' },
              { id: 'inventory', label: 'Acervo', icon: '📦' },
              { id: 'result', label: 'Preview', icon: '🖼️', disabled: !generatedMenu }
            ].map((t) => (
              <button 
                key={t.id}
                onClick={() => setActiveTab(t.id as TabType)}
                disabled={t.disabled}
                className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === t.id ? 'bg-white text-stone-900 shadow-md' : 'text-stone-400 hover:text-stone-600 disabled:opacity-30'}`}
              >
                <span>{t.icon}</span> {t.label}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-8 pt-32 pb-24">
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
            {/* Left Column: Config */}
            <div className="lg:col-span-4 space-y-8">
              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <h2 className="serif text-2xl font-bold mb-6 text-stone-800">Identidade</h2>
                <div className="space-y-6">
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Logomarca do Estabelecimento</span>
                    <div className="relative h-40 rounded-3xl bg-stone-50 border-2 border-dashed border-stone-200 flex items-center justify-center cursor-pointer hover:border-orange-400 hover:bg-orange-50/30 transition-all overflow-hidden group">
                      {logoPreview ? (
                        <div className="relative w-full h-full p-6">
                          <img src={logoPreview} className="w-full h-full object-contain" alt="Preview" />
                          <button onClick={(e) => { e.preventDefault(); setLogoPreview(null); setConfig({...config, logo: undefined}); }} className="absolute top-2 right-2 w-8 h-8 bg-white/80 backdrop-blur-sm rounded-full text-xs shadow-sm hover:text-red-500 transition-colors">✕</button>
                        </div>
                      ) : (
                        <div className="text-center">
                          <span className="text-3xl block mb-2 opacity-30">🖼️</span>
                          <span className="text-[10px] font-bold text-stone-300 uppercase tracking-widest">Upload .png ou .jpg</span>
                        </div>
                      )}
                      <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleLogoUpload} />
                    </div>
                  </label>
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Título Principal do Cardápio</span>
                    <input type="text" value={config.theme} onChange={e => setConfig({...config, theme: e.target.value})} className="w-full bg-stone-50 rounded-2xl px-5 py-4 outline-none focus:ring-2 ring-orange-100 font-bold text-stone-700 border border-stone-100 transition-all" placeholder="Ex: Menu Mediterrâneo" />
                  </label>
                </div>
              </section>

              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="serif text-2xl font-bold text-stone-800">Marmitas</h2>
                  <button onClick={() => setConfig(prev => ({...prev, mealOptions: [...(prev.mealOptions||[]), {id: Date.now().toString(), title: '', price: ''}]}))} className="w-10 h-10 bg-orange-500 text-white rounded-2xl shadow-lg shadow-orange-100 hover:scale-105 active:scale-95 transition-all">+</button>
                </div>
                <div className="space-y-4">
                  {config.mealOptions?.map(opt => (
                    <div key={opt.id} className="p-5 bg-stone-50 rounded-[2rem] border border-stone-100 relative animate-in zoom-in-95">
                      <button onClick={() => setConfig(prev => ({...prev, mealOptions: prev.mealOptions?.filter(o => o.id !== opt.id)}))} className="absolute -top-2 -right-2 w-7 h-7 bg-white border border-stone-100 rounded-full flex items-center justify-center text-[10px] shadow-sm hover:text-red-500 hover:border-red-100 transition-all">✕</button>
                      <div className="space-y-3">
                        <input placeholder="Ex: Marmita G" value={opt.title} onChange={e => updateMealOption(opt.id, 'title', e.target.value)} className="bg-white border border-stone-100 rounded-xl px-4 py-2 font-bold text-xs w-full outline-none focus:border-orange-500 transition-all" />
                        <input placeholder="R$ 00,00" value={opt.price} onChange={e => updateMealOption(opt.id, 'price', e.target.value)} className="bg-white border border-stone-100 rounded-xl px-4 py-2 text-[11px] text-orange-600 font-black outline-none focus:border-orange-500 transition-all" />
                      </div>
                    </div>
                  ))}
                  {(!config.mealOptions || config.mealOptions.length === 0) && (
                    <div className="py-6 text-center border-2 border-dashed border-stone-100 rounded-3xl opacity-30">
                      <span className="text-[10px] font-black uppercase tracking-widest">Sem ofertas cadastradas</span>
                    </div>
                  )}
                </div>
              </section>

              <button onClick={handleGenerate} disabled={isGenerating} className="group relative w-full py-6 bg-orange-500 text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-xs shadow-2xl shadow-orange-200 hover:scale-[1.02] active:scale-95 transition-all overflow-hidden">
                <div className="absolute inset-0 bg-white/20 -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                {isGenerating ? 'Chef Processando...' : 'Montar Cardápio Gourmet'}
              </button>
            </div>

            {/* Right Column: Structure */}
            <div className="lg:col-span-8 bg-white rounded-[3.5rem] p-12 shadow-sm border border-stone-100 flex flex-col">
              <div className="flex justify-between items-center mb-12">
                <div>
                  <h2 className="serif text-4xl font-bold text-stone-800">Estrutura</h2>
                  <p className="text-stone-400 text-xs uppercase tracking-widest mt-1">Defina a composição ideal do cardápio</p>
                </div>
                <button onClick={() => setConfig({...config, chefChoice: !config.chefChoice})} className={`px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest shadow-sm transition-all ${config.chefChoice ? 'bg-orange-500 text-white' : 'bg-stone-100 text-stone-400 hover:bg-stone-200'}`}>
                  {config.chefChoice ? '✨ Escolha do Chef Ativa' : '✨ Escolha do Chef'}
                </button>
              </div>

              <div className={`grid grid-cols-1 md:grid-cols-2 gap-6 transition-all duration-500 ${config.chefChoice ? 'opacity-30 pointer-events-none grayscale scale-[0.98]' : 'opacity-100'}`}>
                {CATEGORY_ORDER.map(cat => (
                  <div key={cat} className="group flex items-center justify-between p-6 bg-stone-50 rounded-[2.5rem] border border-stone-100 hover:bg-white hover:border-orange-200 hover:shadow-xl hover:shadow-orange-500/5 transition-all">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-2xl shadow-sm flex items-center justify-center text-2xl group-hover:scale-110 transition-transform">{(ICONS as any)[Object.keys(Category).find(k => (Category as any)[k] === cat) || 'BASE']}</div>
                      <span className="font-bold text-stone-700 tracking-tight">{cat}s</span>
                    </div>
                    <div className="flex items-center gap-5 bg-white px-5 py-2 rounded-2xl shadow-sm border border-stone-100">
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat] - 1)}}))} className="font-black text-stone-400 hover:text-orange-500 transition-colors text-xl">-</button>
                      <span className="font-black w-6 text-center text-sm text-stone-800">{config.counts[cat]}</span>
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat] + 1}}))} className="font-black text-stone-400 hover:text-orange-500 transition-colors text-xl">+</button>
                    </div>
                  </div>
                ))}
              </div>

              {config.chefChoice && (
                <div className="flex-1 flex flex-col items-center justify-center text-center py-20 animate-in fade-in zoom-in-95">
                  <span className="text-6xl mb-6">👨‍🍳</span>
                  <h3 className="serif text-3xl font-bold text-stone-800 mb-2">IA em Comando Total</h3>
                  <p className="text-stone-400 text-sm max-w-sm uppercase tracking-widest leading-relaxed">O ChefAI selecionará as melhores combinações livremente baseado no seu acervo.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="bg-white rounded-[3.5rem] p-12 shadow-sm border border-stone-100">
              <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-12">
                <div>
                  <h2 className="serif text-5xl font-bold text-stone-900 leading-none">Acervo</h2>
                  <p className="text-stone-400 text-xs font-bold uppercase tracking-[0.4em] mt-3">Sua biblioteca de sabores e especialidades</p>
                </div>
                <div className="flex flex-wrap gap-3">
                  <button onClick={handleBulkGenerateDescriptions} className="px-6 py-4 bg-orange-100 text-orange-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-orange-200 hover:-translate-y-1 transition-all shadow-lg shadow-orange-100/20 flex items-center gap-2">✨ Redigir Descrições IA</button>
                  <button onClick={() => setShowImportGuide(true)} className="px-6 py-4 bg-stone-100 text-stone-500 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-stone-200 transition-all flex items-center gap-2">📥 Importar Excel</button>
                  <button onClick={() => setEditingDish({ id: Date.now().toString(), name: '', category: Category.MEAT, description: '' })} className="px-8 py-4 bg-stone-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-black hover:shadow-2xl transition-all shadow-xl shadow-stone-200">+ Novo Prato</button>
                </div>
              </div>

              <div className="flex flex-col md:flex-row gap-4 mb-10">
                <div className="relative flex-1">
                  <span className="absolute left-5 top-1/2 -translate-y-1/2 opacity-30">🔍</span>
                  <input placeholder="Buscar no acervo..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-12 py-4 outline-none focus:ring-2 ring-orange-100 transition-all font-semibold" />
                </div>
                <select value={filterCategory} onChange={e => setFilterCategory(e.target.value as any)} className="bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-500 uppercase tracking-widest text-[10px]">
                  <option value="Todos">Todas Categorias</option>
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {filteredDishes.map(dish => (
                  <div key={dish.id} className="group relative p-8 rounded-[3rem] bg-white border border-stone-100 shadow-[0_4px_25px_rgba(0,0,0,0.02)] hover:shadow-[0_25px_60px_rgba(230,126,34,0.08)] hover:-translate-y-2 transition-all duration-500 overflow-hidden">
                    <div className="flex justify-between items-start mb-5">
                      <span className="text-[9px] font-black uppercase tracking-[0.2em] text-stone-400 bg-stone-50 px-3 py-1.5 rounded-full border border-stone-100">{dish.category}</span>
                      <button 
                        onClick={() => handleToggleDefault(dish)} 
                        className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-all ${dish.isDefault ? 'bg-orange-500 text-white shadow-xl shadow-orange-200' : 'bg-stone-50 text-stone-300 hover:text-orange-400 hover:bg-orange-50'}`}
                        title={dish.isDefault ? "Remover de Padrão" : "Definir como Padrão da Categoria"}
                      >
                        <span className="text-lg">★</span>
                      </button>
                    </div>
                    <h3 className="serif text-2xl font-bold mb-2 leading-tight group-hover:text-orange-500 transition-colors">{dish.name}</h3>
                    <p className="text-[11px] text-stone-400 italic line-clamp-3 leading-relaxed">{dish.description || 'Nenhuma descrição gourmet cadastrada ainda...'}</p>

                    <div className="mt-8 pt-6 border-t border-stone-50 flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all duration-300">
                      <button onClick={() => setEditingDish(dish)} className="p-3 bg-stone-50 rounded-xl hover:bg-orange-500 hover:text-white transition-all shadow-sm">✎</button>
                      <button onClick={() => { if(window.confirm(`Excluir ${dish.name}?`)) setDishPool(p => p.filter(d => d.id !== dish.id)); }} className="p-3 bg-stone-50 rounded-xl hover:bg-red-500 hover:text-white transition-all shadow-sm">✕</button>
                    </div>
                  </div>
                ))}
              </div>

              {filteredDishes.length === 0 && (
                <div className="py-32 text-center">
                  <span className="text-5xl block mb-6 opacity-20">📭</span>
                  <p className="text-stone-400 text-sm font-bold uppercase tracking-[0.3em]">Nenhum prato encontrado no seu acervo</p>
                </div>
              )}
            </div>
          </div>
        )}

        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in zoom-in-95 duration-700">
            <div className="mb-10 flex flex-wrap justify-center gap-6 no-print">
              <div className="flex bg-stone-200/50 p-1.5 rounded-[2rem] shadow-inner border border-stone-200/30">
                <button onClick={() => setExportFormat('standard')} className={`px-10 py-3.5 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'standard' ? 'bg-white text-stone-900 shadow-xl' : 'text-stone-500 hover:text-stone-700'}`}>Impressão A4</button>
                <button onClick={() => setExportFormat('story')} className={`px-10 py-3.5 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'story' ? 'bg-white text-stone-900 shadow-xl' : 'text-stone-500 hover:text-stone-700'}`}>Digital Story</button>
              </div>
              <button onClick={() => saveAsImage(exportFormat)} className="px-10 py-3.5 bg-orange-500 text-white rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest shadow-2xl shadow-orange-200 hover:scale-105 active:scale-95 transition-all">Baixar em Alta Definição</button>
            </div>

            <div 
              ref={menuRef}
              className={`bg-white relative shadow-[0_80px_150px_-40px_rgba(0,0,0,0.15)] overflow-hidden transition-all duration-700 ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16]' : 'w-[850px] min-h-[1200px]'}`}
              style={{ backgroundColor: generatedMenu.visualTheme?.backgroundColor || '#fff' }}
            >
              <div className="absolute inset-0 pointer-events-none opacity-10" style={{ background: generatedMenu.visualTheme?.backgroundGradient }}></div>
              <div className="absolute inset-0 pointer-events-none opacity-[0.03] overflow-hidden">
                <div className="absolute top-0 right-0 w-96 h-96 border-8 border-stone-900 rounded-full -mr-48 -mt-48"></div>
                <div className="absolute bottom-0 left-0 w-64 h-64 border-4 border-stone-900 rounded-full -ml-32 -mb-32"></div>
              </div>

              <div className="relative z-10 h-full flex flex-col items-center p-16">
                <div className="absolute inset-8 border border-stone-900/5 pointer-events-none"></div>

                <header className="text-center mb-16 w-full relative">
                  {logoPreview && <img src={logoPreview} className={`${exportFormat === 'story' ? 'h-20' : 'h-28'} mx-auto mb-8 object-contain drop-shadow-xl`} alt="Estabelecimento" />}
                  <div className="inline-block px-6 py-2 mb-4 bg-stone-900 text-white text-[9px] font-black uppercase tracking-[0.5em] shadow-lg" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor }}>Alta Gastronomia</div>
                  <h1 className="serif uppercase tracking-tighter leading-[0.85] font-black text-stone-900 mb-8" style={{ color: generatedMenu.visualTheme?.textColor, fontSize: exportFormat === 'story' ? '56px' : '92px' }}>{config.theme}</h1>

                  {config.mealOptions && config.mealOptions.length > 0 && (
                    <div className="flex flex-wrap justify-center gap-6 mt-10">
                      {config.mealOptions.map(m => (
                        <div key={m.id} className="bg-white/40 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/60 shadow-sm flex flex-col items-center min-w-[120px]">
                          <span className="text-[8px] font-black uppercase text-stone-400 tracking-widest mb-1">{m.title}</span>
                          <span className="text-lg font-black text-orange-600">{m.price}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </header>

                <div 
                  className={`flex-1 w-full flex flex-col justify-center ${isMultiColumn ? 'grid grid-cols-2 gap-x-16 gap-y-12' : 'space-y-12'}`} 
                  style={{ transform: `scale(${layoutScale})`, transformOrigin: 'top center' }}
                >
                  {CATEGORY_ORDER.map(cat => {
                    const items = generatedMenu.selections[cat];
                    if (!items?.length) return null;
                    return (
                      <div key={cat} className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
                        <div className="flex items-center gap-4">
                          <h3 className="text-[11px] font-black uppercase tracking-[0.6em] whitespace-nowrap" style={{ color: generatedMenu.visualTheme?.primaryColor }}>{cat}s</h3>
                          <div className="h-[1px] w-full bg-stone-100"></div>
                        </div>
                        <div className="space-y-6">
                          {items.map((it, idx) => (
                            <div key={idx} className="group">
                              <h4 className="font-bold text-2xl leading-none flex items-baseline gap-3" style={{ color: generatedMenu.visualTheme?.textColor }}>
                                <span className="w-2 h-2 rounded-full flex-shrink-0" style={{ backgroundColor: generatedMenu.visualTheme?.accentColor }}></span>
                                {it.name}
                              </h4>
                              {it.description && <p className="text-[13px] text-stone-400 italic font-medium leading-relaxed ml-5 mt-2 border-l-2 pl-4 py-1" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}>{it.description}</p>}
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                <footer className="mt-20 w-full pt-16 border-t border-stone-100 flex flex-col items-center relative">
                  <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-white px-4 text-2xl opacity-10">🌿</div>
                  <p className="serif italic text-center text-stone-500 max-w-xl mx-auto mb-10 leading-relaxed text-xl px-8">"{generatedMenu.chefNote}"</p>
                  <div className="serif text-6xl font-black italic tracking-tighter text-stone-900 opacity-[0.08] mb-4">Bon Appétit</div>
                  <div className="text-[9px] font-black uppercase tracking-[0.8em] opacity-20 text-stone-900">ChefAI Digital Studio</div>
                </footer>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Editing Dish Modal */}
      {editingDish && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12 animate-in zoom-in-95 duration-300 border border-white">
            <div className="flex justify-between items-center mb-10">
              <h3 className="serif text-3xl font-black text-stone-800">Ficha do Prato</h3>
              <button onClick={() => setEditingDish(null)} className="text-2xl opacity-20 hover:opacity-100">✕</button>
            </div>
            <div className="space-y-8">
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Nome do Item</span>
                <input value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-[1.5rem] px-6 py-4 outline-none font-bold text-lg text-stone-700 focus:ring-2 ring-orange-100" />
              </label>
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Categoria</span>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full bg-stone-50 border border-stone-100 rounded-[1.5rem] px-6 py-4 outline-none font-bold text-stone-600">
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </label>
              <label className="block">
                <div className="flex justify-between mb-2">
                  <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Apresentação Gourmet</span>
                  <button onClick={async () => {
                    if (!editingDish.name) return;
                    setIsGeneratingDesc(true);
                    try {
                      const desc = await generateDishDescription(editingDish.name);
                      setEditingDish({...editingDish, description: desc});
                    } finally { setIsGeneratingDesc(false); }
                  }} disabled={isGeneratingDesc} className="text-[10px] font-black text-orange-500 uppercase tracking-widest flex items-center gap-1.5 hover:scale-105 transition-transform">
                    {isGeneratingDesc ? '✍️ Redigindo...' : '✨ Sugestão IA'}
                  </button>
                </div>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-[1.5rem] px-6 py-4 outline-none min-h-[120px] text-sm text-stone-600 leading-relaxed" placeholder="Descreva brevemente o preparo e ingredientes..." />
              </label>
              <div className="flex gap-4 pt-6">
                <button onClick={() => setEditingDish(null)} className="flex-1 py-5 font-black uppercase text-[10px] text-stone-400 hover:text-stone-600 tracking-widest">Cancelar</button>
                <button onClick={() => {
                  setDishPool(p => {
                    const idx = p.findIndex(d => d.id === editingDish.id);
                    if (idx >= 0) {
                      const copy = [...p];
                      copy[idx] = editingDish;
                      return copy;
                    }
                    return [...p, editingDish];
                  });
                  setEditingDish(null);
                  setToast({ message: 'Especialidade salva!', type: 'success' });
                }} className="flex-1 py-5 bg-orange-500 text-white rounded-[1.5rem] font-black uppercase text-[10px] shadow-xl shadow-orange-100 tracking-widest hover:scale-[1.02] active:scale-95 transition-all">Confirmar Edição</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Import Modal */}
      {showImportGuide && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-2xl p-12 animate-in zoom-in-95 duration-300 overflow-y-auto max-h-[90vh] border border-white">
            <div className="flex justify-between items-center mb-10">
              <h3 className="serif text-4xl font-black text-stone-800">Importação de Massa</h3>
              <button onClick={() => setShowImportGuide(false)} className="text-2xl opacity-20 hover:opacity-100">✕</button>
            </div>

            <div className="space-y-8">
              <div className="p-6 bg-orange-50 rounded-3xl border border-orange-100 text-sm text-orange-800 leading-relaxed italic">
                Organize seu arquivo com as colunas: <span className="font-bold underline">Nome, Categoria, Descrição</span>. Isso permitirá que o ChefAI entenda cada prato perfeitamente.
              </div>

              <div className="bg-stone-50 rounded-[2rem] p-8 border border-stone-100 overflow-hidden">
                <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-stone-400 mb-4">Exemplo de Estrutura</h4>
                <table className="w-full text-left text-[11px] font-bold uppercase tracking-widest text-stone-300">
                  <tr className="border-b border-stone-200/50">
                    <th className="pb-3 px-2">Nome</th>
                    <th className="pb-3 px-2">Categoria</th>
                    <th className="pb-3 px-2">Descrição</th>
                  </tr>
                  <tr className="text-stone-800">
                    <td className="py-3 px-2">Lasanha Veggie</td>
                    <td className="py-3 px-2">Massa</td>
                    <td className="py-3 px-2 text-[9px] italic text-stone-400">Camadas de abobrinha...</td>
                  </tr>
                </table>
              </div>

              <label className="block w-full cursor-pointer group">
                <div className="w-full h-48 border-2 border-dashed border-stone-200 rounded-[2.5rem] flex flex-col items-center justify-center group-hover:border-orange-500 group-hover:bg-orange-50 transition-all">
                  <span className="text-5xl mb-4 group-hover:scale-110 transition-transform">📊</span>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] text-stone-400">Selecionar arquivo .xlsx ou .csv</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleImportExcel} />
              </label>

              {pendingDishes && (
                <div className="pt-6 animate-in slide-in-from-bottom-4">
                  <p className="text-[10px] font-black uppercase text-orange-500 mb-5 text-center tracking-[0.2em]">Encontrados {pendingDishes.length} itens prontos para o Chef</p>
                  <button onClick={confirmImport} className="w-full py-6 bg-stone-900 text-white rounded-[2rem] font-black uppercase tracking-[0.4em] text-[10px] shadow-2xl hover:bg-black transition-all">Confirmar e Alimentar Acervo</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI, generateDishDescription } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const LOCAL_STORAGE_KEY = 'chefai_default_layout';
const STORAGE_INVENTORY_KEY = 'chefai_inventory';
const STORAGE_CONFIG_KEY = 'chefai_session_config';

const App: React.FC = () => {
  // 1. Inventory State with Persistence
  const [dishPool, setDishPool] = useState<Dish[]>(() => {
    const saved = localStorage.getItem(STORAGE_INVENTORY_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_DISHES;
  });

  // 2. Configuration State with Robust LocalStorage Hydration
  const [config, setConfig] = useState<MenuConfig>(() => {
    const saved = localStorage.getItem(STORAGE_CONFIG_KEY);
    const defaultConfig: MenuConfig = {
      counts: {
        [Category.BASE]: 2,
        [Category.MEAT]: 2,
        [Category.PASTA]: 0,
        [Category.SIDE]: 2,
        [Category.SALAD]: 2,
        [Category.DESSERT]: 0
      },
      theme: 'Cardápio Especial do Dia',
      baseOption: 'Tradicional',
      chefChoice: false,
      useDefaultLayout: false,
      mealOptions: []
    };

    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return {
          ...defaultConfig,
          ...parsed,
          // Garante que counts tenha todas as categorias mesmo se o save for antigo
          counts: { ...defaultConfig.counts, ...parsed.counts },
          useDefaultLayout: false // Sempre inicia desligado para nova sessão
        };
      } catch (e) {
        return defaultConfig;
      }
    }
    return defaultConfig;
  });

  // 3. UI States
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);
  const [isBulkGenerating, setIsBulkGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [defaultLayout, setDefaultLayout] = useState<{ visualTheme: VisualTheme, theme: string } | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Persistence Effects
  useEffect(() => {
    localStorage.setItem(STORAGE_INVENTORY_KEY, JSON.stringify(dishPool));
  }, [dishPool]);

  useEffect(() => {
    const { logo, useDefaultLayout, ...persistableConfig } = config;
    localStorage.setItem(STORAGE_CONFIG_KEY, JSON.stringify(persistableConfig));
  }, [config]);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) setDefaultLayout(JSON.parse(saved));
    if (config.logo) setLogoPreview(config.logo);
  }, []);

  // Dynamic Layout Calculations
  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return (Object.values(generatedMenu.selections) as any[][]).reduce((acc, curr) => acc + (curr?.length || 0), 0);
  }, [generatedMenu]);

  const isMultiColumn = useMemo(() => {
    if (exportFormat === 'story' || !generatedMenu) return false;
    return totalItemsCount > 10;
  }, [exportFormat, totalItemsCount, generatedMenu]);

  const layoutScale = useMemo(() => {
    if (exportFormat === 'story') {
      if (totalItemsCount > 15) return 0.55;
      if (totalItemsCount > 10) return 0.7;
      return 0.85;
    }
    return 1;
  }, [exportFormat, totalItemsCount]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    }).sort((a, b) => (a.isDefault === b.isDefault) ? 0 : a.isDefault ? -1 : 1);
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Handlers
  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
    };
    reader.readAsDataURL(file);
  };

  const handleToggleDefault = (dish: Dish) => {
    setDishPool(prev => prev.map(d => {
      if (d.id === dish.id) return { ...d, isDefault: !d.isDefault };
      if (d.category === dish.category) return { ...d, isDefault: false };
      return d;
    }));
    if (!dish.isDefault) {
      setToast({ message: `${dish.name} agora é o padrão de ${dish.category}`, type: 'success' });
    }
  };

  const updateMealOption = (id: string, field: keyof MealOption, value: string) => {
    let finalValue = value;
    if (field === 'price' && value && !value.startsWith('R$')) {
      finalValue = 'R$ ' + value;
    }
    setConfig(prev => ({
      ...prev,
      mealOptions: prev.mealOptions?.map(o => o.id === id ? { ...o, [field]: finalValue } : o)
    }));
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) { setToast({ message: 'Seu acervo está vazio!', type: 'error' }); setActiveTab('inventory'); return; }
    setIsGenerating(true);
    setGenerationStep('ChefAI está criando sua obra-prima...');
    try {
      const forcedTheme = config.useDefaultLayout && defaultLayout ? defaultLayout.visualTheme : undefined;
      const result = await generateMenuWithAI(dishPool, config, (step) => setGenerationStep(step), forcedTheme);
      setGeneratedMenu(result);
      setActiveTab('result');
      setToast({ message: 'Menu gerado com sucesso!', type: 'success' });
    } catch (error) {
      setToast({ message: 'Erro ao conectar com o ChefAI.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const saveAsImage = async (format: 'standard' | 'story') => {
    if (!menuRef.current) return;
    setExportFormat(format);
    setToast({ message: 'Preparando sua imagem...', type: 'success' });
    setTimeout(async () => {
      try {
        const dataUrl = await toPng(menuRef.current!, { quality: 1, pixelRatio: 3, skipAutoScale: true });
        const link = document.createElement('a');
        link.download = `ChefAI-${config.theme.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) { setToast({ message: 'Erro ao baixar imagem.', type: 'error' }); }
    }, 600);
  };

  const handleBulkGenerateDescriptions = async () => {
    const targets = dishPool.filter(d => !d.description);
    if (targets.length === 0) { setToast({ message: 'Todos os itens já possuem descrição!', type: 'success' }); return; }
    if (!window.confirm(`Deseja gerar descrições automáticas para ${targets.length} pratos?`)) return;

    setIsBulkGenerating(true);
    const updated = [...dishPool];
    for (let i = 0; i < updated.length; i++) {
      if (!updated[i].description) {
        setGenerationStep(`Redigindo: ${updated[i].name}`);
        try {
          updated[i] = { ...updated[i], description: await generateDishDescription(updated[i].name) };
          // Atualiza o estado parcial para feedback visual
          if (i % 3 === 0) setDishPool([...updated]);
        } catch (e) { console.error(e); }
      }
    }
    setDishPool(updated);
    setIsBulkGenerating(false);
    setToast({ message: 'Acervo atualizado com descrições!', type: 'success' });
  };

  // Fix: Added handleImportExcel to parse xlsx/csv files using the XLSX library
  const handleImportExcel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      const wb = XLSX.read(bstr, { type: 'binary' });
      const wsname = wb.SheetNames[0];
      const ws = wb.Sheets[wsname];
      const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

      const imported: Dish[] = data.slice(1).map((row, index) => {
        const categoryString = String(row[1] || '').trim();
        const categoryMatch = Object.values(Category).find(c => c.toLowerCase() === categoryString.toLowerCase());

        return {
          id: `imported-${Date.now()}-${index}`,
          name: String(row[0] || '').trim(),
          category: (categoryMatch || Category.MEAT) as Category,
          description: String(row[2] || '').trim()
        };
      }).filter(d => d.name);

      setPendingDishes(imported);
    };
    reader.readAsBinaryString(file);
  };

  // Fix: Added confirmImport to merge pending dishes into the main pool
  const confirmImport = () => {
    if (pendingDishes && pendingDishes.length > 0) {
      setDishPool(prev => [...prev, ...pendingDishes]);
      setToast({ message: `${pendingDishes.length} especialidades importadas com sucesso!`, type: 'success' });
    }
    setPendingDishes(null);
    setShowImportGuide(false);
  };

  return (
    <div className="min-h-screen bg-[#faf9f6] text-[#2d2d2d] antialiased scrollbar-thin">
      {/* Loading Overlay */}
      {(isGenerating || isBulkGenerating) && (
        <div className="fixed inset-0 z-[1000] bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-500">
          <div className="relative mb-10">
            <div className="w-28 h-28 border-4 border-stone-100 border-t-orange-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-4xl">👨‍🍳</div>
          </div>
          <h2 className="serif text-3xl font-bold text-stone-800 animate-pulse tracking-tight">{generationStep}</h2>
          <p className="text-stone-400 text-[10px] uppercase tracking-[0.3em] mt-4">Aguarde a finalização do Chef</p>
        </div>
      )}

      {/* Toast Notification */}
      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[1100] animate-in slide-in-from-bottom-6">
          <div className={`px-8 py-4 rounded-3xl shadow-2xl font-bold uppercase tracking-widest text-[10px] flex items-center gap-3 ${toast.type === 'success' ? 'bg-stone-900 text-white' : 'bg-red-500 text-white'}`}>
            <span className="text-lg">{toast.type === 'success' ? '✨' : '⚠️'}</span>
            {toast.message}
          </div>
        </div>
      )}

      {/* Navbar */}
      <nav className="fixed top-0 inset-x-0 h-20 bg-white/80 backdrop-blur-lg border-b border-stone-200/50 z-[100] px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center shadow-xl shadow-orange-200 text-white text-2xl">🥗</div>
            <div className="leading-tight">
              <h1 className="serif text-2xl font-black tracking-tighter">CHEF AI</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase tracking-[0.4em]">Menu Designer</span>
            </div>
          </div>
          <div className="flex bg-stone-100 p-1.5 rounded-2xl shadow-inner">
            {[
              { id: 'compose', label: 'Criação', icon: '✨' },
              { id: 'inventory', label: 'Acervo', icon: '📦' },
              { id: 'result', label: 'Preview', icon: '🖼️', disabled: !generatedMenu }
            ].map((t) => (
              <button 
                key={t.id}
                onClick={() => setActiveTab(t.id as TabType)}
                disabled={t.disabled}
                className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === t.id ? 'bg-white text-stone-900 shadow-md' : 'text-stone-400 hover:text-stone-600 disabled:opacity-30'}`}
              >
                <span>{t.icon}</span> {t.label}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-8 pt-32 pb-24">
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
            {/* Left Column: Config */}
            <div className="lg:col-span-4 space-y-8">
              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <h2 className="serif text-2xl font-bold mb-6 text-stone-800">Identidade</h2>
                <div className="space-y-6">
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Logomarca do Estabelecimento</span>
                    <div className="relative h-40 rounded-3xl bg-stone-50 border-2 border-dashed border-stone-200 flex items-center justify-center cursor-pointer hover:border-orange-400 hover:bg-orange-50/30 transition-all overflow-hidden group">
                      {logoPreview ? (
                        <div className="relative w-full h-full p-6">
                          <img src={logoPreview} className="w-full h-full object-contain" alt="Preview" />
                          <button onClick={(e) => { e.preventDefault(); setLogoPreview(null); setConfig({...config, logo: undefined}); }} className="absolute top-2 right-2 w-8 h-8 bg-white/80 backdrop-blur-sm rounded-full text-xs shadow-sm hover:text-red-500 transition-colors">✕</button>
                        </div>
                      ) : (
                        <div className="text-center">
                          <span className="text-3xl block mb-2 opacity-30">🖼️</span>
                          <span className="text-[10px] font-bold text-stone-300 uppercase tracking-widest">Upload .png ou .jpg</span>
                        </div>
                      )}
                      <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleLogoUpload} />
                    </div>
                  </label>
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Título Principal do Cardápio</span>
                    <input type="text" value={config.theme} onChange={e => setConfig({...config, theme: e.target.value})} className="w-full bg-stone-50 rounded-2xl px-5 py-4 outline-none focus:ring-2 ring-orange-100 font-bold text-stone-700 border border-stone-100 transition-all" placeholder="Ex: Menu Mediterrâneo" />
                  </label>
                </div>
              </section>

              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="serif text-2xl font-bold text-stone-800">Marmitas</h2>
                  <button onClick={() => setConfig(prev => ({...prev, mealOptions: [...(prev.mealOptions||[]), {id: Date.now().toString(), title: '', price: ''}]}))} className="w-10 h-10 bg-orange-500 text-white rounded-2xl shadow-lg shadow-orange-100 hover:scale-105 active:scale-95 transition-all">+</button>
                </div>
                <div className="space-y-4">
                  {config.mealOptions?.map(opt => (
                    <div key={opt.id} className="p-5 bg-stone-50 rounded-[2rem] border border-stone-100 relative animate-in zoom-in-95">
                      <button onClick={() => setConfig(prev => ({...prev, mealOptions: prev.mealOptions?.filter(o => o.id !== opt.id)}))} className="absolute -top-2 -right-2 w-7 h-7 bg-white border border-stone-100 rounded-full flex items-center justify-center text-[10px] shadow-sm hover:text-red-500 hover:border-red-100 transition-all">✕</button>
                      <div className="space-y-3">
