import { GoogleGenAI, Type } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme } from "../types";

async function analyzeLogoTheme(logoBase64: string): Promise<VisualTheme> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: "image/png",
      data: logoBase64.split(',')[1] || logoBase64,
    },
  };

  const prompt = `
    Analise esta logomarca de restaurante e extraia uma paleta de cores sofisticada e um conceito de design para um cardápio digital.
    Retorne um JSON com:
    1. primaryColor, 2. secondaryColor, 3. backgroundColor, 4. backgroundGradient, 5. textColor, 6. accentColor, 7. patternType.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [imagePart, { text: prompt }] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          primaryColor: { type: Type.STRING },
          secondaryColor: { type: Type.STRING },
          backgroundColor: { type: Type.STRING },
          backgroundGradient: { type: Type.STRING },
          textColor: { type: Type.STRING },
          accentColor: { type: Type.STRING },
          patternType: { type: Type.STRING, enum: ['dots', 'grid', 'mesh', 'stripes', 'clean'] },
        },
        required: ["primaryColor", "secondaryColor", "backgroundColor", "backgroundGradient", "textColor", "accentColor", "patternType"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
}

export async function generateDishDescription(dishName: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Você é um Chef Michelin. Escreva uma descrição curta e apetitosa (max 8 palavras) para: "${dishName}". Responda APENAS a frase.`;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: { temperature: 0.7 }
  });
  return response.text?.trim() || "";
}

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig,
  onProgress?: (step: string) => void,
  forcedTheme?: VisualTheme
): Promise<GeneratedMenu> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let visualTheme: VisualTheme | undefined = forcedTheme;

  if (!forcedTheme && config.logo) {
    onProgress?.("Sintonizando identidade visual...");
    try {
      visualTheme = await analyzeLogoTheme(config.logo);
    } catch (e) {
      console.error("Erro ao analisar logo:", e);
    }
  }

  onProgress?.("Garantindo rotação de pratos (Regra de 3 dias)...");

  const recentDishes = config.recentDishIds || [];
  const availablePool = dishPool.map(d => ({ 
    id: d.id,
    name: d.name, 
    category: d.category, 
    description: d.description, 
    isDefault: d.isDefault,
    isRecent: recentDishes.includes(d.id)
  }));

  const structureRequested = config.chefChoice 
    ? "ESTILO LIVRE: Escolha as melhores combinações aleatórias do acervo para um menu equilibrado."
    : `METAS POR CATEGORIA:\n${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${cat}: selecionar exatamente ${count} item(ns)`)
        .join('\n')}`;

  const prompt = `
    Aja como um Chef Executivo montando o cardápio: "${config.theme}".

    ACERVO DISPONÍVEL (Use APENAS itens desta lista):
    ${JSON.stringify(availablePool)}

    REGRAS CRÍTICAS DE ROTAÇÃO E ALEATORIEDADE:
    1. REGRA DOS 3 DIAS: Itens com "isRecent: true" NÃO DEVEM ser selecionados a menos que não existam outras opções na categoria. O objetivo é rotacionar o cardápio para que não se repita por pelo menos 3 dias.
    2. ALEATORIEDADE: Não escolha sempre os mesmos pratos. Explore todo o acervo disponível.
    3. PRATOS PADRÃO: Itens com "isDefault: true" têm prioridade, mas se forem recentes, tente rotacionar se houver abundância na categoria.
    4. SELEÇÃO: ${structureRequested}
    5. CHEF NOTE: Frase elegante de boas-vindas (max 15 palavras).

    Retorne o JSON seguindo o schema.
  `;

  onProgress?.("Finalizando seleção gourmet...");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        temperature: 0.9, // Aumentado para maior aleatoriedade
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            selections: {
              type: Type.OBJECT,
              properties: {
                [Category.BASE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.PASTA]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              }
            },
            chefNote: { type: Type.STRING }
          },
          required: ["selections", "chefNote"]
        }
      }
    });

    const parsed = JSON.parse(response.text || '{}');
    const finalSelections: any = {};
    Object.values(Category).forEach(cat => {
      finalSelections[cat] = parsed.selections?.[cat] || [];
    });

    return { selections: finalSelections, chefNote: parsed.chefNote, visualTheme };
  } catch (error) {
    console.error("Erro ChefAI:", error);
    throw error;
  }
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption, MenuHistoryEntry } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI, generateDishDescription } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const LOCAL_STORAGE_KEY = 'chefai_default_layout';
const STORAGE_INVENTORY_KEY = 'chefai_inventory';
const STORAGE_CONFIG_KEY = 'chefai_session_config';
const STORAGE_HISTORY_KEY = 'chefai_menu_history';

const App: React.FC = () => {
  // Inventory State
  const [dishPool, setDishPool] = useState<Dish[]>(() => {
    const saved = localStorage.getItem(STORAGE_INVENTORY_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_DISHES;
  });

  // History State (Rotation logic)
  const [menuHistory, setMenuHistory] = useState<MenuHistoryEntry[]>(() => {
    const saved = localStorage.getItem(STORAGE_HISTORY_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // Configuration State
  const [config, setConfig] = useState<MenuConfig>(() => {
    const saved = localStorage.getItem(STORAGE_CONFIG_KEY);
    const defaultConfig: MenuConfig = {
      counts: { [Category.BASE]: 2, [Category.MEAT]: 2, [Category.PASTA]: 0, [Category.SIDE]: 2, [Category.SALAD]: 2, [Category.DESSERT]: 0 },
      theme: 'Cardápio Especial do Dia',
      baseOption: 'Tradicional',
      chefChoice: false,
      useDefaultLayout: false,
      mealOptions: []
    };
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return { ...defaultConfig, ...parsed, counts: { ...defaultConfig.counts, ...parsed.counts }, useDefaultLayout: false };
      } catch (e) { return defaultConfig; }
    }
    return defaultConfig;
  });

  // UI States
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);
  const [isBulkGenerating, setIsBulkGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [defaultLayout, setDefaultLayout] = useState<{ visualTheme: VisualTheme, theme: string } | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Persistence Effects
  useEffect(() => { localStorage.setItem(STORAGE_INVENTORY_KEY, JSON.stringify(dishPool)); }, [dishPool]);
  useEffect(() => { localStorage.setItem(STORAGE_HISTORY_KEY, JSON.stringify(menuHistory)); }, [menuHistory]);
  useEffect(() => {
    const { logo, useDefaultLayout, ...persistableConfig } = config;
    localStorage.setItem(STORAGE_CONFIG_KEY, JSON.stringify(persistableConfig));
  }, [config]);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) setDefaultLayout(JSON.parse(saved));
    if (config.logo) setLogoPreview(config.logo);
  }, []);

  // Get used IDs from last 3 entries in history
  const recentDishIds = useMemo(() => {
    return menuHistory.slice(-3).flatMap(entry => entry.dishIds);
  }, [menuHistory]);

  // Dynamic Layout Calculations
  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return (Object.values(generatedMenu.selections) as any[][]).reduce((acc, curr) => acc + (curr?.length || 0), 0);
  }, [generatedMenu]);

  const isMultiColumn = useMemo(() => {
    if (exportFormat === 'story' || !generatedMenu) return false;
    return totalItemsCount > 10;
  }, [exportFormat, totalItemsCount, generatedMenu]);

  const layoutScale = useMemo(() => {
    if (exportFormat === 'story') {
      if (totalItemsCount > 15) return 0.55;
      if (totalItemsCount > 10) return 0.7;
      return 0.85;
    }
    return 1;
  }, [exportFormat, totalItemsCount]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    }).sort((a, b) => (a.isDefault === b.isDefault) ? 0 : a.isDefault ? -1 : 1);
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Handlers
  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
    };
    reader.readAsDataURL(file);
  };

  const handleToggleDefault = (dish: Dish) => {
    setDishPool(prev => prev.map(d => {
      if (d.id === dish.id) return { ...d, isDefault: !d.isDefault };
      if (d.category === dish.category) return { ...d, isDefault: false };
      return d;
    }));
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) { setToast({ message: 'Seu acervo está vazio!', type: 'error' }); setActiveTab('inventory'); return; }
    setIsGenerating(true);
    setGenerationStep('ChefAI está rotacionando o cardápio...');
    try {
      const forcedTheme = config.useDefaultLayout && defaultLayout ? defaultLayout.visualTheme : undefined;
      const result = await generateMenuWithAI(
        dishPool, 
        { ...config, recentDishIds }, 
        (step) => setGenerationStep(step), 
        forcedTheme
      );

      setGeneratedMenu(result);

      // Update history with used dish IDs
      const usedIds: string[] = [];
      Object.values(result.selections).forEach((items: any[]) => {
        items.forEach(item => {
          const found = dishPool.find(d => d.name === item.name);
          if (found) usedIds.push(found.id);
        });
      });

      setMenuHistory(prev => {
        const newHistory = [...prev, { date: new Date().toISOString(), dishIds: usedIds }];
        return newHistory.slice(-5); // Keep last 5 generations for safety
      });

      setActiveTab('result');
      setToast({ message: 'Menu gerado com rotação ativa!', type: 'success' });
    } catch (error) {
      setToast({ message: 'Erro ao conectar com o ChefAI.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImportExcel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const wb = XLSX.read(evt.target?.result, { type: 'binary' });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];
      const imported: Dish[] = data.slice(1).map((row, index) => {
        const cat = Object.values(Category).find(c => c.toLowerCase() === String(row[1]||'').trim().toLowerCase());
        return { id: `imp-${Date.now()}-${index}`, name: String(row[0]||''), category: cat || Category.MEAT, description: String(row[2]||'') };
      }).filter(d => d.name);
      setPendingDishes(imported);
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = () => {
    if (pendingDishes) {
      setDishPool(prev => [...prev, ...pendingDishes]);
      setToast({ message: 'Especialidades importadas!', type: 'success' });
    }
    setPendingDishes(null);
    setShowImportGuide(false);
  };

  return (
    <div className="min-h-screen bg-[#faf9f6] text-[#2d2d2d] antialiased scrollbar-thin">
      {(isGenerating || isBulkGenerating) && (
        <div className="fixed inset-0 z-[1000] bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-500">
          <div className="relative mb-10">
            <div className="w-28 h-28 border-4 border-stone-100 border-t-orange-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-4xl">👨‍🍳</div>
          </div>
          <h2 className="serif text-3xl font-bold text-stone-800 animate-pulse tracking-tight">{generationStep}</h2>
          <p className="text-stone-400 text-[10px] uppercase tracking-[0.3em] mt-4 italic">Garantindo que os clientes tenham novidades hoje</p>
        </div>
      )}

      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[1100] animate-in slide-in-from-bottom-6">
          <div className={`px-8 py-4 rounded-3xl shadow-2xl font-bold uppercase tracking-widest text-[10px] flex items-center gap-3 ${toast.type === 'success' ? 'bg-stone-900 text-white' : 'bg-red-500 text-white'}`}>
            <span>{toast.message}</span>
          </div>
        </div>
      )}

      <nav className="fixed top-0 inset-x-0 h-20 bg-white/80 backdrop-blur-lg border-b border-stone-200/50 z-[100] px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center shadow-xl shadow-orange-200 text-white text-2xl">🥗</div>
            <div className="leading-tight">
              <h1 className="serif text-2xl font-black tracking-tighter">CHEF AI</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase tracking-[0.4em]">Menu Rotation Tool</span>
            </div>
          </div>
          <div className="flex bg-stone-100 p-1.5 rounded-2xl">
            {['compose', 'inventory', 'result'].map((t) => (
              <button 
                key={t}
                onClick={() => setActiveTab(t as TabType)}
                disabled={t === 'result' && !generatedMenu}
                className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-white text-stone-900 shadow-md' : 'text-stone-400 hover:text-stone-600 disabled:opacity-30'}`}
