                  <button onClick={() => setConfig(prev => ({...prev, mealOptions: [...(prev.mealOptions||[]), {id: Date.now().toString(), title: '', price: ''}]}))} className="w-10 h-10 bg-orange-500 text-white rounded-2xl shadow-lg">+</button>
                </div>
                <div className="space-y-4">
                  {config.mealOptions?.map(opt => (
                    <div key={opt.id} className="p-5 bg-stone-50 rounded-[2rem] border border-stone-100 relative">
                      <button onClick={() => setConfig(prev => ({...prev, mealOptions: prev.mealOptions?.filter(o => o.id !== opt.id)}))} className="absolute -top-2 -right-2 w-7 h-7 bg-white border border-stone-100 rounded-full flex items-center justify-center text-[10px] shadow-sm hover:text-red-500">✕</button>
                      <input placeholder="Ex: Marmita G" value={opt.title} onChange={e => setConfig(p => ({...p, mealOptions: p.mealOptions?.map(o => o.id === opt.id ? {...o, title: e.target.value} : o)}))} className="bg-white border border-stone-100 rounded-xl px-4 py-2 font-bold text-xs w-full mb-2" />
                      <input placeholder="R$ 25,00" value={opt.price} onChange={e => setConfig(p => ({...p, mealOptions: p.mealOptions?.map(o => o.id === opt.id ? {...o, price: e.target.value} : o)}))} className="bg-white border border-stone-100 rounded-xl px-4 py-2 text-[11px] text-orange-600 font-black w-full" />
                    </div>
                  ))}
                </div>
              </section>

              <button onClick={handleGenerate} disabled={isGenerating} className="w-full py-6 bg-orange-500 text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-xs shadow-2xl hover:scale-[1.02] transition-all">
                {isGenerating ? 'Chef Criando...' : 'Gerar Menu sem Repetições'}
              </button>

              <p className="text-center text-[8px] font-bold text-stone-400 uppercase tracking-widest">
                💡 A IA evitará pratos usados nas últimas 3 gerações.
              </p>
            </div>

            <div className="lg:col-span-8 bg-white rounded-[3.5rem] p-12 shadow-sm border border-stone-100">
              <div className="flex justify-between items-center mb-12">
                <h2 className="serif text-4xl font-bold text-stone-800">Estrutura</h2>
                <button onClick={() => setConfig({...config, chefChoice: !config.chefChoice})} className={`px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${config.chefChoice ? 'bg-orange-500 text-white' : 'bg-stone-100 text-stone-400'}`}>
