              </div>
            </div>

            <div className="flex gap-4 mb-10">
              <input placeholder="Buscar..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="flex-1 bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-semibold" />
              <select value={filterCategory} onChange={e => setFilterCategory(e.target.value as any)} className="bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-500 uppercase text-[10px]">
                <option value="Todos">Todas Categorias</option>
                {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredDishes.map(dish => (
                <div key={dish.id} className="group relative p-8 rounded-[3rem] bg-white border border-stone-100 hover:shadow-2xl hover:-translate-y-1 transition-all">
                  <div className="flex justify-between mb-5">
                    <span className="text-[9px] font-black uppercase tracking-widest text-stone-400 bg-stone-50 px-3 py-1.5 rounded-full">{dish.category}</span>
                    <button onClick={() => handleToggleDefault(dish)} className={`w-10 h-10 rounded-2xl flex items-center justify-center ${dish.isDefault ? 'bg-orange-500 text-white shadow-xl' : 'bg-stone-50 text-stone-300'}`}>★</button>
                  </div>
                  <h3 className="serif text-2xl font-bold mb-2 group-hover:text-orange-500 transition-colors">{dish.name}</h3>
                  <p className="text-[11px] text-stone-400 italic line-clamp-3 leading-relaxed">{dish.description || 'Sem descrição gourmet...'}</p>

                  {recentDishIds.includes(dish.id) && (
                    <div className="mt-4 inline-block px-2 py-1 bg-red-50 text-red-500 text-[8px] font-black uppercase tracking-widest rounded-lg">
                      🕒 Usado Recentemente
                    </div>
                  )}

                  <div className="mt-8 flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all">
                    <button onClick={() => setEditingDish(dish)} className="p-3 bg-stone-50 rounded-xl hover:bg-orange-500 hover:text-white transition-all">✎</button>
                    <button onClick={() => setDishPool(p => p.filter(d => d.id !== dish.id))} className="p-3 bg-stone-50 rounded-xl hover:bg-red-500 hover:text-white transition-all">✕</button>
                  </div>
                </div>
