        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in zoom-in-95 duration-700">
             <div className="mb-10 flex gap-6 no-print">
                <button onClick={() => setExportFormat('standard')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest ${exportFormat === 'standard' ? 'bg-stone-900 text-white shadow-xl' : 'bg-white text-stone-400'}`}>A4 Impressão</button>
                <button onClick={() => setExportFormat('story')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest ${exportFormat === 'story' ? 'bg-stone-900 text-white shadow-xl' : 'bg-white text-stone-400'}`}>Digital Story</button>
                <button onClick={() => { 
                   toPng(menuRef.current!, { quality: 1, pixelRatio: 3 }).then(url => {
                     const l = document.createElement('a');
                     l.download = `Menu-${Date.now()}.png`;
                     l.href = url;
                     l.click();
                   });
                }} className="px-10 py-3.5 bg-orange-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-2xl">Download HD</button>
             </div>

             <div 
               ref={menuRef}
               className={`bg-white relative shadow-2xl overflow-hidden transition-all duration-700 ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16]' : 'w-[850px] min-h-[1200px]'}`}
               style={{ backgroundColor: generatedMenu.visualTheme?.backgroundColor || '#fff' }}
             >
               <div className="absolute inset-0 opacity-10" style={{ background: generatedMenu.visualTheme?.backgroundGradient }}></div>
               <div className="relative z-10 h-full flex flex-col items-center p-16">
                 <header className="text-center mb-16 w-full">
                   {logoPreview && <img src={logoPreview} className="h-28 mx-auto mb-8 object-contain" alt="Logo" />}
                   <div className="inline-block px-6 py-2 mb-4 bg-stone-900 text-white text-[9px] font-black uppercase tracking-[0.5em]" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor }}>ChefAI Premium</div>
                   <h1 className="serif uppercase leading-none font-black text-stone-900 mb-8" style={{ color: generatedMenu.visualTheme?.textColor, fontSize: exportFormat === 'story' ? '56px' : '92px' }}>{config.theme}</h1>

                   <div className="flex flex-wrap justify-center gap-6">
                     {config.mealOptions?.map(m => (
                       <div key={m.id} className="bg-white/40 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/60 shadow-sm flex flex-col items-center">
                         <span className="text-[8px] font-black uppercase text-stone-400 tracking-widest">{m.title}</span>
                         <span className="text-lg font-black text-orange-600">{m.price}</span>
                       </div>
                     ))}
                   </div>
                 </header>

                 <div 
                   className={`flex-1 w-full space-y-12`} 
                   style={{ transform: `scale(${layoutScale})`, transformOrigin: 'top center' }}
                 >
                   {CATEGORY_ORDER.map(cat => {
                     const items = generatedMenu.selections[cat];
                     if (!items?.length) return null;
                     return (
                       <div key={cat} className="space-y-6">
                         <div className="flex items-center gap-4">
                           <h3 className="text-[11px] font-black uppercase tracking-[0.6em] whitespace-nowrap" style={{ color: generatedMenu.visualTheme?.primaryColor }}>{cat}s</h3>
                           <div className="h-[1px] w-full bg-stone-100"></div>
                         </div>
                         <div className="space-y-6">
                           {items.map((it, idx) => (
                             <div key={idx}>
                               <h4 className="font-bold text-2xl leading-none flex items-baseline gap-3" style={{ color: generatedMenu.visualTheme?.textColor }}>
                                 <span className="w-2 h-2 rounded-full flex-shrink-0" style={{ backgroundColor: generatedMenu.visualTheme?.accentColor }}></span>
                                 {it.name}
                               </h4>
                               {it.description && <p className="text-[13px] text-stone-400 italic font-medium leading-relaxed ml-5 mt-2 border-l-2 pl-4 py-1" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}>{it.description}</p>}
                             </div>
                           ))}
                         </div>
                       </div>
                     );
                   })}
                 </div>

                 <footer className="mt-20 w-full pt-16 border-t border-stone-100 flex flex-col items-center">
                   <p className="serif italic text-center text-stone-500 max-w-xl mx-auto mb-10 leading-relaxed text-xl">"{generatedMenu.chefNote}"</p>
                   <div className="serif text-6xl font-black italic tracking-tighter text-stone-900 opacity-[0.08]">Bon Appétit</div>
                 </footer>
               </div>
             </div>
          </div>
        )}
      </main>

      {/* Editing Dish Modal */}
      {editingDish && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12 animate-in zoom-in-95">
            <h3 className="serif text-3xl font-black mb-8 border-b pb-4">Editar Especialidade</h3>
            <div className="space-y-8">
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Nome</span>
                <input value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full bg-stone-50 rounded-2xl px-6 py-4 outline-none font-bold text-lg" />
              </label>
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Categoria</span>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full bg-stone-50 rounded-2xl px-6 py-4 outline-none font-bold">
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </label>
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Descrição</span>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full bg-stone-50 rounded-2xl px-6 py-4 outline-none min-h-[120px] text-sm" />
              </label>
              <div className="flex gap-4 pt-6">
                <button onClick={() => setEditingDish(null)} className="flex-1 py-5 font-black uppercase text-[10px] text-stone-400">Cancelar</button>
                <button onClick={() => {
                  setDishPool(p => {
                    const idx = p.findIndex(d => d.id === editingDish.id);
                    if (idx >= 0) { const c = [...p]; c[idx] = editingDish; return c; }
                    return [...p, editingDish];
                  });
                  setEditingDish(null);
                }} className="flex-1 py-5 bg-orange-500 text-white rounded-[1.5rem] font-black uppercase text-[10px] shadow-xl">Salvar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Import Modal */}
      {showImportGuide && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-2xl p-12 animate-in zoom-in-95 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between mb-10">
              <h3 className="serif text-4xl font-black">Importar</h3>
              <button onClick={() => setShowImportGuide(false)} className="text-2xl opacity-20">✕</button>
            </div>

            <div className="space-y-8">
              <div className="p-6 bg-orange-50 rounded-3xl border border-orange-100 text-sm text-orange-800 leading-relaxed italic">
                Organize seu arquivo com as colunas: <span className="font-bold underline">Nome, Categoria, Descrição</span>.
              </div>

              <label className="block w-full cursor-pointer group">
                <div className="w-full h-48 border-2 border-dashed border-stone-200 rounded-[2.5rem] flex flex-col items-center justify-center group-hover:border-orange-500 group-hover:bg-orange-50 transition-all">
                  <span className="text-5xl mb-4 group-hover:scale-110 transition-transform">📊</span>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] text-stone-400">Selecionar arquivo .xlsx ou .csv</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleImportExcel} />
              </label>

              {pendingDishes && pendingDishes.length > 0 && (
                <div className="pt-6 animate-in slide-in-from-bottom-4">
                  <p className="text-[10px] font-black uppercase text-orange-500 mb-5 text-center tracking-[0.2em]">Encontrados {pendingDishes.length} itens</p>
                  <button onClick={confirmImport} className="w-full py-6 bg-stone-900 text-white rounded-[2rem] font-black uppercase tracking-[0.4em] text-[10px] shadow-2xl">Confirmar Importação</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme } from "../types";

async function analyzeLogoTheme(logoBase64: string): Promise<VisualTheme> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: "image/png",
      data: logoBase64.split(',')[1] || logoBase64,
    },
  };

  const prompt = `
    Analise esta logomarca de restaurante e extraia uma paleta de cores sofisticada e um conceito de design para um cardápio digital.
    Retorne um JSON com:
    1. primaryColor, 2. secondaryColor, 3. backgroundColor, 4. backgroundGradient, 5. textColor, 6. accentColor, 7. patternType.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [imagePart, { text: prompt }] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          primaryColor: { type: Type.STRING },
          secondaryColor: { type: Type.STRING },
          backgroundColor: { type: Type.STRING },
          backgroundGradient: { type: Type.STRING },
          textColor: { type: Type.STRING },
          accentColor: { type: Type.STRING },
          patternType: { type: Type.STRING, enum: ['dots', 'grid', 'mesh', 'stripes', 'clean'] },
        },
        required: ["primaryColor", "secondaryColor", "backgroundColor", "backgroundGradient", "textColor", "accentColor", "patternType"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
}

export async function generateDishDescription(dishName: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Você é um Chef Michelin. Escreva uma descrição curta e apetitosa (max 8 palavras) para: "${dishName}". Responda APENAS a frase.`;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: { temperature: 0.7 }
  });
  return response.text?.trim() || "";
}

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig,
  onProgress?: (step: string) => void,
  forcedTheme?: VisualTheme
): Promise<GeneratedMenu> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let visualTheme: VisualTheme | undefined = forcedTheme;

  if (!forcedTheme && config.logo) {
    onProgress?.("Sintonizando identidade visual...");
    try {
      visualTheme = await analyzeLogoTheme(config.logo);
    } catch (e) {
      console.error("Erro ao analisar logo:", e);
    }
  }

  onProgress?.(`Harmonizando cardápio com o tema: "${config.theme}"...`);

  const recentDishes = config.recentDishIds || [];
  const availablePool = dishPool.map(d => ({ 
    id: d.id,
    name: d.name, 
    category: d.category, 
    description: d.description, 
    isDefault: d.isDefault,
    isRecent: recentDishes.includes(d.id)
  }));

  const structureRequested = config.chefChoice 
    ? "ESTILO LIVRE: Escolha as melhores combinações do acervo que façam sentido GASTRONÔMICO com o título do dia."
    : `METAS POR CATEGORIA:\n${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${cat}: selecionar exatamente ${count} item(ns)`)
        .join('\n')}`;

  const prompt = `
    Aja como um Chef Executivo de renome internacional montando o cardápio do dia.

    TÍTULO/TEMA DO DIA: "${config.theme}"

    INSTRUÇÃO MESTRE: O cardápio deve ser INTEIRAMENTE baseado no título acima. 
    Se o título for "Quarta-feira Brasileira", escolha pratos típicos do Brasil do acervo.
    Se o título for "Especial Fit", escolha opções leves.
    Sua missão é criar uma NARRATIVA GASTRONÔMICA onde os pratos selecionados combinem entre si.

    ACERVO DISPONÍVEL (Use APENAS itens desta lista):
    ${JSON.stringify(availablePool)}

    REGRAS DE OURO:
    1. HARMONIZAÇÃO: O prato principal (Carne/Massa) deve ditar o tom dos acompanhamentos e saladas.
    2. ROTAÇÃO (3 DIAS): Itens com "isRecent: true" devem ser evitados, a menos que sejam essenciais para o TEMA.
    3. PRATOS PADRÃO: Itens "isDefault: true" devem ser incluídos se fizerem sentido com o tema.
    4. SELEÇÃO: ${structureRequested}
    5. CHEF NOTE: Uma frase curta e sofisticada explicando a inspiração do menu baseado no tema (max 15 palavras).

    Retorne o JSON seguindo o schema rigorosamente.
  `;

  onProgress?.("O Chef está finalizando as combinações...");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        temperature: 0.8,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            selections: {
              type: Type.OBJECT,
              properties: {
                [Category.BASE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.PASTA]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              }
            },
            chefNote: { type: Type.STRING }
          },
          required: ["selections", "chefNote"]
        }
      }
    });

    const parsed = JSON.parse(response.text || '{}');
    const finalSelections: any = {};
    Object.values(Category).forEach(cat => {
      finalSelections[cat] = parsed.selections?.[cat] || [];
    });

    return { selections: finalSelections, chefNote: parsed.chefNote, visualTheme };
  } catch (error) {
    console.error("Erro ChefAI:", error);
    throw error;
  }
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption, MenuHistoryEntry } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI, generateDishDescription } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const LOCAL_STORAGE_KEY = 'chefai_default_layout';
const STORAGE_INVENTORY_KEY = 'chefai_inventory';
const STORAGE_CONFIG_KEY = 'chefai_session_config';
const STORAGE_HISTORY_KEY = 'chefai_menu_history';

const App: React.FC = () => {
  // Inventory State
  const [dishPool, setDishPool] = useState<Dish[]>(() => {
    const saved = localStorage.getItem(STORAGE_INVENTORY_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_DISHES;
  });

  // History State (Rotation logic)
  const [menuHistory, setMenuHistory] = useState<MenuHistoryEntry[]>(() => {
    const saved = localStorage.getItem(STORAGE_HISTORY_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // Configuration State
  const [config, setConfig] = useState<MenuConfig>(() => {
    const saved = localStorage.getItem(STORAGE_CONFIG_KEY);
    const defaultConfig: MenuConfig = {
      counts: { [Category.BASE]: 2, [Category.MEAT]: 2, [Category.PASTA]: 0, [Category.SIDE]: 2, [Category.SALAD]: 2, [Category.DESSERT]: 0 },
      theme: 'Cardápio Especial do Dia',
      baseOption: 'Tradicional',
      chefChoice: false,
      useDefaultLayout: false,
      mealOptions: []
    };
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return { ...defaultConfig, ...parsed, counts: { ...defaultConfig.counts, ...parsed.counts }, useDefaultLayout: false };
      } catch (e) { return defaultConfig; }
    }
    return defaultConfig;
  });

  // UI States
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);
  const [isBulkGenerating, setIsBulkGenerating] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [defaultLayout, setDefaultLayout] = useState<{ visualTheme: VisualTheme, theme: string } | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Persistence Effects
  useEffect(() => { localStorage.setItem(STORAGE_INVENTORY_KEY, JSON.stringify(dishPool)); }, [dishPool]);
  useEffect(() => { localStorage.setItem(STORAGE_HISTORY_KEY, JSON.stringify(menuHistory)); }, [menuHistory]);
  useEffect(() => {
    const { logo, useDefaultLayout, ...persistableConfig } = config;
    localStorage.setItem(STORAGE_CONFIG_KEY, JSON.stringify(persistableConfig));
  }, [config]);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) setDefaultLayout(JSON.parse(saved));
    if (config.logo) setLogoPreview(config.logo);
  }, []);

  // Get used IDs from last 3 entries in history
  const recentDishIds = useMemo(() => {
    return menuHistory.slice(-3).flatMap(entry => entry.dishIds);
  }, [menuHistory]);

  // Dynamic Layout Calculations
  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return (Object.values(generatedMenu.selections) as any[][]).reduce((acc, curr) => acc + (curr?.length || 0), 0);
  }, [generatedMenu]);

  const isMultiColumn = useMemo(() => {
    if (exportFormat === 'story' || !generatedMenu) return false;
    return totalItemsCount > 10;
  }, [exportFormat, totalItemsCount, generatedMenu]);

  const layoutScale = useMemo(() => {
    if (exportFormat === 'story') {
      if (totalItemsCount > 15) return 0.55;
      if (totalItemsCount > 10) return 0.7;
      return 0.85;
    }
    return 1;
  }, [exportFormat, totalItemsCount]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    }).sort((a, b) => (a.isDefault === b.isDefault) ? 0 : a.isDefault ? -1 : 1);
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Handlers
  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setLogoPreview(base64);
      setConfig(prev => ({ ...prev, logo: base64 }));
    };
    reader.readAsDataURL(file);
  };

  const handleToggleDefault = (dish: Dish) => {
    setDishPool(prev => prev.map(d => {
      if (d.id === dish.id) return { ...d, isDefault: !d.isDefault };
      if (d.category === dish.category) return { ...d, isDefault: false };
      return d;
    }));
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) { setToast({ message: 'Seu acervo está vazio!', type: 'error' }); setActiveTab('inventory'); return; }
    setIsGenerating(true);
    setGenerationStep(`Inspirando o menu no tema: ${config.theme}...`);
    try {
      const forcedTheme = config.useDefaultLayout && defaultLayout ? defaultLayout.visualTheme : undefined;
      const result = await generateMenuWithAI(
        dishPool, 
        { ...config, recentDishIds }, 
        (step) => setGenerationStep(step), 
        forcedTheme
      );

      setGeneratedMenu(result);

      const usedIds: string[] = [];
      Object.values(result.selections).forEach((items: any[]) => {
        items.forEach(item => {
          const found = dishPool.find(d => d.name === item.name);
          if (found) usedIds.push(found.id);
        });
      });

      setMenuHistory(prev => {
        const newHistory = [...prev, { date: new Date().toISOString(), dishIds: usedIds }];
        return newHistory.slice(-5);
      });

      setActiveTab('result');
      setToast({ message: 'Cardápio harmonizado gerado!', type: 'success' });
    } catch (error) {
      setToast({ message: 'Erro na inspiração do Chef.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImportExcel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const wb = XLSX.read(evt.target?.result, { type: 'binary' });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];
      const imported: Dish[] = data.slice(1).map((row, index) => {
        const cat = Object.values(Category).find(c => c.toLowerCase() === String(row[1]||'').trim().toLowerCase());
        return { id: `imp-${Date.now()}-${index}`, name: String(row[0]||''), category: cat || Category.MEAT, description: String(row[2]||'') };
      }).filter(d => d.name);
      setPendingDishes(imported);
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = () => {
    if (pendingDishes) {
      setDishPool(prev => [...prev, ...pendingDishes]);
      setToast({ message: 'Acervo alimentado!', type: 'success' });
    }
    setPendingDishes(null);
    setShowImportGuide(false);
  };

  return (
