                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Categoria</span>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-600">
