                      const desc = await generateDishDescription(editingDish.name);
                      setEditingDish({...editingDish, description: desc});
                    } finally { setIsGeneratingDesc(false); }
                  }} disabled={isGeneratingDesc} className="text-[10px] font-black text-orange-500 uppercase tracking-widest flex items-center gap-1.5 hover:scale-105 transition-transform">
                    {isGeneratingDesc ? '✍️ Redigindo...' : '✨ Sugestão IA'}
