                </div>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none min-h-[120px] text-sm text-stone-600 leading-relaxed" placeholder="Como esse prato deve ser apresentado?" />
              </label>
              <div className="flex gap-4 pt-6">
                <button onClick={() => setEditingDish(null)} className="flex-1 py-5 font-black uppercase text-[10px] text-stone-400 hover:text-stone-600 tracking-widest transition-colors">Cancelar</button>
                <button onClick={() => {
                  setDishPool(p => {
                    const idx = p.findIndex(d => d.id === editingDish.id);
                    if (idx >= 0) { const c = [...p]; c[idx] = editingDish; return c; }
                    return [...p, editingDish];
                  });
                  setEditingDish(null);
                  setToast({ message: 'Item atualizado no acervo!', type: 'success' });
                }} className="flex-1 py-5 bg-orange-500 text-white rounded-[1.5rem] font-black uppercase text-[10px] shadow-xl hover:scale-[1.02] active:scale-95 transition-all tracking-widest">Salvar Especialidade</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Import Modal */}
      {showImportGuide && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-2xl p-12 animate-in zoom-in-95 overflow-y-auto max-h-[90vh] border border-white">
            <div className="flex justify-between mb-10">
              <h3 className="serif text-4xl font-black text-stone-800">Importar Especialidades</h3>
              <button onClick={() => setShowImportGuide(false)} className="text-2xl opacity-20 hover:opacity-100">✕</button>
            </div>

            <div className="space-y-8">
              <div className="p-6 bg-orange-50 rounded-3xl border border-orange-100 text-sm text-orange-800 leading-relaxed italic">
                A IA analisará cada prato importado para criar o menu perfeito baseado no título.
                Organize seu arquivo com as colunas: <span className="font-bold underline">Nome, Categoria, Descrição</span>.
              </div>

              <label className="block w-full cursor-pointer group">
                <div className="w-full h-48 border-2 border-dashed border-stone-200 rounded-[2.5rem] flex flex-col items-center justify-center group-hover:border-orange-500 group-hover:bg-orange-50 transition-all duration-300">
                  <span className="text-5xl mb-4 group-hover:scale-110 transition-transform">📊</span>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] text-stone-400">Selecionar arquivo (.xlsx, .xls ou .csv)</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleImportExcel} />
              </label>

              {pendingDishes && pendingDishes.length > 0 && (
                <div className="pt-6 animate-in slide-in-from-bottom-4">
                  <p className="text-[10px] font-black uppercase text-orange-500 mb-5 text-center tracking-[0.2em]">Encontrados {pendingDishes.length} itens para o acervo</p>
                  <button onClick={confirmImport} className="w-full py-6 bg-stone-900 text-white rounded-[2rem] font-black uppercase tracking-[0.4em] text-[10px] shadow-2xl hover:bg-black transition-all">Confirmar e Importar</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

