      </main>

      {/* Editing Dish Modal and Import Guide remain as specified... */}
      {editingDish && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12 animate-in zoom-in-95 duration-300">
