              </label>
              <div className="flex gap-4 pt-6">
                <button onClick={() => setEditingDish(null)} className="flex-1 py-5 font-black uppercase text-[10px] text-stone-400 hover:text-stone-600 tracking-widest transition-colors">Cancelar</button>
