      {showImportGuide && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-2xl p-12 animate-in zoom-in-95 overflow-y-auto max-h-[90vh] border border-white">
            <div className="flex justify-between mb-10">
              <h3 className="serif text-4xl font-black text-stone-800">Importar Especialidades</h3>
              <button onClick={() => setShowImportGuide(false)} className="text-2xl opacity-20 hover:opacity-100">✕</button>
            </div>

            <div className="space-y-8">
              <div className="p-6 bg-orange-50 rounded-3xl border border-orange-100 text-sm text-orange-800 leading-relaxed italic">
                A IA analisará cada prato importado para criar o menu perfeito baseado no título.
                Organize seu arquivo com as colunas: <span className="font-bold underline">Nome, Categoria, Descrição</span>.
              </div>

              <label className="block w-full cursor-pointer group">
                <div className="w-full h-48 border-2 border-dashed border-stone-200 rounded-[2.5rem] flex flex-col items-center justify-center group-hover:border-orange-500 group-hover:bg-orange-50 transition-all duration-300">
                  <span className="text-5xl mb-4 group-hover:scale-110 transition-transform">📊</span>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] text-stone-400">Selecionar arquivo (.xlsx, .xls ou .csv)</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleImportExcel} />
              </label>

              {pendingDishes && pendingDishes.length > 0 && (
                <div className="pt-6 animate-in slide-in-from-bottom-4">
                  <p className="text-[10px] font-black uppercase text-orange-500 mb-5 text-center tracking-[0.2em]">Encontrados {pendingDishes.length} itens para o acervo</p>
                  <button onClick={confirmImport} className="w-full py-6 bg-stone-900 text-white rounded-[2rem] font-black uppercase tracking-[0.4em] text-[10px] shadow-2xl hover:bg-black transition-all">Confirmar e Importar</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme } from "../types";

async function analyzeLogoTheme(logoBase64: string): Promise<VisualTheme> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: "image/png",
      data: logoBase64.split(',')[1] || logoBase64,
    },
  };

  const prompt = `
    Analise esta logomarca de restaurante e extraia uma paleta de cores sofisticada e um conceito de design para um cardápio digital.
    Retorne um JSON com:
    1. primaryColor, 2. secondaryColor, 3. backgroundColor, 4. backgroundGradient, 5. textColor, 6. accentColor, 7. patternType.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [imagePart, { text: prompt }] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          primaryColor: { type: Type.STRING },
          secondaryColor: { type: Type.STRING },
          backgroundColor: { type: Type.STRING },
          backgroundGradient: { type: Type.STRING },
          textColor: { type: Type.STRING },
          accentColor: { type: Type.STRING },
          patternType: { type: Type.STRING, enum: ['dots', 'grid', 'mesh', 'stripes', 'clean'] },
        },
        required: ["primaryColor", "secondaryColor", "backgroundColor", "backgroundGradient", "textColor", "accentColor", "patternType"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
}

export async function generateDishDescription(dishName: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Você é um Chef Michelin. Escreva uma descrição curta e apetitosa (max 8 palavras) para: "${dishName}". Responda APENAS a frase.`;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: { temperature: 0.7 }
  });
  return response.text?.trim() || "";
}

export async function generateMenuWithAI(
  dishPool: Dish[],
  config: MenuConfig,
  onProgress?: (step: string) => void,
  forcedTheme?: VisualTheme
): Promise<GeneratedMenu> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let visualTheme: VisualTheme | undefined = forcedTheme;

  if (!forcedTheme && config.logo) {
    onProgress?.("Sintonizando identidade visual...");
    try {
      visualTheme = await analyzeLogoTheme(config.logo);
    } catch (e) {
      console.error("Erro ao analisar logo:", e);
    }
  }

  onProgress?.(`Harmonizando pratos para: "${config.theme}"...`);

  const recentDishes = config.recentDishIds || [];
  const availablePool = dishPool.map(d => ({ 
    name: d.name, 
    category: d.category, 
    description: d.description,
    isRecent: recentDishes.includes(d.id)
  }));

  const structureRequested = config.chefChoice 
    ? "ESTILO LIVRE: Escolha as melhores combinações que façam sentido GASTRONÔMICO com o título."
    : `QUANTIDADES OBRIGATÓRIAS:\n${Object.entries(config.counts)
        .filter(([_, count]) => count > 0)
        .map(([cat, count]) => `- ${cat}: exatamente ${count} item(ns)`)
        .join('\n')}`;

  const prompt = `
    Aja como um Chef Executivo montando o cardápio do dia.
    TÍTULO DO DIA: "${config.theme}"

    ACERVO DISPONÍVEL (Use APENAS estes itens):
    ${JSON.stringify(availablePool)}

    DIRETRIZES DE GERAÇÃO:
    1. TEMA: Selecione pratos que combinem com o título "${config.theme}".
    2. ROTAÇÃO: Evite itens com "isRecent: true". IMPORTANTE: Se não houver pratos suficientes na categoria para cumprir a QUANTIDADE pedida, ignore a regra de rotação e use os itens disponíveis. A prioridade é entregar a quantidade correta.
    3. HARMONIZAÇÃO: A Carne/Massa deve ditar os acompanhamentos.
    4. SCHEMA: Retorne as chaves de categoria exatamente como: "Base", "Carne", "Massa", "Acompanhamento", "Salada", "Sobremesa".
    5. CHEF NOTE: Frase curta sobre a inspiração (max 12 palavras).

    ${structureRequested}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        temperature: 0.8,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            selections: {
              type: Type.OBJECT,
              properties: {
                [Category.BASE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.MEAT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.PASTA]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SIDE]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.SALAD]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
                [Category.DESSERT]: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              }
            },
            chefNote: { type: Type.STRING }
          },
          required: ["selections", "chefNote"]
        }
      }
    });

    const parsed = JSON.parse(response.text || '{}');
    const finalSelections: any = {};
    Object.values(Category).forEach(cat => {
      finalSelections[cat] = parsed.selections?.[cat] || [];
    });

    return { selections: finalSelections, chefNote: parsed.chefNote, visualTheme };
  } catch (error) {
    console.error("Falha na geração Gemini:", error);
    throw new Error("Não foi possível harmonizar o cardápio. Verifique seu acervo ou tente novamente.");
  }
}

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption, MenuHistoryEntry } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI, generateDishDescription } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const STORAGE_LOGO_KEY = 'chefai_brand_logo';
const STORAGE_INVENTORY_KEY = 'chefai_inventory';
const STORAGE_CONFIG_KEY = 'chefai_session_config';
const STORAGE_HISTORY_KEY = 'chefai_menu_history';

const App: React.FC = () => {
  // 1. Inventory State with Persistence
  const [dishPool, setDishPool] = useState<Dish[]>(() => {
    const saved = localStorage.getItem(STORAGE_INVENTORY_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_DISHES;
  });

  // 2. History State (Rotation logic)
  const [menuHistory, setMenuHistory] = useState<MenuHistoryEntry[]>(() => {
    const saved = localStorage.getItem(STORAGE_HISTORY_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // 3. Configuration State
  const [config, setConfig] = useState<MenuConfig>(() => {
    const saved = localStorage.getItem(STORAGE_CONFIG_KEY);
    const savedLogo = localStorage.getItem(STORAGE_LOGO_KEY);

    const defaultConfig: MenuConfig = {
      counts: { 
        [Category.BASE]: 2, 
        [Category.MEAT]: 2, 
        [Category.PASTA]: 0, 
        [Category.SIDE]: 2, 
        [Category.SALAD]: 2, 
        [Category.DESSERT]: 0 
      },
      theme: 'Cardápio Especial do Dia',
      baseOption: 'Tradicional',
      chefChoice: false,
      useDefaultLayout: false,
      mealOptions: []
    };

    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return { 
          ...defaultConfig, 
          ...parsed, 
          logo: savedLogo || undefined,
          counts: { ...defaultConfig.counts, ...parsed.counts }
        };
      } catch (e) { 
        return defaultConfig; 
      }
    }
    return defaultConfig;
  });

  // UI States
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [isSaving, setIsSaving] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  // Persistence Effects
  useEffect(() => {
    localStorage.setItem(STORAGE_INVENTORY_KEY, JSON.stringify(dishPool));
  }, [dishPool]);

  useEffect(() => {
    localStorage.setItem(STORAGE_HISTORY_KEY, JSON.stringify(menuHistory));
  }, [menuHistory]);

  useEffect(() => {
    setIsSaving(true);
    const { logo, ...persistableConfig } = config;
    localStorage.setItem(STORAGE_CONFIG_KEY, JSON.stringify(persistableConfig));
    if (logo) {
      localStorage.setItem(STORAGE_LOGO_KEY, logo);
    } else {
      localStorage.removeItem(STORAGE_LOGO_KEY);
    }
    const timer = setTimeout(() => setIsSaving(false), 800);
    return () => clearTimeout(timer);
  }, [config]);

  const recentDishIds = useMemo(() => {
    // Pegar apenas os últimos 3 dias/gerações para a rotação
    return menuHistory.slice(-3).flatMap(entry => entry.dishIds);
  }, [menuHistory]);

  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return Object.values(generatedMenu.selections).reduce((acc, curr) => acc + (curr?.length || 0), 0);
  }, [generatedMenu]);

  const layoutScale = useMemo(() => {
    if (exportFormat === 'story') {
      if (totalItemsCount > 15) return 0.55;
      if (totalItemsCount > 10) return 0.7;
      return 0.85;
    }
    return 1;
  }, [exportFormat, totalItemsCount]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    }).sort((a, b) => (a.isDefault === b.isDefault) ? 0 : a.isDefault ? -1 : 1);
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Handlers
  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setConfig(prev => ({ ...prev, logo: base64 }));
    };
    reader.readAsDataURL(file);
  };

  const updateMealOption = (id: string, field: keyof MealOption, value: string) => {
    let finalValue = value;
    if (field === 'price' && value && !value.startsWith('R$')) {
      finalValue = 'R$ ' + value;
    }
    setConfig(prev => ({
      ...prev,
      mealOptions: prev.mealOptions?.map(o => o.id === id ? { ...o, [field]: finalValue } : o)
    }));
  };

  const handleToggleDefault = (dish: Dish) => {
    setDishPool(prev => prev.map(d => {
      if (d.id === dish.id) return { ...d, isDefault: !d.isDefault };
      if (d.category === dish.category) return { ...d, isDefault: false };
      return d;
    }));
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) { 
      setToast({ message: 'Seu acervo está vazio!', type: 'error' }); 
      setActiveTab('inventory'); 
      return; 
    }
    setIsGenerating(true);
    setGenerationStep(`ChefAI harmonizando pratos para: ${config.theme}...`);
    try {
      const result = await generateMenuWithAI(
        dishPool, 
        { ...config, recentDishIds }, 
        (step) => setGenerationStep(step)
      );

      setGeneratedMenu(result);

      const usedIds: string[] = [];
      Object.values(result.selections).forEach((items: any[]) => {
        items.forEach(item => {
          const found = dishPool.find(d => d.name === item.name);
          if (found) usedIds.push(found.id);
        });
      });

      setMenuHistory(prev => {
        const newHistory = [...prev, { date: new Date().toISOString(), dishIds: usedIds }];
        return newHistory.slice(-10); // Manter as últimas 10 gerações
      });

      setActiveTab('result');
      setToast({ message: 'Cardápio gerado com sucesso!', type: 'success' });
    } catch (error: any) {
      setToast({ message: error.message || 'Erro na geração.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImportExcel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const wb = XLSX.read(evt.target?.result, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];
        const imported: Dish[] = data.slice(1).map((row, index) => {
          const catStr = String(row[1]||'').trim().toLowerCase();
          const cat = Object.values(Category).find(c => c.toLowerCase() === catStr);
          return { 
            id: `imp-${Date.now()}-${index}`, 
            name: String(row[0]||'').trim(), 
            category: cat || Category.MEAT, 
            description: String(row[2]||'').trim() 
          };
        }).filter(d => d.name);
        setPendingDishes(imported);
      } catch (e) {
        setToast({ message: 'Erro ao ler arquivo. Verifique o formato.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = () => {
    if (pendingDishes) {
      setDishPool(prev => [...prev, ...pendingDishes]);
      setToast({ message: `${pendingDishes.length} itens importados!`, type: 'success' });
    }
    setPendingDishes(null);
    setShowImportGuide(false);
  };

  return (
    <div className="min-h-screen bg-[#faf9f6] text-[#2d2d2d] antialiased scrollbar-thin">
      {/* Loading Overlay */}
      {isGenerating && (
        <div className="fixed inset-0 z-[1000] bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-500">
          <div className="relative mb-10">
            <div className="w-28 h-28 border-4 border-stone-100 border-t-orange-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-4xl">👨‍🍳</div>
          </div>
          <h2 className="serif text-3xl font-bold text-stone-800 animate-pulse tracking-tight text-center px-8">{generationStep}</h2>
          <p className="text-stone-400 text-[10px] uppercase tracking-[0.3em] mt-4 italic text-center px-10">
            Respeitando a rotação de 3 dias e o tema solicitado
          </p>
        </div>
      )}

      {/* Persistence Status */}
      <div className={`fixed top-24 right-8 z-[1100] transition-all duration-500 flex items-center gap-2 ${isSaving ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-2 pointer-events-none'}`}>
        <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
        <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest">Sincronizado</span>
      </div>

      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[1100] animate-in slide-in-from-bottom-6">
          <div className={`px-8 py-4 rounded-3xl shadow-2xl font-bold uppercase tracking-widest text-[10px] flex items-center gap-3 ${toast.type === 'success' ? 'bg-stone-900 text-white' : 'bg-red-500 text-white'}`}>
            <span>{toast.message}</span>
          </div>
        </div>
      )}

      {/* Navbar */}
      <nav className="fixed top-0 inset-x-0 h-20 bg-white/80 backdrop-blur-lg border-b border-stone-200/50 z-[100] px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center shadow-xl shadow-orange-200 text-white text-2xl">🥗</div>
            <div className="leading-tight">
              <h1 className="serif text-2xl font-black tracking-tighter">CHEF AI</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase tracking-[0.4em]">Personalizador Gourmet</span>
            </div>
          </div>
          <div className="flex bg-stone-100 p-1.5 rounded-2xl">
            {['compose', 'inventory', 'result'].map((t) => (
              <button 
                key={t}
                onClick={() => setActiveTab(t as TabType)}
                disabled={t === 'result' && !generatedMenu}
                className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-white text-stone-900 shadow-md' : 'text-stone-400 hover:text-stone-600 disabled:opacity-30'}`}
              >
                {t === 'compose' ? '✨ Criar' : t === 'inventory' ? '📦 Acervo' : '🖼️ Preview'}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-8 pt-32 pb-24">
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="lg:col-span-4 space-y-8">
              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <h2 className="serif text-2xl font-bold mb-6">Identidade Visual</h2>
                <div className="space-y-6">
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Logo da Marca</span>
                    <div className="relative h-40 rounded-3xl bg-stone-50 border-2 border-dashed border-stone-200 flex items-center justify-center cursor-pointer hover:border-orange-400 transition-all overflow-hidden group">
                      {config.logo ? <img src={config.logo} className="w-full h-full object-contain p-4" /> : <span className="text-[10px] font-bold text-stone-300">Upload Logo</span>}
                      <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleLogoUpload} />
                    </div>
                  </label>
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Título do Cardápio</span>
                    <input type="text" value={config.theme} onChange={e => setConfig({...config, theme: e.target.value})} className="w-full bg-stone-50 rounded-2xl px-5 py-4 outline-none font-bold text-stone-700 border border-stone-100 focus:ring-2 ring-orange-200 transition-all" placeholder="Ex: Sexta-feira Brasileira" />
                  </label>
                </div>
              </section>

              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="serif text-2xl font-bold">Marmitas / Preços</h2>
                  <button onClick={() => setConfig(prev => ({...prev, mealOptions: [...(prev.mealOptions||[]), {id: Date.now().toString(), title: '', price: ''}]}))} className="w-10 h-10 bg-orange-500 text-white rounded-2xl shadow-lg hover:scale-110 active:scale-95 transition-all">+</button>
                </div>
                <div className="space-y-4">
                  {config.mealOptions?.map(opt => (
                    <div key={opt.id} className="p-5 bg-stone-50 rounded-[2rem] border border-stone-100 relative group transition-all hover:bg-white hover:shadow-xl hover:shadow-stone-200/50">
                      <button onClick={() => setConfig(prev => ({...prev, mealOptions: prev.mealOptions?.filter(o => o.id !== opt.id)}))} className="absolute -top-2 -right-2 w-7 h-7 bg-white border border-stone-100 rounded-full flex items-center justify-center text-[10px] shadow-sm hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">✕</button>
                      <div className="space-y-3">
                        <input placeholder="Ex: Marmita G" value={opt.title} onChange={e => updateMealOption(opt.id, 'title', e.target.value)} className="bg-white border border-stone-100 rounded-xl px-4 py-2 font-bold text-xs w-full outline-none focus:border-orange-500" />
                        <input placeholder="R$ 00,00" value={opt.price} onChange={e => updateMealOption(opt.id, 'price', e.target.value)} className="bg-white border border-stone-100 rounded-xl px-4 py-2 text-[11px] text-orange-600 font-black w-full outline-none focus:border-orange-500" />
                      </div>
                    </div>
                  ))}
                </div>
              </section>

              <button onClick={handleGenerate} disabled={isGenerating} className="w-full py-6 bg-orange-500 text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-xs shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">
                {isGenerating ? 'Chef Criando...' : 'Gerar Menu Harmonizado'}
              </button>
            </div>

            <div className="lg:col-span-8 bg-white rounded-[3.5rem] p-12 shadow-sm border border-stone-100">
              <div className="flex justify-between items-center mb-12">
                <div>
                  <h2 className="serif text-4xl font-bold text-stone-800">Estrutura</h2>
                  <p className="text-stone-400 text-xs font-bold uppercase tracking-widest mt-1">Defina a composição do seu cardápio</p>
                </div>
                <button onClick={() => setConfig({...config, chefChoice: !config.chefChoice})} className={`px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${config.chefChoice ? 'bg-orange-500 text-white' : 'bg-stone-100 text-stone-400 hover:bg-stone-200'}`}>
                  {config.chefChoice ? '✨ Escolha Livre do Chef' : '⚙️ Quantidades Fixas'}
                </button>
              </div>

              <div className={`grid grid-cols-1 md:grid-cols-2 gap-6 transition-all duration-500 ${config.chefChoice ? 'opacity-30 pointer-events-none grayscale scale-[0.98]' : ''}`}>
                {CATEGORY_ORDER.map(cat => (
                  <div key={cat} className="group flex items-center justify-between p-6 bg-stone-50 rounded-[2.5rem] border border-stone-100 hover:bg-white hover:border-orange-200 hover:shadow-lg transition-all">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-2xl shadow-sm flex items-center justify-center text-2xl group-hover:scale-110 transition-transform">{(ICONS as any)[cat.toUpperCase()] || '🍽️'}</div>
                      <span className="font-bold text-stone-700">{cat}</span>
                    </div>
                    <div className="flex items-center gap-5 bg-white px-5 py-2 rounded-2xl shadow-sm border border-stone-100">
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat] - 1)}}))} className="font-black text-stone-400 hover:text-orange-500 transition-colors text-xl">-</button>
                      <span className="font-black w-6 text-center text-sm">{config.counts[cat]}</span>
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat] + 1}}))} className="font-black text-stone-400 hover:text-orange-500 transition-colors text-xl">+</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="bg-white rounded-[3.5rem] p-12 shadow-sm border border-stone-100 animate-in fade-in slide-in-from-bottom-6">
            <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-12">
              <div>
                <h2 className="serif text-5xl font-bold">Acervo de Sabores</h2>
                <p className="text-stone-400 text-xs font-bold uppercase tracking-widest mt-2">Personalize sua biblioteca de pratos</p>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setShowImportGuide(true)} className="px-6 py-4 bg-stone-100 text-stone-500 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-stone-200 transition-all">📥 Importar Excel</button>
                <button onClick={() => setEditingDish({ id: Date.now().toString(), name: '', category: Category.MEAT, description: '' })} className="px-8 py-4 bg-stone-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-black transition-all">+ Novo Prato</button>
              </div>
            </div>

            <div className="flex gap-4 mb-10">
              <input placeholder="Buscar no acervo..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="flex-1 bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-semibold focus:ring-2 ring-orange-100" />
              <select value={filterCategory} onChange={e => setFilterCategory(e.target.value as any)} className="bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-500 uppercase text-[10px]">
                <option value="Todos">Todas Categorias</option>
                {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredDishes.map(dish => (
                <div key={dish.id} className="group relative p-8 rounded-[3rem] bg-white border border-stone-100 hover:shadow-2xl hover:-translate-y-1 transition-all duration-300">
                  <div className="flex justify-between mb-5">
                    <span className="text-[9px] font-black uppercase tracking-widest text-stone-400 bg-stone-50 px-3 py-1.5 rounded-full border border-stone-100">{dish.category}</span>
                    <button onClick={() => handleToggleDefault(dish)} className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-all ${dish.isDefault ? 'bg-orange-500 text-white shadow-xl' : 'bg-stone-50 text-stone-300'}`} title="Prato Padrão">★</button>
                  </div>
                  <h3 className="serif text-2xl font-bold mb-2 group-hover:text-orange-500 transition-colors">{dish.name}</h3>
                  <p className="text-[11px] text-stone-400 italic line-clamp-3 leading-relaxed">{dish.description || 'Sem descrição gourmet...'}</p>

                  {recentDishIds.includes(dish.id) && (
                    <div className="mt-4 inline-block px-2 py-1 bg-red-50 text-red-500 text-[8px] font-black uppercase tracking-widest rounded-lg">
                      🕒 Rotação Ativa (Usado Recentemente)
                    </div>
                  )}

                  <div className="mt-8 flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all duration-300">
                    <button onClick={() => setEditingDish(dish)} className="p-3 bg-stone-50 rounded-xl hover:bg-orange-500 hover:text-white transition-all">✎</button>
                    <button onClick={() => { if(window.confirm(`Excluir ${dish.name}?`)) setDishPool(p => p.filter(d => d.id !== dish.id)); }} className="p-3 bg-stone-50 rounded-xl hover:bg-red-500 hover:text-white transition-all">✕</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in zoom-in-95 duration-700">
             <div className="mb-10 flex flex-wrap justify-center gap-6 no-print">
                <div className="flex bg-stone-100 p-1.5 rounded-full shadow-inner">
                  <button onClick={() => setExportFormat('standard')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'standard' ? 'bg-white text-stone-900 shadow-xl' : 'text-stone-400 hover:text-stone-600'}`}>A4 Impressão</button>
                  <button onClick={() => setExportFormat('story')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'story' ? 'bg-white text-stone-900 shadow-xl' : 'text-stone-400 hover:text-stone-600'}`}>Digital Story</button>
                </div>
                <button onClick={() => { 
                   setToast({ message: 'Preparando imagem...', type: 'success' });
                   toPng(menuRef.current!, { quality: 1, pixelRatio: 3 }).then(url => {
                     const l = document.createElement('a');
                     l.download = `Menu-${config.theme.replace(/\s+/g, '-')}.png`;
                     l.href = url;
                     l.click();
                   });
                }} className="px-10 py-3.5 bg-orange-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all">Download HD</button>
             </div>

             <div 
               ref={menuRef}
               className={`bg-white relative shadow-[0_50px_100px_-20px_rgba(0,0,0,0.15)] overflow-hidden transition-all duration-700 ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16]' : 'w-[850px] min-h-[1200px]'}`}
               style={{ backgroundColor: generatedMenu.visualTheme?.backgroundColor || '#fff' }}
             >
               <div className="absolute inset-0 pointer-events-none opacity-10" style={{ background: generatedMenu.visualTheme?.backgroundGradient }}></div>
               <div className="relative z-10 h-full flex flex-col items-center p-16">
                 <header className="text-center mb-16 w-full relative">
                   {config.logo && <img src={config.logo} className="h-28 mx-auto mb-8 object-contain drop-shadow-xl" alt="Estabelecimento" />}
                   <div className="inline-block px-6 py-2 mb-4 bg-stone-900 text-white text-[9px] font-black uppercase tracking-[0.5em] shadow-lg" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor }}>ChefAI Harmonized</div>
                   <h1 className="serif uppercase leading-[0.85] font-black text-stone-900 mb-8" style={{ color: generatedMenu.visualTheme?.textColor, fontSize: exportFormat === 'story' ? '56px' : '92px' }}>{config.theme}</h1>

                   <div className="flex flex-wrap justify-center gap-6 mt-10">
                     {config.mealOptions?.map(m => (
                       <div key={m.id} className="bg-white/40 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/60 shadow-sm flex flex-col items-center min-w-[120px]">
                         <span className="text-[8px] font-black uppercase text-stone-400 tracking-widest mb-1">{m.title}</span>
                         <span className="text-lg font-black text-orange-600">{m.price}</span>
                       </div>
                     ))}
                   </div>
                 </header>

                 <div className={`flex-1 w-full space-y-12 flex flex-col justify-center`} style={{ transform: `scale(${layoutScale})`, transformOrigin: 'top center' }}>
                   {CATEGORY_ORDER.map(cat => {
                     const items = generatedMenu.selections[cat];
                     if (!items?.length) return null;
                     return (
                       <div key={cat} className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
                         <div className="flex items-center gap-4">
                           <h3 className="text-[11px] font-black uppercase tracking-[0.6em] whitespace-nowrap" style={{ color: generatedMenu.visualTheme?.primaryColor }}>{cat}s</h3>
                           <div className="h-[1px] w-full bg-stone-100"></div>
                         </div>
                         <div className="space-y-6">
                           {items.map((it, idx) => (
                             <div key={idx} className="group">
                               <h4 className="font-bold text-2xl leading-none flex items-baseline gap-3" style={{ color: generatedMenu.visualTheme?.textColor }}>
                                 <span className="w-2 h-2 rounded-full flex-shrink-0" style={{ backgroundColor: generatedMenu.visualTheme?.accentColor }}></span>
                                 {it.name}
                               </h4>
                               {it.description && <p className="text-[13px] text-stone-400 italic font-medium leading-relaxed ml-5 mt-2 border-l-2 pl-4 py-1" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}>{it.description}</p>}
                             </div>
                           ))}
                         </div>
                       </div>
                     );
                   })}
                 </div>

                 <footer className="mt-20 w-full pt-16 border-t border-stone-100 flex flex-col items-center relative">
                   <p className="serif italic text-center text-stone-500 max-w-xl mx-auto mb-10 leading-relaxed text-xl px-4">"{generatedMenu.chefNote}"</p>
                   <div className="serif text-6xl font-black italic tracking-tighter text-stone-900 opacity-[0.08] mb-2">Bon Appétit</div>
                 </footer>
               </div>
             </div>
          </div>
        )}
      </main>

      {/* Editing Dish Modal */}
      {editingDish && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12 animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-10">
              <h3 className="serif text-3xl font-black text-stone-800">Ficha Técnica</h3>
              <button onClick={() => setEditingDish(null)} className="text-2xl opacity-20 hover:opacity-100 transition-opacity">✕</button>
            </div>
            <div className="space-y-8">
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Nome do Item</span>
                <input value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-lg text-stone-700" />
              </label>
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Categoria</span>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-600">
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </label>
              <label className="block">
                <div className="flex justify-between items-center mb-2">
                  <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Descrição Gourmet</span>
                  <button onClick={async () => {
                    if (!editingDish.name) return;
                    setIsGeneratingDesc(true);
                    try {
                      const desc = await generateDishDescription(editingDish.name);
                      setEditingDish({...editingDish, description: desc});
                    } finally { setIsGeneratingDesc(false); }
                  }} disabled={isGeneratingDesc} className="text-[10px] font-black text-orange-500 uppercase tracking-widest flex items-center gap-1.5 hover:scale-105 transition-transform">
                    {isGeneratingDesc ? '✍️ Redigindo...' : '✨ Sugestão IA'}
                  </button>
                </div>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none min-h-[120px] text-sm text-stone-600 leading-relaxed" placeholder="Como esse prato deve ser apresentado?" />
              </label>
              <div className="flex gap-4 pt-6">
                <button onClick={() => setEditingDish(null)} className="flex-1 py-5 font-black uppercase text-[10px] text-stone-400 hover:text-stone-600 tracking-widest transition-colors">Cancelar</button>
                <button onClick={() => {
                  setDishPool(p => {
                    const idx = p.findIndex(d => d.id === editingDish.id);
                    if (idx >= 0) { const c = [...p]; c[idx] = editingDish; return c; }
                    return [...p, editingDish];
                  });
                  setEditingDish(null);
                  setToast({ message: 'Item atualizado!', type: 'success' });
                }} className="flex-1 py-5 bg-orange-500 text-white rounded-[1.5rem] font-black uppercase text-[10px] shadow-xl hover:scale-[1.02] active:scale-95 transition-all tracking-widest">Salvar Especialidade</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showImportGuide && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-2xl p-12 animate-in zoom-in-95 overflow-y-auto max-h-[90vh] border border-white">
            <div className="flex justify-between mb-10">
              <h3 className="serif text-4xl font-black text-stone-800">Importar Especialidades</h3>
              <button onClick={() => setShowImportGuide(false)} className="text-2xl opacity-20 hover:opacity-100">✕</button>
            </div>

            <div className="space-y-8">
              <div className="p-6 bg-orange-50 rounded-3xl border border-orange-100 text-sm text-orange-800 leading-relaxed italic">
                A IA analisará cada prato importado para criar o menu perfeito baseado no título.
                Organize seu arquivo com as colunas: <span className="font-bold underline">Nome, Categoria, Descrição</span>.
              </div>

              <label className="block w-full cursor-pointer group">
                <div className="w-full h-48 border-2 border-dashed border-stone-200 rounded-[2.5rem] flex flex-col items-center justify-center group-hover:border-orange-500 group-hover:bg-orange-50 transition-all duration-300">
                  <span className="text-5xl mb-4 group-hover:scale-110 transition-transform">📊</span>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] text-stone-400">Selecionar arquivo (.xlsx, .xls ou .csv)</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleImportExcel} />
              </label>

              {pendingDishes && pendingDishes.length > 0 && (
                <div className="pt-6 animate-in slide-in-from-bottom-4">
                  <p className="text-[10px] font-black uppercase text-orange-500 mb-5 text-center tracking-[0.2em]">Encontrados {pendingDishes.length} itens para o acervo</p>
                  <button onClick={confirmImport} className="w-full py-6 bg-stone-900 text-white rounded-[2rem] font-black uppercase tracking-[0.4em] text-[10px] shadow-2xl hover:bg-black transition-all">Confirmar e Importar</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption, MenuHistoryEntry } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI, generateDishDescription } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const STORAGE_LOGO_KEY = 'chefai_brand_logo';
const STORAGE_INVENTORY_KEY = 'chefai_inventory';
const STORAGE_CONFIG_KEY = 'chefai_session_config';
const STORAGE_HISTORY_KEY = 'chefai_menu_history';

const App: React.FC = () => {
  // 1. Inventory State with Persistence
  const [dishPool, setDishPool] = useState<Dish[]>(() => {
    const saved = localStorage.getItem(STORAGE_INVENTORY_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_DISHES;
  });

  // 2. History State (Rotation logic)
  const [menuHistory, setMenuHistory] = useState<MenuHistoryEntry[]>(() => {
    const saved = localStorage.getItem(STORAGE_HISTORY_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // 3. Configuration State
  const [config, setConfig] = useState<MenuConfig>(() => {
    const saved = localStorage.getItem(STORAGE_CONFIG_KEY);
    const savedLogo = localStorage.getItem(STORAGE_LOGO_KEY);

    const defaultConfig: MenuConfig = {
      counts: { 
        [Category.BASE]: 2, 
        [Category.MEAT]: 2, 
        [Category.PASTA]: 0, 
        [Category.SIDE]: 2, 
        [Category.SALAD]: 2, 
        [Category.DESSERT]: 0 
      },
      theme: 'Cardápio Especial do Dia',
      baseOption: 'Tradicional',
      chefChoice: false,
      useDefaultLayout: false,
      mealOptions: []
    };

    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return { 
          ...defaultConfig, 
          ...parsed, 
          logo: savedLogo || undefined,
          counts: { ...defaultConfig.counts, ...parsed.counts }
        };
      } catch (e) { 
        return defaultConfig; 
      }
    }
    return defaultConfig;
  });

  // UI States
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [isSaving, setIsSaving] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  // Persistence Effects
  useEffect(() => {
    localStorage.setItem(STORAGE_INVENTORY_KEY, JSON.stringify(dishPool));
  }, [dishPool]);

  useEffect(() => {
    localStorage.setItem(STORAGE_HISTORY_KEY, JSON.stringify(menuHistory));
  }, [menuHistory]);

  useEffect(() => {
    setIsSaving(true);
    const { logo, ...persistableConfig } = config;
    localStorage.setItem(STORAGE_CONFIG_KEY, JSON.stringify(persistableConfig));
    if (logo) {
      localStorage.setItem(STORAGE_LOGO_KEY, logo);
    } else {
      localStorage.removeItem(STORAGE_LOGO_KEY);
    }
    const timer = setTimeout(() => setIsSaving(false), 800);
    return () => clearTimeout(timer);
  }, [config]);

  const recentDishIds = useMemo(() => {
    // Pegar apenas os últimos 3 dias/gerações para a rotação
    return menuHistory.slice(-3).flatMap(entry => entry.dishIds);
  }, [menuHistory]);

  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    // Fix: Explicitly type the current value as any to avoid 'unknown' type error on length access
    return Object.values(generatedMenu.selections).reduce((acc: number, curr: any) => acc + (curr?.length || 0), 0);
  }, [generatedMenu]);

  const layoutScale = useMemo(() => {
    if (exportFormat === 'story') {
      if (totalItemsCount > 15) return 0.55;
      if (totalItemsCount > 10) return 0.7;
      return 0.85;
    }
    return 1;
  }, [exportFormat, totalItemsCount]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    }).sort((a, b) => (a.isDefault === b.isDefault) ? 0 : a.isDefault ? -1 : 1);
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Handlers
  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setConfig(prev => ({ ...prev, logo: base64 }));
    };
    reader.readAsDataURL(file);
  };

  const updateMealOption = (id: string, field: keyof MealOption, value: string) => {
    let finalValue = value;
    if (field === 'price' && value && !value.startsWith('R$')) {
      finalValue = 'R$ ' + value;
    }
    setConfig(prev => ({
      ...prev,
      mealOptions: prev.mealOptions?.map(o => o.id === id ? { ...o, [field]: finalValue } : o)
    }));
  };

  const handleToggleDefault = (dish: Dish) => {
    setDishPool(prev => prev.map(d => {
      if (d.id === dish.id) return { ...d, isDefault: !d.isDefault };
      if (d.category === dish.category) return { ...d, isDefault: false };
      return d;
    }));
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) { 
      setToast({ message: 'Seu acervo está vazio!', type: 'error' }); 
      setActiveTab('inventory'); 
      return; 
    }
    setIsGenerating(true);
    setGenerationStep(`ChefAI harmonizando pratos para: ${config.theme}...`);
    try {
      const result = await generateMenuWithAI(
        dishPool, 
        { ...config, recentDishIds }, 
        (step) => setGenerationStep(step)
      );

      setGeneratedMenu(result);

      const usedIds: string[] = [];
      Object.values(result.selections).forEach((items: any[]) => {
        items.forEach(item => {
          const found = dishPool.find(d => d.name === item.name);
          if (found) usedIds.push(found.id);
        });
      });

      setMenuHistory(prev => {
        const newHistory = [...prev, { date: new Date().toISOString(), dishIds: usedIds }];
        return newHistory.slice(-10); // Manter as últimas 10 gerações
      });

      setActiveTab('result');
      setToast({ message: 'Cardápio gerado com sucesso!', type: 'success' });
    } catch (error: any) {
      setToast({ message: error.message || 'Erro na geração.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImportExcel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const wb = XLSX.read(evt.target?.result, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];
        const imported: Dish[] = data.slice(1).map((row, index) => {
          const catStr = String(row[1]||'').trim().toLowerCase();
          const cat = Object.values(Category).find(c => c.toLowerCase() === catStr);
          return { 
            id: `imp-${Date.now()}-${index}`, 
            name: String(row[0]||'').trim(), 
            category: cat || Category.MEAT, 
            description: String(row[2]||'').trim() 
          };
        }).filter(d => d.name);
        setPendingDishes(imported);
      } catch (e) {
        setToast({ message: 'Erro ao ler arquivo. Verifique o formato.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = () => {
    if (pendingDishes) {
      setDishPool(prev => [...prev, ...pendingDishes]);
      setToast({ message: `${pendingDishes.length} itens importados!`, type: 'success' });
    }
    setPendingDishes(null);
    setShowImportGuide(false);
  };

  return (
    <div className="min-h-screen bg-[#faf9f6] text-[#2d2d2d] antialiased scrollbar-thin">
      {/* Loading Overlay */}
      {isGenerating && (
        <div className="fixed inset-0 z-[1000] bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-500">
          <div className="relative mb-10">
            <div className="w-28 h-28 border-4 border-stone-100 border-t-orange-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-4xl">👨‍🍳</div>
          </div>
          <h2 className="serif text-3xl font-bold text-stone-800 animate-pulse tracking-tight text-center px-8">{generationStep}</h2>
          <p className="text-stone-400 text-[10px] uppercase tracking-[0.3em] mt-4 italic text-center px-10">
            Respeitando a rotação de 3 dias e o tema solicitado
          </p>
        </div>
      )}

      {/* Persistence Status */}
      <div className={`fixed top-24 right-8 z-[1100] transition-all duration-500 flex items-center gap-2 ${isSaving ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-2 pointer-events-none'}`}>
        <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
        <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest">Sincronizado</span>
      </div>

      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[1100] animate-in slide-in-from-bottom-6">
          <div className={`px-8 py-4 rounded-3xl shadow-2xl font-bold uppercase tracking-widest text-[10px] flex items-center gap-3 ${toast.type === 'success' ? 'bg-stone-900 text-white' : 'bg-red-500 text-white'}`}>
            <span>{toast.message}</span>
          </div>
        </div>
      )}

      {/* Navbar */}
      <nav className="fixed top-0 inset-x-0 h-20 bg-white/80 backdrop-blur-lg border-b border-stone-200/50 z-[100] px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center shadow-xl shadow-orange-200 text-white text-2xl">🥗</div>
            <div className="leading-tight">
              <h1 className="serif text-2xl font-black tracking-tighter">CHEF AI</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase tracking-[0.4em]">Personalizador Gourmet</span>
            </div>
          </div>
          <div className="flex bg-stone-100 p-1.5 rounded-2xl">
            {['compose', 'inventory', 'result'].map((t) => (
              <button 
                key={t}
                onClick={() => setActiveTab(t as TabType)}
                disabled={t === 'result' && !generatedMenu}
                className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-white text-stone-900 shadow-md' : 'text-stone-400 hover:text-stone-600 disabled:opacity-30'}`}
              >
                {t === 'compose' ? '✨ Criar' : t === 'inventory' ? '📦 Acervo' : '🖼️ Preview'}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-8 pt-32 pb-24">
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="lg:col-span-4 space-y-8">
              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <h2 className="serif text-2xl font-bold mb-6">Identidade Visual</h2>
                <div className="space-y-6">
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Logo da Marca</span>
                    <div className="relative h-40 rounded-3xl bg-stone-50 border-2 border-dashed border-stone-200 flex items-center justify-center cursor-pointer hover:border-orange-400 transition-all overflow-hidden group">
                      {config.logo ? <img src={config.logo} className="w-full h-full object-contain p-4" /> : <span className="text-[10px] font-bold text-stone-300">Upload Logo</span>}
                      <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleLogoUpload} />
                    </div>
                  </label>
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Título do Cardápio</span>
                    <input type="text" value={config.theme} onChange={e => setConfig({...config, theme: e.target.value})} className="w-full bg-stone-50 rounded-2xl px-5 py-4 outline-none font-bold text-stone-700 border border-stone-100 focus:ring-2 ring-orange-200 transition-all" placeholder="Ex: Sexta-feira Brasileira" />
                  </label>
                </div>
              </section>

              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="serif text-2xl font-bold">Marmitas / Preços</h2>
                  <button onClick={() => setConfig(prev => ({...prev, mealOptions: [...(prev.mealOptions||[]), {id: Date.now().toString(), title: '', price: ''}]}))} className="w-10 h-10 bg-orange-500 text-white rounded-2xl shadow-lg hover:scale-110 active:scale-95 transition-all">+</button>
                </div>
                <div className="space-y-4">
                  {config.mealOptions?.map(opt => (
                    <div key={opt.id} className="p-5 bg-stone-50 rounded-[2rem] border border-stone-100 relative group transition-all hover:bg-white hover:shadow-xl hover:shadow-stone-200/50">
                      <button onClick={() => setConfig(prev => ({...prev, mealOptions: prev.mealOptions?.filter(o => o.id !== opt.id)}))} className="absolute -top-2 -right-2 w-7 h-7 bg-white border border-stone-100 rounded-full flex items-center justify-center text-[10px] shadow-sm hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">✕</button>
                      <div className="space-y-3">
                        <input placeholder="Ex: Marmita G" value={opt.title} onChange={e => updateMealOption(opt.id, 'title', e.target.value)} className="bg-white border border-stone-100 rounded-xl px-4 py-2 font-bold text-xs w-full outline-none focus:border-orange-500" />
                        <input placeholder="R$ 00,00" value={opt.price} onChange={e => updateMealOption(opt.id, 'price', e.target.value)} className="bg-white border border-stone-100 rounded-xl px-4 py-2 text-[11px] text-orange-600 font-black w-full outline-none focus:border-orange-500" />
                      </div>
                    </div>
                  ))}
                </div>
              </section>

              <button onClick={handleGenerate} disabled={isGenerating} className="w-full py-6 bg-orange-500 text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-xs shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">
                {isGenerating ? 'Chef Criando...' : 'Gerar Menu Harmonizado'}
              </button>
            </div>

            <div className="lg:col-span-8 bg-white rounded-[3.5rem] p-12 shadow-sm border border-stone-100">
              <div className="flex justify-between items-center mb-12">
                <div>
                  <h2 className="serif text-4xl font-bold text-stone-800">Estrutura</h2>
                  <p className="text-stone-400 text-xs font-bold uppercase tracking-widest mt-1">Defina a composição do seu cardápio</p>
                </div>
                <button onClick={() => setConfig({...config, chefChoice: !config.chefChoice})} className={`px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${config.chefChoice ? 'bg-orange-500 text-white' : 'bg-stone-100 text-stone-400 hover:bg-stone-200'}`}>
                  {config.chefChoice ? '✨ Escolha Livre do Chef' : '⚙️ Quantidades Fixas'}
                </button>
              </div>

              <div className={`grid grid-cols-1 md:grid-cols-2 gap-6 transition-all duration-500 ${config.chefChoice ? 'opacity-30 pointer-events-none grayscale scale-[0.98]' : ''}`}>
                {CATEGORY_ORDER.map(cat => (
                  <div key={cat} className="group flex items-center justify-between p-6 bg-stone-50 rounded-[2.5rem] border border-stone-100 hover:bg-white hover:border-orange-200 hover:shadow-lg transition-all">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-2xl shadow-sm flex items-center justify-center text-2xl group-hover:scale-110 transition-transform">{(ICONS as any)[cat.toUpperCase()] || '🍽️'}</div>
                      <span className="font-bold text-stone-700">{cat}</span>
                    </div>
                    <div className="flex items-center gap-5 bg-white px-5 py-2 rounded-2xl shadow-sm border border-stone-100">
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat] - 1)}}))} className="font-black text-stone-400 hover:text-orange-500 transition-colors text-xl">-</button>
                      <span className="font-black w-6 text-center text-sm">{config.counts[cat]}</span>
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat] + 1}}))} className="font-black text-stone-400 hover:text-orange-500 transition-colors text-xl">+</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="bg-white rounded-[3.5rem] p-12 shadow-sm border border-stone-100 animate-in fade-in slide-in-from-bottom-6">
            <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-12">
              <div>
                <h2 className="serif text-5xl font-bold">Acervo de Sabores</h2>
                <p className="text-stone-400 text-xs font-bold uppercase tracking-widest mt-2">Personalize sua biblioteca de pratos</p>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setShowImportGuide(true)} className="px-6 py-4 bg-stone-100 text-stone-500 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-stone-200 transition-all">📥 Importar Excel</button>
                <button onClick={() => setEditingDish({ id: Date.now().toString(), name: '', category: Category.MEAT, description: '' })} className="px-8 py-4 bg-stone-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-black transition-all">+ Novo Prato</button>
              </div>
            </div>

            <div className="flex gap-4 mb-10">
              <input placeholder="Buscar no acervo..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="flex-1 bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-semibold focus:ring-2 ring-orange-100" />
              <select value={filterCategory} onChange={e => setFilterCategory(e.target.value as any)} className="bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-500 uppercase text-[10px]">
                <option value="Todos">Todas Categorias</option>
                {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredDishes.map(dish => (
                <div key={dish.id} className="group relative p-8 rounded-[3rem] bg-white border border-stone-100 hover:shadow-2xl hover:-translate-y-1 transition-all duration-300">
                  <div className="flex justify-between mb-5">
                    <span className="text-[9px] font-black uppercase tracking-widest text-stone-400 bg-stone-50 px-3 py-1.5 rounded-full border border-stone-100">{dish.category}</span>
                    <button onClick={() => handleToggleDefault(dish)} className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-all ${dish.isDefault ? 'bg-orange-500 text-white shadow-xl' : 'bg-stone-50 text-stone-300'}`} title="Prato Padrão">★</button>
                  </div>
                  <h3 className="serif text-2xl font-bold mb-2 group-hover:text-orange-500 transition-colors">{dish.name}</h3>
                  <p className="text-[11px] text-stone-400 italic line-clamp-3 leading-relaxed">{dish.description || 'Sem descrição gourmet...'}</p>

                  {recentDishIds.includes(dish.id) && (
                    <div className="mt-4 inline-block px-2 py-1 bg-red-50 text-red-500 text-[8px] font-black uppercase tracking-widest rounded-lg">
                      🕒 Rotação Ativa (Usado Recentemente)
                    </div>
                  )}

                  <div className="mt-8 flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all duration-300">
                    <button onClick={() => setEditingDish(dish)} className="p-3 bg-stone-50 rounded-xl hover:bg-orange-500 hover:text-white transition-all">✎</button>
                    <button onClick={() => { if(window.confirm(`Excluir ${dish.name}?`)) setDishPool(p => p.filter(d => d.id !== dish.id)); }} className="p-3 bg-stone-50 rounded-xl hover:bg-red-500 hover:text-white transition-all">✕</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in zoom-in-95 duration-700">
             <div className="mb-10 flex flex-wrap justify-center gap-6 no-print">
                <div className="flex bg-stone-100 p-1.5 rounded-full shadow-inner">
                  <button onClick={() => setExportFormat('standard')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'standard' ? 'bg-white text-stone-900 shadow-xl' : 'text-stone-400 hover:text-stone-600'}`}>A4 Impressão</button>
                  <button onClick={() => setExportFormat('story')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'story' ? 'bg-white text-stone-900 shadow-xl' : 'text-stone-400 hover:text-stone-600'}`}>Digital Story</button>
                </div>
                <button onClick={() => { 
                   setToast({ message: 'Preparando imagem...', type: 'success' });
                   toPng(menuRef.current!, { quality: 1, pixelRatio: 3 }).then(url => {
                     const l = document.createElement('a');
                     l.download = `Menu-${config.theme.replace(/\s+/g, '-')}.png`;
                     l.href = url;
                     l.click();
                   });
                }} className="px-10 py-3.5 bg-orange-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all">Download HD</button>
             </div>

             <div 
               ref={menuRef}
               className={`bg-white relative shadow-[0_50px_100px_-20px_rgba(0,0,0,0.15)] overflow-hidden transition-all duration-700 ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16]' : 'w-[850px] min-h-[1200px]'}`}
               style={{ backgroundColor: generatedMenu.visualTheme?.backgroundColor || '#fff' }}
             >
               <div className="absolute inset-0 pointer-events-none opacity-10" style={{ background: generatedMenu.visualTheme?.backgroundGradient }}></div>
               <div className="relative z-10 h-full flex flex-col items-center p-16">
                 <header className="text-center mb-16 w-full relative">
                   {config.logo && <img src={config.logo} className="h-28 mx-auto mb-8 object-contain drop-shadow-xl" alt="Estabelecimento" />}
                   <div className="inline-block px-6 py-2 mb-4 bg-stone-900 text-white text-[9px] font-black uppercase tracking-[0.5em] shadow-lg" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor }}>ChefAI Harmonized</div>
                   <h1 className="serif uppercase leading-[0.85] font-black text-stone-900 mb-8" style={{ color: generatedMenu.visualTheme?.textColor, fontSize: exportFormat === 'story' ? '56px' : '92px' }}>{config.theme}</h1>

                   <div className="flex flex-wrap justify-center gap-6 mt-10">
                     {config.mealOptions?.map(m => (
                       <div key={m.id} className="bg-white/40 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/60 shadow-sm flex flex-col items-center min-w-[120px]">
                         <span className="text-[8px] font-black uppercase text-stone-400 tracking-widest mb-1">{m.title}</span>
                         <span className="text-lg font-black text-orange-600">{m.price}</span>
                       </div>
                     ))}
                   </div>
                 </header>

                 <div className={`flex-1 w-full space-y-12 flex flex-col justify-center`} style={{ transform: `scale(${layoutScale})`, transformOrigin: 'top center' }}>
                   {CATEGORY_ORDER.map(cat => {
                     const items = generatedMenu.selections[cat];
                     if (!items?.length) return null;
                     return (
                       <div key={cat} className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
                         <div className="flex items-center gap-4">
                           <h3 className="text-[11px] font-black uppercase tracking-[0.6em] whitespace-nowrap" style={{ color: generatedMenu.visualTheme?.primaryColor }}>{cat}s</h3>
                           <div className="h-[1px] w-full bg-stone-100"></div>
                         </div>
                         <div className="space-y-6">
                           {items.map((it, idx) => (
                             <div key={idx} className="group">
                               <h4 className="font-bold text-2xl leading-none flex items-baseline gap-3" style={{ color: generatedMenu.visualTheme?.textColor }}>
                                 <span className="w-2 h-2 rounded-full flex-shrink-0" style={{ backgroundColor: generatedMenu.visualTheme?.accentColor }}></span>
                                 {it.name}
                               </h4>
                               {it.description && <p className="text-[13px] text-stone-400 italic font-medium leading-relaxed ml-5 mt-2 border-l-2 pl-4 py-1" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}>{it.description}</p>}
                             </div>
                           ))}
                         </div>
                       </div>
                     );
                   })}
                 </div>

                 <footer className="mt-20 w-full pt-16 border-t border-stone-100 flex flex-col items-center relative">
                   <p className="serif italic text-center text-stone-500 max-w-xl mx-auto mb-10 leading-relaxed text-xl px-4">"{generatedMenu.chefNote}"</p>
                   <div className="serif text-6xl font-black italic tracking-tighter text-stone-900 opacity-[0.08] mb-2">Bon Appétit</div>
                 </footer>
               </div>
             </div>
          </div>
        )}
      </main>

      {/* Editing Dish Modal */}
      {editingDish && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12 animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-10">
              <h3 className="serif text-3xl font-black text-stone-800">Ficha Técnica</h3>
              <button onClick={() => setEditingDish(null)} className="text-2xl opacity-20 hover:opacity-100 transition-opacity">✕</button>
            </div>
            <div className="space-y-8">
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Nome do Item</span>
                <input value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-lg text-stone-700" />
              </label>
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Categoria</span>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-600">
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </label>
              <label className="block">
                <div className="flex justify-between items-center mb-2">
                  <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Descrição Gourmet</span>
                  <button onClick={async () => {
                    if (!editingDish.name) return;
                    setIsGeneratingDesc(true);
                    try {
                      const desc = await generateDishDescription(editingDish.name);
                      setEditingDish({...editingDish, description: desc});
                    } finally { setIsGeneratingDesc(false); }
                  }} disabled={isGeneratingDesc} className="text-[10px] font-black text-orange-500 uppercase tracking-widest flex items-center gap-1.5 hover:scale-105 transition-transform">
                    {isGeneratingDesc ? '✍️ Redigindo...' : '✨ Sugestão IA'}
                  </button>
                </div>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none min-h-[120px] text-sm text-stone-600 leading-relaxed" placeholder="Como esse prato deve ser apresentado?" />
              </label>
              <div className="flex gap-4 pt-6">
                <button onClick={() => setEditingDish(null)} className="flex-1 py-5 font-black uppercase text-[10px] text-stone-400 hover:text-stone-600 tracking-widest transition-colors">Cancelar</button>
                <button onClick={() => {
                  setDishPool(p => {
                    const idx = p.findIndex(d => d.id === editingDish.id);
                    if (idx >= 0) { const c = [...p]; c[idx] = editingDish; return c; }
                    return [...p, editingDish];
                  });
                  setEditingDish(null);
                  setToast({ message: 'Item atualizado!', type: 'success' });
                }} className="flex-1 py-5 bg-orange-500 text-white rounded-[1.5rem] font-black uppercase text-[10px] shadow-xl hover:scale-[1.02] active:scale-95 transition-all tracking-widest">Salvar Especialidade</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showImportGuide && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-2xl p-12 animate-in zoom-in-95 overflow-y-auto max-h-[90vh] border border-white">
            <div className="flex justify-between mb-10">
              <h3 className="serif text-4xl font-black text-stone-800">Importar Especialidades</h3>
              <button onClick={() => setShowImportGuide(false)} className="text-2xl opacity-20 hover:opacity-100">✕</button>
            </div>

            <div className="space-y-8">
              <div className="p-6 bg-orange-50 rounded-3xl border border-orange-100 text-sm text-orange-800 leading-relaxed italic">
                A IA analisará cada prato importado para criar o menu perfeito baseado no título.
                Organize seu arquivo com as colunas: <span className="font-bold underline">Nome, Categoria, Descrição</span>.
              </div>

              <label className="block w-full cursor-pointer group">
                <div className="w-full h-48 border-2 border-dashed border-stone-200 rounded-[2.5rem] flex flex-col items-center justify-center group-hover:border-orange-500 group-hover:bg-orange-50 transition-all duration-300">
                  <span className="text-5xl mb-4 group-hover:scale-110 transition-transform">📊</span>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] text-stone-400">Selecionar arquivo (.xlsx, .xls ou .csv)</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleImportExcel} />
              </label>

              {pendingDishes && pendingDishes.length > 0 && (
                <div className="pt-6 animate-in slide-in-from-bottom-4">
                  <p className="text-[10px] font-black uppercase text-orange-500 mb-5 text-center tracking-[0.2em]">Encontrados {pendingDishes.length} itens para o acervo</p>
                  <button onClick={confirmImport} className="w-full py-6 bg-stone-900 text-white rounded-[2rem] font-black uppercase tracking-[0.4em] text-[10px] shadow-2xl hover:bg-black transition-all">Confirmar e Importar</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { toPng } from 'html-to-image';
import * as XLSX from 'xlsx';
import { Category, Dish, MenuConfig, GeneratedMenu, VisualTheme, MealOption, MenuHistoryEntry } from './types';
import { DEFAULT_DISHES, ICONS, CATEGORY_ORDER } from './constants';
import { generateMenuWithAI, generateDishDescription } from './services/geminiService';

type TabType = 'compose' | 'inventory' | 'result';

const STORAGE_LOGO_KEY = 'chefai_brand_logo';
const STORAGE_INVENTORY_KEY = 'chefai_inventory';
const STORAGE_CONFIG_KEY = 'chefai_session_config';
const STORAGE_HISTORY_KEY = 'chefai_menu_history';

const App: React.FC = () => {
  // 1. Inventory State with Persistence
  const [dishPool, setDishPool] = useState<Dish[]>(() => {
    const saved = localStorage.getItem(STORAGE_INVENTORY_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_DISHES;
  });

  // 2. History State (Rotation logic)
  const [menuHistory, setMenuHistory] = useState<MenuHistoryEntry[]>(() => {
    const saved = localStorage.getItem(STORAGE_HISTORY_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // 3. Configuration State
  const [config, setConfig] = useState<MenuConfig>(() => {
    const saved = localStorage.getItem(STORAGE_CONFIG_KEY);
    const savedLogo = localStorage.getItem(STORAGE_LOGO_KEY);

    const defaultConfig: MenuConfig = {
      counts: { 
        [Category.BASE]: 2, 
        [Category.MEAT]: 2, 
        [Category.PASTA]: 0, 
        [Category.SIDE]: 2, 
        [Category.SALAD]: 2, 
        [Category.DESSERT]: 0 
      },
      theme: 'Cardápio Especial do Dia',
      baseOption: 'Tradicional',
      chefChoice: false,
      useDefaultLayout: false,
      mealOptions: []
    };

    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return { 
          ...defaultConfig, 
          ...parsed, 
          logo: savedLogo || undefined,
          counts: { ...defaultConfig.counts, ...parsed.counts }
        };
      } catch (e) { 
        return defaultConfig; 
      }
    }
    return defaultConfig;
  });

  // UI States
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [generatedMenu, setGeneratedMenu] = useState<GeneratedMenu | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('compose');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState<Category | 'Todos'>('Todos');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [editingDish, setEditingDish] = useState<Dish | null>(null);
  const [showImportGuide, setShowImportGuide] = useState(false);
  const [pendingDishes, setPendingDishes] = useState<Dish[] | null>(null);
  const [exportFormat, setExportFormat] = useState<'standard' | 'story'>('standard');
  const [isSaving, setIsSaving] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  // Persistence Effects
  useEffect(() => {
    localStorage.setItem(STORAGE_INVENTORY_KEY, JSON.stringify(dishPool));
  }, [dishPool]);

  useEffect(() => {
    localStorage.setItem(STORAGE_HISTORY_KEY, JSON.stringify(menuHistory));
  }, [menuHistory]);

  useEffect(() => {
    setIsSaving(true);
    const { logo, ...persistableConfig } = config;
    localStorage.setItem(STORAGE_CONFIG_KEY, JSON.stringify(persistableConfig));
    if (logo) {
      localStorage.setItem(STORAGE_LOGO_KEY, logo);
    } else {
      localStorage.removeItem(STORAGE_LOGO_KEY);
    }
    const timer = setTimeout(() => setIsSaving(false), 800);
    return () => clearTimeout(timer);
  }, [config]);

  const recentDishIds = useMemo(() => {
    return menuHistory.slice(-3).flatMap(entry => entry.dishIds);
  }, [menuHistory]);

  const totalItemsCount = useMemo(() => {
    if (!generatedMenu) return 0;
    return Object.values(generatedMenu.selections).reduce((acc: number, curr: any) => acc + (curr?.length || 0), 0);
  }, [generatedMenu]);

  const layoutScale = useMemo(() => {
    if (exportFormat === 'story') {
      if (totalItemsCount > 15) return 0.55;
      if (totalItemsCount > 10) return 0.7;
      return 0.85;
    }
    return 1;
  }, [exportFormat, totalItemsCount]);

  const filteredDishes = useMemo(() => {
    return dishPool.filter(dish => {
      const matchesSearch = dish.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory === 'Todos' || dish.category === filterCategory;
      return matchesSearch && matchesCategory;
    }).sort((a, b) => (a.isDefault === b.isDefault) ? 0 : a.isDefault ? -1 : 1);
  }, [dishPool, searchTerm, filterCategory]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Handlers
  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = evt.target?.result as string;
      setConfig(prev => ({ ...prev, logo: base64 }));
    };
    reader.readAsDataURL(file);
  };

  const updateMealOption = (id: string, field: keyof MealOption, value: string) => {
    let finalValue = value;
    if (field === 'price' && value && !value.startsWith('R$')) {
      finalValue = 'R$ ' + value;
    }
    setConfig(prev => ({
      ...prev,
      mealOptions: prev.mealOptions?.map(o => o.id === id ? { ...o, [field]: finalValue } : o)
    }));
  };

  const handleToggleDefault = (dish: Dish) => {
    setDishPool(prev => prev.map(d => {
      if (d.id === dish.id) return { ...d, isDefault: !d.isDefault };
      if (d.category === dish.category) return { ...d, isDefault: false };
      return d;
    }));
  };

  const handleGenerate = async () => {
    if (dishPool.length === 0) { 
      setToast({ message: 'Seu acervo está vazio!', type: 'error' }); 
      setActiveTab('inventory'); 
      return; 
    }
    setIsGenerating(true);
    setGenerationStep(`ChefAI harmonizando pratos para: ${config.theme}...`);
    try {
      const result = await generateMenuWithAI(
        dishPool, 
        { ...config, recentDishIds }, 
        (step) => setGenerationStep(step)
      );

      setGeneratedMenu(result);

      const usedIds: string[] = [];
      Object.values(result.selections).forEach((items: any[]) => {
        items.forEach(item => {
          const found = dishPool.find(d => d.name === item.name);
          if (found) usedIds.push(found.id);
        });
      });

      setMenuHistory(prev => {
        const newHistory = [...prev, { date: new Date().toISOString(), dishIds: usedIds }];
        return newHistory.slice(-10);
      });

      setActiveTab('result');
      setToast({ message: 'Cardápio gerado com sucesso!', type: 'success' });
    } catch (error: any) {
      setToast({ message: error.message || 'Erro na geração.', type: 'error' });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImportExcel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const wb = XLSX.read(evt.target?.result, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];
        const imported: Dish[] = data.slice(1).map((row, index) => {
          const catStr = String(row[1]||'').trim().toLowerCase();
          const cat = Object.values(Category).find(c => c.toLowerCase() === catStr);
          return { 
            id: `imp-${Date.now()}-${index}`, 
            name: String(row[0]||'').trim(), 
            category: cat || Category.MEAT, 
            description: String(row[2]||'').trim() 
          };
        }).filter(d => d.name);
        setPendingDishes(imported);
      } catch (e) {
        setToast({ message: 'Erro ao ler arquivo. Verifique o formato.', type: 'error' });
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = () => {
    if (pendingDishes) {
      setDishPool(prev => [...prev, ...pendingDishes]);
      setToast({ message: `${pendingDishes.length} itens importados!`, type: 'success' });
    }
    setPendingDishes(null);
    setShowImportGuide(false);
  };

  return (
    <div className="min-h-screen bg-[#faf9f6] text-[#2d2d2d] antialiased scrollbar-thin">
      {/* Loading Overlay */}
      {isGenerating && (
        <div className="fixed inset-0 z-[1000] bg-white/90 backdrop-blur-xl flex flex-col items-center justify-center animate-in fade-in duration-500">
          <div className="relative mb-10">
            <div className="w-28 h-28 border-4 border-stone-100 border-t-orange-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-4xl">👨‍🍳</div>
          </div>
          <h2 className="serif text-3xl font-bold text-stone-800 animate-pulse tracking-tight text-center px-8">{generationStep}</h2>
          <p className="text-stone-400 text-[10px] uppercase tracking-[0.3em] mt-4 italic text-center px-10">
            Respeitando a rotação de 3 dias e o tema solicitado
          </p>
        </div>
      )}

      {/* Persistence Status */}
      <div className={`fixed top-24 right-8 z-[1100] transition-all duration-500 flex items-center gap-2 ${isSaving ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-2 pointer-events-none'}`}>
        <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
        <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest">Sincronizado</span>
      </div>

      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[1100] animate-in slide-in-from-bottom-6">
          <div className={`px-8 py-4 rounded-3xl shadow-2xl font-bold uppercase tracking-widest text-[10px] flex items-center gap-3 ${toast.type === 'success' ? 'bg-stone-900 text-white' : 'bg-red-500 text-white'}`}>
            <span>{toast.message}</span>
          </div>
        </div>
      )}

      {/* Navbar */}
      <nav className="fixed top-0 inset-x-0 h-20 bg-white/80 backdrop-blur-lg border-b border-stone-200/50 z-[100] px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center shadow-xl shadow-orange-200 text-white text-2xl">🥗</div>
            <div className="leading-tight">
              <h1 className="serif text-2xl font-black tracking-tighter">CHEF AI</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase tracking-[0.4em]">Personalizador Gourmet</span>
            </div>
          </div>
          <div className="flex bg-stone-100 p-1.5 rounded-2xl">
            {['compose', 'inventory', 'result'].map((t) => (
              <button 
                key={t}
                onClick={() => setActiveTab(t as TabType)}
                disabled={t === 'result' && !generatedMenu}
                className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-white text-stone-900 shadow-md' : 'text-stone-400 hover:text-stone-600 disabled:opacity-30'}`}
              >
                {t === 'compose' ? '✨ Criar' : t === 'inventory' ? '📦 Acervo' : '🖼️ Preview'}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-8 pt-32 pb-24">
        {activeTab === 'compose' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="lg:col-span-4 space-y-8">
              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <h2 className="serif text-2xl font-bold mb-6">Identidade Visual</h2>
                <div className="space-y-6">
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Logo da Marca</span>
                    <div className="relative h-40 rounded-3xl bg-stone-50 border-2 border-dashed border-stone-200 flex items-center justify-center cursor-pointer hover:border-orange-400 transition-all overflow-hidden group">
                      {config.logo ? <img src={config.logo} className="w-full h-full object-contain p-4" /> : <span className="text-[10px] font-bold text-stone-300">Upload Logo</span>}
                      <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleLogoUpload} />
                    </div>
                  </label>
                  <label className="block">
                    <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Título do Cardápio</span>
                    <input type="text" value={config.theme} onChange={e => setConfig({...config, theme: e.target.value})} className="w-full bg-stone-50 rounded-2xl px-5 py-4 outline-none font-bold text-stone-700 border border-stone-100 focus:ring-2 ring-orange-200 transition-all" placeholder="Ex: Sexta-feira Brasileira" />
                  </label>
                </div>
              </section>

              <section className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-stone-100">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="serif text-2xl font-bold">Marmitas / Preços</h2>
                  <button onClick={() => setConfig(prev => ({...prev, mealOptions: [...(prev.mealOptions||[]), {id: Date.now().toString(), title: '', price: ''}]}))} className="w-10 h-10 bg-orange-500 text-white rounded-2xl shadow-lg hover:scale-110 active:scale-95 transition-all">+</button>
                </div>
                <div className="space-y-4">
                  {config.mealOptions?.map(opt => (
                    <div key={opt.id} className="p-5 bg-stone-50 rounded-[2rem] border border-stone-100 relative group transition-all hover:bg-white hover:shadow-xl hover:shadow-stone-200/50">
                      <button onClick={() => setConfig(prev => ({...prev, mealOptions: prev.mealOptions?.filter(o => o.id !== opt.id)}))} className="absolute -top-2 -right-2 w-7 h-7 bg-white border border-stone-100 rounded-full flex items-center justify-center text-[10px] shadow-sm hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">✕</button>
                      <div className="space-y-3">
                        <input placeholder="Ex: Marmita G" value={opt.title} onChange={e => updateMealOption(opt.id, 'title', e.target.value)} className="bg-white border border-stone-100 rounded-xl px-4 py-2 font-bold text-xs w-full outline-none focus:border-orange-500" />
                        <input placeholder="R$ 00,00" value={opt.price} onChange={e => updateMealOption(opt.id, 'price', e.target.value)} className="bg-white border border-stone-100 rounded-xl px-4 py-2 text-[11px] text-orange-600 font-black w-full outline-none focus:border-orange-500" />
                      </div>
                    </div>
                  ))}
                </div>
              </section>

              <button onClick={handleGenerate} disabled={isGenerating} className="w-full py-6 bg-orange-500 text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-xs shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">
                {isGenerating ? 'Chef Criando...' : 'Gerar Menu Harmonizado'}
              </button>
            </div>

            <div className="lg:col-span-8 bg-white rounded-[3.5rem] p-12 shadow-sm border border-stone-100">
              <div className="flex justify-between items-center mb-12">
                <div>
                  <h2 className="serif text-4xl font-bold text-stone-800">Estrutura</h2>
                  <p className="text-stone-400 text-xs font-bold uppercase tracking-widest mt-1">Defina a composição do seu cardápio</p>
                </div>
                <button onClick={() => setConfig({...config, chefChoice: !config.chefChoice})} className={`px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${config.chefChoice ? 'bg-orange-500 text-white' : 'bg-stone-100 text-stone-400 hover:bg-stone-200'}`}>
                  {config.chefChoice ? '✨ Escolha Livre do Chef' : '⚙️ Quantidades Fixas'}
                </button>
              </div>

              <div className={`grid grid-cols-1 md:grid-cols-2 gap-6 transition-all duration-500 ${config.chefChoice ? 'opacity-30 pointer-events-none grayscale scale-[0.98]' : ''}`}>
                {CATEGORY_ORDER.map(cat => (
                  <div key={cat} className="group flex items-center justify-between p-6 bg-stone-50 rounded-[2.5rem] border border-stone-100 hover:bg-white hover:border-orange-200 hover:shadow-lg transition-all">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-2xl shadow-sm flex items-center justify-center text-2xl group-hover:scale-110 transition-transform">{(ICONS as any)[cat.toUpperCase()] || '🍽️'}</div>
                      <span className="font-bold text-stone-700">{cat}</span>
                    </div>
                    <div className="flex items-center gap-5 bg-white px-5 py-2 rounded-2xl shadow-sm border border-stone-100">
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: Math.max(0, p.counts[cat] - 1)}}))} className="font-black text-stone-400 hover:text-orange-500 transition-colors text-xl">-</button>
                      <span className="font-black w-6 text-center text-sm">{config.counts[cat]}</span>
                      <button onClick={() => setConfig(p => ({...p, counts: {...p.counts, [cat]: p.counts[cat] + 1}}))} className="font-black text-stone-400 hover:text-orange-500 transition-colors text-xl">+</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="bg-white rounded-[3.5rem] p-12 shadow-sm border border-stone-100 animate-in fade-in slide-in-from-bottom-6">
            <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-12">
              <div>
                <h2 className="serif text-5xl font-bold">Acervo de Sabores</h2>
                <p className="text-stone-400 text-xs font-bold uppercase tracking-widest mt-2">Personalize sua biblioteca de pratos</p>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setShowImportGuide(true)} className="px-6 py-4 bg-stone-100 text-stone-500 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-stone-200 transition-all">📥 Importar Excel</button>
                <button onClick={() => setEditingDish({ id: Date.now().toString(), name: '', category: Category.MEAT, description: '' })} className="px-8 py-4 bg-stone-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-black transition-all">+ Novo Prato</button>
              </div>
            </div>

            <div className="flex gap-4 mb-10">
              <input placeholder="Buscar no acervo..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="flex-1 bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-semibold focus:ring-2 ring-orange-100" />
              <select value={filterCategory} onChange={e => setFilterCategory(e.target.value as any)} className="bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-500 uppercase text-[10px]">
                <option value="Todos">Todas Categorias</option>
                {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredDishes.map(dish => (
                <div key={dish.id} className="group relative p-8 rounded-[3rem] bg-white border border-stone-100 hover:shadow-2xl hover:-translate-y-1 transition-all duration-300">
                  <div className="flex justify-between mb-5">
                    <span className="text-[9px] font-black uppercase tracking-widest text-stone-400 bg-stone-50 px-3 py-1.5 rounded-full border border-stone-100">{dish.category}</span>
                    <button onClick={() => handleToggleDefault(dish)} className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-all ${dish.isDefault ? 'bg-orange-500 text-white shadow-xl' : 'bg-stone-50 text-stone-300'}`} title="Prato Padrão">★</button>
                  </div>
                  <h3 className="serif text-2xl font-bold mb-2 group-hover:text-orange-500 transition-colors">{dish.name}</h3>
                  <p className="text-[11px] text-stone-400 italic line-clamp-3 leading-relaxed">{dish.description || 'Sem descrição gourmet...'}</p>

                  {recentDishIds.includes(dish.id) && (
                    <div className="mt-4 inline-block px-2 py-1 bg-red-50 text-red-500 text-[8px] font-black uppercase tracking-widest rounded-lg">
                      🕒 Rotação Ativa (Usado Recentemente)
                    </div>
                  )}

                  <div className="mt-8 flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all duration-300">
                    <button onClick={() => setEditingDish(dish)} className="p-3 bg-stone-50 rounded-xl hover:bg-orange-500 hover:text-white transition-all">✎</button>
                    <button onClick={() => { if(window.confirm(`Excluir ${dish.name}?`)) setDishPool(p => p.filter(d => d.id !== dish.id)); }} className="p-3 bg-stone-50 rounded-xl hover:bg-red-500 hover:text-white transition-all">✕</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'result' && generatedMenu && (
          <div className="flex flex-col items-center animate-in zoom-in-95 duration-700">
             <div className="mb-10 flex flex-wrap justify-center gap-6 no-print">
                <div className="flex bg-stone-100 p-1.5 rounded-full shadow-inner">
                  <button onClick={() => setExportFormat('standard')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'standard' ? 'bg-white text-stone-900 shadow-xl' : 'text-stone-400 hover:text-stone-600'}`}>A4 Impressão</button>
                  <button onClick={() => setExportFormat('story')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${exportFormat === 'story' ? 'bg-white text-stone-900 shadow-xl' : 'text-stone-400 hover:text-stone-600'}`}>Digital Story</button>
                </div>
                <div className="flex gap-4">
                  <button onClick={handleGenerate} className="px-10 py-3.5 bg-stone-900 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all">Outra Combinação</button>
                  <button onClick={() => { 
                     setToast({ message: 'Preparando imagem...', type: 'success' });
                     toPng(menuRef.current!, { quality: 1, pixelRatio: 3 }).then(url => {
                       const l = document.createElement('a');
                       l.download = `Menu-${config.theme.replace(/\s+/g, '-')}.png`;
                       l.href = url;
                       l.click();
                     });
                  }} className="px-10 py-3.5 bg-orange-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all">Download HD</button>
                </div>
             </div>

             <div 
               ref={menuRef}
               className={`bg-white relative shadow-[0_50px_100px_-20px_rgba(0,0,0,0.15)] overflow-hidden transition-all duration-700 ${exportFormat === 'story' ? 'w-[450px] aspect-[9/16]' : 'w-[850px] min-h-[1200px]'}`}
               style={{ backgroundColor: generatedMenu.visualTheme?.backgroundColor || '#fff' }}
             >
               <div className="absolute inset-0 pointer-events-none opacity-10" style={{ background: generatedMenu.visualTheme?.backgroundGradient }}></div>
               <div className="relative z-10 h-full flex flex-col items-center p-16">
                 <header className="text-center mb-16 w-full relative">
                   {config.logo && <img src={config.logo} className="h-28 mx-auto mb-8 object-contain drop-shadow-xl" alt="Estabelecimento" />}
                   <div className="inline-block px-6 py-2 mb-4 bg-stone-900 text-white text-[9px] font-black uppercase tracking-[0.5em] shadow-lg" style={{ backgroundColor: generatedMenu.visualTheme?.primaryColor }}>ChefAI Harmonized</div>
                   <h1 className="serif uppercase leading-[0.85] font-black text-stone-900 mb-8" style={{ color: generatedMenu.visualTheme?.textColor, fontSize: exportFormat === 'story' ? '56px' : '92px' }}>{config.theme}</h1>

                   <div className="flex flex-wrap justify-center gap-6 mt-10">
                     {config.mealOptions?.map(m => (
                       <div key={m.id} className="bg-white/40 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/60 shadow-sm flex flex-col items-center min-w-[120px]">
                         <span className="text-[8px] font-black uppercase text-stone-400 tracking-widest mb-1">{m.title}</span>
                         <span className="text-lg font-black text-orange-600">{m.price}</span>
                       </div>
                     ))}
                   </div>
                 </header>

                 <div className={`flex-1 w-full space-y-12 flex flex-col justify-center`} style={{ transform: `scale(${layoutScale})`, transformOrigin: 'top center' }}>
                   {CATEGORY_ORDER.map(cat => {
                     const items = generatedMenu.selections[cat];
                     if (!items?.length) return null;
                     return (
                       <div key={cat} className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
                         <div className="flex items-center gap-4">
                           <h3 className="text-[11px] font-black uppercase tracking-[0.6em] whitespace-nowrap" style={{ color: generatedMenu.visualTheme?.primaryColor }}>{cat}s</h3>
                           <div className="h-[1px] w-full bg-stone-100"></div>
                         </div>
                         <div className="space-y-6">
                           {items.map((it, idx) => (
                             <div key={idx} className="group">
                               <h4 className="font-bold text-2xl leading-none flex items-baseline gap-3" style={{ color: generatedMenu.visualTheme?.textColor }}>
                                 <span className="w-2 h-2 rounded-full flex-shrink-0" style={{ backgroundColor: generatedMenu.visualTheme?.accentColor }}></span>
                                 {it.name}
                               </h4>
                               {it.description && <p className="text-[13px] text-stone-400 italic font-medium leading-relaxed ml-5 mt-2 border-l-2 pl-4 py-1" style={{ borderColor: generatedMenu.visualTheme?.primaryColor + '20' }}>{it.description}</p>}
                             </div>
                           ))}
                         </div>
                       </div>
                     );
                   })}
                 </div>

                 <footer className="mt-20 w-full pt-16 border-t border-stone-100 flex flex-col items-center relative">
                   <p className="serif italic text-center text-stone-500 max-w-xl mx-auto mb-10 leading-relaxed text-xl px-4">"{generatedMenu.chefNote}"</p>
                   <div className="serif text-6xl font-black italic tracking-tighter text-stone-900 opacity-[0.08] mb-2">Bon Appétit</div>
                 </footer>
               </div>
             </div>
          </div>
        )}
      </main>

      {/* Editing Dish Modal */}
      {editingDish && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-lg p-12 animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-10">
              <h3 className="serif text-3xl font-black text-stone-800">Ficha Técnica</h3>
              <button onClick={() => setEditingDish(null)} className="text-2xl opacity-20 hover:opacity-100 transition-opacity">✕</button>
            </div>
            <div className="space-y-8">
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Nome do Item</span>
                <input value={editingDish.name} onChange={e => setEditingDish({...editingDish, name: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-lg text-stone-700" />
              </label>
              <label className="block">
                <span className="text-[10px] font-black text-stone-400 uppercase mb-2 block tracking-widest">Categoria</span>
                <select value={editingDish.category} onChange={e => setEditingDish({...editingDish, category: e.target.value as Category})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none font-bold text-stone-600">
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </label>
              <label className="block">
                <div className="flex justify-between items-center mb-2">
                  <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Descrição Gourmet</span>
                  <button onClick={async () => {
                    if (!editingDish.name) return;
                    setIsGeneratingDesc(true);
                    try {
                      const desc = await generateDishDescription(editingDish.name);
                      setEditingDish({...editingDish, description: desc});
                    } finally { setIsGeneratingDesc(false); }
                  }} disabled={isGeneratingDesc} className="text-[10px] font-black text-orange-500 uppercase tracking-widest flex items-center gap-1.5 hover:scale-105 transition-transform">
                    {isGeneratingDesc ? '✍️ Redigindo...' : '✨ Sugestão IA'}
                  </button>
                </div>
                <textarea value={editingDish.description || ''} onChange={e => setEditingDish({...editingDish, description: e.target.value})} className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-6 py-4 outline-none min-h-[120px] text-sm text-stone-600 leading-relaxed" placeholder="Como esse prato deve ser apresentado?" />
              </label>
              <div className="flex gap-4 pt-6">
                <button onClick={() => setEditingDish(null)} className="flex-1 py-5 font-black uppercase text-[10px] text-stone-400 hover:text-stone-600 tracking-widest transition-colors">Cancelar</button>
                <button onClick={() => {
                  setDishPool(p => {
                    const idx = p.findIndex(d => d.id === editingDish.id);
                    if (idx >= 0) { const c = [...p]; c[idx] = editingDish; return c; }
                    return [...p, editingDish];
                  });
                  setEditingDish(null);
                  setToast({ message: 'Item atualizado!', type: 'success' });
                }} className="flex-1 py-5 bg-orange-500 text-white rounded-[1.5rem] font-black uppercase text-[10px] shadow-xl hover:scale-[1.02] active:scale-95 transition-all tracking-widest">Salvar Especialidade</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showImportGuide && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-6 bg-stone-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] shadow-2xl w-full max-w-2xl p-12 animate-in zoom-in-95 overflow-y-auto max-h-[90vh] border border-white">
            <div className="flex justify-between mb-10">
              <h3 className="serif text-4xl font-black text-stone-800">Importar Especialidades</h3>
              <button onClick={() => setShowImportGuide(false)} className="text-2xl opacity-20 hover:opacity-100">✕</button>
            </div>

            <div className="space-y-8">
              <div className="p-6 bg-orange-50 rounded-3xl border border-orange-100 text-sm text-orange-800 leading-relaxed italic">
                A IA analisará cada prato importado para criar o menu perfeito baseado no título.
                Organize seu arquivo com as colunas: <span className="font-bold underline">Nome, Categoria, Descrição</span>.
              </div>

              <label className="block w-full cursor-pointer group">
                <div className="w-full h-48 border-2 border-dashed border-stone-200 rounded-[2.5rem] flex flex-col items-center justify-center group-hover:border-orange-500 group-hover:bg-orange-50 transition-all duration-300">
                  <span className="text-5xl mb-4 group-hover:scale-110 transition-transform">📊</span>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] text-stone-400">Selecionar arquivo (.xlsx, .xls ou .csv)</span>
                </div>
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleImportExcel} />
              </label>

              {pendingDishes && pendingDishes.length > 0 && (
                <div className="pt-6 animate-in slide-in-from-bottom-4">
                  <p className="text-[10px] font-black uppercase text-orange-500 mb-5 text-center tracking-[0.2em]">Encontrados {pendingDishes.length} itens para o acervo</p>
                  <button onClick={confirmImport} className="w-full py-6 bg-stone-900 text-white rounded-[2rem] font-black uppercase tracking-[0.4em] text-[10px] shadow-2xl hover:bg-black transition-all">Confirmar e Importar</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
